        bool playerWasInVehicleForFriendlies = false;
        Vehicle lastPlayerVehicleForFriendlies = 0;
        DWORD lastBodyguardVehicleCommandTick = 0;
        DWORD lastBodyguardBrainTick = 0;
        DWORD lastBodyguardMedicHealTick = 0;
        DWORD lastFriendlyNpcProtectionTick = 0;
        std::string lastFriendlyNpcProtectionReport = "Friendly NPC support ready.";
        // BUGFIX 124: remember the active target given to each companion. GTA can
        // keep a drive-by / combat aim task alive after the target dies, leaving
        // the friendly NPC aiming at a corpse instead of returning to vehicle
        // handoff/auto-seat logic.
        std::map<Ped, Ped> companionCombatTarget;
        std::map<Ped, DWORD> companionCombatTargetUntilTick;
        // BUGFIX 128: active vehicle-fire reissue throttles.  Anti-panic runs every
        // frame, but drive-by task reissue must be rate-limited so it does not reset
        // door/seat animations or spam native tasks.
        std::map<Ped, DWORD> companionVehicleFireLastReissueTick;
        // BUGFIX 174: seated companion vehicle-fire needs its own weapon/task
        // stabilization state. Re-applying SET_CURRENT_PED_WEAPON / TASK_DRIVE_BY
        // every support pass can restart the draw-weapon animation forever, so the
        // weapon handoff and drive-by task are now throttled per companion/target.
        std::map<Ped, DWORD> companionVehicleWeaponPrepLastTick;
        std::map<Ped, DWORD> companionVehicleFireTaskLastIssueTick;
        std::map<Ped, Ped> companionVehicleFireTaskTarget;
        // BUGFIX 143: keep anti-panic throttles in State instead of function-local
        // static maps so stale ped handles are purged with the rest of companion runtime
        // and DLL detach can release the storage.
        std::map<Ped, DWORD> companionPanicLastCleanupAttemptTick;
        std::map<Ped, DWORD> companionPanicLastPoliceScanTick;
        // HOTFIX 218: throttle the wide wanted-police emergency scans added in 217.
        // Without this, multiple friendlies/bodyguards can run duplicated 900m+ world
        // scans several times per second during wanted chases.
        std::map<Ped, DWORD> companionWantedPoliceEmergencyLastScanTick;
        // HOTFIX 215: throttle regroup/follow tasks after the player exits a vehicle.
        // Without this, friendlies can either stay seated forever or receive follow task
        // spam every support tick.
        std::map<Ped, DWORD> companionFootFollowLastIssueTick;
        // BUGFIX 146: throttles forced defensive assist target acquisition.  Earlier
        // anti-panic fixes removed flee, but if no target was already registered the
        // companion could fall back to follow/idle and never return fire.
        std::map<Ped, DWORD> companionDefensiveAssistLastTick;
        size_t companionAntiPanicCursor = 0;
        // BUGFIX 124: police can keep their explicit combat task after player death
        // and respawn even when the wanted level has already been cleared. Track the
        // transition so stale law-enforcement aggro is flushed once the player is alive.
        bool playerWasDeadForPoliceAggroReset = false;
