    static const char* MenuSoundNativeName(MenuSoundKind kind)
    {
        switch (kind)
        {
            case MenuSoundKind::Open: return "SELECT";
            case MenuSoundKind::Close: return "BACK";
            case MenuSoundKind::Navigate: return "NAV_UP_DOWN";
            case MenuSoundKind::Select: return "SELECT";
            case MenuSoundKind::Back: return "BACK";
            case MenuSoundKind::Favorite: return "TOGGLE_ON";
            default: return "SELECT";
        }
    }

