    static std::string NowTag()
    {
        SYSTEMTIME t{};
        GetLocalTime(&t);
        char buf[64];
        sprintf_s(buf, "%02d:%02d:%02d", t.wHour, t.wMinute, t.wSecond);
        return buf;
    }

    static void Log(const std::string& text)
    {
        if (g_logPath.empty()) return;
        try
        {
            std::string safe = text;
            for (char& ch : safe)
            {
                if (ch == '\0' || ch == '\r' || ch == '\n') ch = ' ';
            }
            if (safe.size() > 4096) safe = safe.substr(0, 4093) + "...";

            // Keep the runtime log bounded. A faulting module should not be able
            // to fill the GTA folder with an endlessly growing log file.
            std::error_code ec;
            if (std::filesystem::exists(g_logPath, ec))
            {
                ec.clear();
                const auto size = std::filesystem::file_size(g_logPath, ec);
                if (!ec && size > 1024u * 1024u)
                {
                    std::error_code rotateEc;
                    const std::string oldPath = g_logPath + ".old";
                    std::filesystem::remove(oldPath, rotateEc);
                    rotateEc.clear();
                    std::filesystem::rename(g_logPath, oldPath, rotateEc);
                    if (rotateEc)
                    {
                        std::ofstream reset(g_logPath, std::ios::trunc);
                        if (reset) reset << "[" << NowTag() << "] log rotation fallback: previous log truncated\n";
                    }
                }
            }

            std::ofstream f(g_logPath, std::ios::app);
            if (f) f << "[" << NowTag() << "] " << safe << "\n";
        }
        catch (...)
        {
            // Logging must never become a crash source inside DllMain/ScriptTick recovery.
        }
    }

    static std::string Trim(std::string s)
    {
        auto notSpace = [](unsigned char c) { return !std::isspace(c); };
        s.erase(s.begin(), std::find_if(s.begin(), s.end(), notSpace));
        s.erase(std::find_if(s.rbegin(), s.rend(), notSpace).base(), s.end());
        return s;
    }

    static std::string StripInlineCommentBasic(std::string s)
    {
        bool quoted = false;
        char quote = 0;
        for (size_t i = 0; i < s.size(); ++i)
        {
            const char ch = s[i];
            if ((ch == '\'' || ch == '"') && (i == 0 || s[i - 1] != '\\'))
            {
                if (!quoted)
                {
                    quoted = true;
                    quote = ch;
                }
                else if (quote == ch)
                {
                    quoted = false;
                    quote = 0;
                }
            }
            else if (!quoted && (ch == '#' || ch == ';'))
            {
                return Trim(s.substr(0, i));
            }
        }
        return Trim(s);
    }

    static std::vector<std::string> Split(const std::string& s, char delim)
    {
        std::vector<std::string> out;
        std::stringstream ss(s);
        std::string item;
        while (std::getline(ss, item, delim)) out.push_back(Trim(item));
        return out;
    }

    static int ParseIntOr(const std::string& value, int fallback)
    {
        try
        {
            std::string t = StripInlineCommentBasic(value);
            if (t.empty()) return fallback;
            size_t used = 0;
            int parsed = std::stoi(t, &used);
            return used == t.size() ? parsed : fallback;
        }
        catch (...) { return fallback; }
    }

    static float ParseFloatOr(const std::string& value, float fallback)
    {
        try
        {
            std::string t = StripInlineCommentBasic(value);
            if (t.empty()) return fallback;
            size_t used = 0;
            float parsed = std::stof(t, &used);
            return (used == t.size() && std::isfinite(parsed)) ? parsed : fallback;
        }
        catch (...) { return fallback; }
    }

    static bool TryParseIntStrict(const std::string& value, int& out)
    {
        try
        {
            std::string t = StripInlineCommentBasic(value);
            if (t.empty()) return false;
            size_t used = 0;
            int parsed = std::stoi(t, &used);
            if (used != t.size()) return false;
            out = parsed;
            return true;
        }
        catch (...) { return false; }
    }

    static bool TryParseFloatStrict(const std::string& value, float& out)
    {
        try
        {
            std::string t = StripInlineCommentBasic(value);
            if (t.empty()) return false;
            size_t used = 0;
            float parsed = std::stof(t, &used);
            if (used != t.size() || !std::isfinite(parsed)) return false;
            out = parsed;
            return true;
        }
        catch (...) { return false; }
    }

    static bool TryParseUnsignedStrict(const std::string& value, unsigned long& out, int base)
    {
        try
        {
            std::string t = StripInlineCommentBasic(value);
            if (t.empty()) return false;
            // std::stoul accepts a leading minus sign and wraps it into an
            // unsigned value. That is unsafe for config/garage/hash parsing.
            if (t[0] == '-') return false;
            size_t used = 0;
            unsigned long parsed = std::stoul(t, &used, base);
            if (used != t.size()) return false;
            out = parsed;
            return true;
        }
        catch (...) { return false; }
    }

    static std::string NormalizeModelName(const std::string& value, const std::string& fallback)
    {
        std::string model = Trim(value);

        // Catalogs and manual input are user-editable. Strip common inline comments
        // before hashing so entries like "adder ; note" or "s_m_m_cop_01 # LSPD"
        // do not become invalid model names after messy edits. GTA model names do not
        // legitimately contain whitespace, quotes, pipes or INI/comment markers.
        size_t comment = model.find_first_of("#;");
        if (comment != std::string::npos) model = Trim(model.substr(0, comment));
        if (model.empty()) model = fallback;
        comment = model.find_first_of("#;");
        if (comment != std::string::npos) model = Trim(model.substr(0, comment));

        model.erase(std::remove_if(model.begin(), model.end(), [](unsigned char c)
        {
            return std::isspace(c) || c == '"' || c == '\'' || c == '|';
        }), model.end());
        return model.empty() ? fallback : model;
    }

    static std::string CompactKey(std::string value)
    {
        value = StripInlineCommentBasic(value);
        value.erase(std::remove_if(value.begin(), value.end(), [](unsigned char c)
        {
            return std::isspace(c) || c == '_' || c == '-' || c == '/';
        }), value.end());
        std::transform(value.begin(), value.end(), value.begin(), [](unsigned char c){ return (char)std::tolower(c); });
        return value;
    }

    static MovieSceneIntensity ParseMovieSceneIntensity(const std::string& value, MovieSceneIntensity fallback)
    {
        std::string v = CompactKey(value);
        if (v == "0" || v == "calm") return MovieSceneIntensity::Calm;
        if (v == "1" || v == "action") return MovieSceneIntensity::Action;
        if (v == "2" || v == "chaos") return MovieSceneIntensity::Chaos;
        if (v == "3" || v == "insane") return MovieSceneIntensity::Insane;
        if (v == "4" || v == "directorcut" || v == "director") return MovieSceneIntensity::DirectorCut;
        return fallback;
    }

    static MovieSceneCameraMode ParseMovieSceneCameraMode(const std::string& value, MovieSceneCameraMode fallback)
    {
        std::string v = CompactKey(value);
        if (v == "0" || v == "off" || v == "disabled") return MovieSceneCameraMode::Off;
        if (v == "1" || v == "followplayer" || v == "player") return MovieSceneCameraMode::FollowPlayer;
        if (v == "2" || v == "followtarget" || v == "target") return MovieSceneCameraMode::FollowTarget;
        if (v == "3" || v == "chasecam" || v == "chase") return MovieSceneCameraMode::ChaseCam;
        if (v == "4" || v == "actioncut" || v == "cuts") return MovieSceneCameraMode::ActionCut;
        if (v == "5" || v == "freedrone" || v == "drone") return MovieSceneCameraMode::FreeDrone;
        return fallback;
    }


