    static int ParseVirtualKey(const std::string& value, int fallback)
    {
        std::string v = StripInlineCommentBasic(value);
        std::transform(v.begin(), v.end(), v.begin(), [](unsigned char c){ return (char)std::toupper(c); });
        if (v.empty()) return fallback;
        if (v.rfind("VK_", 0) == 0) v = v.substr(3);
        if (v.size() == 1 && v[0] >= 'A' && v[0] <= 'Z') return v[0];
        if (v.size() == 1 && v[0] >= '0' && v[0] <= '9') return v[0];

        int parsedKey = 0;
        if (TryParseIntStrict(v, parsedKey) && parsedKey > 0 && parsedKey <= 255) return parsedKey;
        if (v.rfind("0X", 0) == 0)
        {
            unsigned long hexKey = 0;
            if (TryParseUnsignedStrict(v.substr(2), hexKey, 16) && hexKey > 0 && hexKey <= 255) return (int)hexKey;
        }

        if (v == "F1") return VK_F1;
        if (v == "F2") return VK_F2;
        if (v == "F3") return VK_F3;
        if (v == "F4") return VK_F4;
        if (v == "F5") return VK_F5;
        if (v == "F6") return VK_F6;
        if (v == "F7") return VK_F7;
        if (v == "F8") return VK_F8;
        if (v == "F9") return VK_F9;
        if (v == "F10") return VK_F10;
        if (v == "F11") return VK_F11;
        if (v == "F12") return VK_F12;
        if (v == "INSERT" || v == "INS") return VK_INSERT;
        if (v == "DELETE" || v == "DEL") return VK_DELETE;
        if (v == "HOME") return VK_HOME;
        if (v == "END") return VK_END;
        if (v == "PAGEUP" || v == "PGUP") return VK_PRIOR;
        if (v == "PAGEDOWN" || v == "PGDN") return VK_NEXT;
        if (v == "UP" || v == "ARROWUP") return VK_UP;
        if (v == "DOWN" || v == "ARROWDOWN") return VK_DOWN;
        if (v == "LEFT" || v == "ARROWLEFT") return VK_LEFT;
        if (v == "RIGHT" || v == "ARROWRIGHT") return VK_RIGHT;
        if (v == "ENTER" || v == "RETURN") return VK_RETURN;
        if (v == "ESC" || v == "ESCAPE") return VK_ESCAPE;
        if (v == "BACKSPACE" || v == "BACK") return VK_BACK;
        if (v == "SPACE" || v == "SPACEBAR") return VK_SPACE;
        if (v == "TAB") return 0x09;
        if (v == "SHIFT") return VK_SHIFT;
        if (v == "CTRL" || v == "CONTROL") return VK_CONTROL;
        if (v == "ALT" || v == "MENU") return VK_MENU;
        if (v == "NUMPAD0") return VK_NUMPAD0;
        if (v == "NUMPAD1") return VK_NUMPAD1;
        if (v == "NUMPAD2") return VK_NUMPAD2;
        if (v == "NUMPAD3") return VK_NUMPAD3;
        if (v == "NUMPAD4") return VK_NUMPAD4;
        if (v == "NUMPAD5") return VK_NUMPAD5;
        if (v == "NUMPAD6") return VK_NUMPAD6;
        if (v == "NUMPAD7") return VK_NUMPAD7;
        if (v == "NUMPAD8") return VK_NUMPAD8;
        if (v == "NUMPAD9") return VK_NUMPAD9;
        if (v == "ADD" || v == "PLUS") return VK_ADD;
        if (v == "SUBTRACT" || v == "MINUS") return VK_SUBTRACT;
        return fallback;
    }

    static std::string KeyName(int vk)
    {
        if (vk >= 'A' && vk <= 'Z') return std::string(1, (char)vk);
        if (vk >= '0' && vk <= '9') return std::string(1, (char)vk);
        switch (vk)
        {
            case VK_F1: return "F1"; case VK_F2: return "F2"; case VK_F3: return "F3"; case VK_F4: return "F4";
            case VK_F5: return "F5"; case VK_F6: return "F6"; case VK_F7: return "F7"; case VK_F8: return "F8";
            case VK_F9: return "F9"; case VK_F10: return "F10"; case VK_F11: return "F11"; case VK_F12: return "F12";
            case VK_INSERT: return "INSERT"; case VK_DELETE: return "DELETE"; case VK_HOME: return "HOME"; case VK_END: return "END";
            case VK_PRIOR: return "PAGEUP"; case VK_NEXT: return "PAGEDOWN";
            case VK_UP: return "UP"; case VK_DOWN: return "DOWN"; case VK_LEFT: return "LEFT"; case VK_RIGHT: return "RIGHT";
            case VK_RETURN: return "ENTER"; case VK_ESCAPE: return "ESCAPE"; case VK_BACK: return "BACKSPACE";
            case VK_SPACE: return "SPACE"; case 0x09: return "TAB"; case VK_SHIFT: return "SHIFT"; case VK_CONTROL: return "CTRL"; case VK_MENU: return "ALT";
            case VK_NUMPAD0: return "NUMPAD0"; case VK_NUMPAD1: return "NUMPAD1"; case VK_NUMPAD2: return "NUMPAD2"; case VK_NUMPAD3: return "NUMPAD3"; case VK_NUMPAD4: return "NUMPAD4";
            case VK_NUMPAD5: return "NUMPAD5"; case VK_NUMPAD6: return "NUMPAD6"; case VK_NUMPAD7: return "NUMPAD7"; case VK_NUMPAD8: return "NUMPAD8"; case VK_NUMPAD9: return "NUMPAD9";
            case VK_ADD: return "ADD"; case VK_SUBTRACT: return "SUBTRACT";
            default: return (vk > 0 && vk <= 255) ? (std::string("VK_") + std::to_string(vk)) : "KEY";
        }
    }

    static bool IsReservedHotkeyVirtualKeyCode(int vk)
    {
        // Mouse buttons and menu-control keys are intentionally blocked as
        // configurable trainer hotkeys. They collide with GTA input, menu
        // navigation, confirmation/back actions, and free-camera controls.
        if (vk >= 0x01 && vk <= 0x06) return true;
        if (vk == 0x09 || vk == VK_SPACE) return true;
        if (vk == VK_RETURN || vk == VK_BACK || vk == VK_ESCAPE) return true;
        if (vk == VK_UP || vk == VK_DOWN || vk == VK_LEFT || vk == VK_RIGHT) return true;
        if (vk == VK_SHIFT || vk == VK_CONTROL || vk == VK_MENU) return true;
        return false;
    }

    static bool IsSafeVirtualKeyCode(int vk)
    {
        if (vk <= 0 || vk > 255) return false;
        return !IsReservedHotkeyVirtualKeyCode(vk);
    }

    static int SafeVirtualKeyOr(int vk, int fallback)
    {
        if (IsSafeVirtualKeyCode(vk)) return vk;
        if (IsSafeVirtualKeyCode(fallback)) return fallback;
        return VK_F5;
    }

    static bool KeyAlreadyUsed(int key, const std::vector<int>& used)
    {
        return std::find(used.begin(), used.end(), key) != used.end();
    }

    static int PickSafeHotkey(int preferred, const std::vector<int>& used)
    {
        static const int fallbacks[] = { VK_F5, VK_F7, VK_F6, VK_F8, VK_F9, VK_F10, VK_INSERT, VK_HOME, VK_END, VK_F11, VK_F12 };
        if (IsSafeVirtualKeyCode(preferred) && !KeyAlreadyUsed(preferred, used)) return preferred;
        for (int key : fallbacks)
        {
            if (IsSafeVirtualKeyCode(key) && !KeyAlreadyUsed(key, used)) return key;
        }
        return VK_F5;
    }

    static Language ParseLanguage(const std::string& value)
    {
        std::string v = Trim(value);
        std::transform(v.begin(), v.end(), v.begin(), [](unsigned char c){ return (char)std::tolower(c); });
        if (v == "russian" || v == "ru" || v == "русский") return Language::Russian;
        if (v == "chinese" || v == "zh" || v == "中文") return Language::Chinese;
        if (v == "french" || v == "fr" || v == "francais" || v == "français") return Language::French;
        if (v == "german" || v == "de" || v == "deutsch") return Language::German;
        if (v == "japanese" || v == "ja" || v == "日本語") return Language::Japanese;
        if (v == "spanish" || v == "es" || v == "espanol" || v == "español") return Language::Spanish;
        if (v == "italian" || v == "it" || v == "italiano") return Language::Italian;
        return Language::English;
    }

    static std::string LanguageName(Language lang)
    {
        switch (lang)
        {
            case Language::Russian: return "Russian";
            case Language::Chinese: return "Chinese";
            case Language::French: return "French";
            case Language::German: return "German";
            case Language::Japanese: return "Japanese";
            case Language::Spanish: return "Spanish";
            case Language::Italian: return "Italian";
            default: return "English";
        }
    }


