    static void CycleLanguage()
    {
        int idx = ((int)st.language + 1) % 8;
        st.language = (Language)idx;
        Notify("Language: " + LanguageName(st.language));
    }

    static bool StartsWith(const std::string& s, const std::string& prefix)
    {
        return s.rfind(prefix, 0) == 0;
    }

    static bool ParseLooseBool(const std::string& value)
    {
        std::string v = StripInlineCommentBasic(value);
        std::transform(v.begin(), v.end(), v.begin(), [](unsigned char c){ return (char)std::tolower(c); });
        return v == "1" || v == "true" || v == "yes" || v == "on" || v == "enabled";
    }

    static bool ParseLooseBoolOr(const std::string& value, bool fallback)
    {
        std::string v = StripInlineCommentBasic(value);
        std::transform(v.begin(), v.end(), v.begin(), [](unsigned char c){ return (char)std::tolower(c); });
        if (v == "1" || v == "true" || v == "yes" || v == "on" || v == "enabled") return true;
        if (v == "0" || v == "false" || v == "no" || v == "off" || v == "disabled") return false;
        return fallback;
    }

    static std::string TrDynamic(const std::string& text)
    {
        if (st.language == Language::Russian)
        {
            static const std::vector<std::pair<std::string, std::string>> ruPrefixes =
            {
                {"Save Location Slot ", "Сохранить точку "},
                {"Load Location Slot ", "Загрузить точку "},
                {"Save Mission Slot ", "Сохранить миссию "},
                {"Load Mission Slot ", "Загрузить миссию "},
                {"Save Outfit Slot ", "Сохранить образ "},
                {"Load Outfit Slot ", "Загрузить образ "},
                {"Save Preset Slot ", "Сохранить пресет "},
                {"Load Preset Slot ", "Загрузить пресет "},
                {"Load: ", "Загрузить: "},
                {"Slot ", "Слот "},
                {"Name: ", "Имя: "},
                {"Save Slot ", "Сохранить слот "},
                {"Load Slot ", "Загрузить слот "},
                {"Preset: ", "Пресет: "},
                {"Vehicle: ", "Машина: "},
                {"Toggle ", "Переключить "},
                {"Language: ", "Язык: "},
                {"Notification Style: ", "Стиль уведомлений: "},
                {"Added to Quick Favorites: ", "Добавлено в избранное: "},
                {"Already in Quick Favorites: ", "Уже есть в избранном: "},
                {"Obj ", "Объект "}
            };
            for (const auto& p : ruPrefixes)
            {
                if (StartsWith(text, p.first)) return p.second + text.substr(p.first.size());
            }
        }
        return text;
    }

