    static constexpr long long kMaxSafeTextFileBytes = 4LL * 1024LL * 1024LL;
    static constexpr size_t kMaxSafeTextLines = 250000;
    static constexpr size_t kMaxSafeTextLineBytes = 16384;

    static bool FileExists(const std::string& path)
    {
        if (path.empty()) return false;
        try
        {
            std::error_code ec;
            const bool exists = std::filesystem::exists(path, ec);
            if (!ec)
            {
                if (!exists) return false;
                if (std::filesystem::is_regular_file(path, ec) && !ec) return true;
                ec.clear();
                if (std::filesystem::is_directory(path, ec) && !ec) return false;
                return false;
            }
        }
        catch (...)
        {
        }
#if defined(INVALID_FILE_ATTRIBUTES) && defined(FILE_ATTRIBUTE_DIRECTORY)
        const DWORD attrs = GetFileAttributesA(path.c_str());
        if (attrs == INVALID_FILE_ATTRIBUTES) return false;
        if ((attrs & FILE_ATTRIBUTE_DIRECTORY) != 0) return false;
#endif
        std::ifstream f(path, std::ios::binary);
        return f.good();
    }

    static bool EnsureParentDirectoryForFile(const std::string& path)
    {
        if (path.empty()) return false;
        try
        {
            std::filesystem::path fsPath(path);
            std::filesystem::path parent = fsPath.parent_path();
            if (parent.empty()) return true;
            std::error_code ec;
            const bool parentExists = std::filesystem::exists(parent, ec);
            if (ec) return false;
            if (parentExists)
            {
                const bool isDir = std::filesystem::is_directory(parent, ec);
                return !ec && isDir;
            }
            ec.clear();
            if (!std::filesystem::create_directories(parent, ec))
            {
                if (ec) return false;
                ec.clear();
                return std::filesystem::exists(parent, ec) && !ec && std::filesystem::is_directory(parent, ec) && !ec;
            }
            ec.clear();
            const bool isDir = std::filesystem::is_directory(parent, ec);
            return !ec && isDir;
        }
        catch (...)
        {
            return false;
        }
    }

    static std::string FileStamp();
    static bool CopyTextFileSafe(const std::string& from, const std::string& to);

    static std::string SanitizeTextFileLineForWrite(std::string line)
    {
        for (char& ch : line)
        {
            if (ch == '\0' || ch == '\r' || ch == '\n') ch = ' ';
        }
        if (line.size() > kMaxSafeTextLineBytes)
            line.resize(kMaxSafeTextLineBytes);
        return line;
    }

    static bool FitsSafeTextWriteBudget(const std::vector<std::string>& lines)
    {
        unsigned long long totalBytes = 0;
        for (const std::string& line : lines)
        {
            if (line.size() > kMaxSafeTextLineBytes) return false;
            totalBytes += static_cast<unsigned long long>(line.size()) + 1ULL;
            if (totalBytes > static_cast<unsigned long long>(kMaxSafeTextFileBytes)) return false;
        }
        return true;
    }

    static bool AtomicWriteLines(const std::string& path, const std::vector<std::string>& lines, bool backup = true)
    {
        if (path.empty())
        {
            Log("Atomic write rejected: empty path");
            return false;
        }
        if (!EnsureParentDirectoryForFile(path))
        {
            Log("Atomic write rejected: parent directory unavailable for " + path);
            return false;
        }
        if (lines.size() > kMaxSafeTextLines)
        {
            Log("Atomic write rejected: too many lines for " + path);
            return false;
        }
        if (!FitsSafeTextWriteBudget(lines))
        {
            Log("Atomic write rejected: output would exceed safe text file budget for " + path);
            return false;
        }

        static unsigned int atomicWriteCounter = 0;
        const std::string stamp = std::to_string(GetTickCount()) + "_" + std::to_string(++atomicWriteCounter);
        const std::string tmpPath = path + "." + stamp + ".tmp";
        {
            std::ofstream out(tmpPath, std::ios::binary | std::ios::trunc);
            if (!out)
            {
                Log("Atomic write failed to open tmp: " + tmpPath);
                return false;
            }
            for (const auto& l : lines)
            {
                const std::string safeLine = SanitizeTextFileLineForWrite(l);
                out << safeLine << "\n";
            }
            out.flush();
            if (!out.good())
            {
                Log("Atomic write failed while writing tmp: " + tmpPath);
                out.close();
                std::remove(tmpPath.c_str());
                return false;
            }
        }

        if (backup && FileExists(path))
        {
            const std::string rollingBackup = path + ".bak";
            const std::string stampedBackup = path + "." + FileStamp() + ".bak";
            if (!CopyTextFileSafe(path, rollingBackup))
                Log("Atomic write warning: safe rolling backup failed for " + path);
            if (!CopyTextFileSafe(path, stampedBackup))
                Log("Atomic write warning: safe stamped backup failed for " + path);
        }

        if (!MoveFileExA(tmpPath.c_str(), path.c_str(), MOVEFILE_REPLACE_EXISTING | MOVEFILE_WRITE_THROUGH))
        {
            Log("Atomic write failed to replace: " + path);
            std::remove(tmpPath.c_str());
            return false;
        }
        return true;
    }


    static std::string FileStamp()
    {
        static unsigned int stampCounter = 0;
        SYSTEMTIME t{};
        GetLocalTime(&t);
        char buf[80];
        sprintf_s(buf, "%04d%02d%02d_%02d%02d%02d_%03lu_%04u",
                  t.wYear, t.wMonth, t.wDay, t.wHour, t.wMinute, t.wSecond,
                  (unsigned long)(GetTickCount() % 1000), ++stampCounter);
        return buf;
    }

    static long long FileSizeBytes(const std::string& path)
    {
        if (path.empty()) return -1;
        try
        {
            std::error_code ec;
            const bool exists = std::filesystem::exists(path, ec);
            if (!ec)
            {
                if (!exists) return -1;
                if (!std::filesystem::is_regular_file(path, ec) || ec) return -1;
                const auto size = std::filesystem::file_size(path, ec);
                if (!ec) return static_cast<long long>(size);
                return -1;
            }
        }
        catch (...)
        {
        }
#if defined(INVALID_FILE_ATTRIBUTES) && defined(FILE_ATTRIBUTE_DIRECTORY)
        const DWORD attrs = GetFileAttributesA(path.c_str());
        if (attrs == INVALID_FILE_ATTRIBUTES || (attrs & FILE_ATTRIBUTE_DIRECTORY) != 0) return -1;
#endif
        std::ifstream f(path, std::ios::binary | std::ios::ate);
        if (!f) return -1;
        const std::streampos pos = f.tellg();
        return pos < std::streampos(0) ? -1 : static_cast<long long>(pos);
    }

    static bool CopyTextFileSafe(const std::string& from, const std::string& to)
    {
        if (from.empty() || to.empty()) return false;
        try
        {
            std::error_code ecFrom, ecTo;
            const auto absFrom = std::filesystem::weakly_canonical(std::filesystem::absolute(from, ecFrom), ecFrom);
            const auto absTo = std::filesystem::weakly_canonical(std::filesystem::absolute(to, ecTo), ecTo);
            if (!ecFrom && !ecTo && absFrom == absTo)
            {
                Log("Safe copy rejected identical source/destination: " + from);
                return false;
            }
            std::error_code ecEq;
            if (std::filesystem::exists(from, ecEq) && !ecEq && std::filesystem::exists(to, ecEq) && !ecEq && std::filesystem::equivalent(from, to, ecEq) && !ecEq)
            {
                Log("Safe copy rejected equivalent source/destination: " + from);
                return false;
            }
        }
        catch (...)
        {
        }
        const long long size = FileSizeBytes(from);
        if (size < 0 || size > kMaxSafeTextFileBytes)
        {
            Log("Safe copy rejected source size: " + from);
            return false;
        }
        if (!EnsureParentDirectoryForFile(to))
        {
            Log("Safe copy rejected destination parent: " + to);
            return false;
        }

        std::ifstream in(from, std::ios::binary);
        if (!in) return false;

        const std::string tmpPath = to + "." + FileStamp() + ".tmp";
        std::ofstream out(tmpPath, std::ios::binary | std::ios::trunc);
        if (!out) return false;

        char buffer[4096];
        size_t completedLineCount = 0;
        size_t lineBytes = 0;
        bool sawAnyByte = false;
        bool endedWithNewline = false;
        while (in)
        {
            in.read(buffer, sizeof(buffer));
            const std::streamsize got = in.gcount();
            if (got <= 0) break;
            for (std::streamsize i = 0; i < got; ++i)
            {
                const char ch = buffer[i];
                sawAnyByte = true;
                if (ch == '\0')
                {
                    Log("Safe copy rejected binary/corrupt source: " + from);
                    out.close();
                    std::remove(tmpPath.c_str());
                    return false;
                }
                if (ch == '\n')
                {
                    ++completedLineCount;
                    endedWithNewline = true;
                    lineBytes = 0;
                    if (completedLineCount > kMaxSafeTextLines)
                    {
                        Log("Safe copy rejected source with too many lines: " + from);
                        out.close();
                        std::remove(tmpPath.c_str());
                        return false;
                    }
                }
                else if (ch != '\r')
                {
                    endedWithNewline = false;
                    ++lineBytes;
                    if (lineBytes > kMaxSafeTextLineBytes)
                    {
                        Log("Safe copy rejected source with oversized line: " + from);
                        out.close();
                        std::remove(tmpPath.c_str());
                        return false;
                    }
                }
            }
            const size_t actualLineCount = completedLineCount + ((sawAnyByte && !endedWithNewline) ? 1u : 0u);
            if (actualLineCount > kMaxSafeTextLines)
            {
                Log("Safe copy rejected source with too many lines: " + from);
                out.close();
                std::remove(tmpPath.c_str());
                return false;
            }
            out.write(buffer, got);
            if (!out.good())
            {
                out.close();
                std::remove(tmpPath.c_str());
                return false;
            }
        }
        if (in.bad())
        {
            out.close();
            std::remove(tmpPath.c_str());
            Log("Safe copy failed while reading: " + from);
            return false;
        }
        out.flush();
        out.close();
        if (!MoveFileExA(tmpPath.c_str(), to.c_str(), MOVEFILE_REPLACE_EXISTING | MOVEFILE_WRITE_THROUGH))
        {
            std::remove(tmpPath.c_str());
            Log("Safe copy failed to replace destination: " + to);
            return false;
        }
        return true;
    }

    static bool ReadTextLinesSafe(const std::string& path, std::vector<std::string>& lines)
    {
        lines.clear();
        if (path.empty()) return false;

        const long long size = FileSizeBytes(path);
        if (size < 0)
        {
            Log("Text file rejected: missing or not a regular file: " + path);
            return false;
        }
        if (size > kMaxSafeTextFileBytes)
        {
            Log("Text file rejected as too large: " + path + " (" + std::to_string(size) + " bytes)");
            return false;
        }

        std::ifstream in(path, std::ios::binary);
        if (!in) return false;
        std::string line;
        while (std::getline(in, line))
        {
            if (!line.empty() && line.back() == '\r') line.pop_back();
            if (line.find('\0') != std::string::npos)
            {
                Log("Text file rejected as binary/corrupt: " + path);
                lines.clear();
                return false;
            }
            if (lines.empty() && line.size() >= 3 &&
                (unsigned char)line[0] == 0xEF &&
                (unsigned char)line[1] == 0xBB &&
                (unsigned char)line[2] == 0xBF)
            {
                line.erase(0, 3);
            }
            if (line.size() > kMaxSafeTextLineBytes)
            {
                Log("Text file rejected: oversized line in " + path);
                lines.clear();
                return false;
            }
            lines.push_back(line);
            if (lines.size() > kMaxSafeTextLines)
            {
                Log("Text file rejected: too many lines in " + path);
                lines.clear();
                return false;
            }
        }
        if (in.bad())
        {
            Log("Text file read failed: " + path);
            lines.clear();
            return false;
        }
        return true;
    }

    static bool LooksBinaryLike(const std::string& path);

    static bool EnsureTextFileWithDefaults(const std::string& path, const std::vector<std::string>& defaults)
    {
        if (path.empty()) return false;
        if (FileExists(path))
        {
            std::vector<std::string> existing;
            if (ReadTextLinesSafe(path, existing)) return true;

            const std::string backup = path + ".corrupt." + FileStamp() + ".bak";
            if (!CopyTextFileSafe(path, backup))
                Log("Corrupt data file backup skipped/failed safely: " + path);
            else
                Log("Corrupt data file backed up: " + backup);
        }
        if (AtomicWriteLines(path, defaults, false)) return true;
        Log("Failed to create/repair data file: " + path);
        return false;
    }

    static bool EndsWithNoCase(const std::string& value, const std::string& suffix)
    {
        if (suffix.size() > value.size()) return false;
        const size_t offset = value.size() - suffix.size();
        for (size_t i = 0; i < suffix.size(); ++i)
        {
            const unsigned char a = static_cast<unsigned char>(value[offset + i]);
            const unsigned char b = static_cast<unsigned char>(suffix[i]);
            if (std::tolower(a) != std::tolower(b)) return false;
        }
        return true;
    }

    static bool IsTrainerManagedTextFileName(const std::string& fileName)
    {
        if (fileName.find('\\') != std::string::npos || fileName.find('/') != std::string::npos) return false;
        return EndsWithNoCase(fileName, ".txt");
    }

    static std::string CaoTrainerFolderPath()
    {
        return g_rootDir + "CaoTrainer\\";
    }

    static std::string CaoTrainerTextFilePath(const std::string& fileName)
    {
        return CaoTrainerFolderPath() + fileName;
    }

    static std::string DisplayCaoTrainerTextPath(const std::string& fileName)
    {
        return std::string("CaoTrainer\\") + fileName;
    }

    static bool IsSafeReadableTextPath(const std::string& path)
    {
        if (!FileExists(path)) return false;
        const long long size = FileSizeBytes(path);
        if (size <= 0 || size > kMaxSafeTextFileBytes) return false;
        if (LooksBinaryLike(path)) return false;
        return true;
    }

    static std::string ResolveDataFileReadPath(const std::string& fileName)
    {
        const bool trainerText = IsTrainerManagedTextFileName(fileName);
        const std::string caoTrainerPath = CaoTrainerTextFilePath(fileName);
        const std::string caoTrainerPathSlash = g_rootDir + "CaoTrainer/" + fileName;
        const std::string rootPath = g_rootDir + fileName;
        const std::string dataCaoTrainerPath = g_rootDir + "data\\CaoTrainer\\" + fileName;
        const std::string dataCaoTrainerPathSlash = g_rootDir + "data/CaoTrainer/" + fileName;
        const std::string dataPath = g_rootDir + "data\\" + fileName;
        const std::string dataPathSlash = g_rootDir + "data/" + fileName;

        if (trainerText)
        {
            // Update 225 keeps every trainer-managed .txt authoritative in /CaoTrainer.
            // Legacy root/data locations remain readable only as migration fallbacks.
            if (IsSafeReadableTextPath(caoTrainerPath)) return caoTrainerPath;
            if (IsSafeReadableTextPath(caoTrainerPathSlash)) return caoTrainerPathSlash;
            if (IsSafeReadableTextPath(dataCaoTrainerPath)) return dataCaoTrainerPath;
            if (IsSafeReadableTextPath(dataCaoTrainerPathSlash)) return dataCaoTrainerPathSlash;
            if (IsSafeReadableTextPath(rootPath)) return rootPath;
            if (IsSafeReadableTextPath(dataPath)) return dataPath;
            if (IsSafeReadableTextPath(dataPathSlash)) return dataPathSlash;

            if (FileExists(caoTrainerPath)) return caoTrainerPath;
            if (FileExists(caoTrainerPathSlash)) return caoTrainerPathSlash;
            if (FileExists(dataCaoTrainerPath)) return dataCaoTrainerPath;
            if (FileExists(dataCaoTrainerPathSlash)) return dataCaoTrainerPathSlash;
            if (FileExists(rootPath)) return rootPath;
            if (FileExists(dataPath)) return dataPath;
            if (FileExists(dataPathSlash)) return dataPathSlash;
            return caoTrainerPath;
        }

        if (IsSafeReadableTextPath(rootPath)) return rootPath;

        // Some packaged builds keep editable data under /data.  Fall back to that
        // folder not only when the root copy is missing, but also when the root
        // copy is empty/corrupt/too large. Otherwise a bad root file can shadow a
        // valid packaged catalog or INI and make in-game QA report false failures.
        if (IsSafeReadableTextPath(dataPath)) return dataPath;
        if (IsSafeReadableTextPath(dataPathSlash)) return dataPathSlash;

        if (FileExists(rootPath)) return rootPath;
        if (FileExists(dataPath)) return dataPath;
        if (FileExists(dataPathSlash)) return dataPathSlash;
        return rootPath;
    }

    static std::string ResolveDataFileWritePath(const std::string& fileName)
    {
        if (IsTrainerManagedTextFileName(fileName))
            return CaoTrainerTextFilePath(fileName);

        const std::string effectiveReadPath = ResolveDataFileReadPath(fileName);
        if (!effectiveReadPath.empty() && FileExists(effectiveReadPath))
            return effectiveReadPath;
        return g_rootDir + fileName;
    }

    static bool LooksBinaryLike(const std::string& path)
    {
        std::ifstream in(path, std::ios::binary);
        if (!in) return false;
        char ch = 0;
        int checked = 0;
        while (checked < 1024 && in.get(ch))
        {
            if (ch == '\0') return true;
            ++checked;
        }
        return false;
    }

