    static bool IsRequiredCatalogDataFile(const std::string& name)
    {
        return name == "CaoUrbanTrainer_PedModels.txt" ||
               name == "CaoUrbanTrainer_Vehicles.txt" ||
               name == "CaoUrbanTrainer_Objects.txt";
    }

    static bool SupportDataFileHasLoadableEntry(const std::string& name, const std::string& path)
    {
        std::vector<std::string> lines;
        if (!ReadTextLinesSafe(path, lines)) return false;

        for (const auto& raw : lines)
        {
            std::string line = Trim(raw);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;

            if (IsRequiredCatalogDataFile(name))
            {
                auto parts = Split(line, '|');
                if (parts.size() >= 2 && !NormalizeModelName(parts[1], "").empty()) return true;
                continue;
            }

            return true;
        }

        return false;
    }

    static bool IsIniLineStructurallyValid(const std::string& rawLine)
    {
        std::string line = Trim(rawLine);
        if (line.empty() || line[0] == '#' || line[0] == ';') return true;
        if (line.front() == '[')
        {
            size_t close = line.find(']');
            return close != std::string::npos && close > 1;
        }
        size_t eq = line.find('=');
        if (eq == std::string::npos) return false;
        return !Trim(line.substr(0, eq)).empty();
    }

    static bool TryReadIniBoolSetting(const std::string& path, const std::string& wantedSection, const std::string& wantedKey, bool& outValue)
    {
        std::vector<std::string> lines;
        if (!ReadTextLinesSafe(path, lines)) return false;

        const std::string canonicalWantedSection = CanonicalIniSectionName(wantedSection);
        const std::string canonicalWantedKey = CanonicalIniKeyName(canonicalWantedSection, wantedKey);

        std::string section;
        const std::map<int, bool> keepIniKeyLines = ComputeIniKeyLinesToApply(lines);
        for (int lineIndex = 0; lineIndex < (int)lines.size(); ++lineIndex)
        {
            std::string line = Trim(lines[lineIndex]);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;
            if (line[0] == '[')
            {
                size_t close = line.find(']');
                section = (close == std::string::npos || close <= 1) ? std::string() : CanonicalIniSectionName(line.substr(1, close - 1));
                continue;
            }

            size_t eq = line.find('=');
            if (eq == std::string::npos) continue;
            if (!keepIniKeyLines.empty() && keepIniKeyLines.find(lineIndex) == keepIniKeyLines.end())
                continue;
            std::string key = CanonicalIniKeyName(section, line.substr(0, eq));
            std::string value = StripIniInlineComment(line.substr(eq + 1));
            if (SameIniSectionName(section, canonicalWantedSection) && SameIniKeyName(section, key, canonicalWantedKey))
            {
                outValue = ParseLooseBoolOr(value, outValue);
                return true;
            }
        }
        return false;
    }

    static bool ShouldRunBootConfigRepair()
    {
        const std::string path = ResolveDataFileReadPath("CaoUrbanTrainerASI.ini");
        const long long size = FileSizeBytes(path);
        if (!FileExists(path) || size <= 0 || size > kMaxSafeTextFileBytes || LooksBinaryLike(path)) return true;

        bool enabled = cfg.configAutoRepair;
        if (TryReadIniBoolSetting(path, "Diagnostics", "AutoRepairConfig", enabled)) return enabled;
        return cfg.configAutoRepair;
    }

    static bool BackupFileWithStamp(const std::string& path, const std::string& suffix, std::string* backupOut = nullptr)
    {
        if (!FileExists(path)) return false;
        std::string backup = path + "." + suffix + "_" + FileStamp() + ".bak";
        bool ok = CopyTextFileSafe(path, backup);
        if (backupOut) *backupOut = ok ? backup : "";
        if (ok) Log("Backup created: " + backup);
        else Log("Backup failed: " + path);
        return ok;
    }

    static bool AppendMissingDefaultIniKeys(std::vector<std::string>& lines, int& addedKeys)
    {
        addedKeys = 0;

        std::map<std::string, bool> existingKeys;
        std::string section;
        for (const auto& raw : lines)
        {
            std::string line = Trim(raw);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;
            if (line.front() == '[')
            {
                size_t close = line.find(']');
                section = (close == std::string::npos || close <= 1) ? std::string() : CanonicalIniSectionName(line.substr(1, close - 1));
                continue;
            }
            size_t eq = line.find('=');
            if (eq == std::string::npos) continue;
            std::string key = CanonicalIniKeyName(section, line.substr(0, eq));
            if (!key.empty()) existingKeys[section + "\n" + key] = true;
        }

        std::map<std::string, std::vector<std::string>> missingBySection;
        std::vector<std::string> sectionOrder;
        std::map<std::string, bool> orderedSections;
        std::string defaultSection;
        for (const auto& raw : BuildDefaultIniLines())
        {
            std::string line = Trim(raw);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;
            if (line.front() == '[')
            {
                size_t close = line.find(']');
                defaultSection = (close == std::string::npos || close <= 1) ? std::string() : CanonicalIniSectionName(line.substr(1, close - 1));
                continue;
            }
            size_t eq = line.find('=');
            if (eq == std::string::npos) continue;
            std::string key = CanonicalIniKeyName(defaultSection, line.substr(0, eq));
            if (key.empty()) continue;
            std::string id = defaultSection + "\n" + key;
            if (existingKeys.find(id) != existingKeys.end()) continue;
            if (!orderedSections[defaultSection])
            {
                orderedSections[defaultSection] = true;
                sectionOrder.push_back(defaultSection);
            }
            missingBySection[defaultSection].push_back(line);
        }

        if (sectionOrder.empty()) return false;

        if (!lines.empty() && !Trim(lines.back()).empty()) lines.push_back("");
        lines.push_back("; Added by Config Repair: missing default keys for this trainer version");
        for (const auto& sec : sectionOrder)
        {
            lines.push_back("");
            if (!sec.empty()) lines.push_back("[" + sec + "]");
            for (const auto& keyLine : missingBySection[sec])
            {
                lines.push_back(keyLine);
                ++addedKeys;
            }
        }
        return addedKeys > 0;
    }

    static int RepairIniFile(bool forceRecreate)
    {
        // Manual reset still writes the root INI used by a direct GTA install.
        // Automatic repair must operate on the effective read-path, otherwise a
        // packaged /data INI can be silently shadowed by a freshly-created root
        // default during boot.
        const std::string path = forceRecreate ? (g_rootDir + "CaoUrbanTrainerASI.ini") : ResolveDataFileReadPath("CaoUrbanTrainerASI.ini");
        int fixed = 0;
        const long long iniSize = FileSizeBytes(path);
        bool recreate = forceRecreate || !FileExists(path) || iniSize <= 0 || iniSize > kMaxSafeTextFileBytes || LooksBinaryLike(path);
        std::vector<std::string> lines;
        int malformed = 0;
        int sections = 0;
        int keys = 0;

        if (!recreate && ReadTextLinesSafe(path, lines))
        {
            for (const auto& raw : lines)
            {
                std::string line = Trim(raw);
                if (line.empty() || line[0] == '#' || line[0] == ';') continue;
                if (!IsIniLineStructurallyValid(raw)) { ++malformed; continue; }
                if (line.front() == '[') { ++sections; continue; }
                if (line.find('=') != std::string::npos) { ++keys; continue; }
            }
            if (sections == 0 || keys == 0) recreate = true;
        }
        else if (!recreate)
        {
            recreate = true;
        }

        if (recreate)
        {
            BackupFileWithStamp(path, forceRecreate ? "manual_reset" : "auto_repair");
            if (AtomicWriteLines(path, BuildDefaultIniLines(), false))
            {
                Log(forceRecreate ? "INI recreated from defaults." : "INI repaired from defaults.");
                return 1;
            }
            return 0;
        }

        if (malformed > 0)
        {
            std::vector<std::string> repaired;
            repaired.reserve(lines.size() + 2);
            for (const auto& raw : lines)
            {
                if (IsIniLineStructurallyValid(raw)) repaired.push_back(raw);
                else
                {
                    repaired.push_back("; Removed malformed line by Config Repair: " + raw);
                    ++fixed;
                }
            }
            if (fixed > 0)
            {
                BackupFileWithStamp(path, "malformed_lines");
                if (AtomicWriteLines(path, repaired, false))
                {
                    lines = repaired;
                    Log("INI malformed lines repaired: " + std::to_string(fixed));
                }
            }
        }

        int duplicateKeys = 0;
        std::vector<std::string> deduped = lines;
        if (RemoveDuplicateIniKeys(deduped, duplicateKeys))
        {
            BackupFileWithStamp(path, "duplicate_keys");
            if (AtomicWriteLines(path, deduped, false))
            {
                lines = deduped;
                fixed += duplicateKeys;
                Log("INI duplicate keys removed/commented: " + std::to_string(duplicateKeys));
            }
        }

        int addedKeys = 0;
        std::vector<std::string> merged = lines;
        if (AppendMissingDefaultIniKeys(merged, addedKeys))
        {
            BackupFileWithStamp(path, "missing_keys");
            if (AtomicWriteLines(path, merged, false))
            {
                fixed += addedKeys;
                Log("INI missing default keys added: " + std::to_string(addedKeys));
            }
        }
        return fixed;
    }

