    static void MigrateTrainerTextFilesToCaoTrainerFolder()
    {
        if (g_rootDir.empty()) return;

        const std::string dstFolder = CaoTrainerFolderPath();
        if (!EnsureParentDirectoryForFile(dstFolder + ".folder_probe"))
        {
            Log("CaoTrainer folder unavailable; legacy .txt migration skipped.");
            return;
        }

        int migrated = 0;
        int kept = 0;
        for (const auto& name : SupportDataFileNames())
        {
            if (!IsTrainerManagedTextFileName(name)) continue;

            const std::string dst = CaoTrainerTextFilePath(name);
            const bool dstExists = FileExists(dst);
            const bool dstUsable = IsSafeReadableTextPath(dst);
            if (dstUsable)
            {
                ++kept;
                continue;
            }
            if (dstExists)
            {
                BackupFileWithStamp(dst, "caotrainer_invalid_dst");
                Log("CaoTrainer .txt exists but is not safe/readable; trying legacy migration: " + name);
            }

            const std::vector<std::string> legacyCandidates =
            {
                g_rootDir + "data\\CaoTrainer\\" + name,
                g_rootDir + "data/CaoTrainer/" + name,
                g_rootDir + name,
                g_rootDir + "data\\" + name,
                g_rootDir + "data/" + name
            };

            for (const auto& src : legacyCandidates)
            {
                if (src == dst || !IsSafeReadableTextPath(src)) continue;
                if (CopyTextFileSafe(src, dst))
                {
                    ++migrated;
                    Log("Migrated trainer .txt into CaoTrainer folder: " + name);
                    break;
                }
            }
        }

        if (migrated > 0) Log("CaoTrainer .txt migration complete. Migrated: " + std::to_string(migrated) + ", existing kept: " + std::to_string(kept));
    }

    static bool IsSupportDataFileHealthy(const std::string& name, const std::string& path, std::string* statusOut = nullptr)
    {
        auto setStatus = [&](const std::string& status)
        {
            if (statusOut) *statusOut = status;
        };

        if (!FileExists(path))
        {
            setStatus("missing");
            return false;
        }
        long long size = FileSizeBytes(path);
        if (size < 0)
        {
            setStatus("not a regular file");
            return false;
        }
        if (size > kMaxSafeTextFileBytes)
        {
            setStatus("too large: " + std::to_string(size) + " bytes");
            return false;
        }
        if (LooksBinaryLike(path))
        {
            setStatus("binary/corrupt");
            return false;
        }

        // Location slots may be blank; save/load code expands them on demand.
        if (name == "CaoUrbanTrainer_Locations.txt")
        {
            setStatus("OK, " + std::to_string(size) + " bytes");
            return true;
        }

        if (size == 0)
        {
            setStatus("empty");
            return false;
        }

        // Required catalogs with only comments or malformed rows are effectively empty
        // and can break browser pages after Reload Config/Catalogs.
        if (IsRequiredCatalogDataFile(name) && !SupportDataFileHasLoadableEntry(name, path))
        {
            setStatus("no loadable entries");
            return false;
        }

        setStatus("OK, " + std::to_string(size) + " bytes");
        return true;
    }

    [[maybe_unused]] static bool ShouldRepairSupportDataFile(const std::string& name, const std::string& path)
    {
        return !IsSupportDataFileHealthy(name, path, nullptr);
    }

    static int EnsureSupportDataFiles()
    {
        int repaired = 0;
        for (const auto& name : SupportDataFileNames())
        {
            const std::string effectivePath = ResolveDataFileReadPath(name);
            std::string status;
            if (IsSupportDataFileHealthy(name, effectivePath, &status))
            {
                // Valid packaged /data files must remain authoritative when the
                // root copy is absent. Creating root defaults here would shadow
                // user-edited /data catalogs on the next LoadCatalogFile() call.
                continue;
            }

            BackupFileWithStamp(effectivePath, "data_repair");
            const std::string repairTarget = FileExists(effectivePath) ? effectivePath : ResolveDataFileWritePath(name);
            if (AtomicWriteLines(repairTarget, BuildDefaultFileLines(name), false))
            {
                ++repaired;
                Log("Repaired/created data file: " + repairTarget + " (reason: " + status + ")");
            }
        }
        return repaired;
    }

    static int ClampIntValue(int value, int low, int high)
    {
        if (high < low) return low;
        return std::max(low, std::min(high, value));
    }

    static float ClampFloatValue(float value, float low, float high, float fallback)
    {
        if (!std::isfinite(value)) return fallback;
        return std::max(low, std::min(high, value));
    }

    static float ClampFloatExclusiveUpperValue(float value, float low, float highExclusive, float fallback)
    {
        if (!std::isfinite(low) || !std::isfinite(highExclusive) || highExclusive <= low)
            return std::isfinite(fallback) ? fallback : 0.0f;

        const float maxAllowed = std::nextafter(highExclusive, low);
        if (!std::isfinite(value)) value = fallback;
        if (!std::isfinite(value)) value = low;
        if (value < low) value = low;
        if (value >= highExclusive) value = maxAllowed;
        return value;
    }

    static DWORD SafeIntervalFromIntMs(int value, int fallback, int minMs, int maxMs, const std::string& module = "timer", const std::string& action = "interval")
    {
        if (minMs < 0) minMs = 0;
        if (maxMs < minMs) maxMs = minMs;
        if (value < minMs || value > maxMs)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, action, "Timer interval was clamped");
            value = fallback;
        }
        value = ClampIntValue(value, minMs, maxMs);
        return core::ClampTickInterval((DWORD)value);
    }

    static DWORD SafeIntervalAddOneMs(int value, int fallback, int minMs, int maxMs, const std::string& module = "timer", const std::string& action = "interval")
    {
        DWORD interval = SafeIntervalFromIntMs(value, fallback, minMs, maxMs, module, action);
        return interval >= core::kMaxSafeTickIntervalMs ? core::kMaxSafeTickIntervalMs : interval + 1u;
    }

    static DWORD SafeIntervalFromIntSeconds(int value, int fallback, int minSec, int maxSec, const std::string& module = "timer", const std::string& action = "interval")
    {
        if (minSec < 0) minSec = 0;
        if (maxSec < minSec) maxSec = minSec;
        if (value < minSec || value > maxSec)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, action, "Timer seconds interval was clamped");
            value = fallback;
        }
        value = ClampIntValue(value, minSec, maxSec);
        const long long ms = static_cast<long long>(value) * 1000LL;
        const DWORD clamped = ms <= 0LL ? 0u : (ms > static_cast<long long>(core::kMaxSafeTickIntervalMs) ? core::kMaxSafeTickIntervalMs : static_cast<DWORD>(ms));
        return core::ClampTickInterval(clamped);
    }


    template <typename Fn>
    static bool SafeNativeVoidRuntime(const std::string& module, const std::string& action, Fn&& fn)
    {
        if (!core::TryNativeVoid(std::forward<Fn>(fn)))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, action, "Native call failed safely");
            return false;
        }
        return true;
    }

    template <typename T, typename Fn>
    static T SafeNativeValueRuntime(const T& fallback, const std::string& module, const std::string& action, Fn&& fn)
    {
        T value = fallback;
        if (!core::TryNativeValueChecked<T>(value, fallback, std::forward<Fn>(fn)))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, action, "Native value call failed safely");
            return fallback;
        }
        return value;
    }


    static void PlayMenuSound(MenuSoundKind kind)
    {
        if (!cfg.menuSounds) return;
        const DWORD now = GetTickCount();
        const int index = std::max(0, std::min(5, (int)kind));
        const DWORD minInterval = (kind == MenuSoundKind::Navigate) ? 55u : 35u;
        if (!core::TickElapsed(now, g_lastMenuSoundTicks[index], minInterval)) return;
        g_lastMenuSoundTicks[index] = now;
        const char* sound = MenuSoundNativeName(kind);
        SafeNativeVoidRuntime("ui_sound", "play menu sound", [&]()
        {
            AUDIO::PLAY_SOUND_FRONTEND(-1, (char*)sound, (char*)"HUD_FRONTEND_DEFAULT_SOUNDSET", true);
        });
    }

