    static bool SafeEnableDispatchServiceRuntime(int service, bool enabled, const std::string& module = "wanted")
    {
        service = ClampIntValue(service, 0, 15);

        // BUGFIX 186:
        // Some ScriptHookV native header snapshots no longer expose
        // GAMEPLAY::ENABLE_DISPATCH_SERVICE, while others moved the native under
        // MISC or omit the wrapper entirely. Calling the native hash directly
        // keeps the source compatible with those SDK layouts.
        //
        // Native: ENABLE_DISPATCH_SERVICE(dispatchService, toggle)
        // Hash:   0xDC0F817884CDD856
        return SafeNativeVoidRuntime(module, "enable dispatch service", [&]()
        {
            invoke<Void>(static_cast<Hash>(0xDC0F817884CDD856ULL), service, enabled ? TRUE : FALSE);
        });
    }

    static void SafeSetDispatchServicesRuntime(bool enabled, const std::string& module = "wanted")
    {
        // HOTFIX 228:
        // ENABLE_DISPATCH_SERVICE by raw hash is unsafe on some GTA V / ScriptHookV
        // combinations and can crash a few seconds after gameplay begins. Keep normal
        // police restoration on SET_DISPATCH_COPS_FOR_PLAYER / wanted-level natives,
        // and only queue per-service dispatch toggles when the user explicitly enables
        // the advanced native repair switch.
        if (!cfg.wantedPoliceRepairDispatchServices || !cfg.wantedPoliceRepairDispatchServiceNative)
        {
            g_pendingDispatchServiceRestore = false;
            g_dispatchServiceRestoreNextService = 1;
            const DWORD now = GetTickCount();
            if (g_lastDispatchServiceNativeSkipLogTick == 0 ||
                core::TickElapsed(now, g_lastDispatchServiceNativeSkipLogTick, 15000u))
            {
                g_lastDispatchServiceNativeSkipLogTick = now;
                Log(std::string("Dispatch service native restore skipped for crash safety (module=") +
                    module + ", requested=" + (enabled ? "ON" : "OFF") + ")");
            }
            return;
        }

        g_pendingDispatchServiceRestore = true;
        g_pendingDispatchServiceRestoreEnabled = enabled;
        g_dispatchServiceRestoreNextService = 1;

        const DWORD now = GetTickCount();
        if (g_lastDispatchServiceNativeSkipLogTick == 0 ||
            core::TickElapsed(now, g_lastDispatchServiceNativeSkipLogTick, 15000u))
        {
            g_lastDispatchServiceNativeSkipLogTick = now;
            Log(std::string("Dispatch service restore queued until crash-safe world gate (module=") +
                module + ", requested=" + (enabled ? "ON" : "OFF") + ")");
        }
    }

