    static bool SafeResetVehiclePassengerDoorsForEntryRuntime(Vehicle vehicle, const std::string& module = "vehicle")
    {
        if (!vehicle || !core::IsVehicle((Entity)vehicle)) return false;
        // Used only after detecting a stuck companion entry animation. Closing passenger
        // doors resets GTA's half-open door state without warping the NPC into the car.
        return SafeNativeVoidRuntime(module, "reset passenger doors for entry", [&]()
        {
            // Passenger doors are front-right/rear-left/rear-right on normal GTA V
            // vehicles.  Do not close hood/trunk here; this helper is only meant to
            // reset the half-open passenger-door state after a stuck TASK_ENTER_VEHICLE.
            for (int door = 1; door <= 3; ++door)
                VEHICLE::SET_VEHICLE_DOOR_SHUT(vehicle, door, false);
        });
    }

