    static bool SafeSetWantedLevelMultiplierRuntime(float multiplier, const std::string& module = "wanted")
    {
        multiplier = ClampFloatValue(multiplier, 0.0f, 5.0f, 1.0f);
        // BUGFIX 181: multiplier 0 can make crimes stop generating wanted stars.
        // Keep 0 reserved for explicit No Wanted-style suppression only.
        if (!st.noWanted && multiplier <= 0.01f) multiplier = 1.0f;
        return SafeNativeVoidRuntime(module, "set wanted multiplier", [&](){ PLAYER::SET_WANTED_LEVEL_MULTIPLIER(multiplier); });
    }

    static int EffectiveNaturalMaxWantedLevelRuntime()
    {
        // BUGFIX 179: Max Wanted Level = 0 is effectively a hidden global No Wanted.
        // Keep 0 reserved for explicit No Wanted / mission-only suppression. During normal
        // gameplay, restore a legal wanted cap so GTA can create stars for crimes again.
        if (st.noWanted) return 0;
        if (st.maxWantedLevel <= 0)
        {
            st.maxWantedLevel = 5;
            st.frozenWantedLevel = ClampIntValue(st.frozenWantedLevel, 0, st.maxWantedLevel);
            st.selectedWantedLevel = ClampIntValue(st.selectedWantedLevel, 0, st.maxWantedLevel);
            st.lastPoliceRealismAction = "Natural wanted restored: max wanted was 0";
        }
        return ClampIntValue(st.maxWantedLevel, 0, 5);
    }

    static void RestoreNaturalWantedSuppressionRuntime(const std::string& module = "wanted")
    {
        const bool runtimeTickCall = (module == "wanted_runtime_tick");
        const DWORD now = GetTickCount();
        if (runtimeTickCall && !core::TickElapsed(now, st.lastNaturalWantedRestoreTick, 1500u))
            return;
        if (runtimeTickCall) st.lastNaturalWantedRestoreTick = now;

        if (st.noWanted)
        {
            SafeClearPlayerWantedLevelRuntime(module);
            SafeSetMaxWantedLevelRuntime(0, module);
            return;
        }

        if (st.policeIgnore && !st.policeIgnoreManual)
        {
            st.policeIgnore = false;
            st.lastPoliceRealismAction = "Natural wanted restored: non-manual Police Ignore cleared";
        }
        if (st.everyoneIgnore && !st.everyoneIgnoreManual)
        {
            st.everyoneIgnore = false;
            st.lastPoliceRealismAction = "Natural wanted restored: non-manual Everyone Ignore cleared";
        }

        const int effectiveMax = EffectiveNaturalMaxWantedLevelRuntime();
        SafeSetMaxWantedLevelRuntime(effectiveMax, module);
        SafeSetWantedLevelMultiplierRuntime(st.wantedMultiplierBoost ? 2.5f : 1.0f, module);
        SafeSetDispatchCopsForPlayerRuntime(true, module);
        SafeSetDispatchServicesRuntime(true, module);

        if (!st.policeIgnore) SafeSetPoliceIgnorePlayerRuntime(false, module);
        if (!st.everyoneIgnore) SafeSetEveryoneIgnorePlayerRuntime(false, module);
    }

    static int SafeRandomIntRuntime(int minInclusive, int maxExclusive, int fallback, const std::string& module = "random")
    {
        if (maxExclusive <= minInclusive)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "random int", "Rejected invalid integer random range");
            return ClampIntValue(fallback, minInclusive, minInclusive);
        }

        fallback = ClampIntValue(fallback, minInclusive, maxExclusive - 1);
        int value = SafeNativeValueRuntime<int>(fallback, module, "random int", [&](){ return GAMEPLAY::GET_RANDOM_INT_IN_RANGE(minInclusive, maxExclusive); });
        if (value < minInclusive || value >= maxExclusive)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "random int", "Native returned out-of-range integer random value");
            value = fallback;
        }
        return value;
    }

    static float SafeRandomFloatRuntime(float minInclusive, float maxExclusive, float fallback, const std::string& module = "random")
    {
        if (!std::isfinite(minInclusive) || !std::isfinite(maxExclusive) || maxExclusive <= minInclusive)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "random float", "Rejected invalid float random range");
            if (std::isfinite(minInclusive)) return minInclusive;
            return std::isfinite(fallback) ? fallback : 0.0f;
        }

        fallback = ClampFloatExclusiveUpperValue(fallback, minInclusive, maxExclusive, minInclusive);
        float value = SafeNativeValueRuntime<float>(fallback, module, "random float", [&](){ return GAMEPLAY::GET_RANDOM_FLOAT_IN_RANGE(minInclusive, maxExclusive); });
        if (!std::isfinite(value) || value < minInclusive || value >= maxExclusive)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "random float", "Native returned out-of-range float random value");
            value = fallback;
        }
        return ClampFloatExclusiveUpperValue(value, minInclusive, maxExclusive, fallback);
    }

