    static bool SafeGetClosestVehicleNodeRuntime(const Vector3& desired, int nth, Vector3& outNode, const std::string& module = "pathfind")
    {
        if (!IsUsableRuntimeWorldPosition(desired) || nth < 1 || nth > 64)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "vehicle node", "Rejected invalid vehicle-node query");
            return false;
        }
        Vector3 node{};
        const bool ok = SafeNativeValueRuntime<bool>(false, module, "get closest vehicle node", [&](){ return PATHFIND::GET_NTH_CLOSEST_VEHICLE_NODE(desired.x, desired.y, desired.z, nth, &node, 0, 0, 0); });
        if (!ok || !IsUsableRuntimeWorldPosition(node)) return false;
        outNode = node;
        return true;
    }

    static bool SafeDrawMarkerRuntime(int markerType, const Vector3& pos, const Vector3& dir, const Vector3& rot,
                                      const Vector3& scale, int r, int g, int b, int a,
                                      bool bobUpAndDown, bool faceCamera, int drawOnEnts, bool rotate,
                                      const std::string& module = "marker")
    {
        if (!IsUsableRuntimeWorldPosition(pos))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "draw marker", "Rejected invalid marker position");
            return false;
        }
        markerType = ClampIntValue(markerType, 0, 43);
        Vector3 safeDir = dir;
        Vector3 safeRot = rot;
        Vector3 safeScale = scale;
        if (!std::isfinite(safeDir.x)) safeDir.x = 0.0f;
        if (!std::isfinite(safeDir.y)) safeDir.y = 0.0f;
        if (!std::isfinite(safeDir.z)) safeDir.z = 0.0f;
        if (!std::isfinite(safeRot.x)) safeRot.x = 0.0f;
        if (!std::isfinite(safeRot.y)) safeRot.y = 0.0f;
        if (!std::isfinite(safeRot.z)) safeRot.z = 0.0f;
        safeScale.x = ClampFloatValue(safeScale.x, 0.01f, 500.0f, 1.0f);
        safeScale.y = ClampFloatValue(safeScale.y, 0.01f, 500.0f, 1.0f);
        safeScale.z = ClampFloatValue(safeScale.z, 0.01f, 500.0f, 1.0f);
        r = ClampIntValue(r, 0, 255);
        g = ClampIntValue(g, 0, 255);
        b = ClampIntValue(b, 0, 255);
        a = ClampIntValue(a, 0, 255);
        drawOnEnts = ClampIntValue(drawOnEnts, 0, 2);
        return SafeNativeVoidRuntime(module, "draw marker", [&]()
        {
            GRAPHICS::DRAW_MARKER(markerType,
                                  pos.x, pos.y, pos.z,
                                  safeDir.x, safeDir.y, safeDir.z,
                                  safeRot.x, safeRot.y, safeRot.z,
                                  safeScale.x, safeScale.y, safeScale.z,
                                  r, g, b, a,
                                  bobUpAndDown, faceCamera, drawOnEnts, rotate,
                                  nullptr, nullptr, false);
        });
    }

    static float ClampMenuWidthValue(float value)
    {
        return ClampFloatValue(value, 0.24f, 0.82f, 0.340f);
    }

    static int ClampMenuWidthModeValue(int mode)
    {
        return (mode < 0 || mode > 3) ? 1 : mode;
    }

    static std::string MenuWidthModeName(int mode)
    {
        switch (ClampMenuWidthModeValue(mode))
        {
            case 0: return "Compact";
            case 2: return "Wide";
            case 3: return "Custom";
            default: return "Normal";
        }
    }

    static int ParseMenuWidthMode(const std::string& value, int fallback)
    {
        std::string v = StripInlineCommentBasic(value);
        std::transform(v.begin(), v.end(), v.begin(), [](unsigned char c){ return (char)std::tolower(c); });
        if (v == "0" || v == "compact" || v == "small" || v == "narrow") return 0;
        if (v == "1" || v == "normal" || v == "default" || v == "medium") return 1;
        if (v == "2" || v == "wide" || v == "large") return 2;
        if (v == "3" || v == "custom" || v == "manual") return 3;
        return ClampMenuWidthModeValue(fallback);
    }

    static float MenuWidthPresetValue(int mode)
    {
        switch (ClampMenuWidthModeValue(mode))
        {
            case 0: return 0.295f;
            case 2: return 0.495f;
            default: return 0.340f;
        }
    }

    static void ApplyMenuWidthModePreset(int mode, bool notifyResult = true)
    {
        cfg.menuWidthMode = ClampMenuWidthModeValue(mode);
        if (cfg.menuWidthMode != 3)
            cfg.menuW = MenuWidthPresetValue(cfg.menuWidthMode);
        cfg.menuW = ClampMenuWidthValue(cfg.menuW);
        InvalidateAdaptiveMenuWidth();
        if (notifyResult) Notify("Menu width mode: " + MenuWidthModeName(cfg.menuWidthMode));
    }

    static void CycleMenuWidthMode()
    {
        // Click cycles the three presets. Manual Menu Width editing switches to Custom.
        int current = ClampMenuWidthModeValue(cfg.menuWidthMode);
        int next = current >= 2 ? 0 : current + 1;
        ApplyMenuWidthModePreset(next, true);
    }

    static void NudgeMenuWidth()
    {
        cfg.menuW = ClampMenuWidthValue(cfg.menuW + 0.025f);
        if (cfg.menuW > 0.82f - 0.001f) cfg.menuW = 0.24f;
        cfg.menuWidthMode = 3;
        InvalidateAdaptiveMenuWidth();
    }

