    static int RunConfigRepair(bool forceIni, bool notifyResult)
    {
        int repaired = 0;
        repaired += RepairIniFile(forceIni);
        repaired += EnsureSupportDataFiles();
        if (notifyResult)
        {
            if (repaired > 0) Notify("Config Repair complete. Fixed/created: " + std::to_string(repaired));
            else Notify("Config Repair: no problems found.");
        }
        return repaired;
    }

