        AddHealthLine(st.healthReportLines, "Ped Catalog", std::to_string((int)pedCatalog.size()) + " entries", pedCatalog.empty() ? 1 : 0);
        AddHealthLine(st.healthReportLines, "Vehicle Catalog", std::to_string((int)vehicleCatalog.size()) + " entries", vehicleCatalog.empty() ? 1 : 0);
