        AddHealthLine(st.healthReportLines, "Notifications", NotificationStyleName(cfg.notificationStyle), 0);
        AddHealthLine(st.healthReportLines, "Auto Recovery", OnOff(cfg.autoRecoveryEnabled) + " / last: " + st.lastAutoRecoveryAction, 0);
        AddHealthLine(st.healthReportLines, "Game Mode Core", OnOff(cfg.gameModesEnabled) + " / " + (st.gameMode.active ? GameModeName(st.gameMode.type) : std::string("idle")), cfg.gameModesEnabled ? 0 : 1);
        AddHealthLine(st.healthReportLines, "Random Mission Generator", OnOff(cfg.randomMissionGeneratorEnabled) + " / radius " + std::to_string(cfg.randomMissionRadius) + "m" + (cfg.randomMissionLargeScaleEnabled ? " / large-scale" : ""), cfg.randomMissionGeneratorEnabled ? 0 : 1);
        AddHealthLine(st.healthReportLines, "World Director", OnOff(cfg.worldDirectorEnabled) + " / auto " + OnOff(cfg.worldDirectorAutoEvents) + " / chaos " + std::to_string(cfg.worldDirectorChaosLevel) + "/5 / tracked " + std::to_string(CountExistingMixedEntities(st.worldDirectorEntities)), cfg.worldDirectorEnabled ? 0 : 1);
        AddHealthLine(st.healthReportLines, "Urban Life", OnOff(cfg.urbanLifeEnabled) + " / auto " + OnOff(cfg.urbanLifeAutoEvents) + " / safe " + OnOff(cfg.urbanLifeSafeMode) + " / tracked " + std::to_string(CountExistingMixedEntities(st.urbanLifeEntities)), cfg.urbanLifeEnabled ? 0 : 1);
        AddHealthLine(st.healthReportLines, "Vehicle AI", OnOff(cfg.vehicleAIEnabled) + " / auto " + OnOff(cfg.vehicleAIAutoEvents) + " / profile " + std::to_string(cfg.vehicleAIProfile) + " / tracked " + std::to_string(CountExistingMixedEntities(st.vehicleAIEntities)), cfg.vehicleAIEnabled ? 0 : 1);
        AddHealthLine(st.healthReportLines, "Movie Scene Mode", OnOff(cfg.movieSceneModeEnabled) + " / actors cap " + std::to_string(cfg.movieSceneMaxActors) + " / intensity " + std::to_string((int)cfg.movieSceneIntensity) + " / camera " + OnOff(cfg.movieSceneCinematicCameraEnabled), cfg.movieSceneModeEnabled ? 0 : 1);
        AddHealthLine(st.healthReportLines, "Recovery Fixes", std::to_string(st.autoRecoveryFixes) + " total, invalid " + std::to_string(st.autoRecoveryInvalidCleanups) + ", player " + std::to_string(st.autoRecoveryPlayerFixes) + ", vehicle " + std::to_string(st.autoRecoveryVehicleFixes) + ", blips " + std::to_string(st.autoRecoveryBlipFixes) + ", chauffeur " + std::to_string(st.autoRecoveryChauffeurFixes) + ", bodyguards " + std::to_string(st.autoRecoveryBodyguardFixes) + ", missions " + std::to_string(st.autoRecoveryMissionFixes) + ", UI " + std::to_string(st.autoRecoveryUiFixes), 0);
