        AddHealthLine(st.healthReportLines, "Performance Safety", OnOff(cfg.performanceSafetyEnabled) + " / total " + std::to_string(st.performanceSafetyLastEntityTotal) + " / " + st.lastPerformanceSafetyReport, cfg.performanceSafetyEnabled ? 0 : 1);
