    static std::string StateManagerCharacterName(int slot)
    {
        switch (slot)
        {
            case 0: return "Michael";
            case 1: return "Franklin";
            case 2: return "Trevor";
            default: return "Auto";
        }
    }

    static int StateManagerStorySlotFromModelHash(Hash model)
    {
        if (!model) return -1;
        if (model == H("player_zero")) return 0;
        if (model == H("player_one")) return 1;
        if (model == H("player_two")) return 2;
        return -1;
    }

    static int StateManagerCurrentStorySlot()
    {
        if (st.stateManagerCharacterSlot >= 0 && st.stateManagerCharacterSlot <= 2)
            return st.stateManagerCharacterSlot;

        Ped p = 0;
        if (GetPlayerPedSafe(p))
        {
            const int currentSlot = StateManagerStorySlotFromModelHash(core::SafeGetPedModel(p));
            if (currentSlot >= 0) return currentSlot;
        }

        // BUGFIX 131: Auto mode must not blindly fall back to Franklin after a
        // temporary/custom player model swap.  If the trainer captured the original
        // story model, keep stat/money writes on that story slot unless the user
        // manually chooses Michael/Franklin/Trevor.
        const int originalSlot = StateManagerStorySlotFromModelHash(st.originalPlayerModel);
        if (originalSlot >= 0) return originalSlot;

        // Final safe fallback for unknown custom-model sessions.
        return 1;
    }

    static std::string StateManagerSlotPrefix(int slot)
    {
        slot = ClampIntValue(slot, 0, 2);
        return std::string("SP") + std::to_string(slot) + "_";
    }

    static std::string StateManagerActiveCharacterLabel()
    {
        if (st.stateManagerCharacterSlot >= 0 && st.stateManagerCharacterSlot <= 2)
            return StateManagerCharacterName(st.stateManagerCharacterSlot) + " / " + StateManagerSlotPrefix(st.stateManagerCharacterSlot);

        const int slot = StateManagerCurrentStorySlot();
        return "Auto -> " + StateManagerCharacterName(slot) + " / " + StateManagerSlotPrefix(slot);
    }

    static const StateManagerStatDef& CurrentStateManagerStat()
    {
        const auto& stats = StateManagerStats();
        int idx = stats.empty() ? 0 : ClampIntValue(st.stateManagerSelectedStat, 0, (int)stats.size() - 1);
        return stats[(size_t)idx];
    }

    static std::string StateManagerStatName(const StateManagerStatDef& stat, int slot)
    {
        return StateManagerSlotPrefix(slot) + std::string(stat.suffix ? stat.suffix : "");
    }

    static std::string StateManagerMoneyStatName(int slot)
    {
        return StateManagerSlotPrefix(slot) + "TOTAL_CASH";
    }

    static std::string FormatCashValue(int value)
    {
        if (value < 0) value = 0;
        std::string s = std::to_string(value);
        for (int i = (int)s.size() - 3; i > 0; i -= 3) s.insert((size_t)i, ",");
        return "$" + s;
    }

    static int CurrentStateManagerSkillValue()
    {
        const auto& values = StateManagerValuePresets();
        if (st.stateManagerValuePreset >= 0 && st.stateManagerValuePreset < (int)values.size())
            return values[(size_t)st.stateManagerValuePreset];
        return ClampIntValue(st.stateManagerCustomSkillValue, 0, 100);
    }

    static int CurrentStateManagerMoneyValue()
    {
        const auto& values = StateManagerMoneyPresets();
        if (st.stateManagerMoneyPreset >= 0 && st.stateManagerMoneyPreset < (int)values.size())
            return values[(size_t)st.stateManagerMoneyPreset];
        return ClampIntValue(st.stateManagerCustomMoneyValue, 0, 2000000000);
    }

    static std::string CurrentStateManagerSkillValueLabel()
    {
        const int value = CurrentStateManagerSkillValue();
        if (st.stateManagerValuePreset < 0) return "Custom: " + std::to_string(value);
        return std::to_string(value);
    }

    static std::string CurrentStateManagerMoneyValueLabel()
    {
        const std::string value = FormatCashValue(CurrentStateManagerMoneyValue());
        if (st.stateManagerMoneyPreset < 0) return "Custom: " + value;
        return value;
    }

    static bool SafeStatSetIntRuntime(const std::string& statName, int value, bool save, const std::string& action)
    {
        const std::string clean = NormalizeModelName(statName, "");
        if (clean.empty())
        {
            ReportCore2(core::ErrorSeverity::Warning, "state_manager", action, "Rejected empty stat name");
            return false;
        }
        const Hash statHash = H(clean);
        if (statHash == 0)
        {
            ReportCore2(core::ErrorSeverity::Warning, "state_manager", action, "Stat hash resolved to zero: " + clean);
            return false;
        }
        const bool ok = SafeNativeValueRuntime<bool>(false, "state_manager", action, [&](){ return STATS::STAT_SET_INT(statHash, value, save); });
        if (!ok) ReportCore2(core::ErrorSeverity::Warning, "state_manager", action, "STAT_SET_INT rejected " + clean);
        return ok;
    }

    static bool SafeStatGetIntRuntime(const std::string& statName, int& out, int fallback, const std::string& action)
    {
        out = fallback;
        const std::string clean = NormalizeModelName(statName, "");
        if (clean.empty()) return false;
        const Hash statHash = H(clean);
        if (statHash == 0) return false;
        int value = fallback;
        const bool ok = SafeNativeValueRuntime<bool>(false, "state_manager", action, [&](){ return STATS::STAT_GET_INT(statHash, &value, -1); });
        if (!ok) return false;
        out = value;
        return true;
    }

    static void CycleStateManagerCharacter()
    {
        // -1 Auto, then 0 Michael, 1 Franklin, 2 Trevor.
        ++st.stateManagerCharacterSlot;
        if (st.stateManagerCharacterSlot > 2) st.stateManagerCharacterSlot = -1;
        st.lastStateManagerReport = "Target: " + StateManagerActiveCharacterLabel();
        Notify(st.lastStateManagerReport);
    }

    static void CycleStateManagerStat()
    {
        const auto& stats = StateManagerStats();
        if (stats.empty()) return;
        st.stateManagerSelectedStat = (st.stateManagerSelectedStat + 1) % (int)stats.size();
        st.lastStateManagerReport = std::string("Selected stat: ") + CurrentStateManagerStat().label;
        Notify(st.lastStateManagerReport);
    }

    static void CycleStateManagerValuePreset()
    {
        const auto& values = StateManagerValuePresets();
        st.stateManagerValuePreset++;
        if (st.stateManagerValuePreset >= (int)values.size()) st.stateManagerValuePreset = -1;
        st.lastStateManagerReport = "Skill value: " + CurrentStateManagerSkillValueLabel();
        Notify(st.lastStateManagerReport);
    }

    static void CycleStateManagerMoneyPreset()
    {
        const auto& values = StateManagerMoneyPresets();
        st.stateManagerMoneyPreset++;
        if (st.stateManagerMoneyPreset >= (int)values.size()) st.stateManagerMoneyPreset = -1;
        st.lastStateManagerReport = "Money value: " + CurrentStateManagerMoneyValueLabel();
        Notify(st.lastStateManagerReport);
    }

    static bool ApplyStateManagerStatValue(const StateManagerStatDef& stat, int slot, int value, bool notifyResult)
    {
        value = ClampIntValue(value, stat.minValue, stat.maxValue);
        const std::string statName = StateManagerStatName(stat, slot);
        const bool ok = SafeStatSetIntRuntime(statName, value, true, std::string("set ") + stat.label);
        if (ok)
        {
            st.lastStateManagerReport = StateManagerCharacterName(slot) + " " + stat.label + " = " + std::to_string(value);
            if (notifyResult) Notify(st.lastStateManagerReport);
            if (std::string(stat.suffix) == "STAMINA") SafeRestorePlayerStaminaRuntime(1.0f, "state_manager");
        }
        else
        {
            st.lastStateManagerReport = "Failed to set " + statName;
            if (notifyResult) Notify(st.lastStateManagerReport);
        }
        return ok;
    }

    static void SetSelectedStateManagerStat()
    {
        const int slot = StateManagerCurrentStorySlot();
        ApplyStateManagerStatValue(CurrentStateManagerStat(), slot, CurrentStateManagerSkillValue(), true);
    }

    static void MaxSelectedStateManagerStat()
    {
        const int slot = StateManagerCurrentStorySlot();
        const StateManagerStatDef& stat = CurrentStateManagerStat();
        ApplyStateManagerStatValue(stat, slot, stat.maxValue, true);
    }

    static void MaxAllStateManagerStats()
    {
        const int slot = StateManagerCurrentStorySlot();
        int okCount = 0;
        for (const StateManagerStatDef& stat : StateManagerStats())
        {
            if (ApplyStateManagerStatValue(stat, slot, stat.maxValue, false)) ++okCount;
        }
        SafeRestorePlayerStaminaRuntime(1.0f, "state_manager");
        st.lastStateManagerReport = "Maxed " + std::to_string(okCount) + "/" + std::to_string((int)StateManagerStats().size()) + " stats for " + StateManagerCharacterName(slot);
        Notify(st.lastStateManagerReport);
    }

    static void ResetAllStateManagerStats()
    {
        const int slot = StateManagerCurrentStorySlot();
        int okCount = 0;
        for (const StateManagerStatDef& stat : StateManagerStats())
        {
            if (ApplyStateManagerStatValue(stat, slot, stat.minValue, false)) ++okCount;
        }
        st.lastStateManagerReport = "Reset " + std::to_string(okCount) + "/" + std::to_string((int)StateManagerStats().size()) + " stats for " + StateManagerCharacterName(slot);
        Notify(st.lastStateManagerReport);
    }

    static bool SetStateManagerMoneyToValue(int value, bool notifyResult)
    {
        const int slot = StateManagerCurrentStorySlot();
        value = ClampIntValue(value, 0, 2000000000);
        const std::string statName = StateManagerMoneyStatName(slot);
        const bool ok = SafeStatSetIntRuntime(statName, value, true, "set story cash");
        if (ok)
        {
            st.lastStateManagerReport = StateManagerCharacterName(slot) + " cash = " + FormatCashValue(value);
            if (notifyResult) Notify(st.lastStateManagerReport);
        }
        else
        {
            st.lastStateManagerReport = "Failed to set " + statName;
            if (notifyResult) Notify(st.lastStateManagerReport);
        }
        return ok;
    }

    static void SetStateManagerMoneyPreset()
    {
        SetStateManagerMoneyToValue(CurrentStateManagerMoneyValue(), true);
    }

    static void AddStateManagerMoneyPreset()
    {
        const int slot = StateManagerCurrentStorySlot();
        const std::string statName = StateManagerMoneyStatName(slot);
        int current = 0;
        if (!SafeStatGetIntRuntime(statName, current, 0, "get story cash before add"))
        {
            st.lastStateManagerReport = "Add cash blocked: failed to read " + statName;
            Notify(st.lastStateManagerReport);
            return;
        }
        long long next = (long long)ClampIntValue(current, 0, 2000000000) + (long long)CurrentStateManagerMoneyValue();
        if (next > 2000000000LL) next = 2000000000LL;
        SetStateManagerMoneyToValue((int)next, true);
    }

    static void RefreshStateManagerSnapshot()
    {
        const int slot = StateManagerCurrentStorySlot();
        int cash = 0;
        const bool cashOk = SafeStatGetIntRuntime(StateManagerMoneyStatName(slot), cash, 0, "get story cash");
        int skill = 0;
        const StateManagerStatDef& stat = CurrentStateManagerStat();
        const bool skillOk = SafeStatGetIntRuntime(StateManagerStatName(stat, slot), skill, 0, std::string("get ") + stat.label);
        if (cashOk) cash = ClampIntValue(cash, 0, 2000000000);
        if (skillOk) skill = ClampIntValue(skill, stat.minValue, stat.maxValue);
        st.lastStateManagerReport = StateManagerCharacterName(slot) + " / cash " + (cashOk ? FormatCashValue(cash) : "unknown") + " / " + stat.label + " " + (skillOk ? std::to_string(skill) : "unknown");
        Notify(st.lastStateManagerReport);
    }

    static bool JustPressed(int vk, DWORD delay = 140)
    {
        if (vk <= 0 || vk >= 256) return false;
        if (!(GetAsyncKeyState(vk) & 0x8000)) return false;
        DWORD now = GetTickCount();
        if (!core::TickElapsed(now, lastKeyTick[vk], core::ClampTickInterval(delay))) return false;
        lastKeyTick[vk] = now;
        return true;
    }

    static void DebugLog(const std::string& module, const std::string& action, const std::string& detail)
    {
        if (!cfg.improvedDebugLogging) return;
        Log("[DBG][" + module + "] " + action + " :: " + detail);
    }

    static void Notify(const std::string& text)
    {
        Log(text);
        if (cfg.notificationStyle <= 0) return;
        TrainerNotification n;
        n.text = text;
        n.created = GetTickCount();
        notifications.push_back(n);
        int limit = std::max(1, std::min(8, cfg.maxNotifications));
        while ((int)notifications.size() > limit) notifications.erase(notifications.begin());
    }

    static std::string MakeUiTextOneLine(const std::string& text)
    {
        std::string out;
        out.reserve(text.size());
        bool lastWasSpace = false;
        for (unsigned char c : text)
        {
            if (c == '\r' || c == '\n' || c == '\t')
            {
                if (!lastWasSpace)
                {
                    out.push_back(' ');
                    lastWasSpace = true;
                }
                continue;
            }
            if (c < 32)
                continue;
            out.push_back((char)c);
            lastWasSpace = (c == ' ');
        }
        return Trim(out);
    }

    static std::string TrimUtf8ToBytes(const std::string& text, size_t maxBytes)
    {
        if (text.size() <= maxBytes) return text;
        if (maxBytes <= 3) return std::string(maxBytes, '.');

        size_t cut = maxBytes - 3;
        while (cut > 0 && ((unsigned char)text[cut] & 0xC0) == 0x80) --cut;
        if (cut == 0) return "...";
        return text.substr(0, cut) + "...";
    }

    static std::string MakeNativeTextSafe(const std::string& text)
    {
        // Native text components are fragile with embedded control chars and very long strings.
        // Menu text is already width-clipped; this is a final crash/bleed guard for every overlay.
        return TrimUtf8ToBytes(MakeUiTextOneLine(text), 180);
    }

    static void DrawText(float x, float y, float scale, const std::string& text, int r = 255, int g = 255, int b = 255, int a = 255, bool centre = false)
    {
        const std::string safeText = MakeNativeTextSafe(text);
        if (safeText.empty()) return;
        x = ClampFloatValue(x, -1.0f, 2.0f, 0.0f);
        y = ClampFloatValue(y, -1.0f, 2.0f, 0.0f);
        scale = ClampFloatValue(scale, 0.05f, 2.0f, 0.35f);
        r = ClampIntValue(r, 0, 255);
        g = ClampIntValue(g, 0, 255);
        b = ClampIntValue(b, 0, 255);
        a = ClampIntValue(a, 0, 255);
        SafeNativeVoidRuntime("ui_draw", "draw text", [&]()
        {
            UI::SET_TEXT_FONT(0);
            UI::SET_TEXT_SCALE(scale, scale);
            UI::SET_TEXT_COLOUR(r, g, b, a);
            UI::SET_TEXT_CENTRE(centre);
            UI::SET_TEXT_OUTLINE();
            UI::_SET_TEXT_ENTRY((char*)"STRING");
            UI::_ADD_TEXT_COMPONENT_STRING((char*)safeText.c_str());
            UI::_DRAW_TEXT(x, y);
        });
    }

    static void DrawRect(float x, float y, float w, float h, int r, int g, int b, int a)
    {
        x = ClampFloatValue(x, -1.0f, 2.0f, 0.5f);
        y = ClampFloatValue(y, -1.0f, 2.0f, 0.5f);
        w = ClampFloatValue(w, 0.0f, 2.0f, 0.1f);
        h = ClampFloatValue(h, 0.0f, 2.0f, 0.1f);
        r = ClampIntValue(r, 0, 255);
        g = ClampIntValue(g, 0, 255);
        b = ClampIntValue(b, 0, 255);
        a = ClampIntValue(a, 0, 255);
        SafeNativeVoidRuntime("ui_draw", "draw rect", [&](){ GRAPHICS::DRAW_RECT(x, y, w, h, r, g, b, a); });
    }

    static size_t Utf8PrevChar(const std::string& text, size_t pos)
    {
        if (pos == 0) return 0;
        --pos;
        while (pos > 0 && ((unsigned char)text[pos] & 0xC0) == 0x80) --pos;
        return pos;
    }

    static float EstimateTextWidth(const std::string& text, float scale)
    {
        // GTA V UI text has no automatic clipping in this trainer.  The estimate
        // intentionally errs on the wide side so menu values are shortened before
        // they can bleed outside the black menu panel on ultrawide/high-scale UI.
        const std::string oneLine = MakeUiTextOneLine(text);
        float units = 0.0f;
        for (size_t i = 0; i < oneLine.size(); ++i)
        {
            unsigned char c = (unsigned char)oneLine[i];
            if (c >= 0x80)
            {
                units += 0.92f;
                while (i + 1 < oneLine.size() && ((unsigned char)oneLine[i + 1] & 0xC0) == 0x80) ++i;
            }
            else if (c == ' ') units += 0.36f;
            else if (c == 'i' || c == 'l' || c == 'I' || c == '|' || c == '.' || c == ':' || c == '/') units += 0.34f;
            else if (c == 'W' || c == 'M' || c == '@' || c == '#' || c == '%') units += 0.92f;
            else units += 0.66f;
        }
        return units * scale * 0.0265f;
    }

    static std::string FitTextWidth(const std::string& text, float scale, float maxWidth)
    {
        std::string cleanText = MakeUiTextOneLine(text);
        if (cleanText.empty()) return cleanText;
        if (maxWidth <= 0.0f) return "";

        const std::string dots = "...";
        const std::string oneDot = ".";
        if (EstimateTextWidth(cleanText, scale) <= maxWidth) return cleanText;
        if (EstimateTextWidth(dots, scale) > maxWidth)
            return (EstimateTextWidth(oneDot, scale) <= maxWidth) ? oneDot : "";

        std::string out = cleanText;
        while (!out.empty() && EstimateTextWidth(out + dots, scale) > maxWidth)
        {
            size_t prev = Utf8PrevChar(out, out.size());
            out.erase(prev);
        }
        return out.empty() ? dots : out + dots;
    }

    static std::string FitMenuTextWidth(const std::string& text, float scale, float maxWidth)
    {
        // Leave a small visual safety margin because the native font renderer
        // varies slightly by resolution, language, and GTA font fallback.
        return FitTextWidth(text, scale, std::max(0.0f, maxWidth * 0.92f));
    }

    static void DrawTrainerNotifications()
    {
        if (cfg.notificationStyle <= 0 || notifications.empty()) return;
        DWORD now = GetTickCount();
        int duration = std::max(1200, cfg.notificationDurationMs);
        notifications.erase(std::remove_if(notifications.begin(), notifications.end(), [now, duration](const TrainerNotification& n)
        {
            return core::TickElapsed(now, n.created, SafeIntervalAddOneMs(duration, cfg.notificationDurationMs, 500, 30000, "ui", "notification duration"));
        }), notifications.end());
        if (notifications.empty()) return;

        int limit = std::max(1, std::min(8, cfg.maxNotifications));
        float right = 0.985f;
        float y = 0.060f;
        float w = cfg.notificationStyle == 1 ? 0.300f : 0.360f;
        float h = cfg.notificationStyle == 1 ? 0.030f : 0.040f;
        float left = right - w;
        if (left < 0.50f) left = 0.50f;
        w = right - left;
        int shown = 0;
        for (int idx = (int)notifications.size() - 1; idx >= 0 && shown < limit; --idx, ++shown)
        {
            const TrainerNotification& n = notifications[idx];
            float yy = y + shown * (h + 0.006f);
            int age = (int)std::min<DWORD>(0x7fffffff, core::TickDelta(now, n.created));
            int alpha = age > duration - 900 ? std::max(55, 220 - (age - (duration - 900)) / 5) : 220;
            if (cfg.notificationStyle >= 2) DrawRect(left + w * 0.5f, yy + h * 0.5f, w, h, 12, 12, 15, alpha);

            if (cfg.notificationStyle >= 3)
            {
                DrawText(left + 0.012f, yy + 0.005f, 0.24f, "CUT", 255, 185, 70, alpha, false);
                std::string msg = FitTextWidth(Tr(n.text), 0.24f, w - 0.070f);
                DrawText(left + 0.058f, yy + 0.005f, 0.24f, FitTextWidth(msg, 0.24f, 0.255f), 245, 245, 245, alpha, false);
            }
            else
            {
                std::string msg = FitTextWidth(Tr(n.text), 0.26f, w - 0.026f);
                DrawText(left + 0.014f, yy + 0.006f, 0.26f, FitTextWidth(msg, 0.26f, 0.325f), 245, 245, 245, alpha, false);
            }
        }
    }

