    static bool LoadIni()
    {
        std::string path = ResolveDataFileReadPath("CaoUrbanTrainerASI.ini");
        if (!FileExists(path))
        {
            Log("INI load skipped: file missing.");
            return false;
        }

        std::vector<std::string> lines;
        if (!ReadTextLinesSafe(path, lines))
        {
            Log("INI load failed: cannot open file.");
            return false;
        }

        // First pass: detect whether the authoritative MenuWidthMode key exists.
        // This makes MenuWidth/Custom behavior independent from line order, casing,
        // spacing, and manual INI edits like Menu Width Mode / menuwidthmode.
        std::string scanSection;
        bool hasExplicitMenuWidthMode = false;
        for (std::string line : lines)
        {
            line = Trim(line);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;
            if (line[0] == '[')
            {
                auto close = line.find(']');
                scanSection = close == std::string::npos ? CanonicalIniSectionName(line.substr(1)) : CanonicalIniSectionName(line.substr(1, close - 1));
                continue;
            }
            auto eq = line.find('=');
            if (eq == std::string::npos) continue;
            std::string k = CanonicalIniKeyName(scanSection, line.substr(0, eq));
            if ((scanSection.empty() || SameIniSectionName(scanSection, "GUI")) && SameIniKeyName("GUI", k, "MenuWidthMode"))
            {
                hasExplicitMenuWidthMode = true;
                break;
            }
        }

        std::string section;
        bool seenBodyguardAutoEnterPlayerVehicle = false;
        int applied = 0;
        const std::map<int, bool> keepIniKeyLines = ComputeIniKeyLinesToApply(lines);
        g_loadingIni = true;
        g_iniHasExplicitMenuWidthMode = hasExplicitMenuWidthMode;
        try
        {
            for (int lineIndex = 0; lineIndex < (int)lines.size(); ++lineIndex)
            {
                std::string line = Trim(lines[lineIndex]);
                if (line.empty() || line[0] == '#' || line[0] == ';') continue;
                if (line[0] == '[')
                {
                    auto close = line.find(']');
                    section = close == std::string::npos ? CanonicalIniSectionName(line.substr(1)) : CanonicalIniSectionName(line.substr(1, close - 1));
                    continue;
                }
                auto eq = line.find('=');
                if (eq == std::string::npos) continue;
                if (!keepIniKeyLines.empty() && keepIniKeyLines.find(lineIndex) == keepIniKeyLines.end())
                    continue;

                std::string rawKey = Trim(line.substr(0, eq));
                std::string rawKeyId = IniNameKey(rawKey);
                std::string k = CanonicalIniKeyName(section, rawKey);
                std::string v = StripIniInlineComment(line.substr(eq + 1));

                // AutoEnterVehicle is a legacy alias for AutoEnterPlayerVehicle.
                // If both keys exist, keep the canonical key authoritative instead of
                // letting the later legacy alias silently override the player's setting.
                if (SameIniSectionName(section, "Bodyguards") && SameIniKeyName(section, k, "AutoEnterPlayerVehicle") && rawKeyId != IniNameKey("AutoEnterVehicle"))
                    seenBodyguardAutoEnterPlayerVehicle = true;
                if (SameIniSectionName(section, "Bodyguards") && rawKeyId == IniNameKey("AutoEnterVehicle") && seenBodyguardAutoEnterPlayerVehicle)
                    continue;

                try
                {
                    ApplyIniValue(section, k, v);
                    ++applied;
                }
                catch (...)
                {
                    Log("INI value skipped after parse error: [" + section + "] " + k);
                }
            }
        }
        catch (...)
        {
            g_loadingIni = false;
            g_iniHasExplicitMenuWidthMode = false;
            Log("INI load aborted safely after unexpected parser error. Defaults/current values kept.");
            return applied > 0;
        }
        g_loadingIni = false;
        g_iniHasExplicitMenuWidthMode = false;

        Log("INI loaded. Applied keys: " + std::to_string(applied));
        return applied > 0;
    }

    static bool ReloadIniSettingsFromDefaults()
    {
        cfg = Config();
        ResetIniBackedRuntimeStateToDefaults();
        bool loaded = LoadIni();
        ClampConfigValues();
        return loaded;
    }

    static std::string CatalogCategoryKey(const std::string& value)
    {
        std::string key = CompactKey(value);
        return key.empty() ? "other" : key;
    }

    static bool SameCatalogCategory(const std::string& a, const std::string& b)
    {
        return CatalogCategoryKey(a) == CatalogCategoryKey(b);
    }

    static std::string GetOrAddCanonicalCatalogCategory(std::vector<std::string>* categories, const std::string& rawCategory)
    {
        std::string category = NormalizeFlatText(rawCategory, 48, "Other");
        if (category.empty()) category = "Other";
        if (!categories) return category;

        const std::string key = CatalogCategoryKey(category);
        auto it = std::find_if(categories->begin(), categories->end(), [&key](const std::string& existing)
        {
            return CatalogCategoryKey(existing) == key;
        });
        if (it != categories->end()) return *it;

        categories->push_back(category);
        return category;
    }

    static void LoadCatalogFile(const std::string& fileName, std::vector<CatalogEntry>& out, std::vector<std::string>* categories = nullptr)
    {
        out.clear();
        if (categories) categories->clear();
        std::string path = ResolveDataFileReadPath(fileName);
        std::vector<std::string> lines;
        if (!ReadTextLinesSafe(path, lines))
        {
            Log("Catalog missing or unreadable: " + path);
            return;
        }

        for (std::string line : lines)
        {
            line = Trim(line);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;
            auto p = Split(line, '|');
            if (p.size() < 2) continue;
            CatalogEntry e;
            std::string rawCategory = p[0];
            e.model = NormalizeModelName(p[1], "");
            if (e.model.empty()) continue;
            e.category = GetOrAddCanonicalCatalogCategory(categories, rawCategory);
            e.display = (p.size() >= 3 && !p[2].empty()) ? NormalizeFlatText(p[2], 72, e.model) : e.model;
            if (std::find_if(out.begin(), out.end(), [&e](const CatalogEntry& existing)
            {
                return CompactKey(existing.model) == CompactKey(e.model) && SameCatalogCategory(existing.category, e.category);
            }) != out.end()) continue;
            out.push_back(e);
        }
    }

    static void DeduplicateCatalogEntries(std::vector<CatalogEntry>& catalog, std::vector<std::string>* categories = nullptr)
    {
        std::vector<CatalogEntry> unique;
        std::vector<std::string> uniqueCategories;
        unique.reserve(catalog.size());

        for (auto entry : catalog)
        {
            if (entry.model.empty()) continue;
            entry.category = GetOrAddCanonicalCatalogCategory(categories ? &uniqueCategories : nullptr, entry.category);
            if (std::find_if(unique.begin(), unique.end(), [&entry](const CatalogEntry& existing)
            {
                return CompactKey(existing.model) == CompactKey(entry.model) &&
                       SameCatalogCategory(existing.category, entry.category);
            }) != unique.end()) continue;

            unique.push_back(entry);
        }

        catalog.swap(unique);
        if (categories) categories->swap(uniqueCategories);
    }

    static void LoadAnimationCatalogFile(const std::string& fileName)
    {
        std::string path = ResolveDataFileReadPath(fileName);
        std::vector<std::string> lines;
        if (!ReadTextLinesSafe(path, lines)) return;

        for (std::string line : lines)
        {
            line = Trim(line);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;
            auto p = Split(line, '|');
            if (p.size() < 3) continue;
            AnimPreset a;
            a.label = NormalizeFlatText(p[0], 72, "DLC Animation");
            a.dict = NormalizeFlatText(p[1], 128, "");
            a.name = NormalizeFlatText(p[2], 96, "");
            a.duration = p.size() >= 4 ? ClampIntValue(ParseIntOr(p[3], -1), -1, 600000) : -1;
            a.flags = p.size() >= 5 ? ClampIntValue(ParseIntOr(p[4], 1), 0, 262144) : 1;
            if (a.label.empty() || a.dict.empty() || a.name.empty()) continue;
            const std::string key = CompactKey(a.dict + "|" + a.name);
            if (std::find_if(animPresets.begin(), animPresets.end(), [&key](const AnimPreset& existing)
            {
                return CompactKey(existing.dict + "|" + existing.name) == key;
            }) != animPresets.end()) continue;
            animPresets.push_back(a);
        }
    }

    static void LoadDlcBlipIconCatalog()
    {
        dlcBlipIcons.clear();
        std::string path = ResolveDataFileReadPath("CaoUrbanTrainer_DlcBlips.txt");
        std::vector<std::string> lines;
        if (!ReadTextLinesSafe(path, lines)) return;

        for (std::string line : lines)
        {
            line = Trim(line);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;
            auto p = Split(line, '|');
            if (p.size() < 3) continue;
            DlcBlipIconEntry b;
            b.category = NormalizeFlatText(p[0], 48, "DLC");
            b.sprite = ClampIntValue(ParseIntOr(p[1], 1), 1, kMaxBlipSpriteId);
            b.label = NormalizeFlatText(p[2], 72, "DLC Blip");
            b.internalName = p.size() >= 4 ? NormalizeFlatText(p[3], 72, b.label) : b.label;
            if (b.label.empty()) continue;
            const std::string key = CompactKey(b.label + "|" + std::to_string(b.sprite));
            if (std::find_if(dlcBlipIcons.begin(), dlcBlipIcons.end(), [&key](const DlcBlipIconEntry& existing)
            {
                return CompactKey(existing.label + "|" + std::to_string(existing.sprite)) == key;
            }) != dlcBlipIcons.end()) continue;
            dlcBlipIcons.push_back(b);
        }
    }

    static int ResolveDlcBlipSpriteByInternalName(const std::string& wanted, int fallbackSprite)
    {
        const std::string key = CompactKey(wanted);
        if (key.empty()) return fallbackSprite;
        for (const DlcBlipIconEntry& b : dlcBlipIcons)
        {
            if (CompactKey(b.internalName) == key || CompactKey(b.label) == key)
                return ClampIntValue(b.sprite, 1, kMaxBlipSpriteId);
        }
        return fallbackSprite;
    }

    static int ParseBlipSpriteOrDlcName(const std::string& value, int fallbackSprite)
    {
        int parsed = fallbackSprite;
        if (TryParseIntStrict(value, parsed))
            return ClampIntValue(parsed, 1, kMaxBlipSpriteId);
        return ResolveDlcBlipSpriteByInternalName(value, fallbackSprite);
    }

    static std::string DlcBlipCatalogStatusText()
    {
        int mansions = 0;
        int narco = 0;
        for (const DlcBlipIconEntry& b : dlcBlipIcons)
        {
            if (CompactKey(b.category).find("mansions") != std::string::npos) ++mansions;
            if (CompactKey(b.internalName).find("narcosurvival") != std::string::npos || CompactKey(b.label).find("narcosurvival") != std::string::npos) ++narco;
        }
        return "Mansions " + std::to_string(mansions) + " / NarcoSurvival " + (narco > 0 ? "correct" : "missing");
    }


    enum class FiveMPBridgeAssetType { Ped, Vehicle, Object, Unknown };

    static std::string FiveMPAsciiLower(std::string text)
    {
        std::transform(text.begin(), text.end(), text.begin(), [](unsigned char c){ return (char)std::tolower(c); });
        return text;
    }

    static std::string FiveMPCleanPathToken(std::string text)
    {
        text = Trim(StripInlineCommentBasic(text));
        if (text.size() >= 2)
        {
            const char first = text.front();
            const char last = text.back();
            if ((first == '"' && last == '"') || (first == '\'' && last == '\''))
                text = Trim(text.substr(1, text.size() - 2));
        }
        return text;
    }

    static std::string FiveMPDisplayFromModel(const std::string& model)
    {
        std::string display = model;
        for (char& ch : display)
        {
            if (ch == '_' || ch == '-') ch = ' ';
        }
        if (!display.empty()) display[0] = (char)std::toupper((unsigned char)display[0]);
        return display.empty() ? "FiveMP Asset" : display;
    }

    static FiveMPBridgeAssetType ParseFiveMPAssetType(const std::string& value)
    {
        const std::string k = CompactKey(value);
        if (k == "ped" || k == "peds" || k == "npc" || k == "skin") return FiveMPBridgeAssetType::Ped;
        if (k == "vehicle" || k == "vehicles" || k == "car" || k == "cars" || k == "bike" || k == "boat" || k == "air") return FiveMPBridgeAssetType::Vehicle;
        if (k == "object" || k == "objects" || k == "prop" || k == "props" || k == "map") return FiveMPBridgeAssetType::Object;
        return FiveMPBridgeAssetType::Unknown;
    }

    static bool LooksLikePedModelName(const std::string& model)
    {
        const std::string m = FiveMPAsciiLower(model);
        return m.rfind("a_f_", 0) == 0 || m.rfind("a_m_", 0) == 0 ||
               m.rfind("cs_", 0) == 0 || m.rfind("csb_", 0) == 0 ||
               m.rfind("ig_", 0) == 0 || m.rfind("mp_f_", 0) == 0 ||
               m.rfind("mp_m_", 0) == 0 || m.rfind("s_f_", 0) == 0 ||
               m.rfind("s_m_", 0) == 0 || m.rfind("u_f_", 0) == 0 ||
               m.rfind("u_m_", 0) == 0 || m.rfind("hc_", 0) == 0;
    }

    static bool FiveMPPathHasToken(const std::filesystem::path& path, const std::vector<std::string>& tokens)
    {
        for (const auto& part : path)
        {
            const std::string compact = CompactKey(part.string());
            if (compact.empty()) continue;
            for (const std::string& token : tokens)
            {
                if (compact == CompactKey(token)) return true;
            }
        }
        return false;
    }

    static bool FiveMPPathLooksLikePedResource(const std::filesystem::path& path)
    {
        return FiveMPPathHasToken(path, {"ped", "peds", "npc", "npcs", "skin", "skins", "addonpeds", "streamedpeds"});
    }

    static bool IsFiveMPScannableAssetFile(const std::filesystem::path& path)
    {
        const std::string ext = FiveMPAsciiLower(path.extension().string());
        return ext == ".yft" || ext == ".ydr" || ext == ".ydd" || ext == ".ymt";
    }

    static FiveMPBridgeAssetType ClassifyFiveMPScannedAsset(const std::filesystem::path& path, const std::string& model)
    {
        const std::string ext = FiveMPAsciiLower(path.extension().string());
        if (ext == ".ydr") return FiveMPBridgeAssetType::Object;
        if (ext == ".ydd" || ext == ".ymt")
        {
            if (FiveMPPathLooksLikePedResource(path) || LooksLikePedModelName(model))
                return FiveMPBridgeAssetType::Ped;
            return FiveMPBridgeAssetType::Unknown;
        }
        if (ext == ".yft")
        {
            if (FiveMPPathLooksLikePedResource(path) || LooksLikePedModelName(model))
                return FiveMPBridgeAssetType::Ped;
            return FiveMPBridgeAssetType::Vehicle;
        }
        return FiveMPBridgeAssetType::Unknown;
    }

    static bool AddFiveMPCatalogEntry(FiveMPBridgeAssetType type, const std::string& category, const std::string& modelName, const std::string& displayName, bool fromScanner)
    {
        const std::string model = NormalizeModelName(modelName, "");
        if (model.empty())
        {
            ++fiveMPAssetBridgeStats.skipped;
            return false;
        }

        CatalogEntry e;
        e.category = NormalizeFlatText(category, 48, "FiveMP");
        e.model = model;
        e.display = NormalizeFlatText(displayName, 72, FiveMPDisplayFromModel(model));

        switch (type)
        {
            case FiveMPBridgeAssetType::Ped:
                fiveMPPedCatalog.push_back(e);
                pedCatalog.push_back(e);
                if (fromScanner) ++fiveMPAssetBridgeStats.scannedPeds; else ++fiveMPAssetBridgeStats.filePeds;
                return true;
            case FiveMPBridgeAssetType::Vehicle:
                fiveMPVehicleCatalog.push_back(e);
                vehicleCatalog.push_back(e);
                addonVehicles.push_back(e);
                if (fromScanner) ++fiveMPAssetBridgeStats.scannedVehicles; else ++fiveMPAssetBridgeStats.fileVehicles;
                return true;
            case FiveMPBridgeAssetType::Object:
                fiveMPObjectCatalog.push_back(e);
                objectCatalog.push_back(e);
                if (fromScanner) ++fiveMPAssetBridgeStats.scannedObjects; else ++fiveMPAssetBridgeStats.fileObjects;
                return true;
            default:
                ++fiveMPAssetBridgeStats.skipped;
                return false;
        }
    }

    static void LoadFiveMPFixedCatalogFile(const std::string& fileName, FiveMPBridgeAssetType type)
    {
        std::vector<std::string> lines;
        const std::string path = ResolveDataFileReadPath(fileName);
        if (!ReadTextLinesSafe(path, lines)) return;

        for (std::string line : lines)
        {
            line = Trim(line);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;
            const auto p = Split(line, '|');
            if (p.size() < 2)
            {
                ++fiveMPAssetBridgeStats.skipped;
                continue;
            }
            const std::string display = (p.size() >= 3 && !p[2].empty()) ? p[2] : FiveMPDisplayFromModel(p[1]);
            AddFiveMPCatalogEntry(type, p[0].empty() ? "FiveMP" : p[0], p[1], display, false);
        }
    }

    static void LoadFiveMPGenericAssetFile()
    {
        std::vector<std::string> lines;
        const std::string path = ResolveDataFileReadPath("CaoUrbanTrainer_FiveMPAssets.txt");
        if (!ReadTextLinesSafe(path, lines)) return;

        for (std::string line : lines)
        {
            line = Trim(line);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;
            const auto p = Split(line, '|');
            if (p.size() < 2)
            {
                ++fiveMPAssetBridgeStats.skipped;
                continue;
            }

            const FiveMPBridgeAssetType type = ParseFiveMPAssetType(p[0]);
            if (type == FiveMPBridgeAssetType::Unknown)
            {
                ++fiveMPAssetBridgeStats.skipped;
                continue;
            }

            std::string category = "FiveMP";
            std::string model;
            std::string display;
            if (p.size() >= 3)
            {
                category = p[1].empty() ? "FiveMP" : p[1];
                model = p[2];
                display = p.size() >= 4 ? p[3] : FiveMPDisplayFromModel(model);
            }
            else
            {
                model = p[1];
                display = FiveMPDisplayFromModel(model);
            }
            AddFiveMPCatalogEntry(type, category, model, display, false);
        }
    }

    static std::string ResolveFiveMPUserPath(const std::string& raw)
    {
        std::string pathText = FiveMPCleanPathToken(raw);
        if (pathText.empty()) return std::string();
        try
        {
            std::filesystem::path fsPath(pathText);
            if (fsPath.is_absolute()) return pathText;
        }
        catch (...) {}
        return g_rootDir + pathText;
    }

    static std::string FiveMPModelNameFromAssetFile(const std::filesystem::path& path)
    {
        std::string model = path.stem().string();
        const std::string lower = FiveMPAsciiLower(model);
        if (lower.size() > 3 && lower.substr(lower.size() - 3) == "_hi")
            model = model.substr(0, model.size() - 3);
        return NormalizeModelName(model, "");
    }

    static void ImportFiveMPAssetFileFromDisk(const std::filesystem::path& path)
    {
        if (!IsFiveMPScannableAssetFile(path))
            return;

        const std::string model = FiveMPModelNameFromAssetFile(path);
        if (model.empty())
        {
            ++fiveMPAssetBridgeStats.skipped;
            return;
        }

        const FiveMPBridgeAssetType type = ClassifyFiveMPScannedAsset(path, model);
        if (type == FiveMPBridgeAssetType::Unknown)
        {
            ++fiveMPAssetBridgeStats.skipped;
            return;
        }

        std::string category = "FiveMP Resource";
        if (type == FiveMPBridgeAssetType::Ped) category = "FiveMP Scanned Peds";
        else if (type == FiveMPBridgeAssetType::Vehicle) category = "FiveMP Scanned Vehicles";
        else if (type == FiveMPBridgeAssetType::Object) category = "FiveMP Scanned Objects";
        AddFiveMPCatalogEntry(type, category, model, FiveMPDisplayFromModel(model), true);
    }

    static void ScanFiveMPResourcePath(const std::string& pathText)
    {
        const std::string resolved = ResolveFiveMPUserPath(pathText);
        if (resolved.empty()) return;

        try
        {
            std::error_code ec;
            std::filesystem::path root(resolved);
            if (!std::filesystem::exists(root, ec) || ec)
            {
                ++fiveMPAssetBridgeStats.skipped;
                return;
            }

            if (std::filesystem::is_regular_file(root, ec) && !ec)
            {
                if (IsFiveMPScannableAssetFile(root))
                {
                    ++fiveMPAssetBridgeStats.scannedFiles;
                    ImportFiveMPAssetFileFromDisk(root);
                }
                else
                {
                    ++fiveMPAssetBridgeStats.skipped;
                }
                return;
            }

            if (!std::filesystem::is_directory(root, ec) || ec)
            {
                ++fiveMPAssetBridgeStats.skipped;
                return;
            }

            ++fiveMPAssetBridgeStats.scannedFolders;
            constexpr int kFiveMPMaxScannedFiles = 6000;
            int visited = 0;
            std::filesystem::recursive_directory_iterator it(root, std::filesystem::directory_options::skip_permission_denied, ec);
            std::filesystem::recursive_directory_iterator end;
            while (!ec && it != end && visited < kFiveMPMaxScannedFiles)
            {
                const std::filesystem::directory_entry entry = *it;
                std::error_code entryEc;
                if (entry.is_regular_file(entryEc) && !entryEc)
                {
                    ++visited;
                    if (IsFiveMPScannableAssetFile(entry.path()))
                    {
                        ++fiveMPAssetBridgeStats.scannedFiles;
                        ImportFiveMPAssetFileFromDisk(entry.path());
                    }
                }
                it.increment(ec);
            }
            if (visited >= kFiveMPMaxScannedFiles)
            {
                fiveMPAssetBridgeStats.scanLimitReached = true;
                fiveMPAssetBridgeStats.lastStatus = "FiveMP scanner reached safe file limit.";
            }
        }
        catch (...)
        {
            ++fiveMPAssetBridgeStats.skipped;
        }
    }

    static void ScanFiveMPResourcePathsFile()
    {
        std::vector<std::string> lines;
        const std::string path = ResolveDataFileReadPath("CaoUrbanTrainer_FiveMPResourcePaths.txt");
        if (!ReadTextLinesSafe(path, lines)) return;
        for (std::string line : lines)
        {
            line = Trim(line);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;
            ScanFiveMPResourcePath(line);
        }
    }

    static void LoadFiveMPAssetBridgeCatalogs()
    {
        fiveMPPedCatalog.clear();
        fiveMPVehicleCatalog.clear();
        fiveMPObjectCatalog.clear();
        fiveMPAssetBridgeStats = FiveMPAssetBridgeStats{};
        LoadFiveMPFixedCatalogFile("CaoUrbanTrainer_FiveMPPeds.txt", FiveMPBridgeAssetType::Ped);
        LoadFiveMPFixedCatalogFile("CaoUrbanTrainer_FiveMPVehicles.txt", FiveMPBridgeAssetType::Vehicle);
        LoadFiveMPFixedCatalogFile("CaoUrbanTrainer_FiveMPObjects.txt", FiveMPBridgeAssetType::Object);
        LoadFiveMPGenericAssetFile();
        ScanFiveMPResourcePathsFile();
        const int total = (int)fiveMPPedCatalog.size() + (int)fiveMPVehicleCatalog.size() + (int)fiveMPObjectCatalog.size();
        if (fiveMPAssetBridgeStats.scanLimitReached)
        {
            fiveMPAssetBridgeStats.lastStatus = "FiveMP scanner reached safe file limit; assets merged: " + std::to_string(total);
        }
        else if (total > 0)
        {
            fiveMPAssetBridgeStats.lastStatus = "FiveMP assets merged: " + std::to_string(total);
        }
        else if (fiveMPAssetBridgeStats.skipped > 0)
        {
            fiveMPAssetBridgeStats.lastStatus = "FiveMP bridge loaded, no spawnable models found.";
        }
        else
        {
            fiveMPAssetBridgeStats.lastStatus = "FiveMP bridge ready; add models or resource paths.";
        }
    }

    static std::string FiveMPAssetBridgeSummary()
    {
        const int total = (int)fiveMPPedCatalog.size() + (int)fiveMPVehicleCatalog.size() + (int)fiveMPObjectCatalog.size();
        std::string summary = std::to_string(total) + " assets / p" + std::to_string((int)fiveMPPedCatalog.size()) +
               " v" + std::to_string((int)fiveMPVehicleCatalog.size()) +
               " o" + std::to_string((int)fiveMPObjectCatalog.size());
        if (fiveMPAssetBridgeStats.scannedFolders > 0 || fiveMPAssetBridgeStats.scannedFiles > 0)
            summary += " / scan " + std::to_string(fiveMPAssetBridgeStats.scannedFolders) + " folders, " + std::to_string(fiveMPAssetBridgeStats.scannedFiles) + " asset files";
        if (fiveMPAssetBridgeStats.scanLimitReached)
            summary += " / limit reached";
        return summary;
    }

    static void LoadAllCatalogs()
    {
        pedCategories.clear();
        vehicleCategories.clear();
        objectCategories.clear();
        LoadCatalogFile("CaoUrbanTrainer_PedModels.txt", pedCatalog, &pedCategories);
        LoadCatalogFile("CaoUrbanTrainer_Vehicles.txt", vehicleCatalog, &vehicleCategories);
        LoadCatalogFile("CaoUrbanTrainer_Objects.txt", objectCatalog, &objectCategories);
        LoadCatalogFile("CaoUrbanTrainer_AddonVehicles.txt", addonVehicles, nullptr);
        LoadFiveMPAssetBridgeCatalogs();
        // Reset to compiled-in presets before reading the external DLC animation
        // catalog.  Without this, Reload All Catalogs keeps animations that were
        // removed or fixed in CaoUrbanTrainer_Animations.txt during the session.
        animPresets = baseAnimPresets;
        LoadAnimationCatalogFile("CaoUrbanTrainer_Animations.txt");
        LoadDlcBlipIconCatalog();

        std::vector<CatalogEntry> cache;
        LoadCatalogFile("CaoUrbanTrainer_AddonVehicles.cache", cache, nullptr);
        addonVehicles.insert(addonVehicles.end(), cache.begin(), cache.end());

        DeduplicateCatalogEntries(pedCatalog, &pedCategories);
        DeduplicateCatalogEntries(vehicleCatalog, &vehicleCategories);
        DeduplicateCatalogEntries(objectCatalog, &objectCategories);
        DeduplicateCatalogEntries(addonVehicles, nullptr);
        DeduplicateCatalogEntries(fiveMPPedCatalog, nullptr);
        DeduplicateCatalogEntries(fiveMPVehicleCatalog, nullptr);
        DeduplicateCatalogEntries(fiveMPObjectCatalog, nullptr);

        Log("Loaded catalogs. Peds=" + std::to_string(pedCatalog.size()) +
            " Vehicles=" + std::to_string(vehicleCatalog.size()) +
            " AddOns=" + std::to_string(addonVehicles.size()) +
            " Objects=" + std::to_string(objectCatalog.size()) +
            " FiveMP=" + std::to_string((int)fiveMPPedCatalog.size() + (int)fiveMPVehicleCatalog.size() + (int)fiveMPObjectCatalog.size()) +
            " Animations=" + std::to_string(animPresets.size()) +
            " DLCBlips=" + std::to_string(dlcBlipIcons.size()));
        ClampStateIndexes();
    }

    static bool LoadModel(Hash model, int timeoutMs = 3000)
    {
        timeoutMs = ClampIntValue(timeoutMs, 100, 15000);
        if (!model)
        {
            ReportCore2(core::ErrorSeverity::Warning, "streaming", "load model", "Rejected zero model hash");
            return false;
        }

        const bool inCdImage = SafeNativeValueRuntime<bool>(false, "streaming", "is model in cdimage", [&](){ return STREAMING::IS_MODEL_IN_CDIMAGE(model); });
        const bool valid = SafeNativeValueRuntime<bool>(false, "streaming", "is model valid", [&](){ return STREAMING::IS_MODEL_VALID(model); });
        if (!inCdImage || !valid)
        {
            ReportCore2(core::ErrorSeverity::Warning, "streaming", "load model", "Rejected model hash that is not valid/in CD image");
            return false;
        }
        if (SafeNativeValueRuntime<bool>(false, "streaming", "has model loaded", [&](){ return STREAMING::HAS_MODEL_LOADED(model); })) return true;
        if (!SafeNativeVoidRuntime("streaming", "request model", [&](){ STREAMING::REQUEST_MODEL(model); })) return false;

        DWORD start = GetTickCount();
        DWORD lastRequest = start;
        int waitFrames = 0;
        const int maxWaitFrames = std::max(30, timeoutMs / 8);
        while (!SafeNativeValueRuntime<bool>(false, "streaming", "has model loaded", [&](){ return STREAMING::HAS_MODEL_LOADED(model); }))
        {
            WAIT(0);
            ++waitFrames;
            const DWORD now = GetTickCount();
            if (core::TickElapsed(now, lastRequest, 501u))
            {
                if (!SafeNativeVoidRuntime("streaming", "request model retry", [&](){ STREAMING::REQUEST_MODEL(model); }))
                {
                    SafeNativeVoidRuntime("streaming", "release model after failed load", [&](){ STREAMING::SET_MODEL_AS_NO_LONGER_NEEDED(model); });
                    return false;
                }
                lastRequest = now;
            }
            if (core::TickElapsed(now, start, SafeIntervalAddOneMs(timeoutMs, 5000, 100, 60000, "streaming", "model load timeout")) || waitFrames > maxWaitFrames)
            {
                SafeNativeVoidRuntime("streaming", "release model after failed load", [&](){ STREAMING::SET_MODEL_AS_NO_LONGER_NEEDED(model); });
                return false;
            }
        }
        return true;
    }

    static bool InvokeIsModelAPedCompat(Hash model)
    {
        // Some ScriptHookV SDK/native header versions do not expose
        // STREAMING::IS_MODEL_A_PED even though the GTA V native exists.
        // Use the raw native hash so Visual Studio builds do not depend on
        // a specific generated natives.h revision.
#if defined(_MSC_VER)
        return invoke<BOOL>(0x75816577FEA6DAD5ULL, model) != FALSE;
#else
        // Non-MSVC local syntax/stub checks may not ship ScriptHookV's
        // native invoker. Keep those checks compiling; the real ASI build
        // uses the MSVC branch above.
        return model != 0;
#endif
    }

    static bool SafeIsModelAPedRuntime(Hash model, const std::string& module = "streaming")
    {
        if (!model)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "is model a ped", "Rejected zero model hash");
            return false;
        }
        return SafeNativeValueRuntime<bool>(false, module, "is model a ped", [&](){ return InvokeIsModelAPedCompat(model); });
    }

    static bool SafeIsModelAVehicleRuntime(Hash model, const std::string& module = "streaming")
    {
        if (!model)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "is model a vehicle", "Rejected zero model hash");
            return false;
        }
        return SafeNativeValueRuntime<bool>(false, module, "is model a vehicle", [&](){ return STREAMING::IS_MODEL_A_VEHICLE(model); });
    }

    static bool SafeReleaseModelRuntime(Hash model, const std::string& module = "streaming")
    {
        if (!model) return true;
        return SafeNativeVoidRuntime(module, "release model", [&](){ STREAMING::SET_MODEL_AS_NO_LONGER_NEEDED(model); });
    }

    static Ped SafeCreatePedRuntime(int pedType, Hash model, Vector3 pos, float heading, bool isNetwork, bool bScriptHostPed, const std::string& module = "spawn")
    {
        if (!model)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "create ped", "Rejected zero model hash");
            return 0;
        }
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "create ped", "Rejected invalid spawn position");
            return 0;
        }
        if (!SafeIsModelAPedRuntime(model, module))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "create ped", "Rejected non-ped model hash");
            return 0;
        }
        pedType = ClampIntValue(pedType, 0, 31);
        heading = NormalizeHeading(heading, 0.0f);
        Ped ped = SafeNativeValueRuntime<Ped>(0, module, "create ped", [&](){ return PED::CREATE_PED(pedType, model, pos.x, pos.y, pos.z, heading, isNetwork, bScriptHostPed); });
        Vector3 createdPos{};
        if (!ped || !core::IsPed((Entity)ped) || !TryGetUsableEntityPosition((Entity)ped, createdPos, -200.0f, 2000.0f))
        {
            if (ped && core::Exists((Entity)ped))
                DeleteRejectedSpawnOrKeepTracked((Entity)ped, true);
            ReportCore2(core::ErrorSeverity::Warning, module, "create ped", "Ped create native returned invalid handle or unusable coordinates");
            return 0;
        }
        return ped;
    }

    static Vehicle SafeCreateVehicleRuntime(Hash model, Vector3 pos, float heading, bool isNetwork, bool netMissionEntity, const std::string& module = "spawn")
    {
        if (!model)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "create vehicle", "Rejected zero model hash");
            return 0;
        }
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "create vehicle", "Rejected invalid spawn position");
            return 0;
        }
        if (!SafeIsModelAVehicleRuntime(model, module))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "create vehicle", "Rejected non-vehicle model hash");
            return 0;
        }
        heading = NormalizeHeading(heading, 0.0f);
        Vehicle vehicle = SafeNativeValueRuntime<Vehicle>(0, module, "create vehicle", [&](){ return VEHICLE::CREATE_VEHICLE(model, pos.x, pos.y, pos.z, heading, isNetwork, netMissionEntity); });
        Vector3 createdPos{};
        if (!vehicle || !core::IsVehicle((Entity)vehicle) || !TryGetUsableEntityPosition((Entity)vehicle, createdPos, -200.0f, 2000.0f))
        {
            if (vehicle && core::Exists((Entity)vehicle))
                DeleteRejectedSpawnOrKeepTracked((Entity)vehicle, false);
            ReportCore2(core::ErrorSeverity::Warning, module, "create vehicle", "Vehicle create native returned invalid handle or unusable coordinates");
            return 0;
        }
        return vehicle;
    }

    static Object SafeCreateObjectRuntime(Hash model, Vector3 pos, bool isNetwork, bool netMissionEntity, bool doorFlag, const std::string& module = "spawn")
    {
        if (!model)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "create object", "Rejected zero model hash");
            return 0;
        }
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "create object", "Rejected invalid spawn position");
            return 0;
        }
        Object object = SafeNativeValueRuntime<Object>(0, module, "create object", [&](){ return OBJECT::CREATE_OBJECT(model, pos.x, pos.y, pos.z, isNetwork, netMissionEntity, doorFlag); });
        Vector3 createdPos{};
        if (!object || !core::IsObject((Entity)object) || !TryGetUsableEntityPosition((Entity)object, createdPos, -200.0f, 2000.0f))
        {
            if (object && core::Exists((Entity)object))
                DeleteRejectedSpawnOrKeepTracked((Entity)object, false);
            ReportCore2(core::ErrorSeverity::Warning, module, "create object", "Object create native returned invalid handle or unusable coordinates");
            return 0;
        }
        return object;
    }

