    static Cam SafeCreateScriptedCamRuntime(Vector3 pos, Vector3 rot, float fov, bool active, int renderType, const std::string& module = "camera")
    {
        if (!IsUsableWorldPosition(pos, -2000.0f, 5000.0f))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "create camera", "Rejected invalid camera position");
            return 0;
        }
        rot.x = ClampFloatValue(std::isfinite(rot.x) ? rot.x : 0.0f, -180.0f, 180.0f, 0.0f);
        rot.y = ClampFloatValue(std::isfinite(rot.y) ? rot.y : 0.0f, -180.0f, 180.0f, 0.0f);
        rot.z = ClampFloatValue(std::isfinite(rot.z) ? rot.z : 0.0f, -360.0f, 360.0f, 0.0f);
        fov = ClampFloatValue(fov, 15.0f, 120.0f, 60.0f);
        renderType = ClampIntValue(renderType, 0, 2);
        Cam cam = SafeNativeValueRuntime<Cam>(0, module, "create camera", [&](){ return CAM::CREATE_CAM_WITH_PARAMS((char*)"DEFAULT_SCRIPTED_CAMERA", pos.x, pos.y, pos.z, rot.x, rot.y, rot.z, fov, active, renderType); });
        if (!cam || !SafeDoesCamExistRuntime(cam, module))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "create camera", "Camera create native returned invalid handle");
            return 0;
        }
        return cam;
    }

