    static Blip InvokeGetBlipFromEntityCompat(Entity entity)
    {
        if (!entity || !core::Exists((Entity)entity)) return 0;
#if defined(_MSC_VER)
        // GET_BLIP_FROM_ENTITY is missing from some generated ScriptHookV native headers.
        return invoke<Blip>(0xBC8DBDCA2436F7E8ULL, entity);
#else
        (void)entity;
        return 0;
#endif
    }

    static Blip InvokeAddBlipForEntityCompat(Entity entity)
    {
        if (!entity || !core::Exists((Entity)entity)) return 0;
#if defined(_MSC_VER)
        // ADD_BLIP_FOR_ENTITY native. Raw hash keeps old SDK packages compiling.
        return invoke<Blip>(0x5CDE92C702A8FCE7ULL, entity);
#else
        (void)entity;
        return 0;
#endif
    }

    static Blip SafeGetBlipFromEntityRuntime(Entity entity, const std::string& module = "blip")
    {
        if (!entity || !core::Exists((Entity)entity)) return 0;
        Blip blip = SafeNativeValueRuntime<Blip>(0, module, "get blip from entity", [&](){ return InvokeGetBlipFromEntityCompat(entity); });
        return (blip && SafeDoesBlipExistRuntime(blip, module)) ? blip : 0;
    }

    static Blip SafeAddBlipForEntityRuntime(Entity entity, const std::string& module = "blip")
    {
        if (!entity || !core::Exists((Entity)entity)) return 0;
        Blip existing = SafeGetBlipFromEntityRuntime(entity, module);
        if (existing) return existing;
        Blip blip = SafeNativeValueRuntime<Blip>(0, module, "add blip for entity", [&](){ return InvokeAddBlipForEntityCompat(entity); });
        if (!blip || !SafeDoesBlipExistRuntime(blip, module))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, "add entity blip", "Entity blip create native returned invalid handle");
            return 0;
        }
        return blip;
    }

