    static Vector3 PlayerPos(float forward = 3.0f)
    {
        Ped p = 0;
        if (!GetPlayerPedSafe(p)) return InvalidWorldVector();

        Vector3 pos{};
        if (!core::TryGetEntityCoords((Entity)p, pos, true) || !IsUsableRuntimeWorldPosition(pos)) return InvalidWorldVector();

        float heading = core::SafeGetEntityHeading((Entity)p, 0.0f);
        if (!std::isfinite(forward)) forward = 3.0f;
        forward = ClampFloatValue(forward, -500.0f, 500.0f, 3.0f);
        float rad = heading * 0.0174532924f;
        pos.x += -sinf(rad) * forward;
        pos.y += cosf(rad) * forward;
        return IsUsableRuntimeWorldPosition(pos) ? pos : InvalidWorldVector();
    }

    static bool GetWaypoint(Vector3& coords)
    {
        Blip wp = SafeGetFirstBlipInfoIdRuntime(8);
        if (!SafeDoesBlipExistRuntime(wp)) return false;
        coords = SafeGetBlipCoordsRuntime(wp);
        return std::isfinite(coords.x) && std::isfinite(coords.y) && std::isfinite(coords.z) &&
               std::fabs(coords.x) <= 12000.0f && std::fabs(coords.y) <= 12000.0f &&
               coords.z >= -200.0f && coords.z <= 2000.0f;
    }

    static bool SafeGetGroundZRuntime(float x, float y, float z, float& groundZ, const std::string& module = "teleport")
    {
        if (!std::isfinite(x) || !std::isfinite(y) || !std::isfinite(z)) return false;
        if (std::fabs(x) > 12000.0f || std::fabs(y) > 12000.0f || z < -500.0f || z > 5000.0f) return false;
        float candidate = groundZ;
        const bool ok = SafeNativeValueRuntime<bool>(false, module, "get ground z", [&](){ return GAMEPLAY::GET_GROUND_Z_FOR_3D_COORD(x, y, z, &candidate, false); });
        if (!ok || !std::isfinite(candidate) || candidate < -300.0f || candidate > 2500.0f) return false;
        groundZ = candidate;
        return true;
    }

    static float ResolveGroundZ(float x, float y, float fallbackZ)
    {
        if (!std::isfinite(fallbackZ)) fallbackZ = 75.0f;

        float groundZ = fallbackZ;
        for (float z = 1000.0f; z >= -120.0f; z -= 50.0f)
        {
            // Valid GTA V ground can be at sea level or below it. The old check used
            // groundZ > 0 and rejected those positions, causing spawn/mission entities
            // to float or sink near docks, beaches, tunnels and low map areas.
            if (SafeGetGroundZRuntime(x, y, z, groundZ, "ground_z"))
                return groundZ;
            WAIT(0);
        }
        return fallbackZ;
    }

    static bool IsFiniteFloat(float v)
    {
        return std::isfinite(v);
    }

    static Vector3 EmergencyRecoveryLandmark()
    {
        Vector3 pos{};
        // A stable street-level fallback near central Los Santos.
        // Safer than 0/0/75, which can place recovery targets in mid-air or water.
        pos.x = 215.76f;
        pos.y = -810.12f;
        pos.z = 30.73f;
        return pos;
    }

    static Vector3 MissionStoredPositionFallback()
    {
        // Mission files are persistent data. Do not rewrite corrupt coordinates to the
        // current player position during load/save; that creates false spawns at runtime.
        return EmergencyRecoveryLandmark();
    }

    static bool IsRecoveryFallbackCandidate(const Vector3& pos)
    {
        return IsFiniteFloat(pos.x) && IsFiniteFloat(pos.y) && IsFiniteFloat(pos.z) &&
            std::fabs(pos.x) <= 12000.0f && std::fabs(pos.y) <= 12000.0f &&
            pos.z >= -100.0f && pos.z <= 1200.0f;
    }

    static bool IsUsableWorldPosition(const Vector3& pos, float minZ = -150.0f, float maxZ = 1500.0f)
    {
        return IsFiniteFloat(pos.x) && IsFiniteFloat(pos.y) && IsFiniteFloat(pos.z) &&
            std::fabs(pos.x) <= 12000.0f && std::fabs(pos.y) <= 12000.0f &&
            pos.z >= minZ && pos.z <= maxZ;
    }

    static bool IsUsableRuntimeWorldPosition(const Vector3& pos)
    {
        // Runtime handles and cinematic cameras can legitimately exist far above
        // normal street-level limits, especially during aircraft/freecam use. Keep
        // strict map X/Y bounds, but use the wider Core 2.0 Z guard.
        return IsUsableWorldPosition(pos, core::kDefaultWorldMinZ, core::kDefaultWorldMaxZ);
    }

    static Vector3 SafeWorldFallbackPosition()
    {
        if (st.hasLastSafePlayerPos && IsRecoveryFallbackCandidate(st.lastSafePlayerPos))
            return st.lastSafePlayerPos;
        return EmergencyRecoveryLandmark();
    }

    static bool TryGetValidatedPlayerCoords(Vector3& out)
    {
        Ped p = 0;
        if (!GetPlayerPedSafe(p)) return false;
        Vector3 raw{};
        if (!core::TryGetEntityCoords((Entity)p, raw, true) || !IsUsableRuntimeWorldPosition(raw)) return false;
        out = raw;
        st.lastSafePlayerPos = raw;
        st.hasLastSafePlayerPos = true;
        return true;
    }

    static float NormalizeHeading(float heading, float fallback = 0.0f)
    {
        // Several paths load heading from user-editable files/snapshots.  Repeated +/- 360 loops
        // can hang on huge finite values, so normalize with fmod and keep a safe fallback.
        if (!IsFiniteFloat(heading)) heading = fallback;
        if (!IsFiniteFloat(heading)) heading = 0.0f;
        heading = std::fmod(heading, 360.0f);
        if (heading < 0.0f) heading += 360.0f;
        if (heading >= 360.0f) heading -= 360.0f;
        return heading;
    }

    static Vector3 SanitizeVector(Vector3 pos, Vector3 fallback)
    {
        if (!IsFiniteFloat(fallback.x) || std::fabs(fallback.x) > 12000.0f) fallback.x = 0.0f;
        if (!IsFiniteFloat(fallback.y) || std::fabs(fallback.y) > 12000.0f) fallback.y = 0.0f;
        if (!IsFiniteFloat(fallback.z) || fallback.z < -150.0f || fallback.z > 1500.0f) fallback.z = 75.0f;
        if (!IsFiniteFloat(pos.x) || !IsFiniteFloat(pos.y) || !IsFiniteFloat(pos.z)) return fallback;
        if (std::fabs(pos.x) > 12000.0f || std::fabs(pos.y) > 12000.0f)
        {
            pos.x = fallback.x;
            pos.y = fallback.y;
        }
        if (pos.z < -150.0f || pos.z > 1500.0f) pos.z = fallback.z;
        return pos;
    }

    static Vector3 SanitizeRuntimeVector(Vector3 pos, Vector3 fallback)
    {
        // Runtime/teleport/undo paths must allow aircraft, high-altitude freecam
        // and mission entities above the old street-level Z cap. Keep normal map
        // X/Y bounds, but use the wider Core 2.0 Z envelope.
        if (!IsFiniteFloat(fallback.x) || std::fabs(fallback.x) > 12000.0f) fallback.x = 0.0f;
        if (!IsFiniteFloat(fallback.y) || std::fabs(fallback.y) > 12000.0f) fallback.y = 0.0f;
        if (!IsFiniteFloat(fallback.z) || fallback.z < core::kDefaultWorldMinZ || fallback.z > core::kDefaultWorldMaxZ) fallback.z = 75.0f;
        if (!IsFiniteFloat(pos.x) || !IsFiniteFloat(pos.y) || !IsFiniteFloat(pos.z)) return fallback;
        if (std::fabs(pos.x) > 12000.0f || std::fabs(pos.y) > 12000.0f)
        {
            pos.x = fallback.x;
            pos.y = fallback.y;
        }
        if (pos.z < core::kDefaultWorldMinZ || pos.z > core::kDefaultWorldMaxZ) pos.z = fallback.z;
        return pos;
    }

    static Vector3 SpawnSafetyPosition(float forward, bool forVehicle, float right = 0.0f)
    {
        Vector3 base{};
        base.x = 0.0f; base.y = 0.0f; base.z = 75.0f;
        float heading = 0.0f;

        // During model swaps / loading screens the player ped can be temporarily invalid.
        // Never use a broken live player position as a spawn base.
        Vector3 raw{};
        if (TryGetValidatedPlayerCoords(raw))
        {
            base = raw;
            heading = SafePlayerHeading();
        }
        else
        {
            return InvalidWorldVector();
        }

        if (!std::isfinite(forward)) forward = forVehicle ? 7.0f : 3.0f;
        if (!std::isfinite(right)) right = 0.0f;
        forward = ClampFloatValue(forward, -500.0f, 500.0f, forVehicle ? 7.0f : 3.0f);
        right = ClampFloatValue(right, -250.0f, 250.0f, 0.0f);

        float rad = heading * 0.0174532924f;
        float safeForward = forward;
        if (cfg.spawnSafetyEnabled)
            safeForward = std::max(forVehicle ? cfg.spawnSafetyVehicleForward : cfg.spawnSafetyPedForward, forward);
        base.x += (-sinf(rad) * safeForward) + (-sinf(rad + 1.5707963f) * right);
        base.y += ( cosf(rad) * safeForward) + ( cosf(rad + 1.5707963f) * right);
        if (cfg.spawnSafetyEnabled)
            base.z = ResolveGroundZ(base.x, base.y, base.z) + (forVehicle ? 0.45f : 0.10f);
        return base;
    }

    static Vector3 ApplySpawnSafety(Vector3 pos, bool forVehicle)
    {
        // Strict spawn safety: never convert a broken requested spawn point into
        // player/emergency coordinates. Callers must supply a valid target; otherwise
        // they receive an invalid vector and cancel before creating/tracking entities.
        if (!IsUsableRuntimeWorldPosition(pos)) return InvalidWorldVector();
        if (!cfg.spawnSafetyEnabled) return pos;

        pos.z = ResolveGroundZ(pos.x, pos.y, pos.z) + (forVehicle ? 0.45f : 0.10f);
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f)) return InvalidWorldVector();
        if (cfg.spawnSafetyClearArea)
        {
            float radius = std::max(1.5f, std::min(12.0f, cfg.spawnSafetyClearRadius + (forVehicle ? 1.5f : 0.0f)));
            SafeClearAreaRuntime(pos, radius, true, false, false, false, "spawn_safety");
        }
        return pos;
    }

    static void ApplySpawnSafetyPostCreate(Entity entity, bool forVehicle)
    {
        if (!cfg.spawnSafetyEnabled || !entity || !core::Exists((Entity)(entity))) return;
        Vector3 createdPos{};
        if (!TryGetUsableEntityPosition(entity, createdPos, -200.0f, 2000.0f))
        {
            ReportCore2(core::ErrorSeverity::Warning, "spawn_safety", "post create", "Post-create safety skipped: entity coordinates are invalid");
            return;
        }
        if (forVehicle && core::IsVehicle((Entity)(entity)))
        {
            SafeSetVehicleOnGround((Vehicle)entity, "spawn_safety");
            SafeSetVehicleEngineOn((Vehicle)entity, true, "spawn_safety");
        }
        else if (!forVehicle && core::IsObject(entity))
        {
            SafePlaceObjectOnGroundRuntime((Object)entity, "spawn_safety");
        }
    }

    static Entity PlayerTeleportEntity()
    {
        Ped p = 0;
        if (!GetPlayerPedSafe(p)) return 0;
        if (st.teleportInVehicle && core::IsPedInAnyVehicle((Ped)(p), false))
        {
            Vehicle v = core::GetVehiclePedIsIn((Ped)(p), false);
            Vector3 vp{};
            if (core::IsVehicle((Entity)v) && core::TryGetEntityCoords((Entity)v, vp, false) && IsUsableRuntimeWorldPosition(vp)) return v;
        }
        return p;
    }

    static int GetPlayerVehicleSeatForTeleport(Vehicle v, Ped p)
    {
        if (!core::IsVehicle((Entity)v) || !core::IsPed((Entity)p)) return -999;
        for (int seat = -1; seat <= 15; ++seat)
        {
            if ((Ped)core::GetPedInVehicleSeat((Vehicle)(v), seat) == p) return seat;
        }
        return -999;
    }

    static void RequestTeleportCollision(const Vector3& pos)
    {
        if (!cfg.teleportLoadCollision) return;
        SafeRequestCollisionRuntime(pos, "teleport_collision");
        DWORD start = GetTickCount();
        while (!core::TickElapsed(GetTickCount(), start, 450u))
        {
            SafeRequestCollisionRuntime(pos, "teleport_collision");
            WAIT(0);
        }
    }

    static bool TryGetClosestVehicleNodeForTeleport(const Vector3& desired, Vector3& outNode)
    {
        if (!cfg.teleportPreferRoadNode) return false;
        for (int i = 1; i <= 8; ++i)
        {
            Vector3 node{};
            if (SafeGetClosestVehicleNodeRuntime(desired, i, node, "teleport_pathfind") &&
                IsUsableWorldPosition(node))
            {
                outNode = node;
                return true;
            }
        }
        return false;
    }

    static Vector3 BuildTeleportDestination(Vector3 desired, const Vector3& fallback, bool isVehicle, bool groundSnap, bool preferRoad)
    {
        // Strict teleport resolver: never turn a broken current/fallback position into
        // player/emergency coordinates. If the caller supplied an invalid fallback, use
        // the already validated desired destination as the only recovery base.
        const bool fallbackUsable = IsUsableRuntimeWorldPosition(fallback);
        Vector3 strictFallback = fallbackUsable ? fallback : desired;
        Vector3 safe = SanitizeRuntimeVector(desired, strictFallback);
        if (cfg.teleportLoadCollision) RequestTeleportCollision(safe);

        if (isVehicle && preferRoad)
        {
            Vector3 road{};
            if (TryGetClosestVehicleNodeForTeleport(safe, road))
            {
                safe.x = road.x;
                safe.y = road.y;
                safe.z = road.z;
                groundSnap = true;
            }
        }

        if (groundSnap)
            safe.z = ResolveGroundZ(safe.x, safe.y, safe.z) + (isVehicle ? 0.45f : 1.0f);

        if (cfg.teleportSafeLandingProbe)
        {
            // Final sanity layer for map-marker/custom coordinate teleports.
            // Prevents rare bad Z values from sending the player/vehicle below the map.
            if (!std::isfinite(safe.z) || safe.z < cfg.playerBelowMapZ)
            {
                // Use the strict fallback only when it is a real world position.  Do not
                // silently convert invalid current coordinates into EmergencyRecoveryLandmark().
                safe = SanitizeRuntimeVector(fallbackUsable ? fallback : desired, desired);
                if (isVehicle && preferRoad)
                {
                    Vector3 road{};
                    if (TryGetClosestVehicleNodeForTeleport(safe, road)) safe = road;
                }
                safe.z = ResolveGroundZ(safe.x, safe.y, safe.z + 8.0f) + (isVehicle ? 0.55f : 1.0f);
            }
        }

        safe = SanitizeRuntimeVector(safe, fallbackUsable ? fallback : desired);
        if (cfg.teleportLoadCollision) RequestTeleportCollision(safe);
        return safe;
    }

    static bool TryGetEntityTeleportCoords(Entity entity, Vector3& out)
    {
        if (!entity || !core::Exists((Entity)(entity))) return false;
        return core::TryGetEntityCoords(entity, out, true) && IsUsableRuntimeWorldPosition(out);
    }

    static bool IsFinalTeleportPositionValid(const Vector3& finalPos, const Vector3& requestedPos)
    {
        if (!IsUsableRuntimeWorldPosition(finalPos)) return false;

        // SET_ENTITY_COORDS can be adjusted by collision/ground placement, but it should
        // still end up near the requested destination.  This prevents false history/undo
        // entries when the native failed and the entity stayed at the old position.
        const float maxHorizontalDrift = 85.0f;
        const float maxVerticalDrift = 85.0f;
        return std::fabs(finalPos.x - requestedPos.x) <= maxHorizontalDrift &&
               std::fabs(finalPos.y - requestedPos.y) <= maxHorizontalDrift &&
               std::fabs(finalPos.z - requestedPos.z) <= maxVerticalDrift;
    }

    static void ApplyVehicleTeleportPost(Vehicle v, const Vector3& oldVelocity, float oldSpeed);

    static bool IsResolvedTeleportDestinationValid(const Vector3& resolved, const Vector3& desired, bool allowLargeVerticalSnap)
    {
        if (!IsUsableRuntimeWorldPosition(resolved) || !IsUsableRuntimeWorldPosition(desired)) return false;

        // Resolver output may legitimately change Z because of ground snap, but it must
        // never silently collapse a broken road-node/fallback path back to the old player
        // position far away from the requested destination.
        const float maxHorizontalResolveDrift = 350.0f;
        const float maxVerticalResolveDrift = allowLargeVerticalSnap ? 2000.0f : 120.0f;
        return std::fabs(resolved.x - desired.x) <= maxHorizontalResolveDrift &&
               std::fabs(resolved.y - desired.y) <= maxHorizontalResolveDrift &&
               std::fabs(resolved.z - desired.z) <= maxVerticalResolveDrift;
    }

    static void RollbackFailedTeleport(Entity ent, const Vector3& fallback, float fallbackHeading, bool wasVehicle, const Vector3& oldVelocity, float oldSpeed)
    {
        if (!ent || !core::Exists((Entity)(ent)) || !IsUsableRuntimeWorldPosition(fallback)) return;
        core::safe_native::SetCoords(ent, fallback, true, &g_coreErrors, "core_teleport");
        core::safe_native::SetHeading(ent, NormalizeHeading(fallbackHeading, 0.0f), &g_coreErrors, "core_teleport");
        if (wasVehicle) ApplyVehicleTeleportPost((Vehicle)ent, oldVelocity, oldSpeed);
    }

