    static void ApplyVehicleTeleportPost(Vehicle v, const Vector3& oldVelocity, float oldSpeed)
    {
        (void)oldVelocity;
        if (!core::IsVehicle((Entity)v)) return;
        SafeSetVehicleOnGround(v, "teleport");
        SafeSetVehicleEngineOn(v, true, "teleport");
        if (cfg.teleportPreserveVehicleSpeed && oldSpeed > 1.0f && oldSpeed < 90.0f)
        {
            // Preserve speed in the vehicle's current forward direction.
            // Re-applying the old world-space velocity after a heading/road-node snap can launch the car sideways.
            SafeSetVehicleForwardSpeed(v, oldSpeed, "teleport");
        }
    }

    static Vector3 OffsetFromHeading(Vector3 origin, float headingDeg, float forward, float right, float up = 0.0f)
    {
        const float h = NormalizeHeading(headingDeg, 0.0f) * 0.0174532924f;
        origin.x += (-sinf(h) * forward) + (-sinf(h + 1.5707963f) * right);
        origin.y += ( cosf(h) * forward) + ( cosf(h + 1.5707963f) * right);
        origin.z += up;
        return origin;
    }

    static Vector3 BuildCompanionTeleportSpot(Vector3 origin, float heading, int index, bool forVehicle)
    {
        if (!IsUsableRuntimeWorldPosition(origin)) return InvalidWorldVector();
        const float spread = std::max(2.0f, std::min(12.0f, cfg.teleportCompanionSpread));
        float row = 2.0f + (float)(index / 4) * spread;
        float lane = ((float)(index % 4) - 1.5f) * spread;
        Vector3 spot = OffsetFromHeading(origin, heading, -row - (forVehicle ? 4.0f : 1.0f), lane, 0.0f);
        if (!IsUsableRuntimeWorldPosition(spot)) return InvalidWorldVector();
        spot.z = ResolveGroundZ(spot.x, spot.y, spot.z + 6.0f) + (forVehicle ? 0.55f : 1.0f);
        return IsUsableWorldPosition(spot, -200.0f, 2000.0f) ? spot : InvalidWorldVector();
    }

    static int FindFreeVehicleSeatForCompanion(Vehicle vehicle)
    {
        if (!core::IsVehicle((Entity)vehicle)) return -999;
        for (int seat = -1; seat <= 7; ++seat)
        {
            if (core::IsVehicleSeatFree((Vehicle)(vehicle), seat)) return seat;
        }
        return -999;
    }

    static void TeleportCompanionsAfterPlayerTeleport(Entity teleportedEntity, const Vector3& destination, float heading, bool forceCompanions = false, bool forceChauffeur = false)
    {
        Vector3 anchorPos{};
        if (!TryGetEntityTeleportCoords(teleportedEntity, anchorPos))
        {
            st.lastCompanionTeleportReport = "Companion teleport skipped: player/vehicle position invalid.";
            return;
        }
        if (!IsUsableRuntimeWorldPosition(destination))
        {
            st.lastCompanionTeleportReport = "Companion teleport skipped: destination invalid.";
            return;
        }

        Vector3 companionOrigin = anchorPos;
        heading = NormalizeHeading(heading, 0.0f);
        int moved = 0;
        std::vector<Vehicle> movedCompanionVehicles;

        auto companionVehicleAlreadyMoved = [&](Vehicle vehicle) -> bool
        {
            return vehicle && std::find(movedCompanionVehicles.begin(), movedCompanionVehicles.end(), vehicle) != movedCompanionVehicles.end();
        };

        auto moveVehicleNearDestination = [&](Vehicle vehicle, int index) -> bool
        {
            if (!vehicle || !core::Exists((Entity)(vehicle)) || !core::IsVehicle((Entity)vehicle) || (Entity)vehicle == teleportedEntity) return false;
            if (companionVehicleAlreadyMoved(vehicle)) return true;
            Vector3 oldPos{};
            if (!TryGetEntityTeleportCoords((Entity)vehicle, oldPos)) return false;
            float oldHeading = NormalizeHeading((float)core::SafeGetEntityHeading((Entity)(vehicle), 0.0f), heading);
            Vector3 spot = BuildCompanionTeleportSpot(companionOrigin, heading, index, true);
            if (!IsUsableWorldPosition(spot, -200.0f, 2000.0f)) return false;
            core::safe_native::SetCollision((Entity)vehicle, true, true, &g_coreErrors, "companion_teleport");
            core::safe_native::SetVelocity((Entity)vehicle, Vector3{}, &g_coreErrors, "companion_teleport");
            core::safe_native::SetCoords((Entity)vehicle, spot, true, &g_coreErrors, "companion_teleport");
            core::safe_native::SetHeading((Entity)vehicle, NormalizeHeading(heading, 0.0f), &g_coreErrors, "companion_teleport");
            SafeSetVehicleOnGround(vehicle, "full_audit");
            SafeSetVehicleEngineOn(vehicle, true, "full_audit");
            if (!IsEntityFinalPositionAcceptable((Entity)vehicle, spot))
            {
                core::safe_native::SetCoords((Entity)vehicle, oldPos, true, &g_coreErrors, "companion_teleport");
                core::safe_native::SetHeading((Entity)vehicle, oldHeading, &g_coreErrors, "companion_teleport");
                return false;
            }
            TrackSpawnedVehicleIfAlive(vehicle);
            movedCompanionVehicles.push_back(vehicle);
            return true;
        };

        auto movePedNearDestination = [&](Ped ped, int index) -> bool
        {
            if (!ped || !core::Exists((Entity)(ped)) || !core::IsPed((Entity)ped) || (Entity)ped == teleportedEntity) return false;
            Vector3 oldPos{};
            if (!TryGetEntityTeleportCoords((Entity)ped, oldPos)) return false;
            Vector3 spot = BuildCompanionTeleportSpot(companionOrigin, heading, index, false);
            if (!IsUsableWorldPosition(spot, -200.0f, 2000.0f)) return false;
            core::safe_native::ClearPedTasks(ped, false, &g_coreErrors, "companion_teleport");
            core::safe_native::SetCollision((Entity)ped, true, true, &g_coreErrors, "companion_teleport");
            core::safe_native::SetVelocity((Entity)ped, Vector3{}, &g_coreErrors, "companion_teleport");
            core::safe_native::SetCoords((Entity)ped, spot, true, &g_coreErrors, "companion_teleport");
            if (!IsEntityFinalPositionAcceptable((Entity)ped, spot))
            {
                core::safe_native::SetCoords((Entity)ped, oldPos, true, &g_coreErrors, "companion_teleport");
                return false;
            }
            return true;
        };

        if (forceCompanions || cfg.teleportCompanionsWithPlayer)
        {
            int idx = 0;
            for (Ped guard : st.bodyguards)
            {
                if (!guard || !core::Exists((Entity)(guard)) || !core::IsPed((Entity)guard) || core::IsPedDeadOrDying((Ped)(guard), true, true))
                {
                    ++idx;
                    continue;
                }
                if ((Entity)guard == teleportedEntity)
                {
                    ++idx;
                    continue;
                }
                if (core::IsVehicle((Entity)(teleportedEntity)) && core::IsPedInVehicle(guard, (Vehicle)teleportedEntity, false))
                {
                    ++idx;
                    continue;
                }

                if (core::IsPedInAnyVehicle((Ped)(guard), false))
                {
                    Vehicle guardVehicle = core::GetVehiclePedIsIn((Ped)(guard), false);
                    if (guardVehicle && core::Exists((Entity)(guardVehicle)) && core::IsVehicle((Entity)guardVehicle))
                    {
                        const bool alreadyMoved = companionVehicleAlreadyMoved(guardVehicle);
                        if (moveVehicleNearDestination(guardVehicle, idx) && !alreadyMoved)
                            ++moved;
                    }
                }
                else if (movePedNearDestination(guard, idx))
                {
                    ++moved;
                }
                ++idx;
            }
        }

        if (forceChauffeur || cfg.teleportChauffeurWithPlayer)
        {
            if (st.chauffeurVehicle && core::Exists((Entity)(st.chauffeurVehicle)) && core::IsVehicle((Entity)st.chauffeurVehicle) && (Entity)st.chauffeurVehicle != teleportedEntity)
            {
                const bool alreadyMoved = companionVehicleAlreadyMoved(st.chauffeurVehicle);
                if (moveVehicleNearDestination(st.chauffeurVehicle, moved + 1))
                {
                    if (st.chauffeur && core::Exists((Entity)(st.chauffeur)) && core::IsPed((Entity)st.chauffeur) &&
                        !core::IsPedInVehicle((Ped)(st.chauffeur), (Vehicle)(st.chauffeurVehicle), false))
                    {
                        const int seat = FindFreeVehicleSeatForCompanion(st.chauffeurVehicle);
                        if (seat != -999)
                            core::safe_native::PutPedIntoVehicle(st.chauffeur, st.chauffeurVehicle, seat, nullptr, "teleport");
                    }
                    if (!alreadyMoved) ++moved;
                }
            }
            else if (st.chauffeur && core::Exists((Entity)(st.chauffeur)) && core::IsPed((Entity)st.chauffeur) && (Entity)st.chauffeur != teleportedEntity)
            {
                if (movePedNearDestination(st.chauffeur, moved + 1)) ++moved;
            }
        }

        st.lastCompanionTeleportReport = moved > 0 ? ("Teleport companions moved: " + std::to_string(moved)) : "No companions moved.";
    }


    static bool CanRecordUndo()
    {
        return cfg.undoSystemEnabled && !st.undoApplying;
    }

    static void TrimUndoStack()
    {
        int limit = std::max(1, cfg.maxUndoSteps);
        while ((int)st.undoStack.size() > limit) st.undoStack.erase(st.undoStack.begin());
    }

    static void TrimRedoStack()
    {
        int limit = std::max(1, cfg.maxUndoSteps);
        while ((int)st.redoStack.size() > limit) st.redoStack.erase(st.redoStack.begin());
    }

