    static UndoWeaponSnapshot SanitizeWeaponSnapshotForRestore(const UndoWeaponSnapshot& snap);

    static void PushUndo(const UndoAction& action)
    {
        if (!CanRecordUndo() || action.label.empty()) return;
        st.undoStack.push_back(action);
        TrimUndoStack();
        // Any new user action invalidates the redo chain, like standard editors.
        st.redoStack.clear();
    }

    static void PushEntityUndo(const std::string& label, Entity entity)
    {
        if (!cfg.undoRecordSpawns || !CanRecordUndo()) return;
        if (!entity || !core::Exists(entity)) return;
        UndoAction a;
        a.type = UndoActionType::DeleteEntities;
        a.label = label;
        a.entities.push_back(entity);
        UndoEntitySnapshot snap;
        if (SnapshotEntityForUndo(entity, snap)) a.entitySnapshots.push_back(snap);
        PushUndo(a);
    }

    static void PushTeleportUndoForEntity(const std::string& label, Entity ent)
    {
        if (!cfg.undoRecordTeleports || !CanRecordUndo()) return;
        if (!ent || !core::Exists(ent)) return;

        UndoAction a;
        a.type = UndoActionType::RestoreTeleport;
        a.label = label.empty() ? "Teleport" : label;
        a.teleportEntity = ent;
        a.teleportWasVehicle = core::IsVehicle(ent);
        a.teleportVehicle = a.teleportWasVehicle ? (Vehicle)ent : 0;
        Vector3 rawPos{};
        if (!core::TryGetEntityCoords(ent, rawPos, true) || !IsUsableRuntimeWorldPosition(rawPos)) return;
        a.pos = rawPos;
        a.heading = core::SafeGetEntityHeading(ent, SafePlayerHeading());

        if (cfg.teleportUndo2)
        {
            a.teleportVelocity = core::SafeGetEntityVelocity(ent);
            if (!IsFiniteFloat(a.teleportVelocity.x) || !IsFiniteFloat(a.teleportVelocity.y) || !IsFiniteFloat(a.teleportVelocity.z)) a.teleportVelocity = Vector3{};
            a.teleportSpeed = core::SafeGetEntitySpeed(ent, 0.0f);
            if (!IsFiniteFloat(a.teleportSpeed)) a.teleportSpeed = 0.0f;
            Ped p = 0;
            if (a.teleportWasVehicle && GetPlayerPedSafe(p))
                a.teleportPlayerSeat = GetPlayerVehicleSeatForTeleport((Vehicle)ent, p);
        }
        PushUndo(a);
    }

    [[maybe_unused]] static void PushTeleportUndo(const std::string& label)
    {
        PushTeleportUndoForEntity(label, PlayerTeleportEntity());
    }

    static void PushWorldUndo(const std::string& label)
    {
        if (!cfg.undoRecordWorld || !CanRecordUndo()) return;
        NormalizeWorldControlRuntimeState();
        UndoAction a;
        a.type = UndoActionType::RestoreWorld;
        a.label = label;
        a.weatherIndex = st.weatherIndex;
        a.hour = st.selectedHour;
        a.minute = st.selectedMinute;
        a.freezeTime = st.freezeTime;
        a.freezeWeather = st.freezeWeather;
        a.blackout = st.blackout;
        a.lowGravity = st.lowGravity;
        a.noTraffic = st.noTraffic;
        a.noPeds = st.noPeds;
        a.denseTraffic = st.denseTraffic;
        a.densePeds = st.densePeds;
        PushUndo(a);
    }

    static void RollbackUndoStackTo(size_t undoSize)
    {
        if (st.undoStack.size() > undoSize) st.undoStack.resize(undoSize);
    }

    struct UndoRedoRollbackPoint
    {
        size_t undoSize = 0;
        std::vector<UndoAction> redoBackup;
    };

    static UndoRedoRollbackPoint CaptureUndoRedoRollbackPoint()
    {
        UndoRedoRollbackPoint point;
        point.undoSize = st.undoStack.size();
        point.redoBackup = st.redoStack;
        return point;
    }

    static void RollbackUndoRedoStacksTo(const UndoRedoRollbackPoint& point)
    {
        RollbackUndoStackTo(point.undoSize);
        st.redoStack = point.redoBackup;
        TrimRedoStack();
    }

    static void PushWantedUndo(const std::string& label)
    {
        if (!cfg.undoRecordWanted || !CanRecordUndo()) return;
        UndoAction a;
        a.type = UndoActionType::RestoreWanted;
        a.label = label;
        a.wantedLevel = SafeGetWantedLevelRuntime();
        a.maxWantedLevel = st.maxWantedLevel;
        a.frozenWantedLevel = st.frozenWantedLevel;
        a.noWanted = st.noWanted;
        a.freezeWanted = st.freezeWanted;
        a.policeIgnore = st.policeIgnore;
        a.everyoneIgnore = st.everyoneIgnore;
        a.policeIgnoreManual = st.policeIgnoreManual;
        a.everyoneIgnoreManual = st.everyoneIgnoreManual;
        a.wantedMultiplierBoost = st.wantedMultiplierBoost;
        PushUndo(a);
    }


    static bool SnapshotEntityForUndo(Entity entity, UndoEntitySnapshot& out)
    {
        if (!entity || !core::Exists(entity)) return false;
        out = UndoEntitySnapshot();
        out.model = core::SafeGetEntityModel(entity);
        if (out.model == 0) return false;

        Vector3 rawPos{};
        if (!core::TryGetEntityCoords(entity, rawPos, true) || !IsUsableRuntimeWorldPosition(rawPos)) return false;
        out.pos = rawPos;
        out.heading = core::SafeGetEntityHeading(entity, SafePlayerHeading());
        out.health = ClampIntValue(core::SafeGetEntityHealth(entity, 0), 0, 10000);
        out.velocity = core::SafeGetEntityVelocity(entity);
        out.speed = core::SafeGetEntitySpeed(entity, 0.0f);
        if (!IsFiniteFloat(out.speed)) out.speed = 0.0f;
        if (!IsFiniteFloat(out.velocity.x) || !IsFiniteFloat(out.velocity.y) || !IsFiniteFloat(out.velocity.z)) out.velocity = Vector3{};
        if (core::IsVehicle(entity)) out.kind = UndoEntityKind::Vehicle;
        else if (core::IsPed(entity)) out.kind = UndoEntityKind::Ped;
        else
        {
            out.kind = UndoEntityKind::Object;
            // Most trainer-spawned objects are frozen by default. The last-object editor
            // is the only place that currently toggles this state, so preserve it here.
            out.frozen = ((Object)entity == st.lastObject) ? st.lastObjectFrozen : true;
        }
        return IsUsableUndoEntitySnapshot(out);
    }

    static std::vector<UndoEntitySnapshot> SnapshotEntitiesForUndo(const std::vector<Entity>& entities)
    {
        std::vector<UndoEntitySnapshot> snaps;
        for (Entity e : entities)
        {
            UndoEntitySnapshot snap;
            if (SnapshotEntityForUndo(e, snap)) snaps.push_back(snap);
        }
        return snaps;
    }

    static bool IsUsableUndoEntitySnapshot(const UndoEntitySnapshot& snap)
    {
        if (snap.kind == UndoEntityKind::Unknown || snap.model == 0) return false;
        if (!IsUsableRuntimeWorldPosition(snap.pos)) return false;
        return true;
    }

    static Entity RestoreEntityFromUndoSnapshot(const UndoEntitySnapshot& snap)
    {
        if (!IsUsableUndoEntitySnapshot(snap)) return 0;

        Vector3 pos = snap.pos;
        if (!IsUsableRuntimeWorldPosition(pos)) return 0;
        if (!LoadModel(snap.model)) return 0;

        float heading = NormalizeHeading(snap.heading, 0.0f);
        Entity restored = 0;
        auto finishFailure = [&]() -> Entity
        {
            SafeReleaseModelRuntime(snap.model, "undo_restore");
            return 0;
        };

        if (snap.kind == UndoEntityKind::Ped)
        {
            Ped ped = SafeCreatePedRuntime(26, snap.model, pos, heading, false, true, "undo_restore");
            if (ped && core::Exists((Entity)(ped)) && core::IsPed((Entity)ped))
            {
                restored = (Entity)ped;
                core::safe_native::SetMissionEntity((Entity)(restored), true, true, &g_coreErrors, "full_audit");
                if (snap.health > 0) core::safe_native::SetHealth((Entity)(restored), ClampIntValue(snap.health, 1, 10000), &g_coreErrors, "full_audit");
                core::safe_native::SetPedCanRagdoll(ped, true, &g_coreErrors, "spawn");
                if (!IsEntityFinalPositionAcceptable(restored, pos))
                {
                    DeleteRejectedSpawnOrKeepTracked(restored, false);
                    return finishFailure();
                }
                TrackSpawnedPedIfAlive(ped);
            }
            else if (ped && core::Exists((Entity)(ped)))
            {
                DeleteRejectedSpawnOrKeepTracked((Entity)ped, false);
            }
        }
        else if (snap.kind == UndoEntityKind::Vehicle)
        {
            Vehicle vehicle = SafeCreateVehicleRuntime(snap.model, pos, heading, false, true, "undo_restore");
            if (vehicle && core::Exists((Entity)(vehicle)) && core::IsVehicle((Entity)vehicle))
            {
                restored = (Entity)vehicle;
                core::safe_native::SetMissionEntity((Entity)(restored), true, true, &g_coreErrors, "full_audit");
                core::safe_native::SetCoords(restored, pos, true, &g_coreErrors, "undo_restore");
                core::safe_native::SetHeading(restored, heading, &g_coreErrors, "undo_restore");
                if (snap.health > 0) core::safe_native::SetHealth((Entity)(restored), ClampIntValue(snap.health, 1, 10000), &g_coreErrors, "full_audit");
                SafeSetVehicleEngineOn(vehicle, true, "full_audit");
                ApplyVehicleTeleportPost(vehicle, snap.velocity, snap.speed);
                if (!IsEntityFinalPositionAcceptable(restored, pos))
                {
                    DeleteRejectedSpawnOrKeepTracked(restored, false);
                    return finishFailure();
                }
                TrackSpawnedVehicleIfAlive(vehicle);
            }
            else if (vehicle && core::Exists((Entity)(vehicle)))
            {
                DeleteRejectedSpawnOrKeepTracked((Entity)vehicle, false);
            }
        }
        else
        {
            Object obj = SafeCreateObjectRuntime(snap.model, pos, true, true, false, "undo_restore");
            if (obj && core::Exists((Entity)(obj)) && core::IsObject((Entity)obj))
            {
                restored = (Entity)obj;
                core::safe_native::SetMissionEntity((Entity)(restored), true, true, &g_coreErrors, "full_audit");
                core::safe_native::SetCoords(restored, pos, true, &g_coreErrors, "undo_restore");
                core::safe_native::SetHeading(restored, heading, &g_coreErrors, "undo_restore");
                if (snap.health > 0) core::safe_native::SetHealth((Entity)(restored), ClampIntValue(snap.health, 1, 10000), &g_coreErrors, "full_audit");
                core::safe_native::Freeze(restored, snap.frozen, &g_coreErrors, "undo_restore");
                if (!IsEntityFinalPositionAcceptable(restored, pos))
                {
                    DeleteRejectedSpawnOrKeepTracked(restored, false);
                    return finishFailure();
                }
                TrackSpawnedObjectIfAlive(obj);
                st.lastObject = obj;
                st.lastObjectFrozen = snap.frozen;
            }
            else if (obj && core::Exists((Entity)(obj)))
            {
                DeleteRejectedSpawnOrKeepTracked((Entity)obj, false);
            }
        }

        SafeReleaseModelRuntime(snap.model, "undo_restore");
        return restored;
    }

    static std::vector<Entity> RestoreEntitiesFromUndoSnapshots(const std::vector<UndoEntitySnapshot>& snaps)
    {
        std::vector<Entity> restored;
        for (const auto& snap : snaps)
        {
            Entity e = RestoreEntityFromUndoSnapshot(snap);
            if (e && core::Exists(e)) restored.push_back(e);
        }
        return restored;
    }

    static bool ApplyEntitySnapshotToExisting(Entity entity, const UndoEntitySnapshot& snap)
    {
        if (!entity || !core::Exists(entity) || snap.kind == UndoEntityKind::Unknown) return false;
        if (!IsUsableUndoEntitySnapshot(snap)) return false;
        if (snap.kind == UndoEntityKind::Vehicle && !core::IsVehicle(entity)) return false;
        if (snap.kind == UndoEntityKind::Ped && !core::IsPed(entity)) return false;
        if (snap.kind == UndoEntityKind::Object && !core::IsObject(entity)) return false;

        Vector3 currentPos{};
        if (!core::TryGetEntityCoords(entity, currentPos, true) || !IsUsableRuntimeWorldPosition(currentPos)) return false;
        Vector3 pos = SanitizeRuntimeVector(snap.pos, currentPos);
        float heading = NormalizeHeading(snap.heading, core::SafeGetEntityHeading(entity, 0.0f));
        if (snap.kind == UndoEntityKind::Object) core::safe_native::Freeze(entity, false, &g_coreErrors, "undo_apply");
        core::safe_native::SetCoords(entity, pos, true, &g_coreErrors, "undo_apply");
        core::safe_native::SetHeading(entity, NormalizeHeading(heading, 0.0f), &g_coreErrors, "undo_apply");
        if (snap.health > 0) core::safe_native::SetHealth((Entity)(entity), ClampIntValue(snap.health, 1, 10000), &g_coreErrors, "full_audit");
        if (snap.kind == UndoEntityKind::Vehicle)
        {
            ApplyVehicleTeleportPost((Vehicle)entity, snap.velocity, snap.speed);
        }
        else if (snap.kind == UndoEntityKind::Object)
        {
            core::safe_native::Freeze(entity, snap.frozen, &g_coreErrors, "undo_apply");
            if ((Object)entity == st.lastObject) st.lastObjectFrozen = snap.frozen;
        }
        return true;
    }

    static UndoAction CaptureTeleportUndoState(const std::string& label, Entity ent)
    {
        UndoAction a;
        if (!ent || !core::Exists(ent)) return a;
        a.type = UndoActionType::RestoreTeleport;
        a.label = label.empty() ? "Teleport" : label;
        a.teleportEntity = ent;
        a.teleportWasVehicle = core::IsVehicle(ent);
        a.teleportVehicle = a.teleportWasVehicle ? (Vehicle)ent : 0;
        Vector3 rawPos{};
        if (!core::TryGetEntityCoords(ent, rawPos, true) || !IsUsableRuntimeWorldPosition(rawPos)) return UndoAction();
        a.pos = rawPos;
        a.heading = core::SafeGetEntityHeading(ent, SafePlayerHeading());
        if (cfg.teleportUndo2)
        {
            a.teleportVelocity = core::SafeGetEntityVelocity(ent);
            if (!IsFiniteFloat(a.teleportVelocity.x) || !IsFiniteFloat(a.teleportVelocity.y) || !IsFiniteFloat(a.teleportVelocity.z)) a.teleportVelocity = Vector3{};
            a.teleportSpeed = core::SafeGetEntitySpeed(ent, 0.0f);
            if (!IsFiniteFloat(a.teleportSpeed)) a.teleportSpeed = 0.0f;
            Ped p = 0;
            if (a.teleportWasVehicle && GetPlayerPedSafe(p))
                a.teleportPlayerSeat = GetPlayerVehicleSeatForTeleport((Vehicle)ent, p);
        }
        return a;
    }

    static UndoAction CaptureWorldUndoState(const std::string& label)
    {
        NormalizeWorldControlRuntimeState();
        UndoAction a;
        a.type = UndoActionType::RestoreWorld;
        a.label = label.empty() ? "World State" : label;
        a.weatherIndex = st.weatherIndex;
        a.hour = st.selectedHour;
        a.minute = st.selectedMinute;
        a.freezeTime = st.freezeTime;
        a.freezeWeather = st.freezeWeather;
        a.blackout = st.blackout;
        a.lowGravity = st.lowGravity;
        a.noTraffic = st.noTraffic;
        a.noPeds = st.noPeds;
        a.denseTraffic = st.denseTraffic;
        a.densePeds = st.densePeds;
        return a;
    }

    static UndoAction CaptureWantedUndoState(const std::string& label)
    {
        UndoAction a;
        a.type = UndoActionType::RestoreWanted;
        a.label = label.empty() ? "Wanted State" : label;
        a.wantedLevel = SafeGetWantedLevelRuntime();
        a.maxWantedLevel = st.maxWantedLevel;
        a.frozenWantedLevel = st.frozenWantedLevel;
        a.noWanted = st.noWanted;
        a.freezeWanted = st.freezeWanted;
        a.policeIgnore = st.policeIgnore;
        a.everyoneIgnore = st.everyoneIgnore;
        a.policeIgnoreManual = st.policeIgnoreManual;
        a.everyoneIgnoreManual = st.everyoneIgnoreManual;
        a.wantedMultiplierBoost = st.wantedMultiplierBoost;
        return a;
    }

    // Forward declarations for weapon-safe helpers used by undo/loadout snapshot code.
    // The definitions live lower in the runtime-wrapper section.
    static bool SafeGetCurrentPedWeapon(Ped ped, Hash& weapon);
    static bool SafeHasPedGotWeapon(Ped ped, Hash weapon);
    static int SafeGetAmmoInPedWeapon(Ped ped, Hash weapon);
    static int SafeGetPedWeaponTint(Ped ped, Hash weapon);
    static bool SafeDoesWeaponTakeComponent(Hash weapon, Hash component);
    static bool SafeHasPedGotWeaponComponent(Ped ped, Hash weapon, Hash component);
    static bool SafeSetInfiniteAmmoRuntime(Ped ped, bool infiniteAmmo, bool infiniteClip, const std::string& module, bool forceWeaponHashSync = false);
    static bool SafeRemoveAllPedWeapons(Ped ped, bool doReload, const std::string& module);
    static bool SafeGiveWeaponToPedRuntime(Ped ped, Hash weapon, int ammo, bool equipNow, const std::string& module);
    static bool SafeSetPedAmmoRuntime(Ped ped, Hash weapon, int ammo, const std::string& module);
    static bool SafeSetPedWeaponTintRuntime(Ped ped, Hash weapon, int tint, const std::string& module);
    static bool SafeGiveWeaponComponentRuntime(Ped ped, Hash weapon, Hash component, const std::string& module);
    static bool SafeSetCurrentPedWeaponRuntime(Ped ped, Hash weapon, const std::string& module);
    static bool SafeSetCurrentPedVehicleWeaponRuntime(Ped ped, Hash weapon, const std::string& module);
    static bool SafeSetPedAccuracy(Ped ped, int accuracy, const std::string& module);
    static bool SafeSetPedCombatAttribute(Ped ped, int attribute, bool enabled, const std::string& module);

    static UndoWeaponSnapshot CaptureWeaponSnapshot()
    {
        UndoWeaponSnapshot snap;
        snap.selectedWeapon = st.selectedWeapon;
        snap.advancedAmmoAmount = st.advancedAmmoAmount;
        snap.weaponTintIndex = st.weaponTintIndex;
        snap.infiniteAmmo = st.infiniteAmmo;
        snap.noReload = st.noReload;
        snap.explosiveAmmo = st.explosiveAmmo;
        snap.fireAmmo = st.fireAmmo;
        snap.explosionGun = st.explosionGun;
        snap.fireworkGun = st.fireworkGun;
        snap.vehicleGun = st.vehicleGun;
        snap.pedGun = st.pedGun;
        snap.ragdollGun = st.ragdollGun;
        snap.teleportGun = st.teleportGun;
        snap.forcePushGun = st.forcePushGun;

        Ped p = 0;
        if (!GetPlayerPedSafe(p)) return snap;
        Hash current = 0;
        if (SafeGetCurrentPedWeapon(p, current)) snap.currentWeapon = current;

        for (const auto& name : AllKnownWeaponNames())
        {
            Hash w = H(name);
            if (!SafeHasPedGotWeapon(p, w)) continue;
            snap.weapons.push_back(name);
            snap.ammoByWeapon[name] = SafeGetAmmoInPedWeapon(p, w);
            snap.tintByWeapon[name] = SafeGetPedWeaponTint(p, w);
            UndoWeaponComponentSnapshot compSnap;
            compSnap.weapon = name;
            for (const auto& compName : weaponComponentNames)
            {
                Hash comp = H(compName);
                if (SafeDoesWeaponTakeComponent(w, comp) && SafeHasPedGotWeaponComponent(p, w, comp))
                    compSnap.components.push_back(compName);
            }
            if (!compSnap.components.empty()) snap.components.push_back(compSnap);
        }
        return snap;
    }

    static void ApplyWeaponAmmoRuntimeFlags(Ped p)
    {
        if (!p || !core::Exists((Entity)(p))) return;
        if (!st.infiniteAmmo && !st.noReload) return;
        // Keep the two Weapon Menu toggles semantically separate:
        // Infinite Ammo refills/reserves ammo, while No Reload controls the infinite clip flag.
        SafeSetInfiniteAmmoRuntime(p, st.infiniteAmmo, st.noReload, "weapon_runtime");
    }

    static bool RestoreWeaponSnapshot(const UndoWeaponSnapshot& snap)
    {
        Ped p = 0;
        if (!GetPlayerPedSafe(p)) return false;

        UndoWeaponSnapshot clean = SanitizeWeaponSnapshotForRestore(snap);
        const bool hadAmmoRuntime = st.infiniteAmmo || st.noReload;
        const bool hadInfiniteAmmo = st.infiniteAmmo;

        st.selectedWeapon = clean.selectedWeapon.empty() ? st.selectedWeapon : clean.selectedWeapon;
        st.advancedAmmoAmount = ClampIntValue(clean.advancedAmmoAmount, 0, 999999);
        st.weaponTintIndex = ClampIntValue(clean.weaponTintIndex, 0, 31);
        st.infiniteAmmo = clean.infiniteAmmo;
        st.noReload = clean.noReload;
        st.explosiveAmmo = clean.explosiveAmmo;
        st.fireAmmo = clean.fireAmmo;
        st.explosionGun = clean.explosionGun;
        st.fireworkGun = clean.fireworkGun;
        st.vehicleGun = clean.vehicleGun;
        st.pedGun = clean.pedGun;
        st.ragdollGun = clean.ragdollGun;
        st.teleportGun = clean.teleportGun;
        st.forcePushGun = clean.forcePushGun;

        SafeRemoveAllPedWeapons(p, true, "weapon_restore");
        for (const auto& name : clean.weapons)
        {
            Hash w = H(name);
            int ammo = 9999;
            auto ammoIt = clean.ammoByWeapon.find(name);
            if (ammoIt != clean.ammoByWeapon.end()) ammo = ClampIntValue(ammoIt->second, 0, 999999);
            SafeGiveWeaponToPedRuntime(p, w, ammo, false, "weapon_restore");
            SafeSetPedAmmoRuntime(p, w, ammo, "weapon_restore");
            auto tintIt = clean.tintByWeapon.find(name);
            if (tintIt != clean.tintByWeapon.end())
                SafeSetPedWeaponTintRuntime(p, w, ClampIntValue(tintIt->second, 0, 31), "weapon_restore");
        }
        for (const auto& compSnap : clean.components)
        {
            Hash w = H(compSnap.weapon);
            if (!SafeHasPedGotWeapon(p, w)) continue;
            for (const auto& compName : compSnap.components)
            {
                Hash comp = H(compName);
                if (SafeDoesWeaponTakeComponent(w, comp))
                    SafeGiveWeaponComponentRuntime(p, w, comp, "weapon_restore");
            }
        }
        if (clean.currentWeapon != 0 && SafeHasPedGotWeapon(p, clean.currentWeapon))
            SafeSetCurrentPedWeaponRuntime(p, clean.currentWeapon, "weapon_restore");
        if (hadInfiniteAmmo && !st.infiniteAmmo)
            SafeSetInfiniteAmmoRuntime(p, false, st.noReload, "weapon_restore", true);
        else if (st.infiniteAmmo || st.noReload)
            ApplyWeaponAmmoRuntimeFlags(p);
        else if (hadAmmoRuntime)
            SafeSetInfiniteAmmoRuntime(p, false, false, "weapon_restore", true);
        ClampWeaponMenuState();
        return true;
    }


    static std::string WeaponLoadoutsPath()
    {
        return ResolveDataFileWritePath("CaoUrbanTrainer_WeaponLoadouts.txt");
    }

    static std::string SafeLoadoutName(std::string name, const std::string& fallback)
    {
        name = NormalizeFlatText(name, 48, fallback);
        for (char& c : name)
            if (c == '|' || c == '\r' || c == '\n' || c == '\t') c = ' ';
        name = Trim(name);
        return name.empty() ? fallback : name;
    }

    static std::string BoolField(bool v) { return v ? "1" : "0"; }

    static std::string ComponentsForWeapon(const UndoWeaponSnapshot& snap, const std::string& weapon)
    {
        for (const auto& c : snap.components)
        {
            if (c.weapon != weapon) continue;
            std::string out;
            for (const auto& comp : c.components)
            {
                if (!out.empty()) out += ",";
                out += comp;
            }
            return out;
        }
        return "";
    }

    static std::string WeaponNameFromHash(Hash hash)
    {
        if (hash == 0) return "";
        for (const auto& name : AllKnownWeaponNames())
            if (H(name) == hash) return name;
        return "";
    }

    static std::string StripInlineCommentValue(std::string value)
    {
        bool inQuote = false;
        char quote = 0;
        for (size_t i = 0; i < value.size(); ++i)
        {
            char c = value[i];
            if ((c == '\'' || c == '"'))
            {
                if (!inQuote) { inQuote = true; quote = c; }
                else if (quote == c) { inQuote = false; quote = 0; }
                continue;
            }
            if (!inQuote && (c == '#' || c == ';'))
                return Trim(value.substr(0, i));
        }
        return Trim(value);
    }

    static bool SameWeaponName(const std::string& a, const std::string& b)
    {
        std::string aa = NormalizeModelName(a, "");
        std::string bb = NormalizeModelName(b, "");
        if (aa.empty() || bb.empty()) return false;
        std::transform(aa.begin(), aa.end(), aa.begin(), [](unsigned char c){ return (char)std::toupper(c); });
        std::transform(bb.begin(), bb.end(), bb.begin(), [](unsigned char c){ return (char)std::toupper(c); });
        return aa == bb;
    }

    static std::string NormalizeKnownWeaponName(const std::string& value, const std::string& fallback = "")
    {
        std::string wanted = NormalizeModelName(StripInlineCommentValue(value), "");
        if (wanted.empty()) return fallback;
        for (const auto& name : AllKnownWeaponNames())
            if (SameWeaponName(name, wanted)) return name;
        return fallback;
    }

    static UndoWeaponSnapshot SanitizeWeaponSnapshotForRestore(const UndoWeaponSnapshot& snap)
    {
        UndoWeaponSnapshot out = snap;
        out.weapons.clear();
        out.ammoByWeapon.clear();
        out.tintByWeapon.clear();
        out.components.clear();

        out.selectedWeapon = NormalizeKnownWeaponName(snap.selectedWeapon, "");
        out.advancedAmmoAmount = ClampIntValue(snap.advancedAmmoAmount, 0, 999999);
        out.weaponTintIndex = ClampIntValue(snap.weaponTintIndex, 0, 31);

        for (const auto& rawWeapon : snap.weapons)
        {
            std::string weapon = NormalizeKnownWeaponName(rawWeapon, "");
            if (weapon.empty()) continue;
            if (std::find(out.weapons.begin(), out.weapons.end(), weapon) != out.weapons.end()) continue;
            out.weapons.push_back(weapon);

            int ammo = 9999;
            auto ammoIt = snap.ammoByWeapon.find(rawWeapon);
            if (ammoIt == snap.ammoByWeapon.end()) ammoIt = snap.ammoByWeapon.find(weapon);
            if (ammoIt != snap.ammoByWeapon.end()) ammo = ammoIt->second;
            out.ammoByWeapon[weapon] = ClampIntValue(ammo, 0, 999999);

            int tint = 0;
            auto tintIt = snap.tintByWeapon.find(rawWeapon);
            if (tintIt == snap.tintByWeapon.end()) tintIt = snap.tintByWeapon.find(weapon);
            if (tintIt != snap.tintByWeapon.end()) tint = tintIt->second;
            out.tintByWeapon[weapon] = ClampIntValue(tint, 0, 31);
        }

        for (const auto& compSnap : snap.components)
        {
            std::string weapon = NormalizeKnownWeaponName(compSnap.weapon, "");
            if (weapon.empty() || std::find(out.weapons.begin(), out.weapons.end(), weapon) == out.weapons.end()) continue;
            std::vector<std::string> comps;
            for (const auto& rawComp : compSnap.components)
            {
                std::string comp = NormalizeModelName(StripInlineCommentValue(rawComp), "");
                if (comp.empty()) continue;
                bool known = std::find(weaponComponentNames.begin(), weaponComponentNames.end(), comp) != weaponComponentNames.end();
                if (!known)
                {
                    for (const auto& knownComp : weaponComponentNames)
                    {
                        if (SameWeaponName(knownComp, comp)) { comp = knownComp; known = true; break; }
                    }
                }
                if (known && std::find(comps.begin(), comps.end(), comp) == comps.end()) comps.push_back(comp);
            }
            UpsertWeaponComponentSnapshot(out, weapon, comps);
        }

        if (!out.selectedWeapon.empty() && std::find(out.weapons.begin(), out.weapons.end(), out.selectedWeapon) == out.weapons.end())
            out.selectedWeapon = out.weapons.empty() ? "" : out.weapons.front();
        else if (out.selectedWeapon.empty() && !out.weapons.empty())
            out.selectedWeapon = out.weapons.front();

        std::string current = WeaponNameFromHash(snap.currentWeapon);
        out.currentWeapon = (!current.empty() && std::find(out.weapons.begin(), out.weapons.end(), current) != out.weapons.end()) ? H(current) : 0;
        if (out.currentWeapon == 0 && !out.selectedWeapon.empty()) out.currentWeapon = H(out.selectedWeapon);
        return out;
    }


    static void UpsertWeaponComponentSnapshot(UndoWeaponSnapshot& snap, const std::string& weapon, const std::vector<std::string>& components)
    {
        if (weapon.empty()) return;
        for (auto& c : snap.components)
        {
            if (c.weapon == weapon)
            {
                c.components = components;
                return;
            }
        }
        if (!components.empty()) snap.components.push_back({weapon, components});
    }

    static std::vector<std::string> SerializeWeaponLoadoutSlot(const WeaponLoadoutSlot& slot)
    {
        std::vector<std::string> lines;
        if (!slot.valid) return lines;
        UndoWeaponSnapshot snap = SanitizeWeaponSnapshotForRestore(slot.snapshot);
        if (snap.weapons.empty()) return lines;
        lines.push_back("SLOT=" + std::to_string(ClampIntValue(slot.slot, 1, 12)));
        lines.push_back("NAME=" + SafeLoadoutName(slot.name, "Loadout " + std::to_string(slot.slot)));
        lines.push_back("SELECTED=" + NormalizeKnownWeaponName(snap.selectedWeapon, ""));
        lines.push_back("CURRENT=" + WeaponNameFromHash(snap.currentWeapon));
        lines.push_back("AMMO_PRESET=" + std::to_string(ClampIntValue(snap.advancedAmmoAmount, 0, 999999)));
        lines.push_back("TINT_INDEX=" + std::to_string(ClampIntValue(snap.weaponTintIndex, 0, 31)));
        lines.push_back(std::string("FLAGS=") +
            BoolField(snap.infiniteAmmo) + "," + BoolField(snap.noReload) + "," + BoolField(snap.explosiveAmmo) + "," + BoolField(snap.fireAmmo) + "," +
            BoolField(snap.explosionGun) + "," + BoolField(snap.fireworkGun) + "," + BoolField(snap.vehicleGun) + "," + BoolField(snap.pedGun) + "," +
            BoolField(snap.ragdollGun) + "," + BoolField(snap.teleportGun) + "," + BoolField(snap.forcePushGun));
        for (const auto& weapon : snap.weapons)
        {
            std::string w = NormalizeKnownWeaponName(weapon, "");
            if (w.empty()) continue;
            int ammo = 9999;
            auto ammoIt = snap.ammoByWeapon.find(w);
            if (ammoIt != snap.ammoByWeapon.end()) ammo = ClampIntValue(ammoIt->second, 0, 999999);
            int tint = 0;
            auto tintIt = snap.tintByWeapon.find(w);
            if (tintIt != snap.tintByWeapon.end()) tint = ClampIntValue(tintIt->second, 0, 31);
            lines.push_back("WEAPON=" + w + "|" + std::to_string(ammo) + "|" + std::to_string(tint) + "|" + ComponentsForWeapon(snap, w));
        }
        lines.push_back("END");
        return lines;
    }

    static bool SaveWeaponLoadoutsFile()
    {
        std::vector<std::string> lines;
        lines.push_back("# Cao Urban Trainer Weapon Loadouts 2.0");
        for (const auto& slot : weaponLoadouts)
        {
            if (!slot.valid) continue;
            std::vector<std::string> block = SerializeWeaponLoadoutSlot(slot);
            lines.insert(lines.end(), block.begin(), block.end());
            lines.push_back("");
        }
        return AtomicWriteLines(WeaponLoadoutsPath(), lines, true);
    }

    static void EnsureWeaponLoadoutSlots()
    {
        if (weaponLoadouts.size() != 12)
        {
            weaponLoadouts.clear();
            for (int i = 1; i <= 12; ++i)
            {
                WeaponLoadoutSlot slot;
                slot.slot = i;
                slot.name = "Loadout " + std::to_string(i);
                weaponLoadouts.push_back(slot);
            }
        }
        st.weaponLoadoutSlot = ClampIntValue(st.weaponLoadoutSlot, 1, 12);
        st.weaponLoadoutPage = ClampIntValue(st.weaponLoadoutPage, 0, 1);
    }

    static void SyncSelectedWeaponLoadoutName()
    {
        EnsureWeaponLoadoutSlots();
        int idx = st.weaponLoadoutSlot - 1;
        st.weaponLoadoutName = SafeLoadoutName(weaponLoadouts[idx].name, "Loadout " + std::to_string(st.weaponLoadoutSlot));
    }

    static int SelectedWeaponLoadoutIndexSafe()
    {
        EnsureWeaponLoadoutSlots();
        st.weaponLoadoutSlot = ClampIntValue(st.weaponLoadoutSlot, 1, 12);
        if (weaponLoadouts.size() != 12) EnsureWeaponLoadoutSlots();
        return ClampIntValue(st.weaponLoadoutSlot - 1, 0, 11);
    }

    static void LoadWeaponLoadoutsFile()
    {
        EnsureWeaponLoadoutSlots();
        for (auto& slot : weaponLoadouts)
        {
            slot.valid = false;
            slot.snapshot = UndoWeaponSnapshot();
            slot.name = "Loadout " + std::to_string(slot.slot);
        }

        std::vector<std::string> lines;
        ReadTextLinesSafe(WeaponLoadoutsPath(), lines);

        WeaponLoadoutSlot cur;
        bool inBlock = false;
        auto commit = [&]()
        {
            if (!inBlock) return;
            int idx = ClampIntValue(cur.slot, 1, 12) - 1;
            cur.slot = idx + 1;
            cur.snapshot = SanitizeWeaponSnapshotForRestore(cur.snapshot);
            cur.valid = cur.valid && !cur.snapshot.weapons.empty();
            if (cur.valid) weaponLoadouts[idx] = cur;
            inBlock = false;
            cur = WeaponLoadoutSlot();
        };

        for (const std::string& raw : lines)
        {
            std::string line = Trim(raw);
            if (line.empty() || line[0] == '#' || line[0] == ';') continue;

            std::string endProbe = StripInlineCommentValue(line);
            std::transform(endProbe.begin(), endProbe.end(), endProbe.begin(), [](unsigned char c){ return (char)std::toupper(c); });
            if (endProbe == "END") { commit(); continue; }

            auto eq = line.find('=');
            if (eq == std::string::npos) continue;
            std::string key = Trim(line.substr(0, eq));
            std::string value = Trim(line.substr(eq + 1));
            std::transform(key.begin(), key.end(), key.begin(), [](unsigned char c){ return (char)std::toupper(c); });
            if (key != "NAME") value = StripInlineCommentValue(value);

            if (key == "SLOT")
            {
                commit();
                inBlock = true;
                cur = WeaponLoadoutSlot();
                cur.slot = ClampIntValue(ParseIntOr(value, 1), 1, 12);
                cur.name = "Loadout " + std::to_string(cur.slot);
                cur.valid = true;
                continue;
            }
            if (!inBlock) continue;
            if (key == "END") { commit(); continue; }
            if (key == "NAME") { cur.name = SafeLoadoutName(value, "Loadout " + std::to_string(cur.slot)); continue; }
            if (key == "SELECTED") { cur.snapshot.selectedWeapon = NormalizeKnownWeaponName(value, cur.snapshot.selectedWeapon); continue; }
            if (key == "CURRENT") { std::string w = NormalizeKnownWeaponName(value, ""); cur.snapshot.currentWeapon = w.empty() ? 0 : H(w); continue; }
            if (key == "AMMO_PRESET") { cur.snapshot.advancedAmmoAmount = ClampIntValue(ParseIntOr(value, cur.snapshot.advancedAmmoAmount), 0, 999999); continue; }
            if (key == "TINT_INDEX") { cur.snapshot.weaponTintIndex = ClampIntValue(ParseIntOr(value, cur.snapshot.weaponTintIndex), 0, 31); continue; }
            if (key == "FLAGS")
            {
                auto f = Split(value, ',');
                auto b = [&](size_t i, bool fallback){ return i < f.size() ? ParseLooseBoolOr(f[i], fallback) : fallback; };
                cur.snapshot.infiniteAmmo = b(0, false);
                cur.snapshot.noReload = b(1, false);
                cur.snapshot.explosiveAmmo = b(2, false);
                cur.snapshot.fireAmmo = b(3, false);
                cur.snapshot.explosionGun = b(4, false);
                cur.snapshot.fireworkGun = b(5, false);
                cur.snapshot.vehicleGun = b(6, false);
                cur.snapshot.pedGun = b(7, false);
                cur.snapshot.ragdollGun = b(8, false);
                cur.snapshot.teleportGun = b(9, false);
                cur.snapshot.forcePushGun = b(10, false);
                continue;
            }
            if (key == "WEAPON")
            {
                auto p = Split(value, '|');
                if (p.empty()) continue;
                std::string weapon = NormalizeKnownWeaponName(p[0], "");
                if (weapon.empty()) continue;
                if (std::find(cur.snapshot.weapons.begin(), cur.snapshot.weapons.end(), weapon) == cur.snapshot.weapons.end())
                    cur.snapshot.weapons.push_back(weapon);
                int ammo = p.size() > 1 ? ClampIntValue(ParseIntOr(p[1], 9999), 0, 999999) : 9999;
                int tint = p.size() > 2 ? ClampIntValue(ParseIntOr(p[2], 0), 0, 31) : 0;
                cur.snapshot.ammoByWeapon[weapon] = ammo;
                cur.snapshot.tintByWeapon[weapon] = tint;
                if (p.size() > 3)
                {
                    std::vector<std::string> comps;
                    for (const auto& rawComp : Split(p[3], ','))
                    {
                        std::string comp = NormalizeModelName(StripInlineCommentValue(rawComp), "");
                        for (const auto& knownComp : weaponComponentNames)
                            if (SameWeaponName(knownComp, comp)) { comp = knownComp; break; }
                        if (!comp.empty() && std::find(weaponComponentNames.begin(), weaponComponentNames.end(), comp) != weaponComponentNames.end() && std::find(comps.begin(), comps.end(), comp) == comps.end()) comps.push_back(comp);
                    }
                    UpsertWeaponComponentSnapshot(cur.snapshot, weapon, comps);
                }
            }
        }
        commit();
        EnsureWeaponLoadoutSlots();
        SyncSelectedWeaponLoadoutName();
    }

    static std::string WeaponLoadoutDisplay(int slot)
    {
        EnsureWeaponLoadoutSlots();
        int idx = ClampIntValue(slot, 1, 12) - 1;
        const auto& l = weaponLoadouts[idx];
        return l.valid ? (l.name + " / " + std::to_string((int)l.snapshot.weapons.size()) + " weapons") : "Empty";
    }

    static void SelectWeaponLoadoutSlot(int slot)
    {
        EnsureWeaponLoadoutSlots();
        st.weaponLoadoutSlot = ClampIntValue(slot, 1, 12);
        st.weaponLoadoutName = SafeLoadoutName(weaponLoadouts[st.weaponLoadoutSlot - 1].name, "Loadout " + std::to_string(st.weaponLoadoutSlot));
        st.lastWeaponLoadoutStatus = "Selected slot " + std::to_string(st.weaponLoadoutSlot);
    }

    static void SaveCurrentWeaponLoadout()
    {
        const int idx = SelectedWeaponLoadoutIndexSafe();
        WeaponLoadoutSlot slot;
        slot.slot = st.weaponLoadoutSlot;
        slot.name = SafeLoadoutName(st.weaponLoadoutName, "Loadout " + std::to_string(slot.slot));
        slot.snapshot = SanitizeWeaponSnapshotForRestore(CaptureWeaponSnapshot());
        slot.valid = !slot.snapshot.weapons.empty();
        if (!slot.valid)
        {
            st.lastWeaponLoadoutStatus = "No weapons to save";
            Notify("Weapon loadout not saved: no weapons found.");
            return;
        }
        WeaponLoadoutSlot previous = weaponLoadouts[idx];
        weaponLoadouts[idx] = slot;
        if (SaveWeaponLoadoutsFile())
        {
            st.lastWeaponLoadoutStatus = "Saved " + slot.name;
            Notify("Weapon loadout saved: " + slot.name);
        }
        else
        {
            weaponLoadouts[idx] = previous;
            SyncSelectedWeaponLoadoutName();
            st.lastWeaponLoadoutStatus = "Save failed";
            Notify("Weapon loadout save failed; previous slot kept in memory.");
        }
    }

    static void LoadSelectedWeaponLoadout()
    {
        const int idx = SelectedWeaponLoadoutIndexSafe();
        const auto& slot = weaponLoadouts[idx];
        if (!slot.valid)
        {
            st.lastWeaponLoadoutStatus = "Slot empty";
            Notify("Weapon loadout slot is empty.");
            return;
        }
        UndoAction undo;
        bool haveUndo = false;
        if (cfg.undoRecordWeapons && CanRecordUndo())
        {
            Ped ped = 0;
            if (GetPlayerPedSafe(ped))
            {
                undo.type = UndoActionType::RestoreWeapons;
                undo.label = "Load Weapon Loadout";
                undo.weaponSnapshot = CaptureWeaponSnapshot();
                haveUndo = true;
            }
        }
        UndoWeaponSnapshot clean = SanitizeWeaponSnapshotForRestore(slot.snapshot);
        if (clean.weapons.empty())
        {
            st.lastWeaponLoadoutStatus = "Load failed: invalid slot";
            Notify("Weapon loadout load failed: slot has no valid weapons.");
            return;
        }
        if (RestoreWeaponSnapshot(clean))
        {
            if (haveUndo) PushUndo(undo);
            st.lastWeaponLoadoutStatus = "Loaded " + slot.name;
            Notify("Weapon loadout loaded: " + slot.name);
        }
        else
        {
            st.lastWeaponLoadoutStatus = "Load failed";
            Notify("Weapon loadout load failed: player unavailable.");
        }
    }

    static void DeleteSelectedWeaponLoadout()
    {
        const int idx = SelectedWeaponLoadoutIndexSafe();
        WeaponLoadoutSlot previous = weaponLoadouts[idx];
        std::string name = weaponLoadouts[idx].valid ? weaponLoadouts[idx].name : ("Loadout " + std::to_string(st.weaponLoadoutSlot));
        weaponLoadouts[idx] = WeaponLoadoutSlot();
        weaponLoadouts[idx].slot = idx + 1;
        weaponLoadouts[idx].name = "Loadout " + std::to_string(idx + 1);
        st.weaponLoadoutName = weaponLoadouts[idx].name;
        if (SaveWeaponLoadoutsFile())
        {
            st.lastWeaponLoadoutStatus = "Deleted " + name;
            Notify("Weapon loadout deleted: " + name);
        }
        else
        {
            weaponLoadouts[idx] = previous;
            SyncSelectedWeaponLoadoutName();
            st.lastWeaponLoadoutStatus = "Delete save failed";
            Notify("Weapon loadout delete failed; previous slot restored in memory.");
        }
    }

    static void RenameSelectedWeaponLoadout()
    {
        EnsureWeaponLoadoutSlots();
        std::string out;
        if (!TryShowTextInputDialogUtf8(st.weaponLoadoutName, "Weapon Loadout Name", "Enter loadout name", 48, out)) return;
        st.weaponLoadoutName = SafeLoadoutName(out, "Loadout " + std::to_string(st.weaponLoadoutSlot));
        const int idx = SelectedWeaponLoadoutIndexSafe();
        std::string previousName = weaponLoadouts[idx].name;
        weaponLoadouts[idx].name = st.weaponLoadoutName;
        if (weaponLoadouts[idx].valid && !SaveWeaponLoadoutsFile())
        {
            weaponLoadouts[idx].name = previousName;
            SyncSelectedWeaponLoadoutName();
            st.lastWeaponLoadoutStatus = "Rename save failed";
            Notify("Weapon loadout rename failed; previous name restored.");
            return;
        }
        st.lastWeaponLoadoutStatus = weaponLoadouts[idx].valid ? ("Renamed slot " + std::to_string(st.weaponLoadoutSlot)) : "Name staged for next save";
        Notify(weaponLoadouts[idx].valid ? ("Loadout name: " + st.weaponLoadoutName) : ("Loadout name staged: " + st.weaponLoadoutName));
    }

    static void RefreshWeaponLoadouts()
    {
        LoadWeaponLoadoutsFile();
        SyncSelectedWeaponLoadoutName();
        st.lastWeaponLoadoutStatus = "Reloaded loadouts";
        Notify("Weapon loadouts reloaded.");
    }

    static void PushOutfitUndo(const std::string& label)
    {
        if (!cfg.undoRecordOutfits || !CanRecordUndo()) return;
        std::string line = CurrentOutfitLine(0, "UndoOutfit");
        if (line.empty()) return;
        UndoAction a;
        a.type = UndoActionType::RestoreOutfit;
        a.label = label.empty() ? "Outfit Change" : label;
        a.outfitLine = line;
        PushUndo(a);
    }

    static void PushWeaponUndo(const std::string& label)
    {
        if (!cfg.undoRecordWeapons || !CanRecordUndo()) return;
        Ped p = 0;
        // Empty weapon inventory is valid, but an unavailable player ped is not a useful snapshot.
        if (!GetPlayerPedSafe(p)) return;
        UndoAction a;
        a.type = UndoActionType::RestoreWeapons;
        a.label = label.empty() ? "Weapon Change" : label;
        a.weaponSnapshot = CaptureWeaponSnapshot();
        PushUndo(a);
    }

    static void PushEntityStateUndo(const std::string& label, Entity entity)
    {
        if (!cfg.undoRecordSpawns || !CanRecordUndo()) return;
        if (!entity || !core::Exists((Entity)(entity))) return;
        UndoEntitySnapshot snap;
        if (!SnapshotEntityForUndo(entity, snap)) return;
        UndoAction a;
        a.type = UndoActionType::RestoreEntityState;
        a.label = label.empty() ? "Entity State" : label;
        a.entities.push_back(entity);
        a.entitySnapshots.push_back(snap);
        PushUndo(a);
    }

    [[maybe_unused]] static void PushRestoreEntitiesUndo(const std::string& label, const std::vector<Entity>& entities)
    {
        if (!cfg.undoRecordSpawns || !CanRecordUndo()) return;
        UndoAction a;
        a.type = UndoActionType::RestoreEntities;
        a.label = label.empty() ? "Restore Entities" : label;
        for (Entity e : entities)
        {
            if (e && core::Exists((Entity)(e))) a.entities.push_back(e);
        }
        a.entitySnapshots = SnapshotEntitiesForUndo(a.entities);
        if (!a.entitySnapshots.empty()) PushUndo(a);
    }

