    static bool IsTrackedBodyguardHandle(Ped ped)
    {
        Vector3 pos{};
        return ped && core::IsPed((Entity)ped) && !core::IsPlayerPed((Entity)ped) &&
               !core::IsPedDeadOrDying(ped, true, true) &&
               TryGetUsableEntityPosition((Entity)ped, pos) &&
               std::find(st.bodyguards.begin(), st.bodyguards.end(), ped) != st.bodyguards.end();
    }

    static int ClearCompanionTargetReferencesToPedRuntime(Ped targetPed)
    {
        if (!targetPed) return 0;
        int cleared = 0;

        Vehicle cleanupPlayerVehicle = 0;
        Ped cleanupPlayer = 0;
        if (GetPlayerPedSafe(cleanupPlayer) && core::IsPedInAnyVehicle((Ped)cleanupPlayer, false))
            cleanupPlayerVehicle = core::GetVehiclePedIsIn((Ped)cleanupPlayer, false);

        std::vector<Ped> companionsToRelease;
        auto queueRelease = [&](Ped companion)
        {
            if (!companion || companion == targetPed) return;
            if (std::find(companionsToRelease.begin(), companionsToRelease.end(), companion) == companionsToRelease.end())
                companionsToRelease.push_back(companion);
        };

        auto clearCompanionFireState = [&](Ped companion)
        {
            st.companionCombatTargetUntilTick.erase(companion);
            ClearCompanionVehicleFireTaskThrottle(companion);
        };

        for (auto it = st.companionCombatTarget.begin(); it != st.companionCombatTarget.end(); )
        {
            const Ped companion = it->first;
            const Ped target = it->second;
            if (companion == targetPed || target == targetPed)
            {
                clearCompanionFireState(companion);
                if (target == targetPed) queueRelease(companion);
                it = st.companionCombatTarget.erase(it);
                ++cleared;
            }
            else
            {
                ++it;
            }
        }

        std::vector<Ped> fireOwnersToClear;
        for (const auto& entry : st.companionVehicleFireTaskTarget)
        {
            const Ped companion = entry.first;
            const Ped target = entry.second;
            if (companion == targetPed || target == targetPed)
            {
                fireOwnersToClear.push_back(companion);
                if (target == targetPed) queueRelease(companion);
            }
        }
        for (Ped companion : fireOwnersToClear)
        {
            ClearCompanionVehicleFireTaskThrottle(companion);
            ++cleared;
        }

        // BUGFIX 196: BUGFIX 195 cleared stale runtime maps, but target-value cleanup
        // used by deleted/converted NPCs only erased maps/throttles. GTA could still
        // keep TASK_COMBAT_PED / TASK_DRIVE_BY latched to the removed ped until another
        // support path touched the companion. Release the actual task immediately.
        for (Ped companion : companionsToRelease)
            ReleaseCompanionCombatAimAfterTargetLost(companion, cleanupPlayerVehicle, "companion_target_cleanup");

        return cleared;
    }

    static void ClearCompanionRuntimeMaps(Ped ped)
    {
        if (!ped) return;
        // BUGFIX 177: companion cleanup must clear both owner-keyed state and
        // target-value references.  When an enemy/NPC was deleted or converted to
        // friendly/bodyguard, other companions could keep that handle as their active
        // combat/drive-by target and continue aiming at a removed or now-allied ped.
        ClearCompanionTargetReferencesToPedRuntime(ped);
        st.companionVehicleEntryUntilTick.erase(ped);
        st.companionVehicleEntryTarget.erase(ped);
        st.companionVehicleEntryIssuedTick.erase(ped);
        st.companionVehicleEntrySeat.erase(ped);
        st.companionVehicleEntryAvoidSeat.erase(ped);
        st.companionVehicleEntryAvoidVehicle.erase(ped);
        st.companionVehicleLeaveUntilTick.erase(ped);
        st.companionVehicleLeaveTarget.erase(ped);
        st.companionVehicleTransferUntilTick.erase(ped);
        st.companionVehicleTransferTarget.erase(ped);
        st.companionCombatTarget.erase(ped);
        st.companionCombatTargetUntilTick.erase(ped);
        ClearCompanionVehicleFireTaskThrottle(ped);
        st.companionPanicLastCleanupAttemptTick.erase(ped);
        st.companionPanicLastPoliceScanTick.erase(ped);
        st.companionWantedPoliceEmergencyLastScanTick.erase(ped);
        st.companionDefensiveAssistLastTick.erase(ped);
    }

    static void ClearBodyguardRuntimeState(Ped ped, bool clearSharedCompanionMaps = true)
    {
        if (!ped) return;
        st.bodyguardRoles.erase(ped);
        st.bodyguardLastCombatRefreshTick.erase(ped);
        st.bodyguardLastRecoveryPos.erase(ped);
        st.bodyguardLastMoveTick.erase(ped);
        // BUGFIX 141: bodyguard-only cleanup must not silently wipe shared
        // friendly/companion runtime when the ped is only being demoted from
        // bodyguard back to friendly.  Callers that delete/dismiss the ped keep the
        // default clearSharedCompanionMaps=true path.
        if (clearSharedCompanionMaps) ClearCompanionRuntimeMaps(ped);
    }

    static int PurgeStaleBodyguardRuntimeState()
    {
        int removed = 0;
        auto purgeBodyguardOnlyMap = [&](auto& mapRef)
        {
            for (auto it = mapRef.begin(); it != mapRef.end(); )
            {
                if (!IsBodyguardTracked(it->first))
                {
                    it = mapRef.erase(it);
                    ++removed;
                }
                else
                {
                    ++it;
                }
            }
        };
        auto purgeSharedCompanionMap = [&](auto& mapRef)
        {
            for (auto it = mapRef.begin(); it != mapRef.end(); )
            {
                if (!IsFriendlyOrBodyguardTracked(it->first))
                {
                    it = mapRef.erase(it);
                    ++removed;
                }
                else
                {
                    ++it;
                }
            }
        };
        auto purgeSharedCompanionTargetMap = [&]()
        {
            std::vector<Ped> invalidOwners;
            for (const auto& entry : st.companionVehicleFireTaskTarget)
            {
                const Ped companion = entry.first;
                const Ped target = entry.second;
                if (!IsFriendlyOrBodyguardTracked(companion) ||
                    !target || !core::Exists((Entity)target) || !core::IsPed((Entity)target) ||
                    IsCompanionTargetDefeatedOrInvalid(target) ||
                    target == companion)
                    invalidOwners.push_back(companion);
            }
            for (Ped companion : invalidOwners)
            {
                ClearCompanionVehicleFireTaskThrottle(companion);
                ++removed;
            }
        };

        purgeBodyguardOnlyMap(st.bodyguardRoles);
        purgeBodyguardOnlyMap(st.bodyguardLastCombatRefreshTick);
        purgeBodyguardOnlyMap(st.bodyguardLastRecoveryPos);
        purgeBodyguardOnlyMap(st.bodyguardLastMoveTick);
        purgeSharedCompanionMap(st.companionVehicleEntryUntilTick);
        purgeSharedCompanionMap(st.companionVehicleEntryTarget);
        purgeSharedCompanionMap(st.companionVehicleEntryIssuedTick);
        purgeSharedCompanionMap(st.companionVehicleEntrySeat);
        purgeSharedCompanionMap(st.companionVehicleEntryAvoidSeat);
        purgeSharedCompanionMap(st.companionVehicleEntryAvoidVehicle);
        purgeSharedCompanionMap(st.companionVehicleLeaveUntilTick);
        purgeSharedCompanionMap(st.companionVehicleLeaveTarget);
        purgeSharedCompanionMap(st.companionVehicleTransferUntilTick);
        purgeSharedCompanionMap(st.companionVehicleTransferTarget);
        removed += PurgeInvalidCompanionCombatTargetRuntime();
        purgeSharedCompanionMap(st.companionVehicleFireLastReissueTick);
        purgeSharedCompanionMap(st.companionVehicleWeaponPrepLastTick);
        purgeSharedCompanionMap(st.companionVehicleFireTaskLastIssueTick);
        purgeSharedCompanionTargetMap();
        purgeSharedCompanionMap(st.companionPanicLastCleanupAttemptTick);
        purgeSharedCompanionMap(st.companionPanicLastPoliceScanTick);
        purgeSharedCompanionMap(st.companionWantedPoliceEmergencyLastScanTick);
        purgeSharedCompanionMap(st.companionDefensiveAssistLastTick);
        if (st.companionAntiPanicCursor > st.friendlyPeds.size() + st.bodyguards.size() + 1)
            st.companionAntiPanicCursor = 0;
        return removed;
    }

    static void EraseMissionSpawnedEntityAt(size_t index)
    {
        if (index >= st.missionSpawnedEntities.size()) return;
        st.missionSpawnedEntities.erase(st.missionSpawnedEntities.begin() + static_cast<std::ptrdiff_t>(index));
        if (index < st.missionSpawnedEntityDefIndexes.size())
            st.missionSpawnedEntityDefIndexes.erase(st.missionSpawnedEntityDefIndexes.begin() + static_cast<std::ptrdiff_t>(index));
        if (st.missionSpawnedEntityDefIndexes.size() > st.missionSpawnedEntities.size())
            st.missionSpawnedEntityDefIndexes.resize(st.missionSpawnedEntities.size());
    }

    static void CompactMissionSpawnedEntityLists()
    {
        std::vector<Entity> unique;
        unique.reserve(st.missionSpawnedEntities.size());
        for (size_t i = 0; i < st.missionSpawnedEntities.size(); )
        {
            Entity e = st.missionSpawnedEntities[i];
            bool invalid = !e || !core::Exists((Entity)(e));
            if (!invalid)
            {
                Vector3 pos{};
                invalid = !TryGetUsableEntityPosition(e, pos);
            }
            if (!invalid)
            {
                if (i < st.missionSpawnedEntityDefIndexes.size())
                    invalid = !MissionRuntimeEntityMatchesDef(e, st.missionSpawnedEntityDefIndexes[i]);
                else
                    invalid = true;
            }
            bool duplicate = !invalid && std::find(unique.begin(), unique.end(), e) != unique.end();
            if (invalid || duplicate)
                EraseMissionSpawnedEntityAt(i);
            else
            {
                unique.push_back(e);
                ++i;
            }
        }
        if (st.missionSpawnedEntityDefIndexes.size() > st.missionSpawnedEntities.size())
            st.missionSpawnedEntityDefIndexes.resize(st.missionSpawnedEntities.size());
    }

    static void RemoveTrackedEntity(Entity entity)
    {
        if (entity && core::IsPed((Entity)entity))
        {
            // BUGFIX 177: untracking a ped must also remove it as a target from
            // every companion.  Previous cleanup only removed runtime where the ped
            // was the companion key, leaving stale enemy handles inside drive-by maps.
            ClearCompanionTargetReferencesToPedRuntime((Ped)entity);
            RemoveFriendlyNpcRuntime((Ped)entity);
        }

        auto eraseEnt = [entity](auto& list)
        {
            list.erase(std::remove_if(list.begin(), list.end(), [entity](auto v)
            {
                Entity e = (Entity)v;
                if (e == entity || !e || !core::Exists((Entity)(e))) return true;
                Vector3 pos{};
                return !TryGetUsableEntityPosition((Entity)e, pos);
            }), list.end());
        };
        eraseEnt(st.spawnedPeds);
        eraseEnt(st.bodyguards);
        eraseEnt(st.enemies);
        eraseEnt(st.scenarioPeds);
        eraseEnt(st.spawnedVehicles);
        eraseEnt(st.scenarioVehicles);
        eraseEnt(st.spawnedObjects);
        eraseEnt(st.worldDirectorEntities);
        eraseEnt(st.urbanLifeEntities);
        eraseEnt(st.vehicleAIEntities);
        eraseEnt(st.policeRealismEntities);

        st.gameMode.trackedEntities.erase(std::remove_if(st.gameMode.trackedEntities.begin(), st.gameMode.trackedEntities.end(), [entity](Entity e)
        {
            if (e == entity || !e || !core::Exists((Entity)e)) return true;
            Vector3 pos{};
            return !TryGetUsableEntityPosition((Entity)e, pos);
        }), st.gameMode.trackedEntities.end());

        st.inspectorFrozenStates.erase(entity);
        ClearBodyguardRuntimeState((Ped)entity);
        PurgeStaleBodyguardRuntimeState();

        for (size_t i = 0; i < st.missionSpawnedEntities.size(); )
        {
            Entity e = st.missionSpawnedEntities[i];
            Vector3 missionPos{};
            const bool invalidMissionEntity = (e == entity) || !e || !core::Exists((Entity)(e)) || !TryGetUsableEntityPosition((Entity)e, missionPos);
            if (invalidMissionEntity)
                EraseMissionSpawnedEntityAt(i);
            else
                ++i;
        }

        if (st.inspectedEntity == entity)
        {
            st.inspectedEntity = 0;
            st.lastInspectorStatus = "No entity selected";
        }

        if ((Entity)st.lastObject == entity)
        {
            st.lastObject = 0;
            st.lastObjectFrozen = true;
        }
        if ((Entity)st.chauffeur == entity)
        {
            st.chauffeur = 0;
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
        }
        if ((Entity)st.chauffeurVehicle == entity)
        {
            bool chauffeurGone = true;
            if (st.chauffeur && core::Exists((Entity)st.chauffeur) && !core::IsPlayerPed((Entity)st.chauffeur))
            {
                chauffeurGone = DeletePedSafely(st.chauffeur) || !core::Exists((Entity)st.chauffeur);
                if (!chauffeurGone)
                    TrackSpawnedPedIfAlive(st.chauffeur);
            }
            if (chauffeurGone) st.chauffeur = 0;
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
        }
        if ((Entity)st.lastPlayerVehicleForBodyguards == entity) st.lastPlayerVehicleForBodyguards = 0;
        if ((Entity)st.bodyguardProtectedVehicle == entity) st.bodyguardProtectedVehicle = 0;
        if ((Entity)st.garageLastLoadedVehicle == entity)
        {
            st.garageLastLoadedVehicle = 0;
            st.garageLastLoadedSlot = 0;
        }
    }

    static void DropInvalidTrackedEntity(Entity entity)
    {
        if (!entity || !core::Exists(entity))
        {
            RemoveTrackedEntity(entity);
            return;
        }

        if (core::IsPed(entity))
        {
            Ped ped = (Ped)entity;
            if (core::IsPlayerPed(entity) || core::IsPedDeadOrDying(ped, true, true))
            {
                RemoveTrackedEntity(entity);
                return;
            }
        }

        Vector3 pos{};
        if (!TryGetUsableEntityPosition(entity, pos))
            RemoveTrackedEntity(entity);
    }

    static bool TryGetUsableEntityPosition(Entity entity, Vector3& pos, float minZ, float maxZ)
    {
        if (!core::Exists(entity)) return false;
        if (!core::TryGetEntityCoords(entity, pos, false)) return false;
        return IsUsableWorldPosition(pos, minZ, maxZ);
    }

    static bool TryGetStrictTrackedEntityPosition(Entity entity, Vector3& pos)
    {
        // Counting, cleanup and inspector validation must not use a fallback position.
        // If a native read fails or the entity has unusable coordinates, the caller
        // needs to see that failure so stale/warped handles can be removed.
        return TryGetUsableEntityPosition(entity, pos, -200.0f, 2000.0f);
    }

    static bool IsUsableVehicleHandle(Vehicle vehicle, bool requireUsablePosition = true)
    {
        if (!core::IsVehicle((Entity)vehicle)) return false;
        if (!requireUsablePosition) return true;
        Vector3 pos{};
        return TryGetUsableEntityPosition((Entity)vehicle, pos);
    }

    static bool IsUsablePedHandle(Ped ped, bool allowPlayer = false, bool requireAlive = false, bool requireUsablePosition = true)
    {
        if (!core::IsPed((Entity)ped)) return false;
        if (!allowPlayer && core::IsPlayerPed((Entity)ped)) return false;
        if (requireAlive && core::IsPedDeadOrDying(ped, true, true)) return false;
        if (!requireUsablePosition) return true;
        Vector3 pos{};
        return TryGetUsableEntityPosition((Entity)ped, pos);
    }

    static bool IsCompanionTargetDefeatedOrInvalid(Ped target)
    {
        if (!target || !core::Exists((Entity)target) || !core::IsPed((Entity)target))
            return true;
        // BUGFIX 195: GTA can keep a killed ped handle "usable" for a short time
        // while IsPedDeadOrDying() has not settled yet.  Health <= 0 is enough for
        // companion AI to release the target, otherwise friendly NPCs can keep a
        // drive-by/combat task aimed at the last corpse when no next enemy exists.
        if (core::IsPedDeadOrDying((Ped)target, true, true))
            return true;
        const int health = (int)core::SafeGetEntityHealth((Entity)target, 0);
        return health <= 0;
    }

    static bool SafeTaskVehicleShootAtPed(Ped shooter, Ped target, float fireTolerance, const std::string& module);
    static bool SafeTaskDriveByPed(Ped shooter, Ped target, float distanceToShoot, int accuracy, const std::string& module);

    static bool InvokeSetCurrentPedVehicleWeaponCompat(Ped ped, Hash weapon)
    {
#if defined(_MSC_VER)
        // SET_CURRENT_PED_VEHICLE_WEAPON(Ped ped, Hash weaponHash)
        return invoke<BOOL>(0x75C55983C2C39DAAULL, ped, weapon) != 0;
#else
        (void)ped; (void)weapon;
        return false;
#endif
    }

    static bool InvokeGetCurrentPedVehicleWeaponCompat(Ped ped, Hash& weapon)
    {
#if defined(_MSC_VER)
        // GET_CURRENT_PED_VEHICLE_WEAPON(Ped ped, Hash* weaponHash)
        return invoke<BOOL>(0x1017582BCD3832DCULL, ped, &weapon) != 0;
#else
        (void)ped;
        weapon = 0;
        return false;
#endif
    }

    static void InvokeSetPedShootRateCompat(Ped ped, int shootRate)
    {
#if defined(_MSC_VER)
        // SET_PED_SHOOT_RATE(Ped ped, int shootRate)
        (void)invoke<int>(0x614DA022990752DCULL, ped, shootRate);
#else
        (void)ped; (void)shootRate;
#endif
    }

    static void InvokeSetPedFiringPatternCompat(Ped ped, Hash patternHash)
    {
#if defined(_MSC_VER)
        // SET_PED_FIRING_PATTERN(Ped ped, Hash patternHash)
        (void)invoke<int>(0x9AC577F5A12AD8A9ULL, ped, patternHash);
#else
        (void)ped; (void)patternHash;
#endif
    }

    static bool EnsureFriendlyVehicleFireWeaponRuntime(Ped ped, const std::string& module)
    {
        if (!IsUsablePedHandle(ped, false, true, false)) return false;

        const Hash vehicleFirearm = H("WEAPON_PISTOL");
        const int vehicleAmmo = std::max(120, std::max(st.selectedPedAmmo, cfg.bodyguardAmmo));
        const int vehicleAccuracy = ClampIntValue(std::max(70, cfg.bodyguardAccuracy), 5, 100);
        const Hash firingPattern = 0xC6EE6B4C; // FIRING_PATTERN_FULL_AUTO
        const bool trackedCompanion = IsFriendlyOrBodyguardTracked(ped);
        const bool inVehicle = core::IsPedInAnyVehicle((Ped)ped, false);

        if (inVehicle)
        {
            Vehicle pedVehicle = core::GetVehiclePedIsIn((Ped)ped, false);
            if (!IsUsableVehicleHandle(pedVehicle, false)) return false;
            // Drivers should keep their driving/chase task.  Only passengers need the
            // vehicle weapon/drive-by handoff; forcing the driver weapon can restart
            // steering tasks or make the car stop.
            if (IsPedDriverOfVehicleRuntime(ped, pedVehicle)) return false;
        }

        bool ok = true;
        const bool hadWeapon = SafeHasPedGotWeapon(ped, vehicleFirearm);
        if (!hadWeapon)
        {
            // BUGFIX 174: do not equipNow-spam a seated companion.  In GTA this can
            // loop the passenger "draw pistol" animation forever while the weapon never
            // becomes usable for TASK_DRIVE_BY.  Give the weapon quietly, then perform a
            // throttled current/vehicle-weapon selection below.
            ok = SafeGiveWeaponToPedRuntime(ped, vehicleFirearm, vehicleAmmo, !inVehicle, module) && ok;
        }
        else
        {
            ok = SafeSetPedAmmoRuntime(ped, vehicleFirearm, vehicleAmmo, module) && ok;
        }

        const DWORD now = GetTickCount();
        bool allowWeaponSelect = true;
        if (inVehicle && trackedCompanion)
        {
            DWORD& lastPrep = st.companionVehicleWeaponPrepLastTick[ped];
            allowWeaponSelect = (lastPrep == 0 || core::TickElapsed(now, lastPrep, 1250u));
            if (allowWeaponSelect) lastPrep = now;
        }

        if (!inVehicle || allowWeaponSelect)
        {
            ok = SafeSetCurrentPedWeaponRuntime(ped, vehicleFirearm, module) && ok;

            // BUGFIX 108/174: seated peds have a separate vehicle weapon slot.  Select
            // it, but not every tick; repeatedly calling this together with drive-by
            // reissues restarts the draw animation and leaves the passenger unarmed.
            if (inVehicle)
            {
                Hash currentVehicleWeapon = 0;
                const bool hasVehicleWeapon = SafeNativeValueRuntime<bool>(false, module, "get current ped vehicle weapon", [&](){ return InvokeGetCurrentPedVehicleWeaponCompat(ped, currentVehicleWeapon); });
                if (!hasVehicleWeapon || currentVehicleWeapon != vehicleFirearm)
                    ok = SafeSetCurrentPedVehicleWeaponRuntime(ped, vehicleFirearm, module) && ok;
            }
        }

        SafeSetPedAccuracy(ped, vehicleAccuracy, module);
        SafeNativeVoidRuntime(module, "set ped shoot rate", [&](){ InvokeSetPedShootRateCompat(ped, 1000); });
        SafeNativeVoidRuntime(module, "set ped firing pattern", [&](){ InvokeSetPedFiringPatternCompat(ped, firingPattern); });
        SafeSetPedCombatAttribute(ped, 5, true, module);
        SafeSetPedCombatAttribute(ped, 46, true, module);
        SafeSetPedCombatAttribute(ped, 58, true, module);
        return ok;
    }

    static bool SafeTaskCombatPed(Ped attacker, Ped target, const std::string& module = "combat")
    {
        if (!IsUsablePedHandle(attacker, false, true, true)) return false;
        if (!IsUsablePedHandle(target, true, true, true)) return false;

        const bool trackedCompanion = IsFriendlyOrBodyguardTracked(attacker);

        // BUGFIX 121: combat wrappers are reached from many old systems.  Do not
        // let a stale combat request cancel TASK_LEAVE_VEHICLE / TASK_ENTER_VEHICLE
        // during a player-car switch.
        if (trackedCompanion && IsCompanionVehicleTaskProtected(attacker))
            return true;

        // BUGFIX 125: legacy callers can still reach this generic wrapper without
        // going through CommandFriendlyNpcAttackThreat().  Those attacks previously
        // were not registered in companionCombatTarget, so dead targets / cleared
        // police-pursuit targets could keep the companion locked in aim/combat until
        // another unrelated support tick touched it.  Track every valid companion
        // combat request at the wrapper layer too.
        auto trackCompanionTarget = [&]()
        {
            if (!trackedCompanion) return;
            RegisterCompanionCombatTargetRuntime(attacker, target);
        };

        // BUGFIX 103: old scenario/mission/menu branches may still call the generic
        // combat wrapper for a friendly/bodyguard passenger.  TASK_COMBAT_PED can make
        // a passenger leave the car or sit idle, so convert that request into the
        // shared drive-by task globally instead of fixing each caller one by one.
        if (trackedCompanion && core::IsPedInAnyVehicle((Ped)attacker, false))
        {
            Vehicle vehicle = core::GetVehiclePedIsIn((Ped)attacker, false);
            if (!IsUsableVehicleHandle(vehicle, true))
            {
                ClearCompanionCombatTargetRuntime(attacker);
                return false;
            }
            // BUGFIX 154: generic legacy combat callers can still reach this wrapper
            // with a tracked companion that is currently driving.  Rejecting the task is
            // correct, but leaving the old active combat target caused every later
            // anti-panic / vehicle-fire refresh to keep retrying a driver-only path.
            if (IsPedDriverOfVehicleRuntime(attacker, vehicle))
            {
                ClearCompanionCombatTargetRuntime(attacker);
                return false;
            }
            if (core::IsPedInVehicle((Ped)target, vehicle, false))
            {
                ClearCompanionCombatTargetRuntime(attacker);
                return false;
            }
            trackCompanionTarget();
            // BUGFIX 127: legacy SafeTaskCombatPed() vehicle branches must prepare
            // tracked companions before vehicle fire.  Without this, GTA can keep a
            // police/SWAT-skinned bodyguard in cop/civilian panic state and accept the
            // task without letting the passenger actually shoot.
            PrepareCompanionForForcedThreatAttack(attacker, target, module);
            EnsureFriendlyVehicleFireWeaponRuntime(attacker, module);
            return SafeTaskVehicleShootAtPed(attacker, target, 90.0f, module);
        }

        trackCompanionTarget();
        if (trackedCompanion)
        {
            // Old foot-combat callers also need the same anti-panic/cop-state handoff.
            // This does not clear tasks; it only refreshes runtime flags before the
            // explicit combat task is issued.
            PrepareCompanionForForcedThreatAttack(attacker, target, module);
        }
        return core::safe_native::TaskCombatPed(attacker, target, &g_coreErrors, module);
    }

    template <typename Fn>
    static bool SafePedRuntimeNative(Ped ped, const std::string& module, const std::string& action, Fn&& fn, bool allowPlayer = false, bool requireAlive = false, bool requireUsablePosition = true)
    {
        if (!IsUsablePedHandle(ped, allowPlayer, requireAlive, requireUsablePosition))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, action, requireUsablePosition ? "Rejected ped native: handle, life state, or coordinates are invalid" : "Rejected ped native: handle or life state is invalid");
            return false;
        }
        return SafeNativeVoidRuntime(module, action, std::forward<Fn>(fn));
    }

    template <typename Fn>
    static bool SafeVehicleRuntimeNative(Vehicle vehicle, const std::string& module, const std::string& action, Fn&& fn, bool requireUsablePosition = true)
    {
        if (!IsUsableVehicleHandle(vehicle, requireUsablePosition))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, action, requireUsablePosition ? "Rejected vehicle native: handle or coordinates are invalid" : "Rejected vehicle native: handle is invalid");
            return false;
        }
        return SafeNativeVoidRuntime(module, action, std::forward<Fn>(fn));
    }

    template <typename Fn>
    static bool SafeVehiclePhysicsRuntimeNative(Vehicle vehicle, const std::string& module, const std::string& action, Fn&& fn)
    {
        if (!IsUsableVehicleHandle(vehicle, true))
        {
            ReportCore2(core::ErrorSeverity::Warning, module, action, "Rejected vehicle native: handle or coordinates are invalid");
            return false;
        }
        return SafeNativeVoidRuntime(module, action, std::forward<Fn>(fn));
    }

