    static bool SafeSetPedCombatProfile(Ped ped, int ability, int movement, int range, const std::string& module = "ped")
    {
        if (!IsUsablePedHandle(ped, false, false, false)) return false;
        const int safeAbility = ClampIntValue(ability, 0, 2);
        const int safeMovement = ClampIntValue(movement, 0, 3);
        const int safeRange = ClampIntValue(range, 0, 2);
        bool ok = true;
        ok = SafePedRuntimeNative(ped, module, "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, safeAbility); }) && ok;
        ok = SafePedRuntimeNative(ped, module, "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, safeMovement); }) && ok;
        ok = SafePedRuntimeNative(ped, module, "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(ped, safeRange); }) && ok;
        return ok;
    }

