    [[maybe_unused]] static bool SafeSetDriverProfile(Ped ped, float ability, float aggression, const std::string& module = "driver")
    {
        if (!IsUsablePedHandle(ped, false, true, false)) return false;
        if (!IsFiniteFloat(ability)) ability = 0.5f;
        if (!IsFiniteFloat(aggression)) aggression = 0.25f;
        ability = ClampFloatValue(ability, 0.0f, 1.0f, 0.5f);
        aggression = ClampFloatValue(aggression, 0.0f, 1.0f, 0.25f);
        bool ok = true;
        ok = SafePedRuntimeNative(ped, module, "set driver ability", [&](){ PED::SET_DRIVER_ABILITY(ped, ability); }) && ok;
        ok = SafePedRuntimeNative(ped, module, "set driver aggression", [&](){ PED::SET_DRIVER_AGGRESSIVENESS(ped, aggression); }) && ok;
        return ok;
    }

    static bool IsFriendlyNpcTracked(Ped ped);
    static bool IsFriendlyOrBodyguardTracked(Ped ped);
    static Vehicle CurrentPlayerVehicleForCompanionEntry();
    static bool TrySeatFriendlyNpcInPlayerVehicleOrSuppressFootFollow(Ped ped, const std::string& module, bool immediateFirst);

    static bool SafeTaskFollowToOffset(Ped ped, Entity target, float ox, float oy, float oz, float speed, int timeoutMs, float stoppingRange, bool persistFollowing, const std::string& module = "ai_task")
    {
        if (!IsUsablePedHandle(ped, false, true, true)) return false;
        if (!core::Exists(target)) return false;

        // BUGFIX 121: never let legacy follow orders overwrite a protected
        // companion vehicle handoff.  Some old menu/scenario branches can still
        // call follow while a friendly/bodyguard is leaving the old vehicle or
        // running to the new player vehicle; preserving that task is safer than
        // reissuing foot-follow.
        if (IsFriendlyOrBodyguardTracked(ped) && IsCompanionVehicleTaskProtected(ped))
            return true;

        // Global guard for old/rare branches: any direct follow-to-player/player-car order
        // for a tracked companion is converted to the shared vehicle-entry pipeline
        // while the player is inside a vehicle. This prevents menu, scenario, mission,
        // and movie-scene code paths from reintroducing the "NPC runs after the car" bug.
        Vehicle companionPlayerVehicle = CurrentPlayerVehicleForCompanionEntry();
        const bool targetIsPlayerOrPlayerVehicle = core::IsPlayerPed(target) || (companionPlayerVehicle && target == (Entity)companionPlayerVehicle);
        if (targetIsPlayerOrPlayerVehicle && IsFriendlyOrBodyguardTracked(ped) && companionPlayerVehicle)
        {
            if (TrySeatFriendlyNpcInPlayerVehicleOrSuppressFootFollow(ped, module, true))
                return true;
            // Seat is full or temporarily unavailable. Do not issue foot-follow to a moving
            // player vehicle for any tracked companion; standing still is safer than chasing.
            if (!core::IsPedInAnyVehicle((Ped)ped, false))
                return true;
        }

        Vector3 targetPos{};
        if (!TryGetUsableEntityPosition(target, targetPos)) return false;
        if (!IsFiniteFloat(ox)) ox = 0.0f;
        if (!IsFiniteFloat(oy)) oy = 0.0f;
        if (!IsFiniteFloat(oz)) oz = 0.0f;
        ox = ClampFloatValue(ox, -50.0f, 50.0f, 0.0f);
        oy = ClampFloatValue(oy, -50.0f, 50.0f, 0.0f);
        oz = ClampFloatValue(oz, -10.0f, 10.0f, 0.0f);
        if (!IsFiniteFloat(speed)) speed = 2.0f;
        speed = ClampFloatValue(speed, 0.1f, 25.0f, 2.0f);
        if (timeoutMs < -1) timeoutMs = -1;
        if (timeoutMs > 600000) timeoutMs = 600000;
        if (!IsFiniteFloat(stoppingRange)) stoppingRange = 2.0f;
        stoppingRange = ClampFloatValue(stoppingRange, 0.1f, 100.0f, 2.0f);
        return SafeNativeVoidRuntime(module, "task follow offset", [&](){ AI::TASK_FOLLOW_TO_OFFSET_OF_ENTITY(ped, target, ox, oy, oz, speed, timeoutMs, stoppingRange, persistFollowing); });
    }

    static bool SafeTaskStandStill(Ped ped, int durationMs = 1500, const std::string& module = "ai_task")
    {
        if (!IsUsablePedHandle(ped, false, true, true)) return false;
        durationMs = ClampIntValue(durationMs, 250, 600000);
        return SafeNativeVoidRuntime(module, "task stand still", [&](){ AI::TASK_STAND_STILL(ped, durationMs); });
    }

    static bool SafeTaskSmartFleePed(Ped ped, Ped target, float distance, int fleeTimeMs, bool preferPavements = false, bool quitIfOutOfRange = false, const std::string& module = "ai_task")
    {
        if (!IsUsablePedHandle(ped, false, true, true)) return false;
        if (!IsUsablePedHandle(target, true, true, true)) return false;

        // BUGFIX 113: tracked companions must never be pushed back into GTA's
        // civilian flee behaviour by old menu/NPC-control branches.  This also
        // protects pending leave/enter/transfer tasks from being overwritten.
        if (IsFriendlyOrBodyguardTracked(ped))
        {
            ConfigureFriendlyCompanion(ped, true);
            if (IsCompanionVehicleTaskProtected(ped)) return true;
            return SafeTaskStandStill(ped, 1200, module);
        }

        if (!IsFiniteFloat(distance)) distance = 80.0f;
        distance = ClampFloatValue(distance, 1.0f, 500.0f, 80.0f);
        if (fleeTimeMs < -1) fleeTimeMs = -1;
        if (fleeTimeMs > 600000) fleeTimeMs = 600000;
        return SafeNativeVoidRuntime(module, "task smart flee", [&](){ AI::TASK_SMART_FLEE_PED(ped, target, distance, fleeTimeMs, preferPavements, quitIfOutOfRange); });
    }

    static void InvokeTaskVehicleShootAtPedCompat(Ped shooter, Ped target, float fireTolerance)
    {
#if defined(_MSC_VER)
        // TASK_VEHICLE_SHOOT_AT_PED is absent from some ScriptHookV native header
        // snapshots, so call the native by hash to keep the ASI build portable.
        (void)invoke<int>(0x10AB107B887214D8ULL, shooter, target, fireTolerance);
#else
        (void)shooter; (void)target; (void)fireTolerance;
#endif
    }

    static void InvokeSetDrivebyTaskTargetCompat(Ped shooter, Ped target, Vehicle targetVehicle, Vector3 targetPos)
    {
#if defined(_MSC_VER)
        // SET_DRIVEBY_TASK_TARGET(shootingPed, targetPed, targetVehicle, x, y, z)
        (void)invoke<int>(0xE5B302114D8162EEULL, shooter, target, targetVehicle, targetPos.x, targetPos.y, targetPos.z);
#else
        (void)shooter; (void)target; (void)targetVehicle; (void)targetPos;
#endif
    }

    static void InvokeTaskDriveByCompat(Ped shooter, Ped target, Vehicle targetVehicle, Vector3 targetPos, float distanceToShoot, int accuracy, Hash firingPattern)
    {
#if defined(_MSC_VER)
        // TASK_DRIVE_BY(ped, targetPed, targetVehicle, x, y, z, distance, accuracy, p8, firingPattern)
        (void)invoke<int>(0x2F8AF0E82773A171ULL, shooter, target, targetVehicle, targetPos.x, targetPos.y, targetPos.z, distanceToShoot, accuracy, false, firingPattern);
#else
        (void)shooter; (void)target; (void)targetVehicle; (void)targetPos; (void)distanceToShoot; (void)accuracy; (void)firingPattern;
#endif
    }

    static bool SafeTaskDriveByPed(Ped shooter, Ped target, float distanceToShoot = 120.0f, int accuracy = 70, const std::string& module = "ai_task")
    {
        if (!IsUsablePedHandle(shooter, false, true, true)) return false;
        const bool trackedShooter = IsFriendlyOrBodyguardTracked(shooter);
        if (!IsUsablePedHandle(target, false, true, true) || IsCompanionTargetDefeatedOrInvalid(target))
        {
            if (trackedShooter) ReleaseCompanionCombatAimAfterTargetLost(shooter, CurrentPlayerVehicleForCompanionEntry(), module);
            return false;
        }
        if (!core::IsPedInAnyVehicle(shooter, false))
        {
            if (trackedShooter) ClearCompanionCombatTargetRuntime(shooter);
            return false;
        }

        Vehicle shooterVehicle = core::GetVehiclePedIsIn(shooter, false);
        if (!IsUsableVehicleHandle(shooterVehicle, true))
        {
            if (trackedShooter) ClearCompanionCombatTargetRuntime(shooter);
            return false;
        }
        if (core::IsPedInVehicle(target, shooterVehicle, false))
        {
            if (trackedShooter) ClearCompanionCombatTargetRuntime(shooter);
            return false;
        }

        if (core::IsPedInAnyVehicle(target, false))
        {
            Vehicle targetVehicleForSameCarCheck = core::GetVehiclePedIsIn(target, false);
            if (targetVehicleForSameCarCheck == shooterVehicle)
            {
                if (trackedShooter) ClearCompanionCombatTargetRuntime(shooter);
                return false;
            }
        }

        Vehicle targetVehicle = 0;
        if (core::IsPedInAnyVehicle((Ped)target, false))
        {
            Vehicle candidateTargetVehicle = core::GetVehiclePedIsIn((Ped)target, false);
            if (IsUsableVehicleHandle(candidateTargetVehicle, true) && candidateTargetVehicle != shooterVehicle)
                targetVehicle = candidateTargetVehicle;
        }

        Vector3 targetPos{};
        if (!TryGetUsableEntityPosition((Entity)target, targetPos))
        {
            if (trackedShooter) ClearCompanionCombatTargetRuntime(shooter);
            return false;
        }

        if (!IsFiniteFloat(distanceToShoot)) distanceToShoot = 120.0f;
        distanceToShoot = ClampFloatValue(distanceToShoot, 20.0f, 300.0f, 120.0f);
        accuracy = ClampIntValue(accuracy, 5, 100);
        const Hash firingPattern = 0xC6EE6B4C; // FIRING_PATTERN_FULL_AUTO

        // BUGFIX 108: hostile peds often attack the player's car from their own car.
        // Passing the target vehicle as context keeps the drive-by task active for
        // those attackers, while the targetPed remains the primary aim point.
        bool ok = SafeNativeVoidRuntime(module, "task drive-by", [&](){ InvokeTaskDriveByCompat(shooter, target, targetVehicle, targetPos, distanceToShoot, accuracy, firingPattern); });

        // BUGFIX 123: do not immediately overwrite a vehicle-context drive-by
        // target with a ped-only refresh.  When police/FIB/SWAT attackers are inside
        // their patrol cars, clearing targetVehicle here can make passenger companions
        // accept TASK_DRIVE_BY but keep aiming at empty space or stop firing entirely.
        // Keep the hostile vehicle context when it exists; use ped-only targeting only
        // for attackers on foot.
        ok = SafeNativeVoidRuntime(module, targetVehicle ? "set drive-by vehicle target" : "set drive-by ped target", [&](){ InvokeSetDrivebyTaskTargetCompat(shooter, target, targetVehicle, targetPos); }) || ok;
        return ok;
    }

    static bool IsPedDriverOfVehicleRuntime(Ped ped, Vehicle vehicle)
    {
        if (!IsUsablePedHandle(ped, false, true, false)) return false;
        if (!IsUsableVehicleHandle(vehicle, false)) return false;
        return (Ped)core::GetPedInVehicleSeat((Vehicle)vehicle, -1) == ped;
    }

    static bool SafeTaskVehicleShootAtPed(Ped shooter, Ped target, float fireTolerance = 80.0f, const std::string& module = "ai_task")
    {
        if (!IsUsablePedHandle(shooter, false, true, true)) return false;
        const bool trackedShooter = IsFriendlyOrBodyguardTracked(shooter);
        if (!IsUsablePedHandle(target, false, true, true) || IsCompanionTargetDefeatedOrInvalid(target))
        {
            if (trackedShooter) ReleaseCompanionCombatAimAfterTargetLost(shooter, CurrentPlayerVehicleForCompanionEntry(), module);
            return false;
        }
        if (!core::IsPedInAnyVehicle(shooter, false))
        {
            if (trackedShooter) ClearCompanionCombatTargetRuntime(shooter);
            return false;
        }
        Vehicle shooterVehicle = core::GetVehiclePedIsIn(shooter, false);
        if (!IsUsableVehicleHandle(shooterVehicle, true))
        {
            if (trackedShooter) ClearCompanionCombatTargetRuntime(shooter);
            return false;
        }
        const bool shooterIsDriver = IsPedDriverOfVehicleRuntime(shooter, shooterVehicle);
        if (core::IsPedInVehicle(target, shooterVehicle, false))
        {
            if (trackedShooter) ClearCompanionCombatTargetRuntime(shooter);
            return false;
        }
        if (!IsFiniteFloat(fireTolerance)) fireTolerance = 80.0f;
        fireTolerance = ClampFloatValue(fireTolerance, 1.0f, 180.0f, 80.0f);

        // BUGFIX 125/127/144: vehicle-fire can be called directly by wrapper
        // fallbacks and chauffeur/bodyguard support. Register the target here too so
        // stale-dead target cleanup can release drive-by aim even when the higher
        // dispatcher was bypassed. Direct calls must also run the same forced-threat
        // preparation as CommandFriendlyNpcAttackThreat(): this disables companion
        // panic/cop-state for the validated target, refreshes vehicle weapon/ammo, and
        // avoids the bug where police/SWAT-skinned friendly passengers accept a task
        // but never fire.
        if (trackedShooter)
        {
            RegisterCompanionCombatTargetRuntime(shooter, target);
            PrepareCompanionForForcedThreatAttack(shooter, target, module);
            EnsureFriendlyVehicleFireWeaponRuntime(shooter, module);
        }

        // BUGFIX 149: tracked companions must not be treated as a generic driver gunner.
        // A driver-side TASK_VEHICLE_SHOOT_AT_PED can steal the driving/chase task and a
        // passenger-side TASK_DRIVE_BY is the only reliable ScriptHookV path for return fire.
        // If this tracked companion is the driver, keep the combat target registered but do
        // not issue a task that can make the vehicle stop. Passenger companions continue
        // through the drive-by pipeline below.
        if (trackedShooter && shooterIsDriver)
        {
            ClearCompanionCombatTargetRuntime(shooter);
            return false;
        }

        // BUGFIX 107/108/145/149: TASK_VEHICLE_SHOOT_AT_PED alone often leaves passenger
        // companions idle, so TASK_DRIVE_BY remains the primary passenger pipeline.  Re-apply
        // vehicle weapon/ammo immediately before every reissue because GTA may silently reset
        // seated weapon state when panic/flee was injected by police combat.
        bool ok = false;
        if (!shooterIsDriver)
        {
            if (trackedShooter)
            {
                const DWORD now = GetTickCount();
                auto taskIt = st.companionVehicleFireTaskLastIssueTick.find(shooter);
                auto targetIt = st.companionVehicleFireTaskTarget.find(shooter);
                // BUGFIX 191: police-chase vehicle fire needs a shorter reissue window.
                // GTA can accept TASK_DRIVE_BY while a wanted-pursuit target is moving fast
                // behind/alongside the player, then silently drop aim when LOS/vehicle angle
                // changes. Keep the old 1250ms guard for normal fights to avoid draw-loop
                // animation spam, but refresh law-enforcement pursuit targets sooner.
                const DWORD sameTargetReissueMs = IsPolicePursuitThreatTarget(target) ? 650u : 1250u;
                const bool sameTargetTaskActive = taskIt != st.companionVehicleFireTaskLastIssueTick.end() &&
                    targetIt != st.companionVehicleFireTaskTarget.end() && targetIt->second == target &&
                    !core::TickElapsed(now, taskIt->second, sameTargetReissueMs);

                EnsureFriendlyVehicleFireWeaponRuntime(shooter, module);

                // BUGFIX 174: TASK_DRIVE_BY reissued every 300-650ms restarts the seated
                // draw-weapon animation for many GTA passenger peds.  While the same target
                // is already active, keep weapon state warm but let the existing drive-by
                // task finish equipping before issuing another task.
                if (sameTargetTaskActive)
                    return true;

            }
            else
            {
                EnsureFriendlyVehicleFireWeaponRuntime(shooter, module);
            }

            ok = SafeTaskDriveByPed(shooter, target, 210.0f, std::max(80, cfg.bodyguardAccuracy), module);
            if (trackedShooter && ok)
            {
                st.companionVehicleFireTaskLastIssueTick[shooter] = GetTickCount();
                st.companionVehicleFireTaskTarget[shooter] = target;
            }
        }

        // BUGFIX 174: do not immediately overwrite a successful TASK_DRIVE_BY with
        // TASK_VEHICLE_SHOOT_AT_PED.  The weaker fallback can cancel the proper passenger
        // drive-by state and put the ped into an endless weapon-draw animation.  Use it
        // only when drive-by could not be issued.
        if (!ok)
        {
            ok = SafeNativeVoidRuntime(module, "task vehicle shoot at ped fallback", [&](){ InvokeTaskVehicleShootAtPedCompat(shooter, target, fireTolerance); }) || ok;
            if (trackedShooter && ok)
            {
                st.companionVehicleFireTaskLastIssueTick[shooter] = GetTickCount();
                st.companionVehicleFireTaskTarget[shooter] = target;
            }
        }
        return ok;
    }

    static void ClearCompanionVehicleFireTaskThrottle(Ped ped)
    {
        if (!ped) return;
        // BUGFIX 178: keep every companion vehicle-fire throttle map in one cleanup
        // path.  BUGFIX 174/175 fixed the draw-loop by throttling weapon prep and
        // task reissues, but some stale-target paths only erased the task target and
        // left lastReissue/weaponPrep timestamps alive.  The next valid enemy could
        // then be skipped for up to a cooldown window, making the passenger sit in
        // a half-armed state or ignore the first return-fire order after cleanup.
        st.companionVehicleFireLastReissueTick.erase(ped);
        st.companionVehicleWeaponPrepLastTick.erase(ped);
        st.companionVehicleFireTaskLastIssueTick.erase(ped);
        st.companionVehicleFireTaskTarget.erase(ped);
    }

    static void ReleaseCompanionCombatAimAfterTargetLost(Ped companion, Vehicle currentPlayerVehicle, const std::string& module)
    {
        if (!IsUsablePedHandle(companion, false, true, true)) return;
        st.companionCombatTarget.erase(companion);
        st.companionCombatTargetUntilTick.erase(companion);
        ClearCompanionVehicleFireTaskThrottle(companion);
        ConfigureFriendlyCompanion(companion, true);
        if (IsCompanionVehicleTaskProtected(companion, currentPlayerVehicle)) return;

        const bool companionInVehicle = core::IsPedInAnyVehicle((Ped)companion, false);
        Vehicle companionVehicle = companionInVehicle ? core::GetVehiclePedIsIn((Ped)companion, false) : 0;
        const bool companionIsDriver = companionInVehicle && IsPedDriverOfVehicleRuntime(companion, companionVehicle);

        // BUGFIX 195: when the last enemy dies and there is no next target, GTA can
        // keep TASK_COMBAT_PED / TASK_DRIVE_BY latched to the corpse.  Clear the
        // actual task tree for passengers/on-foot companions, then return to regroup
        // behavior.  Drivers are left alone so driving/chauffeur tasks are not stolen.
        if (!companionIsDriver)
            core::safe_native::ClearPedTasks(companion, false, &g_coreErrors, module);

        if (IsUsableVehicleHandle(currentPlayerVehicle, true) &&
            !core::IsPedInVehicle((Ped)companion, (Vehicle)currentPlayerVehicle, false))
        {
            TrySeatFriendlyNpcInPlayerVehicleOrSuppressFootFollow(companion, module, true);
        }
        else if (!companionInVehicle)
        {
            Ped player = 0;
            if (GetPlayerPedSafe(player))
                SafeTaskFollowToOffset(companion, (Entity)player, 0.0f, -2.2f, 0.0f, 2.0f, -1, 2.0f, true, module);
        }
    }

    static bool ReleaseCompanionDeadOrInvalidTargetState(Ped companion, Vehicle currentPlayerVehicle, const std::string& module)
    {
        if (!companion || !IsFriendlyOrBodyguardTracked(companion)) return false;

        bool released = false;
        auto combatIt = st.companionCombatTarget.find(companion);
        if (combatIt != st.companionCombatTarget.end())
        {
            Ped target = combatIt->second;
            if (!target || IsCompanionTargetDefeatedOrInvalid(target))
            {
                ReleaseCompanionCombatAimAfterTargetLost(companion, currentPlayerVehicle, module);
                released = true;
            }
        }

        auto fireIt = st.companionVehicleFireTaskTarget.find(companion);
        if (fireIt != st.companionVehicleFireTaskTarget.end())
        {
            Ped target = fireIt->second;
            if (!target || IsCompanionTargetDefeatedOrInvalid(target))
            {
                ReleaseCompanionCombatAimAfterTargetLost(companion, currentPlayerVehicle, module);
                released = true;
            }
        }

        return released;
    }

    static bool ClearTrackedCompanionVehicleFleeAndReissueFire(Ped companion, Ped target, const std::string& module)
    {
        if (!IsFriendlyOrBodyguardTracked(companion)) return false;
        if (!IsUsablePedHandle(companion, false, true, true)) return false;
        if (!IsUsablePedHandle(target, false, true, true) || IsCompanionTargetDefeatedOrInvalid(target) || target == companion) return false;
        if (!core::IsPedInAnyVehicle((Ped)companion, false)) return false;
        if (IsCompanionVehicleTaskProtected(companion)) return false;

        Vehicle companionVehicle = core::GetVehiclePedIsIn((Ped)companion, false);
        if (!IsUsableVehicleHandle(companionVehicle, true)) return false;
        if (IsPedDriverOfVehicleRuntime(companion, companionVehicle)) return false;
        if (core::IsPedInVehicle((Ped)target, (Vehicle)companionVehicle, false))
        {
            ClearCompanionCombatTargetRuntime(companion);
            return false;
        }

        const bool fleeing = SafeIsPedFleeingRuntime(companion, module);
        if (!fleeing) return false;

        // Clear only the proven panic/flee task while the ped is already seated and not
        // in enter/leave/transfer protection. This avoids the emergency-regression from
        // BUGFIX 142, but lets passenger companions recover when police gunfire already
        // pushed them into civilian flee before the drive-by task was issued.
        ConfigureFriendlyCompanion(companion, true);
        PrepareCompanionForForcedThreatAttack(companion, target, module);
        EnsureFriendlyVehicleFireWeaponRuntime(companion, module);

        Ped previousTarget = 0;
        bool hadPreviousTarget = false;
        auto previousTargetIt = st.companionCombatTarget.find(companion);
        if (previousTargetIt != st.companionCombatTarget.end())
        {
            previousTarget = previousTargetIt->second;
            hadPreviousTarget = true;
        }

        DWORD previousLease = 0;
        bool hadPreviousLease = false;
        auto leaseIt = st.companionCombatTargetUntilTick.find(companion);
        if (leaseIt != st.companionCombatTargetUntilTick.end())
        {
            previousLease = leaseIt->second;
            hadPreviousLease = true;
        }

        core::safe_native::ClearPedTasks(companion, false, &g_coreErrors, module);
        ClearCompanionVehicleFireTaskThrottle(companion);
        const bool ok = SafeTaskVehicleShootAtPed(companion, target, 90.0f, module);

        // BUGFIX 176: panic/flee recovery is a low-level task repair, not target
        // acquisition.  SafeTaskVehicleShootAtPed() registers the target internally;
        // restore the previous target/lease so this repair cannot create an immortal
        // combat target that blocks later regroup/vehicle-entry logic.
        RestoreCompanionCombatTargetAfterLowLevelReissue(companion, previousTarget, hadPreviousTarget, previousLease, hadPreviousLease);
        if (hadPreviousTarget)
            st.companionVehicleFireLastReissueTick[companion] = GetTickCount();
        return ok;
    }

    static bool SafeTaskLeaveVehicle(Ped ped, Vehicle vehicle, int flags = 16, const std::string& module = "ai_task")
    {
        if (!IsUsablePedHandle(ped, false, true, true)) return false;
        if (!IsUsableVehicleHandle(vehicle, true)) return false;
        flags = ClampIntValue(flags, 0, 1024);
        return SafeNativeVoidRuntime(module, "task leave vehicle", [&](){ AI::TASK_LEAVE_VEHICLE(ped, vehicle, flags); });
    }

    static bool SafeTaskWanderStandard(Ped ped, float radius, int flags, const std::string& module = "ai_task")
    {
        if (!IsUsablePedHandle(ped, false, true, true)) return false;
        if (IsFriendlyOrBodyguardTracked(ped) && IsCompanionVehicleTaskProtected(ped))
            return true;
        if (!IsFiniteFloat(radius)) radius = 10.0f;
        radius = ClampFloatValue(radius, 0.0f, 200.0f, 10.0f);
        flags = ClampIntValue(flags, 0, 1024);
        return SafeNativeVoidRuntime(module, "task wander", [&](){ AI::TASK_WANDER_STANDARD(ped, radius, flags); });
    }

    static bool SafeTaskVehicleChase(Ped driver, Ped target, const std::string& module = "vehicle_ai")
    {
        if (!IsUsablePedHandle(driver, false, true, true)) return false;
        if (!IsUsablePedHandle(target, true, true, true)) return false;
        if (!core::IsPedInAnyVehicle(driver, false)) return false;
        return SafeNativeVoidRuntime(module, "task vehicle chase", [&](){ AI::TASK_VEHICLE_CHASE(driver, target); });
    }

    static bool SafeTaskVehicleDriveWander(Ped driver, Vehicle vehicle, float speed, int drivingStyle, const std::string& module = "vehicle_ai")
    {
        if (!IsUsablePedHandle(driver, false, true, true)) return false;
        if (!IsUsableVehicleHandle(vehicle, true)) return false;
        if (!core::IsPedInVehicle(driver, vehicle, false)) return false;
        if (!IsFiniteFloat(speed)) speed = 12.0f;
        speed = ClampFloatValue(speed, 0.1f, 120.0f, 12.0f);
        drivingStyle = ClampIntValue(drivingStyle, 0, 0x7FFFFFFF);
        return SafeNativeVoidRuntime(module, "task vehicle drive wander", [&](){ AI::TASK_VEHICLE_DRIVE_WANDER(driver, vehicle, speed, drivingStyle); });
    }

    static bool SafeTaskVehicleDriveToCoordLongrange(Ped driver, Vehicle vehicle, Vector3 destination, float speed, int drivingStyle, float stoppingRange, const std::string& module = "vehicle_ai")
    {
        if (!IsUsablePedHandle(driver, false, true, true)) return false;
        if (!IsUsableVehicleHandle(vehicle, true)) return false;
        if (!core::IsPedInVehicle(driver, vehicle, false)) return false;
        if (!IsUsableWorldPosition(destination, -200.0f, 2000.0f)) return false;
        if (!IsFiniteFloat(speed)) speed = 12.0f;
        speed = ClampFloatValue(speed, 1.0f, 80.0f, 12.0f);
        drivingStyle = ClampIntValue(drivingStyle, 0, 0x7FFFFFFF);
        if (!IsFiniteFloat(stoppingRange)) stoppingRange = 10.0f;
        stoppingRange = ClampFloatValue(stoppingRange, 0.5f, 200.0f, 10.0f);
        return SafeNativeVoidRuntime(module, "task drive to coord", [&](){ AI::TASK_VEHICLE_DRIVE_TO_COORD_LONGRANGE(driver, vehicle, destination.x, destination.y, destination.z, speed, drivingStyle, stoppingRange); });
    }

    static int NormalizeTaskSequenceDuration(int durationMs)
    {
        if (durationMs < 0) return -1;
        if (durationMs == 0) return 1000;
        return ClampIntValue(durationMs, 250, 1200000);
    }

    static bool SafeTaskPlayAnim(Ped ped, const std::string& dict, const std::string& name, int duration, int flags, const std::string& module = "animation")
    {
        if (!IsUsablePedHandle(ped, true, false, true)) return false;
        if (dict.empty() || name.empty() || dict.size() > 96 || name.size() > 96) return false;
        duration = NormalizeTaskSequenceDuration(duration);
        flags = ClampIntValue(flags, 0, 0x3FFFFFFF);
        return SafeNativeVoidRuntime(module, "task play anim", [&](){ AI::TASK_PLAY_ANIM(ped, (char*)dict.c_str(), (char*)name.c_str(), 8.0f, -8.0f, duration, flags, 0.0f, false, false, false); });
    }

    static int SafeGetPedNativeInt(Ped ped, int fallback, const std::string& module, const std::string& action, const std::function<int()>& fn, bool allowPlayer = true)
    {
        if (!IsUsablePedHandle(ped, allowPlayer, false, false)) return fallback;
        try
        {
            int value = fn();
            if (action.find("count") != std::string::npos)
            {
                if (value < 0)
                {
                    ReportCore2(core::ErrorSeverity::Warning, module, action, "Ped variation count was negative");
                    return 0;
                }
                const int maxVariationCount = cfg.unlockMpHeadBlendParents ? 16384 : 4096;
                if (value > maxVariationCount)
                {
                    ReportCore2(core::ErrorSeverity::Warning, module, action, "Ped variation count was clamped");
                    return maxVariationCount;
                }
            }
            return value;
        }
        catch (...)
        {
            ReportCore2(core::ErrorSeverity::Warning, module, action, "Ped getter failed safely");
            return fallback;
        }
    }

    static bool SafeSetPedComponentVariationRuntime(Ped ped, int component, int drawable, int texture, int palette, const std::string& module = "outfit")
    {
        if (!IsUsablePedHandle(ped, true, false, false)) return false;
        if (component < 0 || component > 11) return false;

        // Enhanced builds and addon MPMale/MPFemale heads can expose null/empty
        // component branches. Never feed a negative/null drawable into the setter.
        int maxDrawables = SafeGetPedNativeInt(ped, 0, module, "get component drawable count", [&](){ return (int)PED::GET_NUMBER_OF_PED_DRAWABLE_VARIATIONS(ped, component); });
        if (maxDrawables <= 0)
        {
            DebugLog(module, "component variation", "blocked null component " + std::to_string(component));
            return false;
        }
        drawable = ClampIntValue(drawable, 0, maxDrawables - 1);
        int maxTextures = SafeGetPedNativeInt(ped, 0, module, "get component texture count", [&](){ return (int)PED::GET_NUMBER_OF_PED_TEXTURE_VARIATIONS(ped, component, drawable); });
        texture = maxTextures > 0 ? ClampIntValue(texture, 0, maxTextures - 1) : 0;
        palette = ClampIntValue(palette, 0, 3);
        return SafePedRuntimeNative(ped, module, "set ped component variation", [&](){ PED::SET_PED_COMPONENT_VARIATION(ped, component, drawable, texture, palette); }, true, false);
    }

    static bool SafeClearPedPropRuntime(Ped ped, int prop, const std::string& module = "outfit")
    {
        if (!IsUsablePedHandle(ped, true, false, false)) return false;
        if (prop < 0 || prop > 7) return false;
        return SafePedRuntimeNative(ped, module, "clear ped prop", [&](){ PED::CLEAR_PED_PROP(ped, prop); }, true, false);
    }

    static bool SafeSetPedPropIndexRuntime(Ped ped, int prop, int drawable, int texture, bool attach = true, const std::string& module = "outfit")
    {
        if (!IsUsablePedHandle(ped, true, false, false)) return false;
        if (prop < 0 || prop > 7) return false;
        if (drawable < 0) return SafeClearPedPropRuntime(ped, prop, module);
        int maxDrawables = SafeGetPedNativeInt(ped, 0, module, "get prop drawable count", [&](){ return (int)PED::GET_NUMBER_OF_PED_PROP_DRAWABLE_VARIATIONS(ped, prop); });
        if (maxDrawables <= 0)
        {
            DebugLog(module, "ped prop", "blocked null prop " + std::to_string(prop));
            return SafeClearPedPropRuntime(ped, prop, module);
        }
        drawable = ClampIntValue(drawable, 0, maxDrawables - 1);
        int maxTextures = SafeGetPedNativeInt(ped, 0, module, "get prop texture count", [&](){ return (int)PED::GET_NUMBER_OF_PED_PROP_TEXTURE_VARIATIONS(ped, prop, drawable); });
        texture = maxTextures > 0 ? ClampIntValue(texture, 0, maxTextures - 1) : 0;
        return SafePedRuntimeNative(ped, module, "set ped prop", [&](){ PED::SET_PED_PROP_INDEX(ped, prop, drawable, texture, attach); }, true, false);
    }

