    static bool SafeSetInfiniteAmmoRuntime(Ped ped, bool infiniteAmmo, bool infiniteClip, const std::string& module, bool forceWeaponHashSync)
    {
        if (!IsUsablePedHandle(ped, true, false, false)) return false;

        bool ok = true;
        ok = SafePedRuntimeNative(ped, module, "set infinite ammo clip", [&](){ WEAPON::SET_PED_INFINITE_AMMO_CLIP(ped, infiniteClip); }, true, false) && ok;

        // SET_PED_INFINITE_AMMO is weapon-hash scoped, but No Reload only needs the
        // clip native above. Do not scan the whole weapon catalog every frame when
        // only No Reload is active. Force weapon-hash sync only for explicit
        // Infinite Ammo enable/disable transitions.
        if (!infiniteAmmo && !forceWeaponHashSync) return ok;

        // SET_PED_INFINITE_AMMO is weapon-hash scoped. Passing 0 can leave Infinite Ammo
        // looking enabled in the menu while only the clip/no-reload part actually works.
        // Apply it to the current weapon and every known weapon currently carried by the player.
        std::vector<Hash> targets;
        auto addTarget = [&](Hash weapon)
        {
            if (weapon == 0) return;
            if (std::find(targets.begin(), targets.end(), weapon) == targets.end()) targets.push_back(weapon);
        };

        Hash currentWeapon = 0;
        if (SafeGetCurrentPedWeapon(ped, currentWeapon)) addTarget(currentWeapon);

        for (const auto& weaponName : AllKnownWeaponNames())
        {
            Hash weapon = H(weaponName);
            if (weapon == 0) continue;
            bool hasWeapon = SafeNativeValueRuntime<bool>(false, module, "has weapon for infinite ammo", [&](){ return WEAPON::HAS_PED_GOT_WEAPON(ped, weapon, false); });
            if (hasWeapon) addTarget(weapon);
        }

        if (targets.empty() && currentWeapon != 0) addTarget(currentWeapon);

        for (Hash weapon : targets)
        {
            ok = SafePedRuntimeNative(ped, module, "set infinite ammo for weapon", [&](){ WEAPON::SET_PED_INFINITE_AMMO(ped, infiniteAmmo, weapon); }, true, false) && ok;
        }
        return ok;
    }

