    static std::string SafeTeleportPointName(std::string name, const std::string& fallback)
    {
        name = NormalizeFlatText(name, 64, fallback);
        for (char& c : name)
            if (c == '|' || c == '\r' || c == '\n' || c == '\t') c = ' ';
        name = Trim(name);
        return name.empty() ? fallback : name;
    }

    static bool IsUsableTeleportPoint(const LocationPreset& loc)
    {
        Vector3 pos{}; pos.x = loc.x; pos.y = loc.y; pos.z = loc.z;
        return IsUsableRuntimeWorldPosition(pos);
    }

    static std::string TeleportPointDedupKey(const LocationPreset& loc)
    {
        std::string safeName = SafeTeleportPointName(loc.name, "Saved Teleport");
        std::transform(safeName.begin(), safeName.end(), safeName.begin(), [](unsigned char c){ return (char)std::tolower(c); });
        std::stringstream ss;
        ss << safeName << "|"
           << (int)std::floor(loc.x + 0.5f) << "|"
           << (int)std::floor(loc.y + 0.5f) << "|"
           << (int)std::floor(loc.z + 0.5f);
        return ss.str();
    }

    static void NormalizeTeleportPointList(std::vector<LocationPreset>& list, int limit)
    {
        const int safeLimit = std::max(1, limit);
        std::vector<LocationPreset> clean;
        std::vector<std::string> seen;
        clean.reserve(std::min((int)list.size(), safeLimit));
        for (LocationPreset loc : list)
        {
            if (!IsUsableTeleportPoint(loc)) continue;
            Vector3 fallback = EmergencyRecoveryLandmark();
            Vector3 pos{}; pos.x = loc.x; pos.y = loc.y; pos.z = loc.z;
            pos = SanitizeRuntimeVector(pos, fallback);
            loc.name = SafeTeleportPointName(loc.name, "Saved Teleport");
            loc.x = pos.x; loc.y = pos.y; loc.z = pos.z;
            loc.heading = NormalizeHeading(loc.heading, 0.0f);
            std::string key = TeleportPointDedupKey(loc);
            if (std::find(seen.begin(), seen.end(), key) != seen.end()) continue;
            seen.push_back(key);
            clean.push_back(loc);
            if ((int)clean.size() >= safeLimit) break;
        }
        list.swap(clean);
    }

    static std::string TeleportPointLine(const LocationPreset& loc)
    {
        Vector3 fallback = EmergencyRecoveryLandmark();
        Vector3 pos{}; pos.x = loc.x; pos.y = loc.y; pos.z = loc.z;
        pos = SanitizeRuntimeVector(pos, fallback);
        std::stringstream ss;
        ss << SafeTeleportPointName(loc.name, "Saved Teleport") << "|"
           << std::fixed << std::setprecision(3) << pos.x << "|" << pos.y << "|" << pos.z << "|" << NormalizeHeading(loc.heading, 0.0f);
        return ss.str();
    }

    static bool ParseTeleportPointLine(const std::string& line, LocationPreset& loc)
    {
        std::string trimmed = Trim(line);
        if (trimmed.empty() || trimmed[0] == ';' || trimmed[0] == '#') return false;
        auto p = Split(trimmed, '|');
        if (p.size() < 5) return false;
        float x = 0.0f, y = 0.0f, z = 0.0f, heading = 0.0f;
        if (!TryParseFloatStrict(StripInlineCommentValue(p[1]), x) || !TryParseFloatStrict(StripInlineCommentValue(p[2]), y) ||
            !TryParseFloatStrict(StripInlineCommentValue(p[3]), z) || !TryParseFloatStrict(StripInlineCommentValue(p[4]), heading)) return false;
        Vector3 fallback = EmergencyRecoveryLandmark();
        Vector3 pos{}; pos.x = x; pos.y = y; pos.z = z;
        if (!IsUsableRuntimeWorldPosition(pos)) return false;
        pos = SanitizeRuntimeVector(pos, fallback);
        loc.name = SafeTeleportPointName(p[0], "Saved Teleport");
        loc.x = pos.x; loc.y = pos.y; loc.z = pos.z; loc.heading = NormalizeHeading(heading, 0.0f);
        return true;
    }

    static void TrimTeleportPointList(std::vector<LocationPreset>& list, int limit)
    {
        NormalizeTeleportPointList(list, limit);
    }

    static bool SaveTeleportPointList(const std::string& path, const std::vector<LocationPreset>& list, int limit)
    {
        std::vector<LocationPreset> clean = list;
        NormalizeTeleportPointList(clean, limit);
        std::vector<std::string> lines;
        lines.push_back("; Cao Urban Trainer teleport points");
        for (const auto& loc : clean)
            lines.push_back(TeleportPointLine(loc));
        return AtomicWriteLines(path, lines, true);
    }

    static void LoadTeleportPointList(const std::string& path, std::vector<LocationPreset>& list, int limit)
    {
        list.clear();
        int safeLimit = std::max(1, limit);
        std::vector<std::string> lines;
        ReadTextLinesSafe(path, lines);
        for (const std::string& line : lines)
        {
            LocationPreset loc{};
            if (!ParseTeleportPointLine(line, loc)) continue;
            list.push_back(loc);
        }
        NormalizeTeleportPointList(list, safeLimit);
    }

    static std::string TeleportPointDisplay(const LocationPreset& loc)
    {
        std::stringstream ss;
        ss << loc.name << " (" << std::fixed << std::setprecision(0) << loc.x << ", " << loc.y << ", " << loc.z << ")";
        return ss.str();
    }

    static LocationPreset CurrentTeleportPoint(const std::string& name)
    {
        LocationPreset loc{};
        loc.name = name.empty() ? "Current Location" : name;
        loc.z = -9999.0f;
        Entity ent = PlayerTeleportEntity();
        if (!ent || !core::Exists((Entity)(ent)))
        {
            Ped p = 0;
            if (GetPlayerPedSafe(p)) ent = (Entity)p;
        }
        if (!ent || !core::Exists((Entity)(ent))) return loc;
        Vector3 pos{};
        if (!TryGetEntityTeleportCoords(ent, pos)) return loc;
        pos = SanitizeRuntimeVector(pos, EmergencyRecoveryLandmark());
        loc.x = pos.x; loc.y = pos.y; loc.z = pos.z;
        loc.heading = NormalizeHeading((float)core::SafeGetEntityHeading((Entity)(ent), 0.0f), 0.0f);
        return loc;
    }

