    static bool SaveTeleportHistory()
    {
        TrimTeleportPointList(st.teleportHistory, cfg.teleportHistoryLimit);
        return SaveTeleportPointList(TeleportHistoryPath(), st.teleportHistory, cfg.teleportHistoryLimit);
    }

    static void LoadTeleportFavoritesAndHistory()
    {
        NormalizeTeleportRuntimeState();
        LoadTeleportPointList(TeleportFavoritesPath(), st.teleportFavorites, cfg.teleportFavoriteLimit);
        LoadTeleportPointList(TeleportHistoryPath(), st.teleportHistory, cfg.teleportHistoryLimit);
        NormalizeTeleportRuntimeState();
    }

    static void RecordTeleportHistory(const std::string& label, const Vector3& pos, float heading)
    {
        if (!cfg.teleportHistoryEnabled) return;
        LocationPreset loc{};
        loc.name = label.empty() ? "Teleport" : label;
        loc.x = pos.x; loc.y = pos.y; loc.z = pos.z; loc.heading = NormalizeHeading(heading, 0.0f);
        if (!IsUsableTeleportPoint(loc)) return;

        const std::string newKey = TeleportPointDedupKey(loc);
        st.teleportHistory.erase(std::remove_if(st.teleportHistory.begin(), st.teleportHistory.end(), [&](const LocationPreset& existing)
        {
            return TeleportPointDedupKey(existing) == newKey ||
                (std::fabs(existing.x - loc.x) < 1.0f && std::fabs(existing.y - loc.y) < 1.0f && std::fabs(existing.z - loc.z) < 1.5f);
        }), st.teleportHistory.end());
        st.teleportHistory.insert(st.teleportHistory.begin(), loc);
        TrimTeleportPointList(st.teleportHistory, cfg.teleportHistoryLimit);
        st.selectedTeleportHistory = 0;
        if (!SaveTeleportHistory()) Log("Teleport history save failed.");
    }

    static void AddCurrentTeleportFavorite()
    {
        NormalizeTeleportRuntimeState();
        Entity ent = PlayerTeleportEntity();
        if (!ent || !core::Exists((Entity)(ent))) { Notify("Teleport target unavailable."); return; }
        LocationPreset loc = CurrentTeleportPoint("Favorite " + std::to_string((int)st.teleportFavorites.size() + 1));
        if (!IsUsableTeleportPoint(loc)) { Notify("Teleport favorite not added: current position invalid."); return; }
        const std::string newKey = TeleportPointDedupKey(loc);
        st.teleportFavorites.erase(std::remove_if(st.teleportFavorites.begin(), st.teleportFavorites.end(), [&](const LocationPreset& existing)
        {
            return TeleportPointDedupKey(existing) == newKey ||
                (std::fabs(existing.x - loc.x) < 1.0f && std::fabs(existing.y - loc.y) < 1.0f && std::fabs(existing.z - loc.z) < 1.5f);
        }), st.teleportFavorites.end());
        st.teleportFavorites.insert(st.teleportFavorites.begin(), loc);
        TrimTeleportPointList(st.teleportFavorites, cfg.teleportFavoriteLimit);
        st.selectedTeleportFavorite = 0;
        if (!SaveTeleportFavorites()) { Notify("Teleport favorite save failed."); return; }
        Notify("Teleport favorite added.");
    }

    static void TeleportSelectedFavorite()
    {
        NormalizeTeleportRuntimeState();
        if (st.teleportFavorites.empty()) { Notify("No teleport favorites."); return; }
        if (st.selectedTeleportFavorite < 0 || st.selectedTeleportFavorite >= (int)st.teleportFavorites.size()) st.selectedTeleportFavorite = 0;
        LocationPreset loc = st.teleportFavorites[st.selectedTeleportFavorite];
        TeleportPreset(loc);
    }

    static void DeleteSelectedTeleportFavorite()
    {
        NormalizeTeleportRuntimeState();
        if (st.teleportFavorites.empty()) { Notify("No teleport favorites."); return; }
        if (st.selectedTeleportFavorite < 0 || st.selectedTeleportFavorite >= (int)st.teleportFavorites.size()) st.selectedTeleportFavorite = 0;
        st.teleportFavorites.erase(st.teleportFavorites.begin() + st.selectedTeleportFavorite);
        if (st.selectedTeleportFavorite >= (int)st.teleportFavorites.size()) st.selectedTeleportFavorite = std::max(0, (int)st.teleportFavorites.size() - 1);
        if (!SaveTeleportFavorites()) { Notify("Teleport favorite save failed."); return; }
        Notify("Teleport favorite deleted.");
    }

