    static void ToggleNoWanted()
    {
        PushWantedUndo("No Wanted Toggle");
        st.noWanted = !st.noWanted;
        if (st.noWanted)
        {
            st.freezeWanted = false;
            st.maxWantedLevel = 0;
            st.selectedWantedLevel = 0;
            st.frozenWantedLevel = 0;
            SafeClearPlayerWantedLevelRuntime();
            SafeSetMaxWantedLevelRuntime(0);
            SafeSetWantedLevelMultiplierRuntime(0.0f, "wanted_toggle");
            SafeSetDispatchCopsForPlayerRuntime(false, "wanted_toggle");
            SafeSetDispatchServicesRuntime(false, "wanted_toggle");
        }
        else
        {
            if (st.maxWantedLevel <= 0) st.maxWantedLevel = 5;
            // Turning No Wanted OFF should restore normal police/crime response only
            // for non-manual suppressors. Explicit Police/Everyone Ignore toggles are
            // player-owned runtime state and must survive this transition.
            if (!st.policeIgnoreManual) st.policeIgnore = false;
            if (!st.everyoneIgnoreManual) st.everyoneIgnore = false;
            EffectiveNaturalMaxWantedLevelRuntime();
            RestoreNaturalWantedSuppressionRuntime("wanted_toggle");
        }
        Notify("No Wanted: " + OnOff(st.noWanted));
    }

