    static void ApplyRuntimeStateNow()
    {
        NormalizeWorldControlRuntimeState();
        Ped p = 0;
        const bool playerPedOk = GetPlayerPedSafe(p);
        if (!playerPedOk)
        {
            // BUGFIX 189: During Story Mode loading PLAYER_PED_ID can be unavailable
            // while preset/profile restore is already running from Init(). Do not touch
            // player/world/wanted natives yet; defer once the world actually exists.
            g_pendingRuntimeStateApplyAfterWorldReady = true;
            const DWORD now = GetTickCount();
            if (g_lastDeferredRuntimeStateLogTick == 0 ||
                core::TickElapsed(now, g_lastDeferredRuntimeStateLogTick, 5000u))
            {
                g_lastDeferredRuntimeStateLogTick = now;
                Log("Runtime state apply deferred: player ped/world not ready yet.");
            }
            return;
        }
        g_pendingRuntimeStateApplyAfterWorldReady = false;
        // BUGFIX 190: teleport normalization can sanitize last-destination data
        // without touching player coords now, but keep it after the world-ready
        // guard so future edits cannot reintroduce boot-time player native calls.
        NormalizeTeleportRuntimeState();

        ApplyPlayerGodStateNow();
        SafeSetWantedLevelMultiplierRuntime(st.wantedMultiplierBoost ? 2.5f : 1.0f);
        SafeSetRunSprintMultiplierRuntime(st.fastRun ? 1.49f : 1.0f);
        SafeSetSwimMultiplierRuntime(st.fastSwim ? 1.49f : 1.0f);
        // BUGFIX 183: normalize wanted/dispatch suppression first, then apply the
        // final ignore flags. This avoids a one-tick stale Ignore ON pulse when a
        // profile contains non-manual/runtime-owned suppressors that should be cleaned.
        RestoreNaturalWantedSuppressionRuntime("runtime_apply");
        SafeSetEveryoneIgnorePlayerRuntime(st.everyoneIgnore);
        SafeSetPoliceIgnorePlayerRuntime(st.policeIgnore);

        if (st.noWanted)
        {
            SafeClearPlayerWantedLevelRuntime();
        }
        else if (st.freezeWanted)
        {
            st.frozenWantedLevel = ClampWantedLevelToMax(st.frozenWantedLevel);
            SafeSetPlayerWantedLevelRuntime(st.frozenWantedLevel, true);
        }

        if (playerPedOk)
        {
            core::safe_native::SetVisible((Entity)p, !st.invisible, false, &g_coreErrors, "player");
            core::safe_native::SetPedCanRagdoll(p, !st.noRagdoll, &g_coreErrors, "player");
            ApplyWeaponAmmoRuntimeFlags(p);

            if (core::IsPedInAnyVehicle((Ped)(p), false))
            {
                Vehicle v = core::GetVehiclePedIsIn((Ped)(p), false);
                if (v && core::Exists((Entity)(v)))
                    core::safe_native::SetInvincible((Entity)(v), st.vehicleGodMode, &g_coreErrors, "full_audit");
            }
        }

        SafePauseClockRuntime(st.freezeTime);
        if (st.freezeWeather && !weatherTypes.empty())
            SafeSetOverrideWeatherRuntime(CurrentWeatherName());
        else
            SafeClearOverrideWeatherRuntime();
        SafeSetBlackoutRuntime(st.blackout);
        SafeSetGravityLevelRuntime(st.lowGravity ? 3 : 0);
        SafeSetTimeScaleRuntime(st.cinematicSlowMotion ? SafeCinematicTimeScale() : 1.0f);
    }

    static void DisableRuntimeEffectsForTrainerOff()
    {
        ClearRuntimeEffectFlags(true);
        Ped p = 0;
        const bool playerPedOk = GetPlayerPedSafe(p);
        SafeSetPlayerInvincibleRuntime(false);
        if (playerPedOk)
        {
            core::safe_native::SetInvincible((Entity)(p), false, &g_coreErrors, "full_audit");
            core::safe_native::SetProofs((Entity)p, false, false, false, false, false, false, false, false, &g_coreErrors, "player");
            core::safe_native::SetVisible((Entity)p, true, false, &g_coreErrors, "player");
            core::safe_native::SetPedCanRagdoll(p, true, &g_coreErrors, "player");
            SafeSetInfiniteAmmoRuntime(p, false, false, "weapon_runtime", true);
            if (core::IsPedInAnyVehicle((Ped)(p), false))
            {
                Vehicle v = core::GetVehiclePedIsIn((Ped)(p), false);
                if (core::Exists((Entity)(v))) core::safe_native::SetInvincible((Entity)(v), false, &g_coreErrors, "full_audit");
            }
        }
        st.maxWantedLevel = 5;
        SafeSetMaxWantedLevelRuntime(5, "runtime_cleanup");
        SafeSetEveryoneIgnorePlayerRuntime(false);
        SafeSetPoliceIgnorePlayerRuntime(false);
        SafeSetWantedLevelMultiplierRuntime(1.0f);
        SafeSetDispatchCopsForPlayerRuntime(true, "player_reset");
        SafeSetDispatchServicesRuntime(true, "player_reset");
        SafeSetRunSprintMultiplierRuntime(1.0f);
        SafeSetSwimMultiplierRuntime(1.0f);
        SafePauseClockRuntime(false);
        SafeClearOverrideWeatherRuntime();
        SafeSetTimeScaleRuntime(1.0f);
        SafeSetGravityLevelRuntime(0);
        SafeSetBlackoutRuntime(false);
        StopMovieSceneCamera();
        DisableFreeCamera();
        DisableCinematicTools();
        CancelSafeSpawnPreview(false);
    }

