    static bool GetPlayerPedSafe(Ped& p)
    {
        p = 0;
        try
        {
            Ped candidate = SafePlayerPedIdRuntime();
            if (!candidate || !core::IsPed((Entity)candidate)) return false;
            p = candidate;
            return true;
        }
        catch (...)
        {
            p = 0;
            return false;
        }
    }

