    static void TickDeferredDispatchServiceRestore()
    {
        if (!g_pendingDispatchServiceRestore)
            return;

        const DWORD now = GetTickCount();
        if (!cfg.wantedPoliceRepairDispatchServices || !cfg.wantedPoliceRepairDispatchServiceNative)
        {
            g_pendingDispatchServiceRestore = false;
            g_dispatchServiceRestoreNextService = 1;
            return;
        }
        if (!g_heavyRuntimeWorldReadyOnce || g_firstHeavyRuntimeReadyTick == 0 ||
            !core::TickElapsed(now, g_firstHeavyRuntimeReadyTick, 30000u))
        {
            return;
        }
        if (g_dispatchServiceRestoreHardCooldownUntil != 0 && !core::TickReached(now, g_dispatchServiceRestoreHardCooldownUntil))
            return;
        if (g_lastDispatchServiceRestoreAttemptTick != 0 &&
            !core::TickElapsed(now, g_lastDispatchServiceRestoreAttemptTick, 650u))
        {
            return;
        }
        g_lastDispatchServiceRestoreAttemptTick = now;

        Ped p = 0;
        if (!GetPlayerPedSafe(p) || !IsUsablePedHandle(p, true, true, true))
            return;

        // Crash-safe mode: never fire all 15 dispatch services in one tick. Apply one
        // service per interval and abort into a long cooldown if even one call fails.
        const int service = ClampIntValue(g_dispatchServiceRestoreNextService, 1, 15);
        if (!SafeEnableDispatchServiceRuntime(service, g_pendingDispatchServiceRestoreEnabled, "wanted_dispatch_restore"))
        {
            g_dispatchServiceRestoreHardCooldownUntil = core::TickAdd(now, 60000u);
            Log("Dispatch service native failed; pausing advanced dispatch restore for crash safety.");
            return;
        }

        if (++g_dispatchServiceRestoreNextService > 15)
        {
            g_pendingDispatchServiceRestore = false;
            g_lastDispatchServiceRestoreAttemptTick = 0;
            g_dispatchServiceRestoreNextService = 1;
            Log(std::string("Dispatch services restored after crash-safe gate: ") +
                (g_pendingDispatchServiceRestoreEnabled ? "ON" : "OFF"));
        }
    }

