    static Entity PlayerRecoveryEntity()
    {
        Ped p = 0;
        if (GetPlayerPedSafe(p) && core::IsPedInAnyVehicle((Ped)(p), false))
        {
            Vehicle v = core::GetVehiclePedIsIn((Ped)(p), false);
            Vector3 pos{};
            if (v && core::IsVehicle((Entity)v) && TryGetUsableEntityPosition((Entity)v, pos)) return (Entity)v;
        }
        return (p && core::Exists((Entity)(p))) ? (Entity)p : 0;
    }

