    static void RecoverUnfreezePlayer(bool notifyResult = true)
    {
        Ped p = 0;
        if (!GetPlayerPedSafe(p)) { if (notifyResult) Notify("Player unavailable."); return; }
        st.cinematicFreezePlayer = false;
        st.freeCamFreezePlayer = false;
        core::safe_native::Freeze((Entity)p, false, &g_coreErrors, "recovery");
        Entity ent = PlayerRecoveryEntity();
        if (ent && core::Exists((Entity)(ent))) core::safe_native::Freeze(ent, false, &g_coreErrors, "recovery");
        if (core::IsPedInAnyVehicle((Ped)(p), false))
        {
            Vehicle v = core::GetVehiclePedIsIn((Ped)(p), false);
            if (v && core::Exists((Entity)(v))) core::safe_native::Freeze((Entity)v, false, &g_coreErrors, "recovery");
        }
        if (notifyResult) Notify("Player unfrozen.");
    }

    static void RecoverFixVisibilityCollision(bool notifyResult = true)
    {
        Ped p = 0;
        if (!GetPlayerPedSafe(p)) { if (notifyResult) Notify("Player unavailable."); return; }
        st.invisible = false;
        core::safe_native::SetVisible((Entity)p, true, false, &g_coreErrors, "recovery");
        core::safe_native::SetCollision((Entity)p, true, true, &g_coreErrors, "recovery");
        if (core::IsPedInAnyVehicle((Ped)(p), false))
        {
            Vehicle v = core::GetVehiclePedIsIn((Ped)(p), false);
            if (v && core::Exists((Entity)(v)))
            {
                core::safe_native::SetVisible((Entity)v, true, false, &g_coreErrors, "recovery");
                core::safe_native::SetCollision((Entity)v, true, true, &g_coreErrors, "recovery");
            }
        }
        if (notifyResult) Notify("Visibility and collision restored.");
    }

    static void RecoverSafeGroundTeleport(bool notifyResult = true)
    {
        Entity ent = PlayerRecoveryEntity();
        if (!ent || !core::Exists((Entity)(ent))) { if (notifyResult) Notify("Teleport target unavailable."); return; }

        Vector3 pos = core::SafeGetEntityCoords((Entity)(ent), SafeWorldFallbackPosition(), true);
        float heading = core::SafeGetEntityHeading((Entity)(ent), 0.0f);
        const bool isVehicle = core::IsVehicle((Entity)(ent));

        Vector3 fallback = EmergencyRecoveryLandmark();
        if (st.hasLastSafePlayerPos && IsRecoveryFallbackCandidate(st.lastSafePlayerPos))
        {
            fallback = st.lastSafePlayerPos;
        }

        Vector3 safe = SanitizeVector(pos, fallback);
        if (!IsRecoveryFallbackCandidate(safe))
            safe = fallback;

        SafeRequestCollisionRuntime(safe, "collision_request");
        safe.z = ResolveGroundZ(safe.x, safe.y, safe.z + 5.0f) + (isVehicle ? 0.55f : 1.0f);

        core::safe_native::Freeze(ent, false, &g_coreErrors, "recovery");
        core::safe_native::SetCollision(ent, true, true, &g_coreErrors, "recovery");
        core::safe_native::SetVelocity(ent, Vector3{}, &g_coreErrors, "recovery");
        if (!core::safe_native::SetCoords(ent, safe, false, &g_coreErrors, "recovery")) return;
        if (!core::safe_native::SetHeading(ent, heading, &g_coreErrors, "recovery")) return;
        if (isVehicle)
        {
            SafeSetVehicleOnGround((Vehicle)ent, "full_audit");
            SafeSetVehicleEngineOn((Vehicle)ent, true, "full_audit");
        }
        st.lastSafePlayerPos = safe;
        st.hasLastSafePlayerPos = true;
        if (notifyResult) Notify("Moved to safe ground.");
    }

    static void RecoverLeaveCurrentVehicle(bool notifyResult = true)
    {
        Ped p = 0;
        if (!GetPlayerPedSafe(p)) { if (notifyResult) Notify("Player unavailable."); return; }
        if (!core::IsPedInAnyVehicle((Ped)(p), false)) { if (notifyResult) Notify("Player is not in a vehicle."); return; }
        Vehicle v = core::GetVehiclePedIsIn((Ped)(p), false);
        if (!v || !core::Exists((Entity)(v))) { if (notifyResult) Notify("Vehicle unavailable."); return; }
        core::safe_native::ClearPedTasks(p, false, &g_coreErrors, "runtime");
        SafeTaskLeaveVehicle(p, v, 16, "full_audit");
        if (notifyResult) Notify("Exit vehicle task sent.");
    }

    static void RecoverRepairCurrentVehicle(bool notifyResult = true)
    {
        Ped p = 0;
        if (!GetPlayerPedSafe(p)) { if (notifyResult) Notify("Player unavailable."); return; }
        if (!core::IsPedInAnyVehicle((Ped)(p), false)) { if (notifyResult) Notify("Sit in vehicle first."); return; }
        Vehicle v = core::GetVehiclePedIsIn((Ped)(p), false);
        if (!v || !core::Exists((Entity)(v))) { if (notifyResult) Notify("Vehicle unavailable."); return; }
        if (!core::safe_native::RepairVehicle(v, nullptr, "vehicle"))
        {
            ReportCore2(core::ErrorSeverity::Warning, "vehicle", "repair current vehicle", "SafeNative rejected current vehicle repair.");
            if (notifyResult) Notify("Vehicle repair rejected by Core 2.0 safety.");
            return;
        }
        SafeSetVehicleDirtLevel(v, 0.0f, "vehicle");
        if (notifyResult) Notify("Current vehicle repaired.");
    }

