    static void ToggleWeaponFlagWithUndo(bool& flag, const std::string& label)
    {
        PushWeaponUndo(label);
        const bool hadAmmoRuntime = st.infiniteAmmo || st.noReload;
        const bool wasInfiniteAmmo = st.infiniteAmmo;
        const bool togglingInfiniteAmmo = (&flag == &st.infiniteAmmo);
        flag = !flag;
        const bool hasAmmoRuntime = st.infiniteAmmo || st.noReload;
        Ped p = 0;
        if (GetPlayerPedSafe(p))
        {
            if (togglingInfiniteAmmo && wasInfiniteAmmo && !st.infiniteAmmo)
                SafeSetInfiniteAmmoRuntime(p, false, st.noReload, "weapon_runtime", true);
            else if (!hasAmmoRuntime && hadAmmoRuntime)
                SafeSetInfiniteAmmoRuntime(p, false, false, "weapon_runtime", true);
            else
                ApplyWeaponAmmoRuntimeFlags(p);
        }
        Notify(label + ": " + OnOff(flag));
    }

    static void ToggleInfiniteAmmoUndo() { ToggleWeaponFlagWithUndo(st.infiniteAmmo, "Infinite Ammo"); }
    static void ToggleNoReloadUndo() { ToggleWeaponFlagWithUndo(st.noReload, "No Reload"); }
    static void ToggleExplosiveAmmoUndo() { ToggleWeaponFlagWithUndo(st.explosiveAmmo, "Explosive Ammo"); }
