    static int DismissPeds(std::vector<Ped>& list)
    {
        // Copy first: DeletePedSafely/RemoveTrackedEntity can erase from the same tracking lists.
        // Iterating the original vector while erasing from it can invalidate iterators and leave stale handles.
        std::vector<Ped> targets = list;
        std::vector<Ped> kept;
        list.clear();

        int deleted = 0;
        for (Ped ped : targets)
        {
            if (!ped || !core::Exists((Entity)(ped)) || !core::IsPed((Entity)ped))
            {
                if (ped) RemoveTrackedEntity((Entity)ped);
                continue;
            }
            if (IsActiveGameModeEntity((Entity)ped))
            {
                if (std::find(kept.begin(), kept.end(), ped) == kept.end()) kept.push_back(ped);
                continue;
            }
            if (!core::IsPlayerPed((Entity)(ped)))
            {
                if (DeletePedSafely(ped))
                {
                    RemoveTrackedEntity((Entity)ped);
                    ++deleted;
                }
                else if (core::Exists((Entity)(ped)) && std::find(kept.begin(), kept.end(), ped) == kept.end())
                {
                    kept.push_back(ped);
                }
            }
            else
            {
                RemoveTrackedEntity((Entity)ped);
            }
        }
        list = kept;
        return deleted;
    }

    static int DismissBodyguards()
    {
        // When only the bodyguards are dismissed, their transport should not become an
        // orphaned mission entity. Keep it tracked so later cleanup/recovery can see it.
        TrackSpawnedVehicleIfAlive(st.bodyguardProtectedVehicle);
        TrackSpawnedVehicleIfAlive(st.lastPlayerVehicleForBodyguards);
        std::vector<Ped> dismissedBodyguardTargets = st.bodyguards;
        for (Ped g : dismissedBodyguardTargets)
        {
            RemoveFriendlyNpcRuntime(g);
            ClearBodyguardRuntimeState(g);
        }
        st.bodyguardRoles.clear();
        st.bodyguardLastCombatRefreshTick.clear();
        st.bodyguardLastRecoveryPos.clear();
        st.bodyguardLastMoveTick.clear();
        int dismissed = DismissPeds(st.bodyguards);
        st.playerWasInVehicleForBodyguards = false;
        st.lastPlayerVehicleForBodyguards = 0;
        st.bodyguardProtectedVehicle = 0;
        st.bodyguardHoldPositionActive = false;
        st.bodyguardCommandMode = BodyguardCommandMode::Follow;
        st.lastBodyguardVehicleCommandTick = 0;
        st.lastBodyguardCommandTick = 0;
        return dismissed;
    }

    static int DismissVehicles(std::vector<Vehicle>& list, bool protectActiveChauffeur = true)
    {
        // Keep protected vehicles (player/current escort/chauffeur by default), delete and untrack everything else.
        std::vector<Vehicle> targets = list;
        std::vector<Vehicle> kept;
        list.clear();

        int deleted = 0;
        for (Vehicle vehicle : targets)
        {
            if (!vehicle || !core::Exists((Entity)(vehicle)) || !core::IsVehicle((Entity)vehicle))
            {
                if (vehicle) RemoveTrackedEntity((Entity)vehicle);
                continue;
            }

            if (ShouldProtectVehicleFromCleanup(vehicle, protectActiveChauffeur))
            {
                if (std::find(kept.begin(), kept.end(), vehicle) == kept.end()) kept.push_back(vehicle);
                continue;
            }

            if (DeleteVehicleSafely(vehicle, false))
            {
                RemoveTrackedEntity((Entity)vehicle);
                ++deleted;
            }
            else if (core::Exists((Entity)(vehicle)) && std::find(kept.begin(), kept.end(), vehicle) == kept.end())
            {
                kept.push_back(vehicle);
            }
        }

        list = kept;
        return deleted;
    }

