    static void ResetEverything()
    {
        Vehicle chauffeurVehicleToClean = st.chauffeurVehicle;

        StopGameMode(false, "Reset Everything", false);
        CancelSafeSpawnPreview(false);
        ClearRandomMissionPreviewState();
        StopScenarioBuilder(false);
        ResetPlayerEffects();
        ResetWeaponEffects();
        ResetVehicleEffects();
        DismissPeds(st.spawnedPeds);
        DismissBodyguards();
        DismissPeds(st.enemies);
        ClearScenario();
        ClearWorldDirector(false);
        ClearUrbanLife(false);
        ClearVehicleAI(false);
        ClearPoliceRealism(false);
        ClearSpawnedObjects();
        DisableFreeCamera();
        DisableCinematicTools();
        ResetWorldEffects();
        StopMissionPlaytest(false);
        ClearMissionCreator(false);
        ResetPoliceWantedEffects();
        st.battleActive = false;
        st.battleWave = 0;
        if (st.modelChanged && st.originalPlayerModel != 0) RestoreOriginalPlayerModel();
        bool chauffeurDeletedOrInvalid = !st.chauffeur || !core::Exists((Entity)(st.chauffeur));
        if (st.chauffeur && core::Exists((Entity)(st.chauffeur)) && !core::IsPlayerPed((Entity)(st.chauffeur)))
            chauffeurDeletedOrInvalid = DeleteEntityAndUntrackIfGone((Entity)st.chauffeur, true);
        if (chauffeurDeletedOrInvalid)
        {
            st.chauffeur = 0;
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
        }
        SanitizeCompanionRuntimeState();
        if (chauffeurVehicleToClean && core::Exists((Entity)(chauffeurVehicleToClean)) && !IsPlayerInVehicleEntity(chauffeurVehicleToClean))
        {
            DeleteEntityAndUntrackIfGone((Entity)chauffeurVehicleToClean, true);
        }
        DismissVehicles(st.spawnedVehicles, false);
        st.worldDirectorActive = false;
        st.worldDirectorManualPaused = false;
        st.urbanLifeActive = false;
        st.urbanLifeManualPaused = false;
        st.vehicleAIActive = false;
        st.vehicleAIManualPaused = false;
        st.policeRealismActive = false;
        st.performanceSafetyHardLimitActive = false;
        st.performanceSafetyPausedWorldDirector = false;
        st.performanceSafetyPausedUrbanLife = false;
        st.performanceSafetyPausedVehicleAI = false;
        st.lastWorldDirectorTick = GetTickCount();
        st.lastUrbanLifeTick = GetTickCount();
        st.lastVehicleAITick = GetTickCount();
        st.lastPoliceRealismCleanupTick = GetTickCount();
        st.lastPerformanceSafetyReport = "Reset complete";
        st.undoStack.clear();
        st.redoStack.clear();
        Notify("Everything reset.");
    }


    static Vector3 BodyguardFollowOffset(int index)
    {
        float base = std::max(1.5f, std::min(12.0f, cfg.bodyguardFollowDistance));
        float spread = cfg.bodyguardFormation == 0 ? base * 0.55f : (cfg.bodyguardFormation == 2 ? base * 1.15f : base * 0.85f);
        Vector3 off{};
        switch (cfg.bodyguardFormation)
        {
            case 3:
            {
                float radius = std::max(2.0f, base + 1.25f);
                float angle = ((float)(index % 8) / 8.0f) * 6.2831853f;
                off.x = std::cos(angle) * radius;
                off.y = std::sin(angle) * radius;
                break;
            }
            case 4:
                off.x = ((float)(index % 5) - 2.0f) * spread;
                off.y = -base - (float)(index / 5) * spread;
                break;
            case 5:
                off.x = (index % 2 == 0 ? -spread * 1.35f : spread * 1.35f);
                off.y = -base * 1.6f - (float)(index / 2) * spread;
                break;
            default:
                off.x = (index % 2 == 0 ? -spread : spread);
                off.y = -base - (float)(index / 2) * spread;
                break;
        }
        off.z = 0.0f;
        return off;
    }

    static BodyguardRole GetBodyguardRole(Ped g)
    {
        auto it = st.bodyguardRoles.find(g);
        if (it != st.bodyguardRoles.end()) return it->second;
        return cfg.bodyguardDefaultRole;
    }

    static BodyguardRole BodyguardRoleForSpawnIndex(int index)
    {
        if (!cfg.bodyguardUseRoles) return cfg.bodyguardDefaultRole;
        switch (index % 5)
        {
            case 1: return BodyguardRole::Shooter;
            case 2: return BodyguardRole::Medic;
            case 3: return BodyguardRole::Heavy;
            case 4: return BodyguardRole::Driver;
            default: return cfg.bodyguardDefaultRole;
        }
    }

    static std::string BodyguardWeaponLoadoutName(int index)
    {
        switch (ClampIntValue(index, 0, 4))
        {
            case 1: return "Light";
            case 2: return "Tactical";
            case 3: return "Heavy";
            case 4: return "Stealth";
            default: return "Balanced";
        }
    }

    static std::string BodyguardBlipModeName(int mode)
    {
        switch (ClampIntValue(mode, 0, 3))
        {
            case 0: return "Off";
            case 2: return "Role colours";
            case 3: return "Plain friendly";
            default: return "Role";
        }
    }

    static void CycleBodyguardWeaponLoadout()
    {
        cfg.bodyguardWeaponLoadoutIndex = (ClampIntValue(cfg.bodyguardWeaponLoadoutIndex, 0, 4) + 1) % 5;
        st.lastBodyguardManagerReport = "Loadout: " + BodyguardWeaponLoadoutName(cfg.bodyguardWeaponLoadoutIndex);
        Notify(st.lastBodyguardManagerReport);
    }

    static void CycleBodyguardBlipMode()
    {
        cfg.bodyguardBlipMode = (ClampIntValue(cfg.bodyguardBlipMode, 0, 3) + 1) % 4;
        for (Ped g : st.bodyguards)
        {
            if (IsUsablePedHandle(g, false, true, true)) EnsureFriendlyNpcBlip(g);
            else ClearFriendlyNpcBlip(g);
        }
        st.lastBodyguardManagerReport = "Blips: " + BodyguardBlipModeName(cfg.bodyguardBlipMode);
        Notify(st.lastBodyguardManagerReport);
    }

    static std::string ResolveBodyguardLoadoutWeapon(BodyguardRole role)
    {
        const int loadout = ClampIntValue(cfg.bodyguardWeaponLoadoutIndex, 0, 4);
        if (loadout == 1)
        {
            if (role == BodyguardRole::Medic || role == BodyguardRole::Driver) return "WEAPON_PISTOL";
            return "WEAPON_MICROSMG";
        }
        if (loadout == 2)
        {
            if (role == BodyguardRole::Medic) return "WEAPON_COMBATPISTOL";
            if (role == BodyguardRole::Heavy) return "WEAPON_SPECIALCARBINE";
            return "WEAPON_CARBINERIFLE";
        }
        if (loadout == 3)
        {
            if (role == BodyguardRole::Medic) return "WEAPON_SMG";
            if (role == BodyguardRole::Driver) return "WEAPON_COMBATPDW";
            if (role == BodyguardRole::Shooter) return "WEAPON_SPECIALCARBINE";
            return "WEAPON_COMBATMG";
        }
        if (loadout == 4)
        {
            if (role == BodyguardRole::Heavy) return "WEAPON_ASSAULTSMG";
            return "WEAPON_PISTOL";
        }
        if (role == BodyguardRole::Medic || role == BodyguardRole::Driver) return "WEAPON_COMBATPISTOL";
        if (role == BodyguardRole::Heavy) return "WEAPON_COMBATMG";
        if (role == BodyguardRole::Shooter) return NormalizeModelName(st.selectedWeapon, "WEAPON_CARBINERIFLE");
        return NormalizeModelName(st.selectedWeapon, "WEAPON_CARBINERIFLE");
    }

    static int ApplyCommonWeaponAttachments(Ped ped, Hash weapon, const std::string& module = "bodyguard_loadout")
    {
        if (!cfg.bodyguardApplyWeaponAttachments || !IsUsablePedHandle(ped, false, false, true) || weapon == 0) return 0;
        int applied = 0;
        const std::vector<std::string> preferred = {
            "COMPONENT_AT_PI_FLSH", "COMPONENT_AT_PI_SUPP", "COMPONENT_AT_PI_SUPP_02",
            "COMPONENT_AT_AR_FLSH", "COMPONENT_AT_AR_AFGRIP", "COMPONENT_AT_AR_SUPP", "COMPONENT_AT_AR_SUPP_02",
            "COMPONENT_AT_SCOPE_MACRO", "COMPONENT_AT_SCOPE_MEDIUM", "COMPONENT_AT_SCOPE_SMALL", "COMPONENT_AT_SCOPE_LARGE",
            "COMPONENT_AT_MUZZLE_01", "COMPONENT_AT_MUZZLE_02", "COMPONENT_AT_MUZZLE_03"
        };
        for (const std::string& compName : preferred)
        {
            Hash component = H(compName);
            if (component != 0 && SafeDoesWeaponTakeComponent(weapon, component) && !SafeHasPedGotWeaponComponent(ped, weapon, component))
            {
                if (SafeGiveWeaponComponentRuntime(ped, weapon, component, module)) ++applied;
            }
        }
        return applied;
    }

    static void ApplyConfiguredBodyguardLoadout(Ped g, BodyguardRole role, bool notifyResult)
    {
        if (!IsUsablePedHandle(g, false, false, true)) return;
        const std::string weaponName = ResolveBodyguardLoadoutWeapon(role);
        Hash weapon = H(weaponName);
        if (weapon == 0) return;
        SafeGiveWeaponToPedRuntime(g, weapon, std::max(90, cfg.bodyguardAmmo), true, "bodyguard_loadout");
        int attachments = ApplyCommonWeaponAttachments(g, weapon, "bodyguard_loadout");
        if (notifyResult)
        {
            st.lastBodyguardManagerReport = BodyguardRoleName(role) + std::string(" -> ") + weaponName + " / attachments " + std::to_string(attachments);
            Notify(st.lastBodyguardManagerReport);
        }
    }

    static void ApplyBodyguardLoadoutsNow()
    {
        int count = 0;
        for (Ped g : st.bodyguards)
        {
            if (!IsUsablePedHandle(g, false, false, true)) continue;
            ApplyConfiguredBodyguardLoadout(g, GetBodyguardRole(g), false);
            ++count;
        }
        st.lastBodyguardManagerReport = "Applied " + BodyguardWeaponLoadoutName(cfg.bodyguardWeaponLoadoutIndex) + " loadout to " + std::to_string(count) + " bodyguards.";
        Notify(st.lastBodyguardManagerReport);
    }

    static void ApplyBodyguardRoleLoadout(Ped g)
    {
        if (!IsUsablePedHandle(g, false, false, true) || !cfg.bodyguardRoleLoadouts) return;
        BodyguardRole role = GetBodyguardRole(g);
        switch (role)
        {
            case BodyguardRole::Medic:
                core::safe_native::SetPedArmour(g, 80, &g_coreErrors, "runtime");
                SafeSetPedAccuracy(g, std::max(20, std::min(80, cfg.bodyguardAccuracy - 10)), "full_audit");
                GiveWeapon(g, "WEAPON_PISTOL", std::max(90, cfg.bodyguardAmmo));
                break;
            case BodyguardRole::Heavy:
                if ((int)core::SafeGetEntityHealth((Entity)(g), 0) < cfg.bodyguardHealth)
                    core::safe_native::SetHealth((Entity)(g), std::max(cfg.bodyguardHealth, cfg.bodyguardHealth + 150), &g_coreErrors, "full_audit");
                core::safe_native::SetPedArmour(g, 100, &g_coreErrors, "bodyguards");
                SafeSetPedAccuracy(g, std::max(30, std::min(95, cfg.bodyguardAccuracy)), "full_audit");
                GiveWeapon(g, "WEAPON_COMBATMG", std::max(300, cfg.bodyguardAmmo));
                break;
            case BodyguardRole::Shooter:
                SafeSetPedAccuracy(g, std::max(40, std::min(100, cfg.bodyguardAccuracy + 15)), "full_audit");
                GiveWeapon(g, st.selectedWeapon, cfg.bodyguardAmmo);
                break;
            case BodyguardRole::Driver:
                SafePedRuntimeNative(g, "full_audit", "set driver ability", [&](){ PED::SET_DRIVER_ABILITY(g, 0.95f); });
                SafePedRuntimeNative(g, "full_audit", "set driver aggression", [&](){ PED::SET_DRIVER_AGGRESSIVENESS(g, 0.25f); });
                GiveWeapon(g, "WEAPON_PISTOL", std::max(90, cfg.bodyguardAmmo));
                break;
            default:
                GiveWeapon(g, st.selectedWeapon, cfg.bodyguardAmmo);
                break;
        }
        ApplyConfiguredBodyguardLoadout(g, role, false);
    }

    static void ConfigureBodyguard(Ped g)
    {
        if (!IsUsablePedHandle(g, false, false, true)) return;
        core::safe_native::SetMissionEntity((Entity)(g), true, true, &g_coreErrors, "full_audit");
        // BUGFIX 166: bodyguards are tracked in st.bodyguards, not duplicated in
        // st.friendlyPeds. Force the companion anti-panic profile here so a newly
        // spawned bodyguard cannot briefly inherit ambient civilian flee behaviour
        // before the next bodyguard brain tick.
        if (cfg.bodyguardRelationshipFix) ConfigureFriendlyCompanion(g, true);
        EnsureFriendlyNpcBlip(g);
        core::safe_native::SetInvincible((Entity)(g), cfg.bodyguardInvincible, &g_coreErrors, "full_audit");
        core::safe_native::SetPedArmour(g, 100, &g_coreErrors, "runtime");
        SafePedRuntimeNative(g, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(g, 2); }, true, false);
        SafePedRuntimeNative(g, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(g, GetBodyguardRole(g) == BodyguardRole::Heavy ? 1 : 2); }, true, false);
        SafePedRuntimeNative(g, "full_audit", "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(g, GetBodyguardRole(g) == BodyguardRole::Shooter ? 2 : 1); }, true, false);
        SafeSetPedAccuracy(g, std::max(5, std::min(100, cfg.bodyguardAccuracy)), "full_audit");
        SafePedRuntimeNative(g, "full_audit", "set ped flee attributes", [&](){ PED::SET_PED_FLEE_ATTRIBUTES(g, 0, false); }, true, false);
        SafePedRuntimeNative(g, "full_audit", "set ped combat attribute", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(g, 46, cfg.bodyguardCombatMode != BodyguardCombatMode::HoldFire); }, true, false);
        ApplyBodyguardRoleLoadout(g);
    }

    static void RefreshBodyguardCombatState(Ped g)
    {
        if (!IsUsablePedHandle(g, false, true, true)) return;
        if (cfg.bodyguardRelationshipFix) ConfigureFriendlyCompanion(g, true);
        EnsureFriendlyNpcBlip(g);
        core::safe_native::SetInvincible((Entity)(g), cfg.bodyguardInvincible, &g_coreErrors, "full_audit");
        SafePedRuntimeNative(g, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(g, 2); }, true, false);
        SafePedRuntimeNative(g, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(g, GetBodyguardRole(g) == BodyguardRole::Heavy ? 1 : 2); }, true, false);
        SafePedRuntimeNative(g, "full_audit", "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(g, GetBodyguardRole(g) == BodyguardRole::Shooter ? 2 : 1); }, true, false);
        SafeSetPedAccuracy(g, std::max(5, std::min(100, cfg.bodyguardAccuracy)), "full_audit");
        SafePedRuntimeNative(g, "full_audit", "set ped flee attributes", [&](){ PED::SET_PED_FLEE_ATTRIBUTES(g, 0, false); }, true, false);
        SafePedRuntimeNative(g, "full_audit", "set ped combat attribute", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(g, 46, cfg.bodyguardCombatMode != BodyguardCombatMode::HoldFire); }, true, false);
    }

    static Ped SpawnSingleBodyguard(bool notifyResult)
    {
        Vector3 base{};
        if (!TryGetPlayerPosition(base))
        {
            if (notifyResult) Notify("Bodyguard spawn failed: player position invalid.");
            return 0;
        }
        Vector3 pos = PlayerPos(2.5f);
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f)) pos = base;
        float heading = SafePlayerHeading();
        // BUGFIX 166: spawn as Neutral first, then promote into st.bodyguards.
        // Spawning directly as Relation::Friendly registered the same ped in
        // st.friendlyPeds before it became a bodyguard, causing duplicate support ticks,
        // double blip ownership, and Hold Fire/AttackThreat conflicts.
        Ped g = SpawnPedAtModel(st.selectedPedModel, Relation::Neutral, cfg.bodyguardHealth, st.selectedWeapon, cfg.bodyguardAmmo, pos, heading, false, false);
        if (g)
        {
            const int roleIndex = (int)st.bodyguards.size();
            RemoveFriendlyNpcRuntime(g);
            if (std::find(st.bodyguards.begin(), st.bodyguards.end(), g) == st.bodyguards.end())
                st.bodyguards.push_back(g);
            st.bodyguardRoles[g] = BodyguardRoleForSpawnIndex(roleIndex);
            st.bodyguardLastCombatRefreshTick[g] = 0;
            ConfigureBodyguard(g);
            PushEntityUndo("Spawn Bodyguard: " + st.selectedPedModel, (Entity)g);
        }
        if (notifyResult && g) Notify("Bodyguard spawned.");
        return g;
    }

    static void SpawnBodyguards()
    {
        Vector3 playerBase{};
        if (!TryGetPlayerPosition(playerBase))
        {
            Notify("Bodyguard spawn failed: player position invalid.");
            return;
        }
        if (cfg.replaceBodyguards) DismissBodyguards();
        else
        {
            for (Ped g : st.bodyguards)
            {
                if (!IsUsablePedHandle(g, false, true, true))
                    ClearBodyguardRuntimeState(g);
            }
            st.bodyguards.erase(std::remove_if(st.bodyguards.begin(), st.bodyguards.end(), [](Ped g)
            {
                return !IsUsablePedHandle(g, false, true, true);
            }), st.bodyguards.end());
            PurgeStaleBodyguardRuntimeState();
        }

        int existing = CountExistingPeds(st.bodyguards);
        int maxAllowed = std::max(1, cfg.maxBodyguards);
        int requested = std::max(1, std::min(maxAllowed, st.bodyguardCount));
        int count = cfg.replaceBodyguards ? requested : std::max(0, std::min(requested, maxAllowed - existing));
        int spawned = 0;
        for (int i = 0; i < count; ++i)
        {
            if (SpawnSingleBodyguard(false)) ++spawned;
        }
        Notify(spawned > 0 ? "Bodyguards ready." : "Bodyguard limit reached.");
    }

    static int FindNextFreePassengerSeat(Vehicle v, int startSeat, int maxSeat)
    {
        if (!IsUsableVehicleHandle(v, true)) return -2;
        for (int seat = std::max(0, startSeat); seat <= maxSeat; ++seat)
        {
            if (core::IsVehicleSeatFree((Vehicle)(v), seat)) return seat;
        }
        return -2;
    }

    static int FindPedSeatInVehicle(Vehicle v, Ped ped, int maxSeat)
    {
        if (!IsUsableVehicleHandle(v, true) || !core::IsPed((Entity)ped)) return -999;
        for (int seat = -1; seat <= maxSeat; ++seat)
        {
            if ((Ped)core::GetPedInVehicleSeat((Vehicle)(v), seat) == ped) return seat;
        }
        return -999;
    }

    static bool IsCompanionSeatReservedForOtherPed(Vehicle v, int seat, Ped ped)
    {
        if (!IsUsableVehicleHandle(v, true) || seat < 0) return false;
        const DWORD now = GetTickCount();
        for (const auto& kv : st.companionVehicleEntryTarget)
        {
            Ped other = kv.first;
            if (!other || other == ped || kv.second != v) continue;
            auto untilIt = st.companionVehicleEntryUntilTick.find(other);
            auto seatIt = st.companionVehicleEntrySeat.find(other);
            if (untilIt == st.companionVehicleEntryUntilTick.end() || seatIt == st.companionVehicleEntrySeat.end()) continue;
            if (seatIt->second != seat) continue;
            if (core::TickReached(now, untilIt->second)) continue;
            if (IsUsablePedHandle(other, false, true, true) && !core::IsPedInAnyVehicle((Ped)other, false))
                return true;
        }
        return false;
    }

    static bool IsVehicleSeatFreeForCompanionEntry(Vehicle v, int seat, Ped ped)
    {
        if (!IsUsableVehicleHandle(v, true) || seat < 0) return false;
        return core::IsVehicleSeatFree((Vehicle)v, seat) && !IsCompanionSeatReservedForOtherPed(v, seat, ped);
    }

    static int FindNextFreePassengerSeatForCompanion(Vehicle v, int startSeat, int maxSeat, int avoidSeat, Ped ped)
    {
        if (!IsUsableVehicleHandle(v, true)) return -2;
        for (int seat = std::max(0, startSeat); seat <= maxSeat; ++seat)
        {
            if (seat == avoidSeat) continue;
            if (IsVehicleSeatFreeForCompanionEntry(v, seat, ped)) return seat;
        }
        if (avoidSeat >= 0 && avoidSeat <= maxSeat && IsVehicleSeatFreeForCompanionEntry(v, avoidSeat, ped))
            return avoidSeat;
        return -2;
    }

    static bool PrepareVehicleForCompanionEntry(Vehicle v, const std::string& module)
    {
        if (!IsUsableVehicleHandle(v, true)) return false;
        SafeSetVehicleDoorsLockedRuntime(v, 1, module);
        SafeSetVehicleDoorsLockedForPlayerRuntime(v, false, module);
        SafeSetVehicleOwnedByPlayerRuntime(v, true, module);
        SafeSetVehicleEngineOn(v, true, module);
        return true;
    }

    static bool SeatPedInVehicleOrTaskEnter(Ped ped, Vehicle v, int preferredSeat, bool immediateFirst, int timeoutMs, const std::string& module)
    {
        if (!IsUsablePedHandle(ped, false, true, true) || !IsUsableVehicleHandle(v, true)) return false;
        timeoutMs = ClampIntValue(timeoutMs, 500, 60000);

        const int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        const int currentSeat = FindPedSeatInVehicle(v, ped, maxSeat);
        if (currentSeat != -999)
        {
            ClearCompanionVehicleTransferState(ped);
            return true;
        }

        // BUGFIX 109: if a tracked companion is already sitting in the old player car,
        // do not try to TASK_ENTER_VEHICLE into the new car while they are still seated.
        // GTA often ignores that command. First order a real leave-vehicle task; the
        // next support tick will issue TASK_ENTER_VEHICLE so the NPC runs to the new car.
        if (core::IsPedInAnyVehicle((Ped)ped, false))
        {
            Vehicle currentVehicle = core::GetVehiclePedIsIn((Ped)ped, false);
            if (currentVehicle == v)
            {
                ClearCompanionVehicleTransferState(ped);
                return true;
            }

            if (IsUsableVehicleHandle(currentVehicle, false))
            {
                // BUGFIX 110: do not spam TASK_LEAVE_VEHICLE every refresh while the
                // companion is already climbing out of the old car. Reissuing the leave
                // task can reset the animation and leave them stuck in the previous car.
                if (IsCompanionVehicleLeavePending(ped))
                {
                    PromoteCompanionVehicleLeaveDestination(ped, v, timeoutMs, module);
                    return true;
                }

                PrepareVehicleForCompanionEntry(v, module);
                ConfigureFriendlyCompanion(ped, true);
                // BUGFIX 172: vehicle regroup must override stale combat state.
                // After a friendly NPC has exchanged fire, GTA can keep an old
                // combat/target task alive and ignore the later enter-car request.
                // Clear the companion combat lease before starting the vehicle
                // handoff so the support/anti-panic ticks cannot re-issue attack
                // in the same window.
                ClearCompanionCombatTargetRuntime(ped);
                SafeClearEntityLastDamageRuntime((Entity)ped, module);
                ClearCompanionVehicleEntryState(ped);
                SafeTaskLeaveVehicle(ped, currentVehicle, 0, module);
                MarkCompanionVehicleLeavePending(ped, v, timeoutMs, module);
                return true;
            }

            return false;
        }

        // BUGFIX 119: menu commands and auto-support can call this helper directly.
        // If a physical TASK_ENTER_VEHICLE is already pending for the same car, do
        // not clear/reissue it here; reissuing resets the approach/door animation
        // and can recreate the endless open-door loop fixed in BUGFIX 118.
        if (IsFriendlyOrBodyguardTracked(ped) && IsCompanionVehicleEntryPending(ped, v))
            return true;

        int avoidSeat = -999;
        auto avoidIt = st.companionVehicleEntryAvoidSeat.find(ped);
        if (avoidIt != st.companionVehicleEntryAvoidSeat.end())
        {
            auto avoidVehicleIt = st.companionVehicleEntryAvoidVehicle.find(ped);
            if (avoidVehicleIt != st.companionVehicleEntryAvoidVehicle.end() && avoidVehicleIt->second == v)
                avoidSeat = avoidIt->second;
            else
            {
                st.companionVehicleEntryAvoidSeat.erase(avoidIt);
                st.companionVehicleEntryAvoidVehicle.erase(ped);
            }
        }
        if (avoidSeat != -999)
            SafeResetVehiclePassengerDoorsForEntryRuntime(v, module);

        int seat = -2;
        if (preferredSeat >= 0 && preferredSeat <= maxSeat && preferredSeat != avoidSeat && IsVehicleSeatFreeForCompanionEntry(v, preferredSeat, ped))
            seat = preferredSeat;
        else
            seat = FindNextFreePassengerSeatForCompanion(v, 0, maxSeat, avoidSeat, ped);

        if (seat < 0) return false;
        if (!PrepareVehicleForCompanionEntry(v, module)) return false;

        // BUGFIX 105: tracked friendly/bodyguard companions must not be teleported
        // into the player's car. They should physically run to the door and enter it.
        // Keep instant seat assignment only for generic/non-companion helper calls.
        const bool isTrackedCompanion = IsFriendlyOrBodyguardTracked(ped);
        const bool allowImmediateSeat = immediateFirst && !isTrackedCompanion;
        if (isTrackedCompanion)
        {
            // BUGFIX 172: a friendly/bodyguard that recently fought can still have
            // companionCombatTarget + GTA combat flags.  Those states were allowed
            // to win over TASK_ENTER_VEHICLE, so the NPC stood outside the car with
            // a gun instead of boarding.  Treat an explicit/auto vehicle-entry order
            // as a regroup command and remove stale combat ownership first.
            ClearCompanionCombatTargetRuntime(ped);
            ConfigureFriendlyCompanion(ped, true);
            SafeClearEntityLastDamageRuntime((Entity)ped, module);
            Ped playerPed = 0;
            if (GetPlayerPedSafe(playerPed))
                SafeClearEntityLastDamageRuntime((Entity)playerPed, module);
            SafeClearEntityLastDamageRuntime((Entity)v, module);
        }
        core::safe_native::ClearPedTasks(ped, false, &g_coreErrors, module);
        if (allowImmediateSeat && core::SetPedIntoVehicleSafe((Ped)(ped), (Vehicle)(v), seat))
        {
            ClearCompanionVehicleEntryState(ped);
            return true;
        }

        const bool enterIssued = core::safe_native::TaskEnterVehicle(ped, v, timeoutMs, seat, 2.5f, 1, &g_coreErrors, module);
        if (enterIssued)
        {
            ClearCompanionVehicleLeaveState(ped);
            MarkCompanionVehicleEntryPending(ped, v, timeoutMs, module, seat);
            if (IsFriendlyOrBodyguardTracked(ped))
                MarkCompanionVehicleTransferTarget(ped, v, timeoutMs, module);
        }
        else ClearCompanionVehicleEntryState(ped);
        return enterIssued;
    }

    static Vehicle CurrentPlayerVehicleForCompanionEntry()
    {
        Ped playerPed = 0;
        if (!GetPlayerPedSafe(playerPed)) return 0;
        if (!core::IsPedInAnyVehicle((Ped)(playerPed), false)) return 0;
        Vehicle v = core::GetVehiclePedIsIn((Ped)(playerPed), false);
        return IsUsableVehicleHandle(v, true) ? v : 0;
    }

    static bool TrySeatFriendlyNpcInPlayerVehicle(Ped ped, const std::string& module, bool immediateFirst = true)
    {
        if (!IsUsablePedHandle(ped, false, true, true)) return false;
        if (!cfg.bodyguardsAutoEnterPlayerVehicle) return false;
        Vehicle v = CurrentPlayerVehicleForCompanionEntry();
        if (!v) return false;
        if (core::IsPedInAnyVehicle((Ped)ped, false))
        {
            Vehicle currentVehicle = core::GetVehiclePedIsIn((Ped)ped, false);
            if (currentVehicle == v)
            {
                ClearCompanionVehicleTransferState(ped);
                return true;
            }

            // BUGFIX 109/110: player changed cars while the companion stayed in the old one.
            // Make the NPC exit normally, but protect the leave task from being reissued
            // every support tick. Once on foot, this same pipeline makes them run to the
            // current player vehicle and enter a free passenger seat.
            if (IsUsableVehicleHandle(currentVehicle, false))
            {
                if (IsCompanionVehicleLeavePending(ped))
                {
                    PromoteCompanionVehicleLeaveDestination(ped, v, cfg.bodyguardsAutoEnterTimeoutMs, module);
                    return true;
                }

                PrepareVehicleForCompanionEntry(v, module);
                ConfigureFriendlyCompanion(ped, true);
                // BUGFIX 172: when transferring from an old car to the player's
                // current car, drop stale combat ownership first.  Otherwise a
                // recent shootout can make the support tick re-issue attack and
                // cancel the leave/enter vehicle handoff.
                ClearCompanionCombatTargetRuntime(ped);
                SafeClearEntityLastDamageRuntime((Entity)ped, module);
                ClearCompanionVehicleEntryState(ped);
                SafeTaskLeaveVehicle(ped, currentVehicle, 0, module);
                MarkCompanionVehicleLeavePending(ped, v, cfg.bodyguardsAutoEnterTimeoutMs, module);
                return true;
            }
            return false;
        }

        // BUGFIX 106: do not clear/reissue TASK_ENTER_VEHICLE every tick while a
        // companion is already running to the player's car. Reissuing the task resets
        // the door approach path and can make the NPC stutter or never reach the seat.
        if (IsCompanionVehicleEntryPending(ped, v)) return true;

        return SeatPedInVehicleOrTaskEnter(ped, v, -2, immediateFirst, cfg.bodyguardsAutoEnterTimeoutMs, module);
    }

    static bool SuppressFriendlyFootFollowWhilePlayerIsDriving(Ped ped, const std::string& module)
    {
        if (!IsUsablePedHandle(ped, false, true, true)) return false;
        if (!CurrentPlayerVehicleForCompanionEntry()) return false;
        if (core::IsPedInAnyVehicle((Ped)ped, false))
            return true;
        if (IsCompanionVehicleTaskProtected(ped))
            return true;

        // If the player is already driving and the NPC could not be seated
        // because seats are full/temporarily locked, do not assign a foot-follow
        // task. That task makes friendly NPCs sprint after the moving vehicle.
        // Do this only for NPCs currently on foot; friendly NPCs already inside a
        // vehicle may be driving/escorting and must not have their vehicle task cleared.
        core::safe_native::ClearPedTasks(ped, false, &g_coreErrors, module);
        SafePedRuntimeNative(ped, module, "block ambient while waiting for vehicle seat", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, true); }, true, false);
        SafeTaskStandStill(ped, 1750, module);
        return true;
    }

    static bool TrySeatFriendlyNpcInPlayerVehicleOrSuppressFootFollow(Ped ped, const std::string& module, bool immediateFirst = true)
    {
        if (TrySeatFriendlyNpcInPlayerVehicle(ped, module, immediateFirst)) return true;
        return SuppressFriendlyFootFollowWhilePlayerIsDriving(ped, module);
    }

    static void PrepareVehicleForPlayerPassengerEntry(Vehicle v)
    {
        if (!IsUsableVehicleHandle(v, true)) return;

        // A chauffeur car is a scripted NPC vehicle. GTA can treat it like a locked ambient NPC car,
        // so the player may try to pull the driver out or fail to use the passenger door.
        // Keep it explicitly open/owned by player while the chauffeur is waiting.
        if (cfg.chauffeurUnlockDoors)
        {
            SafeSetVehicleDoorsLockedRuntime(v, 1, "chauffeur"); // 1 = unlocked
            SafeSetVehicleDoorsLockedForPlayerRuntime(v, false, "chauffeur");
        }
        SafeSetVehicleOwnedByPlayerRuntime(v, true, "chauffeur");
        SafeSetVehicleEngineOn(v, true, "full_audit");
    }

    static float EntityDistanceSq(Entity a, Entity b)
    {
        Vector3 pa{};
        Vector3 pb{};
        if (!TryGetUsableEntityPosition(a, pa) || !TryGetUsableEntityPosition(b, pb)) return 999999.0f;
        float dx = pa.x - pb.x;
        float dy = pa.y - pb.y;
        float dz = pa.z - pb.z;
        return dx * dx + dy * dy + dz * dz;
    }

    static int FindPlayerPassengerSeat(Vehicle v)
    {
        if (!IsUsableVehicleHandle(v, true)) return -2;
        Ped player = 0;
        if (!GetPlayerPedSafe(player)) return -2;
        int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        int currentSeat = FindPedSeatInVehicle(v, player, maxSeat);
        if (currentSeat >= 0) return currentSeat;
        return FindNextFreePassengerSeat(v, 0, maxSeat);
    }

    static bool MovePlayerToPassengerSeat(Vehicle v, bool notifyOnFail)
    {
        if (!IsUsableVehicleHandle(v, true)) return false;
        PrepareVehicleForPlayerPassengerEntry(v);
        Ped player = 0;
        if (!GetPlayerPedSafe(player))
        {
            if (notifyOnFail) Notify("Player unavailable for passenger entry.");
            return false;
        }
        int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        int currentSeat = FindPedSeatInVehicle(v, player, maxSeat);

        // Passenger seats are 0..N. Driver seat is -1 and must be vacated before
        // spawning a chauffeur into the same vehicle. Returning true for -1 here
        // lets SpawnChauffeur continue into a guaranteed driver-seat conflict.
        if (currentSeat >= 0) return true;

        int passengerSeat = FindNextFreePassengerSeat(v, 0, maxSeat);
        if (passengerSeat < 0)
        {
            if (notifyOnFail) Notify("No free passenger seat for player.");
            return false;
        }

        core::SetPedIntoVehicleSafe((Ped)(player), (Vehicle)(v), passengerSeat);
        WAIT(0);

        currentSeat = FindPedSeatInVehicle(v, player, maxSeat);
        if (currentSeat >= 0) return true;

        if (notifyOnFail) Notify("Could not move player to passenger seat.");
        return false;
    }


    static std::string MissionAssistLowerAscii(std::string text)
    {
        std::transform(text.begin(), text.end(), text.begin(), [](unsigned char c){ return (char)std::tolower(c); });
        return text;
    }

    static bool MissionObjectiveTextContainsAny(const MissionObjectiveDef& objective, std::initializer_list<const char*> needles)
    {
        const std::string hay = MissionAssistLowerAscii(objective.label + " " + objective.targetLabel + " " + MissionObjectiveTypeName(objective.type));
        for (const char* needle : needles)
        {
            if (!needle) continue;
            if (hay.find(MissionAssistLowerAscii(needle)) != std::string::npos) return true;
        }
        return false;
    }

    static bool IsMissionPassengerEntryObjective(const MissionObjectiveDef& objective)
    {
        // BUGFIX 148: mission creator has no dedicated "enter as passenger" objective type.
        // Treat Escort Vehicle as passenger-friendly by default, and also allow authors to
        // opt into passenger entry through the objective label/target label.  Do not hijack
        // plain Steal Vehicle objectives: those usually expect the player to drive.
        if (objective.type == MissionObjectiveType::EscortVehicle) return true;
        return MissionObjectiveTextContainsAny(objective, {
            "passenger", "front passenger", "back seat", "rear seat", "seat passenger",
            "enter passenger", "enter as passenger", "ride along", "escort vehicle passenger",
            "пассажир", "пассажирск", "сядь пассажир", "сесть пассажир", "садись пассажир",
            "на пассажир", "пассажирское", "пассажирское место", "займи пассажир"
        });
    }

    static bool MissionTargetLabelMatchesDef(const MissionObjectiveDef& objective, const MissionEntityDef& def)
    {
        const std::string targetLabel = MissionAssistLowerAscii(Trim(objective.targetLabel));
        if (targetLabel.empty()) return false;
        const std::string defLabel = MissionAssistLowerAscii(Trim(def.label));
        const std::string defModel = MissionAssistLowerAscii(Trim(def.model));
        return defLabel == targetLabel || defModel == targetLabel;
    }

    static Entity FindMissionRuntimeEntityForObjective(const MissionObjectiveDef& objective, MissionEntityType entityType, Relation relation, bool filterRelation)
    {
        CompactMissionSpawnedEntityLists();
        Entity best = 0;
        float bestScore = 99999999.0f;
        Vector3 objectivePos = MakeVector3(objective.x, objective.y, objective.z);
        const bool hasObjectivePos = IsUsableRuntimeWorldPosition(objectivePos);
        const std::string targetLabel = MissionAssistLowerAscii(Trim(objective.targetLabel));

        for (size_t i = 0; i < st.missionSpawnedEntities.size(); ++i)
        {
            Entity entity = st.missionSpawnedEntities[i];
            if (!entity || !core::Exists((Entity)entity)) continue;
            if (entityType == MissionEntityType::Vehicle && !core::IsVehicle((Entity)entity)) continue;
            if (entityType == MissionEntityType::Ped && !core::IsPed((Entity)entity)) continue;
            if (entityType == MissionEntityType::Object && !core::IsObject((Entity)entity)) continue;

            int defIndex = i < st.missionSpawnedEntityDefIndexes.size() ? st.missionSpawnedEntityDefIndexes[i] : -1;
            if (defIndex < 0 || defIndex >= (int)st.currentMission.entities.size()) continue;
            const MissionEntityDef& def = st.currentMission.entities[(size_t)defIndex];
            if (def.type != entityType) continue;
            if (filterRelation && def.relation != relation) continue;

            const bool labelMatches = MissionTargetLabelMatchesDef(objective, def);
            if (!targetLabel.empty() && !labelMatches) continue;

            Vector3 entityPos{};
            if (!TryGetUsableEntityPosition((Entity)entity, entityPos)) continue;
            float score = hasObjectivePos ? DistanceSq(entityPos, objectivePos) : 0.0f;
            if (labelMatches) score *= 0.20f;
            if (score < bestScore)
            {
                bestScore = score;
                best = entity;
            }
        }
        return best;
    }

    static Vehicle FindMissionVehicleForObjective(const MissionObjectiveDef& objective)
    {
        Entity entity = FindMissionRuntimeEntityForObjective(objective, MissionEntityType::Vehicle, Relation::Neutral, false);
        return entity && core::IsVehicle((Entity)entity) ? (Vehicle)entity : 0;
    }

    static Object FindMissionObjectForObjective(const MissionObjectiveDef& objective)
    {
        Entity entity = FindMissionRuntimeEntityForObjective(objective, MissionEntityType::Object, Relation::Neutral, false);
        return entity && core::IsObject((Entity)entity) ? (Object)entity : 0;
    }

    static Ped FindMissionPedForObjective(const MissionObjectiveDef& objective, Relation relation, bool filterRelation)
    {
        Entity entity = FindMissionRuntimeEntityForObjective(objective, MissionEntityType::Ped, relation, filterRelation);
        return entity && core::IsPed((Entity)entity) ? (Ped)entity : 0;
    }

    static bool IsPlayerInMissionVehicleForObjective(const MissionObjectiveDef& objective, Ped playerPed, bool requireDriverSeat)
    {
        if (!IsUsablePedHandle(playerPed, true, true, false)) return false;
        if (!core::IsPedInAnyVehicle((Ped)playerPed, false)) return false;
        Vehicle currentVehicle = core::GetVehiclePedIsIn((Ped)playerPed, false);
        Vehicle targetVehicle = FindMissionVehicleForObjective(objective);
        if (!IsUsableVehicleHandle(currentVehicle, true) || !IsUsableVehicleHandle(targetVehicle, true)) return false;
        if (currentVehicle != targetVehicle) return false;
        if (!requireDriverSeat) return true;
        return (Ped)core::GetPedInVehicleSeat((Vehicle)currentVehicle, -1) == playerPed;
    }

    static bool IsPlayerNearMissionEntityForObjective(const MissionObjectiveDef& objective, Entity entity, const Vector3& playerPos, float minRadius)
    {
        if (!entity || !core::Exists((Entity)entity)) return false;
        Vector3 targetPos{};
        if (!TryGetUsableEntityPosition((Entity)entity, targetPos)) return false;
        const float radius = std::max(minRadius, std::min(100.0f, objective.radius));
        return DistanceSq(playerPos, targetPos) <= radius * radius;
    }

    static int FindFreeMissionPassengerSeat(Vehicle vehicle)
    {
        if (!IsUsableVehicleHandle(vehicle, true)) return -2;
        const int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        // Prefer front passenger first for mission readability, then rear seats.
        if (core::IsVehicleSeatFree((Vehicle)vehicle, 0)) return 0;
        return FindNextFreePassengerSeat(vehicle, 1, maxSeat);
    }

    static bool IsPlayerPassengerInMissionVehicleForObjective(const MissionObjectiveDef& objective, Ped playerPed)
    {
        if (!IsMissionPassengerEntryObjective(objective)) return false;
        if (!IsUsablePedHandle(playerPed, true, true, false)) return false;
        if (!core::IsPedInAnyVehicle((Ped)playerPed, false)) return false;
        Vehicle currentVehicle = core::GetVehiclePedIsIn((Ped)playerPed, false);
        Vehicle targetVehicle = FindMissionVehicleForObjective(objective);
        if (!IsUsableVehicleHandle(currentVehicle, true) || !IsUsableVehicleHandle(targetVehicle, true)) return false;
        if (currentVehicle != targetVehicle) return false;
        const int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        return FindPedSeatInVehicle(currentVehicle, playerPed, maxSeat) >= 0;
    }

    static void TickMissionPassengerEntryAssist(const MissionObjectiveDef& objective, Ped playerPed)
    {
        if (!st.missionPlaytestActive) return;
        if (!IsMissionPassengerEntryObjective(objective))
        {
            st.missionPassengerEntryAssistHoldFrames = 0;
            return;
        }
        if (!IsUsablePedHandle(playerPed, true, true, true)) return;

        const bool fHeld = (GetAsyncKeyState('F') & 0x8000) != 0;
        if (!fHeld)
        {
            st.missionPassengerEntryAssistHoldFrames = 0;
            return;
        }

        Vehicle targetVehicle = FindMissionVehicleForObjective(objective);
        if (!IsUsableVehicleHandle(targetVehicle, true)) return;
        if (core::IsPedInVehicle((Ped)playerPed, (Vehicle)targetVehicle, false)) return;

        Vector3 playerPos{};
        Vector3 vehiclePos{};
        if (!TryGetUsableEntityPosition((Entity)playerPed, playerPos) || !TryGetUsableEntityPosition((Entity)targetVehicle, vehiclePos)) return;
        const float maxEntryDist = std::max(5.0f, std::min(14.0f, objective.radius + 4.0f));
        if (DistanceSq(playerPos, vehiclePos) > maxEntryDist * maxEntryDist)
        {
            st.missionPassengerEntryAssistHoldFrames = 0;
            return;
        }

        // Stop GTA's default F behaviour from choosing the driver door while the mission
        // explicitly wants passenger entry.
        SafeDisableControlActionRuntime(0, 23, true, "mission_passenger_entry"); // INPUT_ENTER
        SafeDisableControlActionRuntime(0, 75, true, "mission_passenger_entry"); // INPUT_VEH_EXIT / enter overlap on some builds

        ++st.missionPassengerEntryAssistHoldFrames;
        if (st.missionPassengerEntryAssistHoldFrames < 8) return;

        const DWORD now = GetTickCount();
        if (st.missionPassengerEntryAssistLastTick != 0 && !core::TickElapsed(now, st.missionPassengerEntryAssistLastTick, 700u)) return;
        st.missionPassengerEntryAssistLastTick = now;

        int seat = FindFreeMissionPassengerSeat(targetVehicle);
        if (seat < 0)
        {
            if (st.missionPassengerEntryAssistNotifyCooldownTick == 0 || core::TickElapsed(now, st.missionPassengerEntryAssistNotifyCooldownTick, 2500u))
            {
                st.missionPassengerEntryAssistNotifyCooldownTick = now;
                Notify("Mission passenger entry: no free passenger seat.");
            }
            return;
        }

        PrepareVehicleForPlayerPassengerEntry(targetVehicle);
        core::safe_native::ClearPedTasks(playerPed, false, &g_coreErrors, "mission_passenger_entry");
        const bool issued = core::safe_native::TaskEnterVehicle(playerPed, targetVehicle, 9000, seat, 2.0f, 1, &g_coreErrors, "mission_passenger_entry");
        if (!issued)
        {
            core::SetPedIntoVehicleSafe((Ped)playerPed, (Vehicle)targetVehicle, seat);
        }
        st.missionPassengerEntryAssistVehicle = targetVehicle;
        st.missionPassengerEntryAssistSeat = seat;
        st.missionPassengerEntryAssistObjective = st.missionActiveObjective;
    }

    static bool PrepareVehicleForChauffeur(Vehicle v)
    {
        if (!IsUsableVehicleHandle(v, true)) return false;
        Ped player = 0;
        if (!GetPlayerPedSafe(player))
        {
            Notify("Chauffeur vehicle setup failed: player unavailable.");
            return false;
        }
        int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        Ped driver = core::GetPedInVehicleSeat((Vehicle)(v), -1);

        if (driver == player)
        {
            if (!MovePlayerToPassengerSeat(v, true)) return false;
            driver = core::GetPedInVehicleSeat((Vehicle)(v), -1);
            if (driver == player)
            {
                Notify("Chauffeur spawn blocked: player is still in driver seat.");
                return false;
            }
        }
        else
        {
            int playerSeat = FindPedSeatInVehicle(v, player, maxSeat);
            if (playerSeat == -999 && !MovePlayerToPassengerSeat(v, true)) return false;
        }

        if (driver && core::Exists((Entity)(driver)) && driver != player)
        {
            Notify("Driver seat is occupied.");
            return false;
        }
        return true;
    }

    static int CommandBodyguardsEnterVehicle(Vehicle v, bool notify, bool autoMode)
    {
        if (!IsUsableVehicleHandle(v, false)) return 0;

        Vector3 vehiclePos{};
        if (!TryGetUsableEntityPosition((Entity)v, vehiclePos))
        {
            if (notify) Notify("Bodyguard vehicle position invalid.");
            return 0;
        }
        const float autoEnterRadius = ClampFloatValue(cfg.bodyguardsAutoEnterRadius, 5.0f, 250.0f, 65.0f);
        const float radiusSq = autoEnterRadius * autoEnterRadius;
        const int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        int nextSeat = 0;
        int ordered = 0;

        for (Ped g : st.bodyguards)
        {
            if (!IsUsablePedHandle(g, false, true, true)) continue;

            const bool guardInDifferentVehicle = IsCompanionInDifferentVehicleThan(g, v);
            if (core::IsPedInAnyVehicle((Ped)(g), false))
            {
                Vehicle gv = core::GetVehiclePedIsIn((Ped)(g), false);
                if (gv == v)
                {
                    ClearCompanionVehicleTransferState(g);
                    continue;
                }
            }

            if (autoMode && !guardInDifferentVehicle && !IsCompanionVehicleLeavePending(g, v) &&
                !HasCompanionVehicleTransferTarget(g, v) && !HasCompanionVehicleTransferTarget(g))
            {
                Vector3 guardPos{};
                if (!TryGetUsableEntityPosition((Entity)g, guardPos)) continue;
                float dx = guardPos.x - vehiclePos.x;
                float dy = guardPos.y - vehiclePos.y;
                float dz = guardPos.z - vehiclePos.z;
                if ((dx * dx + dy * dy + dz * dz) > radiusSq) continue;
            }

            // BUGFIX 119: bodyguard batch entry must respect seats already reserved
            // by companions that are still running to/opening the door.  The plain
            // native seat scan sees those seats as empty until the ped is seated.
            int seat = FindNextFreePassengerSeatForCompanion(v, nextSeat, maxSeat, -999, g);
            if (seat < 0) break;

            if (SeatPedInVehicleOrTaskEnter(g, v, seat, autoMode, autoMode ? cfg.bodyguardsAutoEnterTimeoutMs : 5000, "bodyguards"))
                ++ordered;
            nextSeat = seat + 1;
            if (nextSeat > maxSeat) break;
        }

        if (notify)
        {
            const bool chauffeurVehicle = IsUsableVehicleHandle(st.chauffeurVehicle, true) && v == st.chauffeurVehicle;
            Notify(ordered > 0
                ? (chauffeurVehicle ? "Bodyguards entering chauffeur vehicle." : "Bodyguards entering player vehicle.")
                : (chauffeurVehicle ? "No bodyguards available for chauffeur vehicle." : "No bodyguards available for vehicle."));
        }
        return ordered;
    }

    static void BodyguardsEnterVehicle()
    {
        Ped player = 0;
        if (!GetPlayerPedSafe(player)) { Notify("Player unavailable."); return; }
        if (!core::IsPedInAnyVehicle((Ped)(player), false)) { Notify("Player must be in vehicle."); return; }
        Vehicle v = core::GetVehiclePedIsIn((Ped)(player), false);
        if (!IsUsableVehicleHandle(v, false)) { Notify("Player vehicle unavailable."); return; }
        CommandBodyguardsEnterVehicle(v, true, false);
    }

    static void BodyguardsFollow(bool notify = false)
    {
        Ped player = 0;
        if (!GetPlayerPedSafe(player))
        {
            if (notify) Notify("Player unavailable.");
            return;
        }

        if (cfg.bodyguardsAutoEnterPlayerVehicle && core::IsPedInAnyVehicle((Ped)(player), false))
        {
            Vehicle vehicle = core::GetVehiclePedIsIn((Ped)(player), false);
            if (IsUsableVehicleHandle(vehicle, true))
            {
                int seated = CommandBodyguardsEnterVehicle(vehicle, false, true);
                if (notify) Notify(seated > 0 ? "Bodyguards entering player vehicle." : "No free vehicle seats for bodyguards.");
                return;
            }
        }

        int ordered = 0;
        int idx = 0;
        for (Ped g : st.bodyguards)
        {
            if (IsUsablePedHandle(g, false, true, true))
            {
                Vector3 off = BodyguardFollowOffset(idx++);
                SafeTaskFollowToOffset(g, (Entity)player, off.x, off.y, off.z, 2.0f, -1, std::max(1.5f, cfg.bodyguardFollowDistance), true, "bodyguards");
                ++ordered;
            }
        }
        if (notify) Notify(ordered > 0 ? "Bodyguards regrouping." : "No active bodyguards.");
    }

    static void StopBodyguards(bool notify = true)
    {
        int stopped = 0;
        for (Ped g : st.bodyguards)
        {
            if (IsUsablePedHandle(g, false, true, true))
            {
                ClearCompanionCombatTargetRuntime(g);
                SafeSetPedCombatAttribute(g, 46, cfg.bodyguardCombatMode != BodyguardCombatMode::HoldFire, "bodyguards");
                core::safe_native::ClearPedTasks(g, false, &g_coreErrors, "runtime");
                ++stopped;
            }
        }
        if (notify) Notify(stopped > 0 ? "Bodyguards stopped." : "No active bodyguards.");
    }

    static int CommandBodyguardsExitVehicle(Vehicle preferredVehicle, bool notify, bool autoMode)
    {
        int ordered = 0;
        for (Ped g : st.bodyguards)
        {
            if (!IsUsablePedHandle(g, false, true, false)) continue;
            if (!core::IsPedInAnyVehicle((Ped)(g), false)) continue;
            Vehicle gv = core::GetVehiclePedIsIn((Ped)(g), false);
            if (!IsUsableVehicleHandle(gv, false)) continue;
            if (preferredVehicle && IsUsableVehicleHandle(preferredVehicle, false) && gv != preferredVehicle && autoMode) continue;
            SafeTaskLeaveVehicle(g, gv, 0, "full_audit");
            ++ordered;
        }
        if (notify) Notify(ordered > 0 ? "Bodyguards exiting vehicle." : "No bodyguards in vehicle.");
        return ordered;
    }

    static void BodyguardsExitVehicle()
    {
        CommandBodyguardsExitVehicle(0, true, false);
    }

    static void ReviveDownedBodyguard(bool notifyResult = true)
    {
        int revived = 0;
        for (auto it = st.bodyguards.begin(); it != st.bodyguards.end(); )
        {
            Ped g = *it;
            if (!IsUsablePedHandle(g, false, false, false))
            {
                ClearBodyguardRuntimeState(g);
                it = st.bodyguards.erase(it);
                continue;
            }
            if (core::IsPedDeadOrDying((Ped)(g), true, true))
            {
                if (DeleteEntityAndUntrackIfGone((Entity)g, true))
                {
                    ClearBodyguardRuntimeState(g);
                    it = st.bodyguards.erase(it);
                    ++revived;
                }
                else
                {
                    ++it;
                }
            }
            else ++it;
        }
        int target = std::max(1, std::min(cfg.maxBodyguards, st.bodyguardCount));
        int canSpawn = std::max(0, target - CountExistingPeds(st.bodyguards));
        int spawned = 0;
        for (int i = 0; i < std::min(revived, canSpawn); ++i)
        {
            if (SpawnSingleBodyguard(false)) ++spawned;
        }
        if (notifyResult) Notify(revived > 0 ? ("Downed bodyguards replaced: " + std::to_string(spawned)) : "No downed bodyguard found.");
    }

    static void RespawnDeadBodyguardsNow()
    {
        ReviveDownedBodyguard(false);
        int target = std::max(1, std::min(cfg.maxBodyguards, st.bodyguardCount));
        int spawned = 0;
        int attempts = 0;
        while ((int)st.bodyguards.size() < target && attempts < target)
        {
            ++attempts;
            if (SpawnSingleBodyguard(false)) ++spawned;
            else break;
        }
        Notify(spawned > 0 ? "Bodyguards respawned." : "Bodyguards already at target count.");
    }

    static bool IsPlayerPassengerInChauffeurVehicle()
    {
        if (!IsUsableVehicleHandle(st.chauffeurVehicle, true)) return false;
        if (!IsPlayerInVehicleEntity(st.chauffeurVehicle)) return false;

        Ped player = 0;
        if (!GetPlayerPedSafe(player)) return false;
        int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        int seat = FindPedSeatInVehicle(st.chauffeurVehicle, player, maxSeat);
        return seat >= 0;
    }

    static bool EnterChauffeurVehicleAsPassenger(bool warpNow, bool notify)
    {
        if (!IsUsableVehicleHandle(st.chauffeurVehicle, true))
        {
            if (notify) Notify("No chauffeur vehicle.");
            return false;
        }

        Ped player = 0;
        if (!GetPlayerPedSafe(player)) { if (notify) Notify("Player unavailable."); return false; }
        if (IsPlayerPassengerInChauffeurVehicle()) return true;

        if (core::IsPedInAnyVehicle((Ped)(player), false))
        {
            Vehicle currentVehicle = core::GetVehiclePedIsIn((Ped)(player), false);
            if (currentVehicle == st.chauffeurVehicle && warpNow)
                return MovePlayerToPassengerSeat(st.chauffeurVehicle, notify);
            if (notify) Notify("Leave current vehicle first.");
            return false;
        }

        PrepareVehicleForPlayerPassengerEntry(st.chauffeurVehicle);
        int passengerSeat = FindPlayerPassengerSeat(st.chauffeurVehicle);
        if (passengerSeat < 0)
        {
            if (notify) Notify("No free passenger seat in chauffeur car.");
            return false;
        }

        if (warpNow)
        {
            core::SetPedIntoVehicleSafe((Ped)(player), (Vehicle)(st.chauffeurVehicle), passengerSeat);
            WAIT(0);
            return IsPlayerPassengerInChauffeurVehicle();
        }

        core::safe_native::TaskEnterVehicle(player, st.chauffeurVehicle, 10000, passengerSeat, 2.0f, 1, &g_coreErrors, "chauffeur");
        return true;
    }

    [[maybe_unused]] static void ForceEnterChauffeurVehicle()
    {
        st.chauffeurPassengerAutoAssistEnabled = false;
        st.lastChauffeurPlayerExitTick = 0;
        if (EnterChauffeurVehicleAsPassenger(true, true))
            Notify("Player moved to chauffeur passenger seat.");
    }

    static constexpr int kChauffeurEntryKey = 'F';
    static constexpr DWORD kChauffeurPassengerHoldMs = 550;
    static constexpr DWORD kChauffeurExitReentryBlockMs = 1200;

    static void ResetChauffeurEntryKeyState()
    {
        st.chauffeurEntryKeyDown = false;
        st.chauffeurEntryHoldIssued = false;
        st.chauffeurEntryKeyDownTick = 0;
    }

    static bool IsChauffeurVehicleEntryCandidate()
    {
        if (st.menuOpen) return false;
        if (!IsUsableVehicleHandle(st.chauffeurVehicle, true)) return false;

        Ped player = 0;
        if (!GetPlayerPedSafe(player)) return false;
        if (core::IsPedInAnyVehicle((Ped)(player), false)) return false; // never block F when the player wants to exit

        DWORD now = GetTickCount();
        if (st.lastChauffeurPlayerExitTick != 0 && !core::TickElapsed(now, st.lastChauffeurPlayerExitTick, kChauffeurExitReentryBlockMs))
            return false;

        // Keep F interception tight so the trainer does not steal the enter key
        // when the player is near the chauffeur car but actually wants another nearby vehicle.
        return EntityDistanceSq((Entity)player, (Entity)st.chauffeurVehicle) <= 36.0f; // 6 meters
    }

    static bool EnterChauffeurVehicleAsDriverFromTap(bool notify)
    {
        if (!IsUsableVehicleHandle(st.chauffeurVehicle, true))
        {
            if (notify) Notify("No chauffeur vehicle.");
            return false;
        }

        Ped player = 0;
        if (!GetPlayerPedSafe(player)) { if (notify) Notify("Player unavailable."); return false; }
        if (core::IsPedInAnyVehicle((Ped)(player), false)) return false;

        PrepareVehicleForPlayerPassengerEntry(st.chauffeurVehicle);
        st.chauffeurPassengerAutoAssistEnabled = false;
        st.chauffeurWaitingForPlayer = false;
        st.chauffeurDriveStarted = false;
        st.chauffeurPlayerWasInside = false;
        st.chauffeurDriverTakeoverUntilTick = core::TickAdd(GetTickCount(), 10000u);

        if (IsUsablePedHandle(st.chauffeur, false, true, true))
        {
            core::safe_native::ClearPedTasks(st.chauffeur, false, &g_coreErrors, "runtime");
            if (core::IsPedInAnyVehicle((Ped)(st.chauffeur), false))
                SafeTaskLeaveVehicle(st.chauffeur, st.chauffeurVehicle, 0, "full_audit");
        }

        core::safe_native::TaskEnterVehicle(player, st.chauffeurVehicle, 10000, -1, 2.0f, 1, &g_coreErrors, "chauffeur");
        if (notify) Notify("Entering driver seat. Hold F for passenger seat.");
        return true;
    }

    static void TickChauffeurManualEntryInput()
    {
        if (!IsChauffeurVehicleEntryCandidate())
        {
            ResetChauffeurEntryKeyState();
            return;
        }

        // Replace GTA's default one-click driver entry only around the chauffeur car.
        // Tap F -> driver seat. Hold F -> passenger seat. In-vehicle F remains untouched for exit.
        SafeDisableControlActionRuntime(0, 23, true, "chauffeur_input"); // INPUT_ENTER / F

        bool down = (GetAsyncKeyState(kChauffeurEntryKey) & 0x8000) != 0;
        DWORD now = GetTickCount();

        if (down)
        {
            if (!st.chauffeurEntryKeyDown)
            {
                st.chauffeurEntryKeyDown = true;
                st.chauffeurEntryHoldIssued = false;
                st.chauffeurEntryKeyDownTick = now;
            }
            else if (!st.chauffeurEntryHoldIssued && core::TickElapsed(now, st.chauffeurEntryKeyDownTick, kChauffeurPassengerHoldMs))
            {
                st.chauffeurEntryHoldIssued = true;
                st.chauffeurDriverTakeoverUntilTick = 0;
                st.chauffeurPassengerAutoAssistEnabled = false;
                if (EnterChauffeurVehicleAsPassenger(false, true))
                    Notify("Entering chauffeur passenger seat.");
            }
            return;
        }

        if (!st.chauffeurEntryKeyDown) return;

        bool wasHold = st.chauffeurEntryHoldIssued || core::TickElapsed(now, st.chauffeurEntryKeyDownTick, kChauffeurPassengerHoldMs);
        ResetChauffeurEntryKeyState();

        if (!wasHold)
            EnterChauffeurVehicleAsDriverFromTap(true);
    }

    static bool IsSameWaypointEnough(const Vector3& a, const Vector3& b)
    {
        float dx = a.x - b.x;
        float dy = a.y - b.y;
        float dz = a.z - b.z;
        return (dx * dx + dy * dy + dz * dz) < 25.0f;
    }

    static float ChauffeurDriveSpeed()
    {
        switch (cfg.chauffeurDriveStyle)
        {
            case ChauffeurDriveStyle::Calm: return 17.0f;
            case ChauffeurDriveStyle::Fast: return 34.0f;
            case ChauffeurDriveStyle::Aggressive: return 44.0f;
            case ChauffeurDriveStyle::Vip: return 24.0f;
            case ChauffeurDriveStyle::Safe: return 19.0f;
            default: return 25.0f;
        }
    }

    static int ChauffeurDriveFlags()
    {
        switch (cfg.chauffeurDriveStyle)
        {
            case ChauffeurDriveStyle::Aggressive: return 1074528293;
            case ChauffeurDriveStyle::Fast: return 787004;
            case ChauffeurDriveStyle::Safe: return 786468;
            default: return 786603;
        }
    }

    static void ResetChauffeurDriveState(bool waitingForPlayer);

    static void ApplyChauffeurDrivingPersonality()
    {
        if (!IsUsablePedHandle(st.chauffeur, false, true, false)) return;
        float aggression = 0.15f;
        float ability = 0.9f;
        switch (cfg.chauffeurDriveStyle)
        {
            case ChauffeurDriveStyle::Calm: aggression = 0.05f; ability = 0.75f; break;
            case ChauffeurDriveStyle::Fast: aggression = 0.35f; ability = 0.95f; break;
            case ChauffeurDriveStyle::Aggressive: aggression = 0.85f; ability = 1.0f; break;
            case ChauffeurDriveStyle::Vip: aggression = 0.12f; ability = 1.0f; break;
            case ChauffeurDriveStyle::Safe: aggression = 0.02f; ability = 0.85f; break;
            default: break;
        }
        SafePedRuntimeNative(st.chauffeur, "full_audit", "set driver ability", [&](){ PED::SET_DRIVER_ABILITY(st.chauffeur, ability); });
        SafePedRuntimeNative(st.chauffeur, "full_audit", "set driver aggression", [&](){ PED::SET_DRIVER_AGGRESSIVENESS(st.chauffeur, aggression); });
        if (cfg.bodyguardRelationshipFix) ConfigureFriendlyCompanion(st.chauffeur, true);
    }

    static bool ValidateChauffeurReadyForDriving(bool notify)
    {
        Vector3 driverPos{};
        Vector3 vehiclePos{};
        if (!IsUsablePedHandle(st.chauffeur, false, true, true) || !IsUsableVehicleHandle(st.chauffeurVehicle, true))
        {
            ClearChauffeurRuntimeState();
            st.chauffeur = 0;
            st.chauffeurVehicle = 0;
            if (notify) Notify("No chauffeur.");
            return false;
        }
        if (!TryGetUsableEntityPosition((Entity)st.chauffeur, driverPos) || !TryGetUsableEntityPosition((Entity)st.chauffeurVehicle, vehiclePos))
        {
            if (notify) Notify("Chauffeur command rejected: driver/vehicle position invalid.");
            return false;
        }
        Ped currentDriver = (Ped)core::GetPedInVehicleSeat((Vehicle)(st.chauffeurVehicle), -1);
        Ped player = 0;
        GetPlayerPedSafe(player);
        if (currentDriver == player && player != 0)
        {
            ResetChauffeurDriveState(false);
            if (notify) Notify("Chauffeur command rejected: player is driving this car.");
            return false;
        }
        if (currentDriver != st.chauffeur)
        {
            if (currentDriver && core::Exists((Entity)currentDriver) && !core::IsPlayerPed((Entity)currentDriver))
                SafeTaskLeaveVehicle(currentDriver, st.chauffeurVehicle, 0, "chauffeur");
            if (!core::IsVehicleSeatFree((Vehicle)(st.chauffeurVehicle), -1))
            {
                if (notify) Notify("Chauffeur command rejected: driver seat unavailable.");
                return false;
            }
            core::SetPedIntoVehicleSafe((Ped)(st.chauffeur), (Vehicle)(st.chauffeurVehicle), -1);
            WAIT(0);
            if ((Ped)core::GetPedInVehicleSeat((Vehicle)(st.chauffeurVehicle), -1) != st.chauffeur)
            {
                if (notify) Notify("Chauffeur command rejected: driver seat unavailable.");
                return false;
            }
        }
        return true;
    }

    static bool CommandChauffeurToWaypointInternal(bool notify, bool force)
    {
        if (!ValidateChauffeurReadyForDriving(notify))
            return false;

        Vector3 c{};
        if (!GetWaypoint(c))
        {
            if (notify) Notify("No waypoint.");
            return false;
        }
        if (!IsUsableWorldPosition(c, -200.0f, 2000.0f))
        {
            if (notify) Notify("Waypoint rejected: invalid chauffeur destination.");
            return false;
        }

        DWORD now = GetTickCount();
        if (!force && st.chauffeurLastHadWaypoint && IsSameWaypointEnough(c, st.chauffeurLastWaypoint) && !core::TickElapsed(now, st.lastChauffeurDriveCommandTick, 5000u))
            return true;

        st.chauffeurRoutePausedByCombat = false;
        ApplyChauffeurDrivingPersonality();
        SafeTaskVehicleDriveToCoordLongrange(st.chauffeur, st.chauffeurVehicle, c, ChauffeurDriveSpeed(), ChauffeurDriveFlags(), 10.0f, "chauffeur");
        st.chauffeurDriveStarted = true;
        st.chauffeurWaitingForPlayer = false;
        st.chauffeurLastHadWaypoint = true;
        st.chauffeurLastWaypoint = c;
        st.lastChauffeurDriveCommandTick = now;
        if (notify) Notify("Driver going to waypoint.");
        return true;
    }

    static void CommandChauffeurCruise(bool notify, bool force)
    {
        if (!ValidateChauffeurReadyForDriving(notify))
            return;

        DWORD now = GetTickCount();
        if (!force && !st.chauffeurLastHadWaypoint && st.chauffeurDriveStarted && !core::TickElapsed(now, st.lastChauffeurDriveCommandTick, 10000u))
            return;

        st.chauffeurRoutePausedByCombat = false;
        ApplyChauffeurDrivingPersonality();
        SafeTaskVehicleDriveWander(st.chauffeur, st.chauffeurVehicle, ChauffeurDriveSpeed(), ChauffeurDriveFlags(), "full_audit");
        st.chauffeurDriveStarted = true;
        st.chauffeurWaitingForPlayer = false;
        st.chauffeurLastHadWaypoint = false;
        st.lastChauffeurDriveCommandTick = now;
        if (notify) Notify("Chauffeur cruising on roads.");
    }

    static void ResetChauffeurDriveState(bool waitingForPlayer)
    {
        ClearChauffeurRuntimeState();
        st.chauffeurWaitingForPlayer = waitingForPlayer;
        // Keep automatic player entry disabled by default. The car stays unlocked,
        // and passenger entry is handled only by the normal F key hold shortcut.
        st.chauffeurPassengerAutoAssistEnabled = false;
    }

    static void SpawnChauffeur()
    {
        Ped player = 0;
        if (!GetPlayerPedSafe(player)) { Notify("Chauffeur spawn failed: player unavailable."); return; }
        Vehicle veh = 0;
        bool playerAlreadyInVehicle = core::IsPedInAnyVehicle((Ped)(player), false);
        std::string vehicleModel = NormalizeModelName(st.selectedChauffeurVehicle, cfg.defaultDriverVehicle.empty() ? "tailgater" : cfg.defaultDriverVehicle);
        st.selectedChauffeurVehicle = vehicleModel;

        if (playerAlreadyInVehicle)
        {
            veh = core::GetVehiclePedIsIn((Ped)(player), false);
            if (!IsUsableVehicleHandle(veh, true) || !PrepareVehicleForChauffeur(veh)) return;
        }
        else
        {
            veh = SpawnVehicleByModel(vehicleModel, false);
            if (!IsUsableVehicleHandle(veh, true)) return;
            Ped existingDriver = core::GetPedInVehicleSeat((Vehicle)(veh), -1);
            if (existingDriver && core::Exists((Entity)(existingDriver)))
            {
                DeleteEntityAndUntrackIfGone((Entity)veh, false);
                Notify("Driver seat is occupied.");
                return;
            }
            PrepareVehicleForPlayerPassengerEntry(veh);
        }

        Ped oldChauffeur = st.chauffeur;
        Vehicle oldChauffeurVehicle = st.chauffeurVehicle;

        if (oldChauffeur && core::Exists((Entity)(oldChauffeur)))
        {
            bool removed = DeleteEntityAndUntrackIfGone((Entity)oldChauffeur, true);
            if (removed && st.chauffeur == oldChauffeur) st.chauffeur = 0;
        }
        else if (st.chauffeur == oldChauffeur) st.chauffeur = 0;

        if (oldChauffeurVehicle && oldChauffeurVehicle != veh && core::Exists((Entity)(oldChauffeurVehicle)) && !IsPlayerInVehicleEntity(oldChauffeurVehicle))
        {
            DeleteEntityAndUntrackIfGone((Entity)oldChauffeurVehicle, true);
        }
        st.chauffeurVehicle = veh;

        Vector3 driverSpawn{};
        if (!TryGetUsableEntityPosition((Entity)veh, driverSpawn))
        {
            if (!playerAlreadyInVehicle && veh && core::Exists((Entity)(veh)) && !IsPlayerInVehicleEntity(veh))
                DeleteEntityAndUntrackIfGone((Entity)veh, false);
            st.chauffeurVehicle = 0;
            st.chauffeur = 0;
            ResetChauffeurDriveState(false);
            Notify("Chauffeur vehicle position invalid.");
            return;
        }
        float driverHeading = NormalizeHeading(core::SafeGetEntityHeading((Entity)(veh), 0.0f), SafePlayerHeading());
        Ped d = SpawnPedAtModel(st.selectedPedModel, Relation::Friendly, st.selectedPedHealth, st.selectedWeapon, st.selectedPedAmmo, driverSpawn, driverHeading, false);
        if (!d)
        {
            if (!playerAlreadyInVehicle && veh && core::Exists((Entity)(veh)) && !IsPlayerInVehicleEntity(veh))
            {
                DeleteEntityAndUntrackIfGone((Entity)veh, false);
            }
            if (st.chauffeurVehicle == veh) st.chauffeurVehicle = 0;
            st.chauffeur = 0;
            ResetChauffeurDriveState(false);
            Notify("Chauffeur ped failed to spawn.");
            return;
        }

        ConfigureFriendlyCompanion(d, true);
        core::safe_native::ClearPedTasks(d, false, &g_coreErrors, "runtime");
        SafePedRuntimeNative(d, "full_audit", "set driver ability", [&](){ PED::SET_DRIVER_ABILITY(d, 1.0f); });
        SafePedRuntimeNative(d, "full_audit", "set driver aggression", [&](){ PED::SET_DRIVER_AGGRESSIVENESS(d, 0.15f); });
        core::SetPedIntoVehicleSafe((Ped)(d), (Vehicle)(veh), -1);
        WAIT(0);

        if ((Ped)core::GetPedInVehicleSeat((Vehicle)(veh), -1) != d)
        {
            DeleteEntityAndUntrackIfGone((Entity)d, true);
            if (!playerAlreadyInVehicle && veh && core::Exists((Entity)(veh)) && !IsPlayerInVehicleEntity(veh))
            {
                DeleteEntityAndUntrackIfGone((Entity)veh, false);
            }
            if (st.chauffeurVehicle == veh) st.chauffeurVehicle = 0;
            st.chauffeur = 0;
            ResetChauffeurDriveState(false);
            Notify("Chauffeur failed to enter driver seat.");
            return;
        }

        st.chauffeur = d;
        st.chauffeurVehicle = veh;
        if (cfg.chauffeurRepairVehicleOnStart)
        {
            SafeSetVehicleFixedRuntime(veh, "chauffeur");
            SafeSetVehicleEngineOn(veh, true, "full_audit");
        }
        ApplyChauffeurDrivingPersonality();
        PrepareVehicleForPlayerPassengerEntry(veh);
        ResetChauffeurDriveState(!IsPlayerPassengerInChauffeurVehicle());
        PushEntityUndo("Spawn Chauffeur: " + st.selectedPedModel, (Entity)d);

        if (IsPlayerPassengerInChauffeurVehicle())
        {
            if (!CommandChauffeurToWaypointInternal(false, true)) CommandChauffeurCruise(false, true);
            st.chauffeurPlayerWasInside = true;
            Notify(playerAlreadyInVehicle ? "Chauffeur spawned. Player moved to passenger seat." : "Chauffeur spawned. Driving started.");
        }
        else
        {
            Notify("Chauffeur spawned in " + vehicleModel + ". Hold F near the car for passenger seat; tap F for driver seat.");
        }
    }

    static void DriverToWaypoint()
    {
        if (!ValidateChauffeurReadyForDriving(true)) return;
        RestoreChauffeurTemporaryDriveStyle();
        if (!IsPlayerPassengerInChauffeurVehicle())
        {
            Vector3 c{};
            if (!GetWaypoint(c)) { Notify("No waypoint."); return; }
            if (!IsUsableWorldPosition(c, -200.0f, 2000.0f)) { Notify("Waypoint rejected: invalid chauffeur destination."); return; }
            st.chauffeurLastWaypoint = c;
            st.chauffeurLastHadWaypoint = true;
            st.chauffeurWaitingForPlayer = true;
            st.chauffeurPassengerAutoAssistEnabled = false;
            st.lastChauffeurPlayerExitTick = 0;
            Notify("Waypoint ready. Enter passenger seat to start.");
            return;
        }
        CommandChauffeurToWaypointInternal(true, true);
    }

    static void ChauffeurCruiseNow()
    {
        RestoreChauffeurTemporaryDriveStyle();
        CommandChauffeurCruise(true, true);
    }

    static void ChauffeurWaitHere()
    {
        if (!ValidateChauffeurReadyForDriving(true)) return;
        RestoreChauffeurTemporaryDriveStyle();
        core::safe_native::ClearPedTasks(st.chauffeur, false, &g_coreErrors, "runtime");
        core::SetPedIntoVehicleSafe((Ped)(st.chauffeur), (Vehicle)(st.chauffeurVehicle), -1);
        SafeSetVehicleEngineOn(st.chauffeurVehicle, true, "full_audit");
        st.chauffeurWaitingForPlayer = true;
        st.chauffeurRoutePausedByCombat = false;
        st.chauffeurDriveStarted = false;
        st.chauffeurLastHadWaypoint = false;
        st.chauffeurPassengerAutoAssistEnabled = false;
        Notify("Chauffeur waiting here.");
    }

    static void RepairChauffeurVehicle()
    {
        if (!IsUsableVehicleHandle(st.chauffeurVehicle, false)) { Notify("No chauffeur vehicle."); return; }
        Vector3 vehiclePos{};
        if (!TryGetUsableEntityPosition((Entity)st.chauffeurVehicle, vehiclePos)) { Notify("Chauffeur vehicle repair rejected: position invalid."); return; }
        if (!core::safe_native::RepairVehicle(st.chauffeurVehicle, nullptr, "vehicle"))
        {
            ReportCore2(core::ErrorSeverity::Warning, "vehicle", "repair chauffeur vehicle", "SafeNative rejected chauffeur vehicle repair.");
            Notify("Chauffeur vehicle repair rejected by Core 2.0 safety.");
            return;
        }
        SafeSetVehicleDirtLevel(st.chauffeurVehicle, 0.0f, "chauffeur");
        Notify("Chauffeur vehicle repaired.");
    }



    static bool CommandChauffeurToCoords(Vector3 c, bool notify, const std::string& label)
    {
        if (!ValidateChauffeurReadyForDriving(notify))
            return false;
        if (!IsUsableWorldPosition(c, -200.0f, 2000.0f))
        {
            if (notify) Notify("Chauffeur destination rejected: invalid coordinates.");
            return false;
        }
        st.chauffeurRoutePausedByCombat = false;
        ApplyChauffeurDrivingPersonality();
        SafeTaskVehicleDriveToCoordLongrange(st.chauffeur, st.chauffeurVehicle, c, ChauffeurDriveSpeed(), ChauffeurDriveFlags(), 10.0f, "chauffeur");
        st.chauffeurDriveStarted = true;
        st.chauffeurWaitingForPlayer = true;
        st.chauffeurLastHadWaypoint = false;
        st.lastChauffeurDriveCommandTick = GetTickCount();
        if (notify) Notify(label);
        return true;
    }

    static void ChauffeurPickMeUp()
    {
        Ped player = 0;
        if (!GetPlayerPedSafe(player)) { Notify("Player unavailable."); return; }
        if (!ValidateChauffeurReadyForDriving(true)) return;
        Vector3 pp{};
        if (!TryGetUsableEntityPosition((Entity)player, pp)) { Notify("Chauffeur pickup failed: invalid player position."); return; }
        st.chauffeurPickupMode = true;
        st.chauffeurEmergencyEscapeMode = false;
        RestoreChauffeurTemporaryDriveStyle();
        st.chauffeurPassengerAutoAssistEnabled = false;
        st.chauffeurLastPickupReissueTick = 0;
        CommandChauffeurToCoords(pp, true, "Chauffeur is coming to pick you up.");
    }

    static void ChauffeurEmergencyEscape()
    {
        if (!ValidateChauffeurReadyForDriving(true)) return;
        st.chauffeurPickupMode = false;
        st.chauffeurEmergencyEscapeMode = true;
        if (!st.chauffeurTemporaryDriveStyleActive)
        {
            st.chauffeurPreviousDriveStyle = cfg.chauffeurDriveStyle;
            st.chauffeurTemporaryDriveStyleActive = true;
        }
        cfg.chauffeurDriveStyle = ChauffeurDriveStyle::Aggressive;
        ApplyChauffeurDrivingPersonality();
        if (cfg.chauffeurEmergencyEscapeClearsWanted) SafeClearPlayerWantedLevelRuntime();
        if (!CommandChauffeurToWaypointInternal(false, true)) CommandChauffeurCruise(false, true);
        Notify("Emergency escape started.");
    }

    static void CancelChauffeurOrder()
    {
        st.chauffeurPickupMode = false;
        st.chauffeurEmergencyEscapeMode = false;
        RestoreChauffeurTemporaryDriveStyle();
        st.chauffeurLastPickupReissueTick = 0;
        st.chauffeurWaitingForPlayer = true;
        st.chauffeurDriveStarted = false;
        if (!IsUsablePedHandle(st.chauffeur, false, true, true) || !IsUsableVehicleHandle(st.chauffeurVehicle, true))
        {
            ClearChauffeurRuntimeState();
            Notify("Chauffeur order cleared; no active chauffeur.");
            return;
        }
        core::safe_native::ClearPedTasks(st.chauffeur, false, &g_coreErrors, "runtime");
        if ((Ped)core::GetPedInVehicleSeat((Vehicle)(st.chauffeurVehicle), -1) != st.chauffeur)
        {
            if (core::IsVehicleSeatFree((Vehicle)(st.chauffeurVehicle), -1))
                core::SetPedIntoVehicleSafe((Ped)(st.chauffeur), (Vehicle)(st.chauffeurVehicle), -1);
            else
                Notify("Chauffeur order cancelled; driver seat is occupied.");
        }
        SafeSetVehicleEngineOn(st.chauffeurVehicle, true, "full_audit");
        Notify("Chauffeur order cancelled.");
    }

    static void CleanupDeadPeds(std::vector<Ped>& list)
    {
        std::vector<Ped> kept;
        kept.reserve(list.size());
        for (Ped ped : list)
        {
            if (IsUsablePedHandle(ped, false, true, true) && std::find(kept.begin(), kept.end(), ped) == kept.end())
                kept.push_back(ped);
            else if (ped && !core::IsPed((Entity)ped))
                RemoveTrackedEntity((Entity)ped);
        }
        list.swap(kept);
    }

    static int AliveCount(const std::vector<Ped>& list)
    {
        int count = 0;
        for (Ped ped : list)
        {
            if (IsUsablePedHandle(ped, false, true, true)) ++count;
        }
        return count;
    }

    static Ped SpawnPedAtModel(const std::string& modelName, Relation relation, int health, const std::string& weapon, int ammo, Vector3 pos, float heading, bool addToSpawned, bool autoTask)
    {
        std::string cleanModel = NormalizeModelName(modelName, "");
        if (cleanModel.empty()) { Notify("Ped model is empty."); return 0; }
        Hash model = H(cleanModel);
        if (!LoadModel(model)) { Notify("Ped model failed: " + cleanModel); return 0; }
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f))
        {
            SafeReleaseModelRuntime(model, "spawn");
            Notify("Ped spawn failed: invalid target position.");
            return 0;
        }
        heading = NormalizeHeading(heading, SafePlayerHeading());
        pos = ApplySpawnSafety(pos, false);
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f))
        {
            SafeReleaseModelRuntime(model, "spawn");
            Notify("Ped spawn failed: unsafe final target.");
            return 0;
        }
        Ped ped = SafeCreatePedRuntime(26, model, pos, heading, false, true, "ped_spawn");
        SafeReleaseModelRuntime(model, "spawn");
        if (!ped || !core::IsPed((Entity)ped)) { if (ped && core::Exists((Entity)(ped))) DeleteRejectedSpawnOrKeepTracked((Entity)ped, true); return 0; }
        if (!IsEntityFinalPositionAcceptable((Entity)ped, pos))
        {
            DeleteRejectedSpawnOrKeepTracked((Entity)ped, true);
            Notify("Ped spawn rejected: final position invalid.");
            return 0;
        }

        int safeHealth = ClampIntValue(health, 1, 10000);
        int safeAmmo = ClampIntValue(ammo, 0, 9999);
        core::safe_native::SetMissionEntity((Entity)(ped), true, true, &g_coreErrors, "full_audit");
        core::safe_native::SetHealth((Entity)(ped), safeHealth, &g_coreErrors, "full_audit");
        core::safe_native::SetPedArmour(ped, relation == Relation::Friendly ? 100 : 0, &g_coreErrors, "spawn");
        if (relation == Relation::Friendly) RegisterFriendlyNpc(ped, true);
        else RemoveFriendlyNpcRuntime(ped);
        GiveWeapon(ped, weapon, safeAmmo);
        core::safe_native::SetPedCanRagdoll(ped, true, &g_coreErrors, "runtime");
        if (relation == Relation::Friendly || relation == Relation::Enemy)
        {
            SafePedRuntimeNative(ped, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 2); }, true, false);
            SafePedRuntimeNative(ped, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, 2); }, true, false);
            SafePedRuntimeNative(ped, "full_audit", "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(ped, 2); }, true, false);
            SafeSetPedAccuracy(ped, relation == Relation::Friendly ? 65 : 55, "full_audit");
            SafePedRuntimeNative(ped, "full_audit", "set ped flee attributes", [&](){ PED::SET_PED_FLEE_ATTRIBUTES(ped, 0, false); }, true, false);
            SafePedRuntimeNative(ped, "full_audit", "set ped combat attribute always fight", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(ped, 5, true); }, true, false);
            SafePedRuntimeNative(ped, "full_audit", "set ped combat attribute armed fight", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(ped, 46, true); }, true, false);
        }
        else
        {
            // BUGFIX 161: neutral spawns must not inherit the companion/enemy anti-panic
            // combat baseline. Older code applied flee-off + combat attributes to every
            // spawned ped, so Civilian/Driver/ambient mission NPCs could behave like
            // armed combatants even when their relation was Neutral.
            SafePedRuntimeNative(ped, "full_audit", "set neutral ped blocking", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, false); }, true, false);
            SafePedRuntimeNative(ped, "full_audit", "set neutral ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 0); }, true, false);
            SafePedRuntimeNative(ped, "full_audit", "set neutral ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, 0); }, true, false);
            SafePedRuntimeNative(ped, "full_audit", "set neutral ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(ped, 0); }, true, false);
            SafeSetPedAccuracy(ped, 20, "full_audit");
            SafePedRuntimeNative(ped, "full_audit", "set neutral ped flee attributes", [&](){ PED::SET_PED_FLEE_ATTRIBUTES(ped, 0, true); }, true, false);
            SafePedRuntimeNative(ped, "full_audit", "clear neutral always fight", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(ped, 5, false); }, true, false);
            SafePedRuntimeNative(ped, "full_audit", "clear neutral armed fight", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(ped, 46, false); }, true, false);
            SafePedRuntimeNative(ped, "full_audit", "clear neutral disable flee", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(ped, 58, false); }, true, false);
        }

        if (autoTask)
        {
            Ped playerPed = 0;
            if (GetPlayerPedSafe(playerPed))
            {
                if (relation == Relation::Enemy)
                {
                    SafeTaskCombatPed(ped, playerPed, "full_audit");
                }
                else if (relation == Relation::Friendly)
                {
                    if (!TrySeatFriendlyNpcInPlayerVehicleOrSuppressFootFollow(ped, "friendly_spawn", true))
                        SafeTaskFollowToOffset(ped, (Entity)playerPed, 0.0f, -2.0f, 0.0f, 2.0f, -1, 2.0f, true, "full_audit");
                }
                else SafeTaskWanderStandard(ped, 10.0f, 10, "npc_control");
            }
            else
            {
                SafeTaskWanderStandard(ped, 10.0f, 10, "npc_control");
            }
        }
        else
        {
            SafePedRuntimeNative(ped, "full_audit", "set ped blocking", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, true); }, true, false);
        }
        if (addToSpawned)
        {
            TrackSpawnedPedIfAlive(ped);
            PushEntityUndo("Spawn Ped: " + cleanModel, (Entity)ped);
        }
        return ped;
    }

    static Vector3 OffsetAroundPlayer(float distance, int index, int total)
    {
        Vector3 center{};
        if (!TryGetPlayerPosition(center)) return InvalidWorldVector();
        float angle = ((float)index / std::max(1, total)) * 6.283185307f;
        center.x += cosf(angle) * distance;
        center.y += sinf(angle) * distance;
        return IsUsableWorldPosition(center, -200.0f, 2000.0f) ? center : InvalidWorldVector();
    }

    static void SpawnEnemySquad()
    {
        Vector3 playerBase{};
        if (!TryGetPlayerPosition(playerBase))
        {
            Notify("Enemy squad spawn failed: player position invalid.");
            return;
        }
        int count = std::max(1, std::min(st.enemyCount, cfg.maxBattleEnemies));
        int spawned = 0;
        for (int i = 0; i < count; ++i)
        {
            Vector3 pos = OffsetAroundPlayer(18.0f + (i % 3) * 4.0f, i, count);
            Ped e = SpawnPedAtModel(st.selectedPedModel, Relation::Enemy, st.enemyHealth, st.selectedWeapon, st.enemyAmmo, pos, 0.0f, false);
            if (e)
            {
                st.enemies.push_back(e);
                PushEntityUndo("Spawn Enemy: " + st.selectedPedModel, (Entity)e);
                ++spawned;
            }
        }
        Notify("Enemy squad spawned: " + std::to_string(spawned));
    }

    static Relation RelationForNpcPersonality(NpcPersonality personality)
    {
        switch (personality)
        {
            case NpcPersonality::Aggressive:
            case NpcPersonality::Gangster:
                return Relation::Enemy;
            case NpcPersonality::Bodyguard:
                // BUGFIX 167: bodyguards have their own runtime owner (st.bodyguards).
                // Spawning them as generic Friendly registers them in st.friendlyPeds
                // before promotion, briefly enabling duplicate support AI and allowing
                // instant vehicle-seat placement before the no-teleport companion rule
                // sees the ped as a bodyguard. Spawn neutral, then promote explicitly.
                return Relation::Neutral;
            case NpcPersonality::Medic:
                return Relation::Friendly;
            default:
                return Relation::Neutral;
        }
    }

    static std::string DefaultWeaponForNpcPersonality(NpcPersonality personality, const std::string& fallback, bool respectDirectorAutoArm = false)
    {
        std::string cleanFallback = NormalizeModelName(fallback, "NONE");
        if (respectDirectorAutoArm && !st.npcDirectorAutoArm &&
            personality != NpcPersonality::Bodyguard &&
            personality != NpcPersonality::Cop &&
            personality != NpcPersonality::Medic)
        {
            return "NONE";
        }
        switch (personality)
        {
            case NpcPersonality::Guard: return cleanFallback == "NONE" ? "WEAPON_PISTOL" : cleanFallback;
            case NpcPersonality::Bodyguard: return cleanFallback == "NONE" ? "WEAPON_CARBINERIFLE" : cleanFallback;
            case NpcPersonality::Gangster: return cleanFallback == "NONE" ? "WEAPON_SMG" : cleanFallback;
            case NpcPersonality::Cop: return "WEAPON_PISTOL";
            case NpcPersonality::Medic: return "WEAPON_PISTOL";
            case NpcPersonality::Aggressive: return cleanFallback == "NONE" ? "WEAPON_BAT" : cleanFallback;
            default: return "NONE";
        }
    }

    static bool IsLiveNonPlayerPed(Ped ped)
    {
        return IsUsablePedHandle(ped, false, true, true);
    }

    static bool IsMissionRuntimeEntity(Entity entity)
    {
        if (!entity) return false;
        return std::find(st.missionSpawnedEntities.begin(), st.missionSpawnedEntities.end(), entity) != st.missionSpawnedEntities.end();
    }

    static bool IsMissionRuntimePed(Ped ped)
    {
        return ped && IsMissionRuntimeEntity((Entity)ped) && core::IsPed((Entity)ped);
    }

    static void RemovePedHandleFromList(std::vector<Ped>& list, Ped ped)
    {
        if (!ped) return;
        list.erase(std::remove(list.begin(), list.end(), ped), list.end());
    }

    static bool PedHandleInList(const std::vector<Ped>& list, Ped ped)
    {
        return ped && std::find(list.begin(), list.end(), ped) != list.end();
    }

    static bool PedTrackedByNpcRuntime(Ped ped)
    {
        if (!ped) return false;
        if (PedHandleInList(st.spawnedPeds, ped) || PedHandleInList(st.friendlyPeds, ped) || PedHandleInList(st.bodyguards, ped) ||
            PedHandleInList(st.enemies, ped) || PedHandleInList(st.scenarioPeds, ped))
            return true;
        return IsMissionRuntimePed(ped);
    }

    static void EnsureRegularNpcTracking(Ped ped)
    {
        if (!IsLiveNonPlayerPed(ped) || IsMissionRuntimePed(ped)) return;
        if (!PedTrackedByNpcRuntime(ped))
            st.spawnedPeds.push_back(ped);
    }

    static bool PromotePedToBodyguardRole(Ped ped)
    {
        if (!IsLiveNonPlayerPed(ped) || IsMissionRuntimePed(ped)) return false;
        const bool alreadyBodyguard = PedHandleInList(st.bodyguards, ped);
        if (!alreadyBodyguard && CountExistingPeds(st.bodyguards) >= std::max(1, cfg.maxBodyguards))
            return false;
        RemovePedHandleFromList(st.enemies, ped);
        ClearCompanionTargetReferencesToPedRuntime(ped);
        RemovePedHandleFromList(st.scenarioPeds, ped);
        RemovePedHandleFromList(st.spawnedPeds, ped);
        // BUGFIX 166: bodyguard runtime has its own list. Keep the ped out of
        // st.friendlyPeds to avoid duplicate friendly support ticks and double command
        // ownership after Convert Last NPC / Bodyguard personality promotion.
        RemoveFriendlyNpcRuntime(ped);
        if (!alreadyBodyguard)
            st.bodyguards.push_back(ped);
        st.bodyguardRoles[ped] = BodyguardRole::Guard;
        ConfigureBodyguard(ped);
        return true;
    }

    static void RemovePedFromBodyguardRole(Ped ped)
    {
        if (!ped) return;
        RemovePedHandleFromList(st.bodyguards, ped);
        ClearBodyguardRuntimeState(ped, !IsFriendlyNpcTracked(ped));
    }

    static void SyncNpcRoleAfterPersonality(Ped ped, NpcPersonality personality)
    {
        if (!IsLiveNonPlayerPed(ped) || IsMissionRuntimePed(ped)) return;
        if (personality == NpcPersonality::Bodyguard)
        {
            if (!PromotePedToBodyguardRole(ped))
            {
                RemovePedHandleFromList(st.enemies, ped);
                EnsureRegularNpcTracking(ped);
            }
            return;
        }

        RemovePedFromBodyguardRole(ped);
        if (personality == NpcPersonality::Aggressive || personality == NpcPersonality::Gangster)
        {
            RemoveFriendlyNpcRuntime(ped);
            if (std::find(st.enemies.begin(), st.enemies.end(), ped) == st.enemies.end())
                st.enemies.push_back(ped);
        }
        else
        {
            RemovePedHandleFromList(st.enemies, ped);
            if (personality == NpcPersonality::Medic)
            {
                RegisterFriendlyNpc(ped, true);
            }
            else
            {
                // BUGFIX 160: demoting a former bodyguard/friendly NPC to Civilian,
                // Coward, Guard, Cop or Driver must fully remove friendly runtime.
                // Otherwise friendly protection/vehicle-entry ticks keep treating the
                // ped as an ally after the NPC Menu changed its personality.
                RemoveFriendlyNpcRuntime(ped);
            }
            EnsureRegularNpcTracking(ped);
        }
    }

    static std::vector<Ped> CollectLiveNpcTargets(bool includeSpawned, bool includeBodyguards, bool includeEnemies, bool includeScenario, bool includeMission = false)
    {
        std::vector<Ped> out;
        auto addList = [&](const std::vector<Ped>& list)
        {
            for (Ped ped : list)
            {
                if (!IsLiveNonPlayerPed(ped)) continue;
                if (std::find(out.begin(), out.end(), ped) == out.end()) out.push_back(ped);
            }
        };
        if (includeSpawned) addList(st.spawnedPeds);
        if (includeBodyguards) addList(st.bodyguards);
        if (includeEnemies) addList(st.enemies);
        if (includeScenario) addList(st.scenarioPeds);
        if (includeMission)
        {
            for (Entity entity : st.missionSpawnedEntities)
            {
                if (entity && core::Exists((Entity)(entity)) && core::IsPed((Entity)(entity)))
                {
                    Ped ped = (Ped)entity;
                    if (IsLiveNonPlayerPed(ped) && std::find(out.begin(), out.end(), ped) == out.end()) out.push_back(ped);
                }
            }
        }
        return out;
    }

    static void ResetNpcPersonalityRuntimeFlags(Ped ped, NpcPersonality personality)
    {
        if (!IsLiveNonPlayerPed(ped)) return;

        core::safe_native::Freeze((Entity)ped, false, &g_coreErrors, "npc_personality");
        core::safe_native::SetInvincible((Entity)ped, false, &g_coreErrors, "npc_personality");
        core::safe_native::SetPedCanRagdoll(ped, true, &g_coreErrors, "npc_personality");

        const bool friendlyRole = personality == NpcPersonality::Bodyguard || personality == NpcPersonality::Medic;
        const bool enemyRole = personality == NpcPersonality::Aggressive || personality == NpcPersonality::Gangster;
        if (!friendlyRole && !enemyRole)
        {
            SafeSetPedCombatAttribute(ped, 5, false, "npc_personality");
            SafeSetPedCombatAttribute(ped, 46, false, "npc_personality");
            SafeSetPedCombatAttribute(ped, 58, false, "npc_personality");
            SafePedRuntimeNative(ped, "npc_personality", "reset ped flee attributes", [&](){ PED::SET_PED_FLEE_ATTRIBUTES(ped, 0, true); }, true, false);
        }
    }

    static void ApplyNpcPersonality(Ped ped, NpcPersonality personality, bool issueTask, bool respectDirectorAutoArm = false)
    {
        if (!IsLiveNonPlayerPed(ped)) return;
        ResetNpcPersonalityRuntimeFlags(ped, personality);
        Ped playerPed = 0;
        Vector3 playerPos{};
        if (!GetPlayerPedSafe(playerPed) || !TryGetPlayerPosition(playerPos))
            playerPed = 0;

        core::safe_native::SetMissionEntity((Entity)((Entity)ped), true, true, &g_coreErrors, "full_audit");
        core::safe_native::SetPedCanRagdoll(ped, true, &g_coreErrors, "runtime");
        const bool personalityCombatRole = personality == NpcPersonality::Aggressive ||
                                           personality == NpcPersonality::Guard ||
                                           personality == NpcPersonality::Bodyguard ||
                                           personality == NpcPersonality::Gangster ||
                                           personality == NpcPersonality::Cop ||
                                           personality == NpcPersonality::Medic;
        if (personalityCombatRole)
        {
            SafePedRuntimeNative(ped, "npc_personality", "set combat-role flee attributes", [&](){ PED::SET_PED_FLEE_ATTRIBUTES(ped, 0, false); }, true, false);
            SafePedRuntimeNative(ped, "npc_personality", "set combat-role always fight", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(ped, 5, true); }, true, false);
            SafePedRuntimeNative(ped, "npc_personality", "set combat-role armed fight", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(ped, 46, true); }, true, false);
        }
        else
        {
            // BUGFIX 161: BUGFIX 160 neutral cleanup was being undone here by a
            // global combat baseline. Civilian/Coward/Driver now keep their
            // non-combat/flee-capable flags instead of being silently re-armed as fighters.
            SafePedRuntimeNative(ped, "npc_personality", "set neutral flee attributes", [&](){ PED::SET_PED_FLEE_ATTRIBUTES(ped, 0, true); }, true, false);
            SafePedRuntimeNative(ped, "npc_personality", "clear neutral always fight", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(ped, 5, false); }, true, false);
            SafePedRuntimeNative(ped, "npc_personality", "clear neutral armed fight", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(ped, 46, false); }, true, false);
            SafePedRuntimeNative(ped, "npc_personality", "clear neutral disable flee", [&](){ PED::SET_PED_COMBAT_ATTRIBUTES(ped, 58, false); }, true, false);
        }
        SafeRemoveAllPedWeapons(ped, true, "npc_personality");
        if (personality != NpcPersonality::Cop)
            SafePedRuntimeNative(ped, "full_audit", "set ped cop", [&](){ PED::SET_PED_AS_COP(ped, false); }, true, false);

        switch (personality)
        {
            case NpcPersonality::Coward:
                SafeRemoveAllPedWeapons(ped, true, "npc_personality");
                SafePedRuntimeNative(ped, "full_audit", "set ped blocking", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, false); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 0); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, 0); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(ped, 0); }, true, false);
                SafeSetPedAccuracy(ped, 5, "full_audit");
                core::safe_native::SetPedArmour(ped, 0, &g_coreErrors, "runtime");
                if (issueTask) SafeTaskWanderStandard(ped, 10.0f, 10, "npc_control");
                break;
            case NpcPersonality::Aggressive:
                SafePedRuntimeNative(ped, "full_audit", "set ped blocking", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, true); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 2); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, 2); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(ped, 1); }, true, false);
                SafeSetPedAccuracy(ped, 55, "full_audit");
                GiveWeapon(ped, DefaultWeaponForNpcPersonality(personality, st.selectedWeapon, respectDirectorAutoArm), std::max(120, st.selectedPedAmmo));
                if (issueTask && playerPed) SafeTaskCombatPed(ped, playerPed, "full_audit");
                break;
            case NpcPersonality::Guard:
                SafePedRuntimeNative(ped, "full_audit", "set ped blocking", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, true); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 2); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, 1); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(ped, 1); }, true, false);
                SafeSetPedAccuracy(ped, 60, "full_audit");
                core::safe_native::SetPedArmour(ped, 80, &g_coreErrors, "runtime");
                GiveWeapon(ped, DefaultWeaponForNpcPersonality(personality, st.selectedWeapon, respectDirectorAutoArm), std::max(120, st.selectedPedAmmo));
                if (issueTask) SafeTaskWanderStandard(ped, 5.0f, 5, "full_audit");
                break;
            case NpcPersonality::Bodyguard:
            {
                // BUGFIX 167: do not route Bodyguard personality through the generic
                // friendly registration path. Promote first so vehicle entry uses the
                // physical companion pipeline and the ped is owned only by st.bodyguards.
                const bool promoted = PromotePedToBodyguardRole(ped);
                if (!promoted)
                {
                    RemoveFriendlyNpcRuntime(ped);
                    EnsureRegularNpcTracking(ped);
                }
                core::safe_native::SetPedArmour(ped, 100, &g_coreErrors, "runtime");
                SafePedRuntimeNative(ped, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 2); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, 2); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(ped, 2); }, true, false);
                SafeSetPedAccuracy(ped, std::max(60, cfg.bodyguardAccuracy), "full_audit");
                GiveWeapon(ped, DefaultWeaponForNpcPersonality(personality, st.selectedWeapon, respectDirectorAutoArm), std::max(300, st.selectedPedAmmo));
                if (issueTask && playerPed && IsBodyguardTracked(ped))
                {
                    if (!TrySeatFriendlyNpcInPlayerVehicleOrSuppressFootFollow(ped, "npc_director", true))
                        SafeTaskFollowToOffset(ped, (Entity)playerPed, 0.0f, -2.0f, 0.0f, 2.2f, -1, 2.0f, true, "npc_director");
                }
                break;
            }
            case NpcPersonality::Gangster:
                SafePedRuntimeNative(ped, "full_audit", "set ped blocking", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, true); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 2); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, 2); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(ped, 2); }, true, false);
                SafeSetPedAccuracy(ped, 48, "full_audit");
                core::safe_native::SetPedArmour(ped, 40, &g_coreErrors, "runtime");
                GiveWeapon(ped, DefaultWeaponForNpcPersonality(personality, st.selectedWeapon, respectDirectorAutoArm), std::max(180, st.selectedPedAmmo));
                if (issueTask && playerPed) SafeTaskCombatPed(ped, playerPed, "full_audit");
                break;
            case NpcPersonality::Cop:
                SafePedRuntimeNative(ped, "full_audit", "set ped cop", [&](){ PED::SET_PED_AS_COP(ped, true); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped blocking", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, true); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 2); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, 2); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(ped, 2); }, true, false);
                SafeSetPedAccuracy(ped, 62, "full_audit");
                core::safe_native::SetPedArmour(ped, 80, &g_coreErrors, "runtime");
                GiveWeapon(ped, DefaultWeaponForNpcPersonality(personality, st.selectedWeapon, respectDirectorAutoArm), std::max(120, st.selectedPedAmmo));
                if (issueTask) SafeTaskWanderStandard(ped, 7.0f, 7, "full_audit");
                break;
            case NpcPersonality::Driver:
                SafePedRuntimeNative(ped, "full_audit", "set ped blocking", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, false); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set driver ability", [&](){ PED::SET_DRIVER_ABILITY(ped, 0.92f); });
                SafePedRuntimeNative(ped, "full_audit", "set driver aggression", [&](){ PED::SET_DRIVER_AGGRESSIVENESS(ped, 0.18f); });
                SafePedRuntimeNative(ped, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 1); }, true, false);
                SafeSetPedAccuracy(ped, 35, "full_audit");
                if (issueTask) SafeTaskWanderStandard(ped, 12.0f, 12, "full_audit");
                break;
            case NpcPersonality::Medic:
                RegisterFriendlyNpc(ped, true);
                core::safe_native::SetPedArmour(ped, 70, &g_coreErrors, "runtime");
                SafePedRuntimeNative(ped, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 1); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, 1); }, true, false);
                SafeSetPedAccuracy(ped, 35, "full_audit");
                GiveWeapon(ped, DefaultWeaponForNpcPersonality(personality, st.selectedWeapon, respectDirectorAutoArm), std::max(90, st.selectedPedAmmo));
                if (issueTask && playerPed)
                {
                    if (!TrySeatFriendlyNpcInPlayerVehicleOrSuppressFootFollow(ped, "npc_director", true))
                        SafeTaskFollowToOffset(ped, (Entity)playerPed, 1.5f, -2.5f, 0.0f, 2.0f, -1, 2.0f, true, "npc_director");
                }
                break;
            default:
                SafeRemoveAllPedWeapons(ped, true, "npc_personality");
                SafePedRuntimeNative(ped, "full_audit", "set ped cop", [&](){ PED::SET_PED_AS_COP(ped, false); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped blocking", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, false); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat ability", [&](){ PED::SET_PED_COMBAT_ABILITY(ped, 0); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat movement", [&](){ PED::SET_PED_COMBAT_MOVEMENT(ped, 0); }, true, false);
                SafePedRuntimeNative(ped, "full_audit", "set ped combat range", [&](){ PED::SET_PED_COMBAT_RANGE(ped, 0); }, true, false);
                SafeSetPedAccuracy(ped, 20, "full_audit");
                core::safe_native::SetPedArmour(ped, 0, &g_coreErrors, "runtime");
                if (issueTask) SafeTaskWanderStandard(ped, 10.0f, 10, "npc_control");
                break;
        }
    }

