    static void ConvertLastNpcToBodyguard()
    {
        Entity entity = LastExistingPedEntity();
        if (!entity || !core::Exists((Entity)(entity)) || !core::IsPed((Entity)(entity)))
        {
            Notify("No valid NPC found.");
            return;
        }
        Ped ped = (Ped)entity;
        if (!IsLiveNonPlayerPed(ped))
        {
            Notify("Last NPC is invalid or dead.");
            return;
        }
        if (IsMissionRuntimePed(ped))
        {
            Notify("Mission NPC is protected. Use Mission Creator tools.");
            return;
        }
        if (!PedHandleInList(st.bodyguards, ped) && CountExistingPeds(st.bodyguards) >= std::max(1, cfg.maxBodyguards))
        {
            Notify("Bodyguard limit reached.");
            return;
        }
        ApplyNpcPersonality(ped, NpcPersonality::Bodyguard, true);
        if (!PromotePedToBodyguardRole(ped))
        {
            EnsureRegularNpcTracking(ped);
            Notify("Bodyguard conversion failed.");
            return;
        }
        Notify("Last NPC converted to bodyguard.");
    }

    static Ped SpawnNpcDirectorPed(const std::string& model, NpcPersonality personality, int index, int total, float baseDistance)
    {
        Vector3 pos = OffsetAroundPlayer(baseDistance + (float)(index % 3) * 2.5f, index, total);
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f)) return 0;
        std::string weapon = DefaultWeaponForNpcPersonality(personality, st.selectedWeapon, true);
        int health = 170 + ClampIntValue(st.npcDirectorIntensity, 1, 5) * 35;
        if (personality == NpcPersonality::Coward || personality == NpcPersonality::Civilian) health = 120;
        Ped ped = SpawnPedAtModel(model, RelationForNpcPersonality(personality), health, weapon, st.selectedPedAmmo, pos, SafePlayerHeading(), true, false);
        if (!ped) return 0;
        ApplyNpcPersonality(ped, personality, true, true);
        SyncNpcRoleAfterPersonality(ped, personality);
        return ped;
    }

    static void LaunchNpcDirectorScene(NpcDirectorScene scene)
    {
        Vector3 playerBase{};
        if (!TryGetPlayerPosition(playerBase))
        {
            Notify("NPC Director failed: player position invalid.");
            return;
        }
        int intensity = ClampIntValue(st.npcDirectorIntensity, 1, 5);
        int spawned = 0;
        std::vector<Ped> scenePeds;
        auto addPed = [&](const std::string& model, NpcPersonality personality, int index, int total, float dist) -> Ped
        {
            Ped ped = SpawnNpcDirectorPed(model, personality, index, total, dist);
            if (ped)
            {
                scenePeds.push_back(ped);
                ++spawned;
            }
            return ped;
        };

        switch (scene)
        {
            case NpcDirectorScene::CivilianCrowd:
            {
                int count = 3 + intensity * 2;
                for (int i = 0; i < count; ++i)
                    addPed(i % 2 == 0 ? "a_m_y_business_01" : "a_f_y_tourist_01", i % 4 == 0 ? NpcPersonality::Coward : NpcPersonality::Civilian, i, count, 7.0f);
                break;
            }
            case NpcDirectorScene::GangPatrol:
            {
                int count = 2 + intensity;
                for (int i = 0; i < count; ++i)
                    addPed(i % 2 == 0 ? "g_m_y_ballaorig_01" : "g_m_y_famca_01", NpcPersonality::Gangster, i, count, 13.0f);
                break;
            }
            case NpcDirectorScene::PoliceFootPatrol:
            {
                int count = 2 + std::min(3, intensity);
                for (int i = 0; i < count; ++i)
                    addPed(i % 2 == 0 ? "s_m_y_cop_01" : "s_f_y_cop_01", NpcPersonality::Cop, i, count, 10.0f);
                break;
            }
            case NpcDirectorScene::BodyguardEscort:
            {
                int oldCount = st.bodyguardCount;
                bool oldReplace = cfg.replaceBodyguards;
                cfg.replaceBodyguards = false;
                st.bodyguardCount = std::min(cfg.maxBodyguards, std::max(2, intensity + 1));
                int before = CountExistingPeds(st.bodyguards);
                SpawnBodyguards();
                int after = CountExistingPeds(st.bodyguards);
                spawned += std::max(0, after - before);
                st.bodyguardCount = oldCount;
                cfg.replaceBodyguards = oldReplace;
                BodyguardsCoverPlayer();
                break;
            }
            case NpcDirectorScene::HostileAmbush:
            {
                int count = 3 + intensity * 2;
                for (int i = 0; i < count; ++i)
                    addPed(i % 3 == 0 ? "g_m_y_lost_01" : "g_m_y_mexgang_01", NpcPersonality::Aggressive, i, count, 18.0f);
                break;
            }
            default:
            {
                Ped a = addPed("a_m_y_business_01", NpcPersonality::Aggressive, 0, 2, 7.5f);
                Ped b = addPed("a_m_y_hipster_01", NpcPersonality::Aggressive, 1, 2, 7.5f);
                if (a && b)
                {
                    SafeTaskCombatPed(a, b, "full_audit");
                    SafeTaskCombatPed(b, a, "full_audit");
                }
                break;
            }
        }

        if (scene != NpcDirectorScene::BodyguardEscort)
        {
            for (Ped ped : scenePeds)
            {
                if (IsLiveNonPlayerPed(ped) && std::find(st.scenarioPeds.begin(), st.scenarioPeds.end(), ped) == st.scenarioPeds.end())
                    st.scenarioPeds.push_back(ped);
            }
        }
        st.lastNpcDirectorReport = NpcDirectorSceneName(scene) + ": spawned " + std::to_string(spawned);
        Notify(st.lastNpcDirectorReport);
    }

    static void LaunchSelectedNpcDirectorScene()
    {
        LaunchNpcDirectorScene(st.selectedNpcDirectorScene);
    }

