    static bool NpcControlPedGroupAllowed(Ped ped)
    {
        if (!ped) return false;
        if (!st.npcControlIncludeBodyguards && PedHandleInList(st.bodyguards, ped)) return false;
        if (!st.npcControlIncludeEnemies && PedHandleInList(st.enemies, ped)) return false;
        if (!st.npcControlIncludeScenario && PedHandleInList(st.scenarioPeds, ped)) return false;
        return true;
    }

    static void AddNpcControlTargetUnique(std::vector<Ped>& out, Ped ped)
    {
        if (!IsLiveNonPlayerPed(ped) || IsMissionRuntimePed(ped) || !NpcControlPedGroupAllowed(ped)) return;
        if (std::find(out.begin(), out.end(), ped) == out.end()) out.push_back(ped);
    }

    static void CompactNpcControlRuntimeLists()
    {
        auto compactPedList = [](std::vector<Ped>& list)
        {
            std::vector<Ped> kept;
            kept.reserve(list.size());
            for (Ped ped : list)
            {
                if (!IsLiveNonPlayerPed(ped)) continue;
                if (std::find(kept.begin(), kept.end(), ped) == kept.end()) kept.push_back(ped);
            }
            list.swap(kept);
        };

        compactPedList(st.spawnedPeds);
        compactPedList(st.friendlyPeds);
        compactPedList(st.bodyguards);
        compactPedList(st.enemies);
        compactPedList(st.scenarioPeds);
        if (st.chauffeur && !IsLiveNonPlayerPed(st.chauffeur)) st.chauffeur = 0;
    }

    static std::vector<Ped> CollectNpcControlTargets()
    {
        CompactNpcControlRuntimeLists();
        std::vector<Ped> out;
        for (Ped ped : st.spawnedPeds) AddNpcControlTargetUnique(out, ped);
        for (Ped ped : st.friendlyPeds) AddNpcControlTargetUnique(out, ped);
        if (st.npcControlIncludeBodyguards)
            for (Ped ped : st.bodyguards) AddNpcControlTargetUnique(out, ped);
        if (st.npcControlIncludeEnemies)
            for (Ped ped : st.enemies) AddNpcControlTargetUnique(out, ped);
        if (st.npcControlIncludeScenario)
            for (Ped ped : st.scenarioPeds) AddNpcControlTargetUnique(out, ped);
        if (st.chauffeur && (st.npcControlIncludeBodyguards || !PedHandleInList(st.bodyguards, st.chauffeur))) AddNpcControlTargetUnique(out, st.chauffeur);
        return out;
    }

    static Ped NpcControlAimedPedTarget()
    {
        Entity aimed = 0;
        try
        {
            if (SafeGetEntityPlayerIsFreeAimingAtRuntime(aimed) && core::IsPed(aimed))
            {
                Ped ped = (Ped)aimed;
                if (IsLiveNonPlayerPed(ped)) return ped;
            }
        }
        catch (...) {}
        return 0;
    }

    static Vehicle NpcControlPlayerVehicle()
    {
        return CurrentPlayerVehicleForCompanionEntry();
    }

    static int FirstFreeNpcControlVehicleSeat(Vehicle vehicle)
    {
        if (!IsUsableVehicleHandle(vehicle, true)) return -2;
        const int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        for (int seat = 0; seat <= maxSeat; ++seat)
        {
            if (core::IsVehicleSeatFree(vehicle, seat, false)) return seat;
        }
        return -2;
    }

    static bool TryNpcControlPedNative(Ped ped, const char* action, const std::function<void()>& fn)
    {
        if (!IsLiveNonPlayerPed(ped)) return false;
        const std::string safeAction = action ? action : "unknown";
        const bool ok = SafeNativeVoidRuntime("npc_control", safeAction, fn);
        if (!ok) Log(std::string("[NPC Control] Native failed safely: ") + safeAction);
        return ok;
    }

    static bool TryNpcControlSetBlocking(Ped ped, bool block)
    {
        if (!block && IsFriendlyOrBodyguardTracked(ped))
        {
            ConfigureFriendlyCompanion(ped, true);
            return true;
        }
        return TryNpcControlPedNative(ped, "set blocking", [&](){ PED::SET_BLOCKING_OF_NON_TEMPORARY_EVENTS(ped, block); });
    }

    static bool TryNpcControlClearTasks(Ped ped)
    {
        // BUGFIX 121: the NPC Control menu can include friendly NPCs/bodyguards.
        // A generic Clear Tasks action during a protected vehicle handoff cancels
        // TASK_LEAVE_VEHICLE/TASK_ENTER_VEHICLE and recreates the "runs on foot" bug.
        if (IsFriendlyOrBodyguardTracked(ped) && IsCompanionVehicleTaskProtected(ped))
        {
            ConfigureFriendlyCompanion(ped, true);
            return true;
        }
        return core::safe_native::ClearPedTasks(ped, false, &g_coreErrors, "npc_control");
    }

    static bool TryNpcControlUnfreeze(Ped ped)
    {
        return core::safe_native::Freeze((Entity)ped, false, &g_coreErrors, "npc_control");
    }

    static bool TryNpcControlFreeze(Ped ped)
    {
        return core::safe_native::Freeze((Entity)ped, true, &g_coreErrors, "npc_control");
    }

    static void ReleaseNpcControlCompanionRole(Ped ped, bool markAsEnemy)
    {
        if (!IsLiveNonPlayerPed(ped) || IsMissionRuntimePed(ped)) return;

        const bool wasBodyguard = PedHandleInList(st.bodyguards, ped);
        if (wasBodyguard)
        {
            RemovePedHandleFromList(st.bodyguards, ped);
            ClearBodyguardRuntimeState(ped, true);
        }
        RemoveFriendlyNpcRuntime(ped);

        if (markAsEnemy)
        {
            if (std::find(st.enemies.begin(), st.enemies.end(), ped) == st.enemies.end())
                st.enemies.push_back(ped);
        }
        else
        {
            RemovePedHandleFromList(st.enemies, ped);
        }
        EnsureRegularNpcTracking(ped);
    }

    static void ApplyNpcControlLoadout(Ped ped)
    {
        if (!IsLiveNonPlayerPed(ped)) return;
        int health = ClampIntValue(st.selectedPedHealth, 1, 10000);
        int armor = ClampIntValue(st.npcControlArmor, 0, 500);
        int accuracy = ClampIntValue(st.npcControlAccuracy, 0, 100);
        int aggression = ClampIntValue(st.npcControlAggression, 0, 3);

        core::safe_native::SetMissionEntity((Entity)ped, true, true, &g_coreErrors, "npc_control");
        core::safe_native::SetInvincible((Entity)ped, st.npcControlInvincible, &g_coreErrors, "npc_control");
        core::safe_native::SetHealth((Entity)ped, health, &g_coreErrors, "npc_control");
        core::safe_native::SetPedArmour(ped, armor, &g_coreErrors, "npc_control");
        SafeSetPedAccuracy(ped, accuracy, "npc_control");
        core::safe_native::SetPedCanRagdoll(ped, !st.npcControlInvincible, &g_coreErrors, "npc_control");
        const bool trackedCompanion = IsFriendlyOrBodyguardTracked(ped);
        const bool trackedBodyguard = IsBodyguardTracked(ped);
        const bool bodyguardHoldFire = trackedBodyguard && cfg.bodyguardCombatMode == BodyguardCombatMode::HoldFire;
        if (bodyguardHoldFire) ClearCompanionCombatTargetRuntime(ped);
        SafePedRuntimeNative(ped, "npc_control", "set ped flee attributes", [&](){ PED::SET_PED_FLEE_ATTRIBUTES(ped, 0, trackedCompanion ? false : (aggression > 0 ? false : true)); });
        SafeSetPedCombatProfile(ped, aggression >= 2 ? 2 : aggression, aggression >= 2 ? 2 : aggression, aggression >= 3 ? 2 : std::max(0, aggression), "npc_control");
        SafeSetPedCombatAttribute(ped, 5, trackedCompanion ? true : aggression >= 1, "npc_control");
        SafeSetPedCombatAttribute(ped, 46, trackedCompanion ? !bodyguardHoldFire : aggression >= 2, "npc_control");
        if (trackedCompanion) SafeSetPedCombatAttribute(ped, 58, true, "npc_control");
        GiveWeapon(ped, st.selectedWeapon, st.selectedPedAmmo);
        if (trackedCompanion) ConfigureFriendlyCompanion(ped, true);
    }

    static bool ApplyNpcControlCommandToPed(Ped ped, NpcControlCommand command, Ped aimedTarget, Vehicle forcedVehicle = 0, int forcedSeat = -3)
    {
        if (!IsLiveNonPlayerPed(ped) || IsMissionRuntimePed(ped)) return false;
        Ped playerPed = 0;
        const bool hasPlayer = GetPlayerPedSafe(playerPed);
        if (!st.npcControlKeepTasks && !TryNpcControlClearTasks(ped)) return false;
        if (command != NpcControlCommand::HoldPosition && !TryNpcControlUnfreeze(ped)) return false;

        if (command == NpcControlCommand::AttackPlayer)
            ReleaseNpcControlCompanionRole(ped, true);
        else if (command == NpcControlCommand::AttackAimed && aimedTarget && aimedTarget != ped && IsUsablePedHandle(aimedTarget, false, true, true))
        {
            // BUGFIX 161: manual Attack Aimed must also detach a bodyguard/friendly
            // from companion AI. Otherwise the support tick can immediately overwrite
            // the explicit target with protect-player logic.
            ReleaseNpcControlCompanionRole(ped, false);
        }
        else if (command == NpcControlCommand::FleePlayer || command == NpcControlCommand::Wander ||
                 command == NpcControlCommand::HoldPosition || command == NpcControlCommand::ClearTasks)
            ReleaseNpcControlCompanionRole(ped, false);

        ApplyNpcControlLoadout(ped);

        switch (command)
        {
            case NpcControlCommand::GuardPlayer:
                if (!hasPlayer) return false;
                RegisterFriendlyNpc(ped, true);
                TryNpcControlSetBlocking(ped, true);
                return SafeTaskFollowToOffset(ped, (Entity)playerPed, 0.0f, -std::max(1.5f, st.npcControlFollowSpacing), 0.0f, 2.4f, -1, 2.0f, true, "npc_control");
            case NpcControlCommand::AttackAimed:
            {
                Ped target = aimedTarget;
                if (!target || target == ped || !core::IsPed((Entity)target) || core::IsPedDeadOrDying(target, true, true)) return false;
                TryNpcControlSetBlocking(ped, true);
                return SafeTaskCombatPed(ped, target, "npc_control");
            }
            case NpcControlCommand::AttackPlayer:
                if (!hasPlayer || playerPed == ped) return false;
                TryNpcControlSetBlocking(ped, true);
                return SafeTaskCombatPed(ped, playerPed, "npc_control");
            case NpcControlCommand::FleePlayer:
                if (!hasPlayer) return false;
                TryNpcControlSetBlocking(ped, false);
                SafeSetPedCombatAttribute(ped, 58, false, "npc_control");
                SafePedRuntimeNative(ped, "npc_control", "enable flee attributes", [&](){ PED::SET_PED_FLEE_ATTRIBUTES(ped, 0, true); }, true, false);
                return SafeTaskSmartFleePed(ped, playerPed, 90.0f, -1, false, false, "npc_control");
            case NpcControlCommand::EnterPlayerVehicle:
            {
                Vehicle vehicle = forcedVehicle ? forcedVehicle : NpcControlPlayerVehicle();
                if (!vehicle || !core::IsVehicle((Entity)vehicle)) return false;
                int seat = forcedSeat >= 0 ? forcedSeat : FirstFreeNpcControlVehicleSeat(vehicle);
                if (seat < 0 || !core::IsVehicleSeatFree(vehicle, seat, false)) return false;
                RegisterFriendlyNpc(ped, true);
                return SeatPedInVehicleOrTaskEnter(ped, vehicle, seat, true, 10000, "npc_control");
            }
            case NpcControlCommand::ExitVehicle:
                if (core::IsPedInAnyVehicle(ped, false))
                {
                    Vehicle vehicle = core::GetVehiclePedIsIn(ped, false);
                    if (vehicle && core::IsVehicle((Entity)vehicle)) return SafeTaskLeaveVehicle(ped, vehicle, 16, "npc_control");
                }
                return true;
            case NpcControlCommand::Wander:
                TryNpcControlSetBlocking(ped, false);
                return SafeTaskWanderStandard(ped, 10.0f, 10, "npc_control");
            case NpcControlCommand::HoldPosition:
                TryNpcControlSetBlocking(ped, true);
                return TryNpcControlFreeze(ped);
            case NpcControlCommand::ClearTasks:
                TryNpcControlClearTasks(ped);
                TryNpcControlSetBlocking(ped, false);
                return true;
            default:
                if (!hasPlayer) return false;
                RegisterFriendlyNpc(ped, true);
                return SafeTaskFollowToOffset(ped, (Entity)playerPed, 0.0f, -std::max(1.2f, st.npcControlFollowSpacing), 0.0f, 2.0f, -1, 2.0f, true, "npc_control");
        }
    }

    static void ApplyNpcControlCommandToLastNpc()
    {
        Entity entity = LastExistingPedEntity();
        if (!entity || !core::IsPed(entity)) { Notify("No valid NPC found."); return; }
        Ped ped = (Ped)entity;
        if (!IsLiveNonPlayerPed(ped) || IsMissionRuntimePed(ped)) { Notify("Last NPC cannot be controlled."); return; }
        Ped aimedTarget = NpcControlAimedPedTarget();
        bool ok = ApplyNpcControlCommandToPed(ped, st.selectedNpcControlCommand, aimedTarget);
        st.lastNpcControlReport = ok ? ("Last NPC command: " + NpcControlCommandName(st.selectedNpcControlCommand)) : "Last NPC command failed.";
        Notify(st.lastNpcControlReport);
    }

    static std::vector<int> FreeNpcControlVehicleSeats(Vehicle vehicle)
    {
        std::vector<int> seats;
        if (!IsUsableVehicleHandle(vehicle, true)) return seats;
        const int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        for (int seat = 0; seat <= maxSeat; ++seat)
        {
            if (core::IsVehicleSeatFree(vehicle, seat, false)) seats.push_back(seat);
        }
        return seats;
    }

    static void ApplyNpcControlCommandToAll()
    {
        std::vector<Ped> targets = CollectNpcControlTargets();
        Ped aimedTarget = NpcControlAimedPedTarget();
        int changed = 0;

        if (st.selectedNpcControlCommand == NpcControlCommand::EnterPlayerVehicle)
        {
            Vehicle vehicle = NpcControlPlayerVehicle();
            std::vector<int> seats = FreeNpcControlVehicleSeats(vehicle);
            size_t seatIndex = 0;
            for (Ped ped : targets)
            {
                if (seatIndex >= seats.size()) break;
                if (ApplyNpcControlCommandToPed(ped, st.selectedNpcControlCommand, aimedTarget, vehicle, seats[seatIndex]))
                {
                    ++changed;
                    ++seatIndex;
                }
            }
        }
        else
        {
            for (Ped ped : targets)
            {
                if (ApplyNpcControlCommandToPed(ped, st.selectedNpcControlCommand, aimedTarget)) ++changed;
            }
        }

        st.lastNpcControlReport = NpcControlCommandName(st.selectedNpcControlCommand) + " applied: " + std::to_string(changed) + "/" + std::to_string((int)targets.size());
        Notify(st.lastNpcControlReport);
    }

    static void SpawnNpcControlSquad()
    {
        Vector3 playerBase{};
        if (!TryGetPlayerPosition(playerBase)) { Notify("NPC Control Squad failed: player position invalid."); return; }
        int count = ClampIntValue(st.npcControlSquadCount, 1, 12);
        Vehicle enterVehicle = 0;
        std::vector<int> reservedSeats;
        size_t reservedSeatIndex = 0;
        if (st.selectedNpcControlCommand == NpcControlCommand::EnterPlayerVehicle)
        {
            enterVehicle = NpcControlPlayerVehicle();
            if (!enterVehicle)
            {
                st.lastNpcControlReport = "NPC Control Squad failed: player vehicle unavailable.";
                Notify(st.lastNpcControlReport);
                return;
            }
            reservedSeats = FreeNpcControlVehicleSeats(enterVehicle);
            if (reservedSeats.empty())
            {
                st.lastNpcControlReport = "NPC Control Squad failed: no free passenger seats.";
                Notify(st.lastNpcControlReport);
                return;
            }
            count = std::min(count, (int)reservedSeats.size());
        }

        int spawned = 0;
        int commanded = 0;
        Ped aimedTarget = NpcControlAimedPedTarget();
        for (int i = 0; i < count; ++i)
        {
            Vector3 pos = OffsetAroundPlayer(3.5f + (float)(i % 3) * 1.8f, i, count);
            if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f)) continue;
            NpcPersonality personality = st.selectedNpcPersonality;
            Relation relation = RelationForNpcPersonality(personality);
            if (st.selectedNpcControlCommand == NpcControlCommand::AttackPlayer) relation = Relation::Enemy;
            if (st.selectedNpcControlCommand == NpcControlCommand::FollowPlayer || st.selectedNpcControlCommand == NpcControlCommand::GuardPlayer || st.selectedNpcControlCommand == NpcControlCommand::EnterPlayerVehicle) relation = Relation::Friendly;
            Ped ped = SpawnPedAtModel(st.selectedPedModel, relation, st.selectedPedHealth, st.selectedWeapon, st.selectedPedAmmo, pos, SafePlayerHeading(), true, false);
            if (!ped) continue;
            ApplyNpcPersonality(ped, personality, false);
            ApplyNpcControlLoadout(ped);

            bool commandOk = false;
            if (st.selectedNpcControlCommand == NpcControlCommand::EnterPlayerVehicle)
            {
                if (reservedSeatIndex >= reservedSeats.size()) break;
                commandOk = ApplyNpcControlCommandToPed(ped, st.selectedNpcControlCommand, aimedTarget, enterVehicle, reservedSeats[reservedSeatIndex]);
                if (commandOk) ++reservedSeatIndex;
            }
            else
            {
                commandOk = ApplyNpcControlCommandToPed(ped, st.selectedNpcControlCommand, aimedTarget);
            }
            if (commandOk) ++commanded;
            ++spawned;
        }
        st.lastNpcControlReport = "NPC Control Squad spawned: " + std::to_string(spawned) + "/" + std::to_string(count) + ", commanded: " + std::to_string(commanded);
        Notify(st.lastNpcControlReport);
    }

    static void HealArmorNpcControlTargets()
    {
        std::vector<Ped> targets = CollectNpcControlTargets();
        int changed = 0;
        for (Ped ped : targets)
        {
            if (!IsLiveNonPlayerPed(ped)) continue;
            core::safe_native::SetHealth((Entity)ped, ClampIntValue(st.selectedPedHealth, 1, 10000), &g_coreErrors, "npc_control");
            core::safe_native::SetPedArmour(ped, ClampIntValue(st.npcControlArmor, 0, 500), &g_coreErrors, "npc_control");
            ++changed;
        }
        st.lastNpcControlReport = "NPC heal/armor applied: " + std::to_string(changed);
        Notify(st.lastNpcControlReport);
    }

    static void ArmNpcControlTargets()
    {
        std::vector<Ped> targets = CollectNpcControlTargets();
        int changed = 0;
        for (Ped ped : targets)
        {
            if (!IsLiveNonPlayerPed(ped)) continue;
            SafeRemoveAllPedWeapons(ped, true, "npc_control");
            GiveWeapon(ped, st.selectedWeapon, st.selectedPedAmmo);
            SafeSetPedAccuracy(ped, st.npcControlAccuracy, "npc_control");
            ++changed;
        }
        st.lastNpcControlReport = "NPC loadout applied: " + std::to_string(changed);
        Notify(st.lastNpcControlReport);
    }

    static void ToggleNpcControlInvincibleForTargets()
    {
        st.npcControlInvincible = !st.npcControlInvincible;
        std::vector<Ped> targets = CollectNpcControlTargets();
        int changed = 0;
        for (Ped ped : targets)
        {
            if (!IsLiveNonPlayerPed(ped)) continue;
            core::safe_native::SetInvincible((Entity)ped, st.npcControlInvincible, &g_coreErrors, "npc_control");
            core::safe_native::SetPedCanRagdoll(ped, !st.npcControlInvincible, &g_coreErrors, "npc_control");
            ++changed;
        }
        st.lastNpcControlReport = "NPC invincible " + OnOff(st.npcControlInvincible) + ": " + std::to_string(changed);
        Notify(st.lastNpcControlReport);
    }

    static void TeleportNpcControlTargetsToPlayer()
    {
        Vector3 base{};
        if (!TryGetPlayerPosition(base)) { Notify("NPC teleport failed: player position invalid."); return; }
        std::vector<Ped> targets = CollectNpcControlTargets();
        int moved = 0;
        for (size_t i = 0; i < targets.size(); ++i)
        {
            Ped ped = targets[i];
            if (!IsLiveNonPlayerPed(ped)) continue;
            Vector3 pos = OffsetAroundPlayer(2.0f + (float)(i % 4) * 1.2f, (int)i, std::max(1, (int)targets.size()));
            if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f)) continue;
            core::safe_native::Freeze((Entity)ped, false, &g_coreErrors, "npc_control");
            core::safe_native::SetCoords((Entity)ped, pos, false, &g_coreErrors, "npc_control");
            core::safe_native::SetHeading((Entity)ped, SafePlayerHeading(), &g_coreErrors, "npc_control");
            ++moved;
        }
        st.lastNpcControlReport = "NPCs teleported to player: " + std::to_string(moved);
        Notify(st.lastNpcControlReport);
    }

    static void ClearNpcControlTargets()
    {
        std::vector<Ped> targets = CollectNpcControlTargets();
        int deleted = 0;
        for (Ped ped : targets)
        {
            if (!ped || !core::IsPed((Entity)ped) || core::IsPlayerPed((Entity)ped) || IsActiveGameModeEntity((Entity)ped)) continue;
            if (st.chauffeur && ped == st.chauffeur)
            {
                st.chauffeurDriveStarted = false;
                st.chauffeurWaitingForPlayer = false;
            }
            if (DeletePedSafely(ped))
            {
                RemoveTrackedEntity((Entity)ped);
                if (st.chauffeur == ped) st.chauffeur = 0;
                ++deleted;
            }
        }
        st.lastNpcControlReport = "NPC Control cleanup deleted: " + std::to_string(deleted);
        Notify(st.lastNpcControlReport);
    }

