    static void SpawnBattleWave()
    {
        CleanupDeadPeds(st.enemies);
        int currentAlive = AliveCount(st.enemies);
        int allowed = std::max(0, cfg.maxBattleEnemies - currentAlive);
        if (allowed <= 0) return;
        st.battleWave++;
        int count = std::min(allowed, std::max(3, st.enemyCount + st.battleWave * 2));
        int oldCount = st.enemyCount;
        int oldHealth = st.enemyHealth;
        int oldAmmo = st.enemyAmmo;
        st.enemyCount = count;
        st.enemyHealth = std::min(2000, oldHealth + st.battleWave * 25);
        st.enemyAmmo = std::max(oldAmmo, 120 + st.battleWave * 30);
        SpawnEnemySquad();
        st.enemyCount = oldCount;
        st.enemyHealth = oldHealth;
        st.enemyAmmo = oldAmmo;
        Notify("Battle wave " + std::to_string(st.battleWave) + " spawned.");
    }

    static void TickBattleArena()
    {
        if (!st.battleActive) return;
        CleanupDeadPeds(st.enemies);
        if (AliveCount(st.enemies) > 0) return;
        DWORD now = GetTickCount();
        if (st.nextBattleWaveTick == 0) st.nextBattleWaveTick = core::TickAdd(now, SafeIntervalFromIntMs(cfg.battleWaveDelayMs, 4000, 500, 120000, "battle_arena", "wave delay"));
        if (core::TickReached(now, st.nextBattleWaveTick))
        {
            st.nextBattleWaveTick = 0;
            SpawnBattleWave();
        }
    }

