        o.label = NormalizeFlatText(st.missionObjectiveLabel.empty() ? "Mission Objective" : st.missionObjectiveLabel, 80, "Mission Objective");
        o.type = SelectedMissionObjectiveTypeSafe();
        o.durationSec = std::max(1, st.missionObjectiveTimerSec);
        o.x = p.x; o.y = p.y; o.z = p.z;
