    static void RemoveLastMissionEntity()
    {
        if (!st.currentMission.entities.empty())
        {
            ResetMissionRuntimeForCreatorEdit(true);
            PushMissionUndo("remove entity");
            st.currentMission.entities.pop_back();
            if (st.missionEntityPage < 0) st.missionEntityPage = 0;
            Notify("Last mission entity removed. Preview cleared.");
        }
    }

    static void RemoveLastMissionObjective()
    {
        if (st.currentMission.objectives.empty()) return;
        ResetMissionRuntimeForCreatorEdit(false);
        PushMissionUndo("remove objective");
        st.currentMission.objectives.pop_back();
        int count = (int)st.currentMission.objectives.size();
        if (count <= 0)
        {
            st.selectedMissionObjectiveIndex = 0;
            st.missionActiveObjective = 0;
            st.missionPlaytestActive = false;
        }
        else
        {
            if (st.selectedMissionObjectiveIndex >= count) st.selectedMissionObjectiveIndex = count - 1;
            if (st.missionActiveObjective >= count) st.missionActiveObjective = count - 1;
        }
        ClearMissionBlips();
        Notify("Last mission objective removed.");
    }

    static void NormalizeMissionData(CustomMission& mission)
    {
        mission.name = NormalizeMissionName(mission.name.empty() ? "Custom Mission" : mission.name);

        int maxMissionEntities = ClampIntValue(cfg.maxMissionEntities, 1, 500);
        int maxMissionObjectives = ClampIntValue(cfg.maxMissionObjectives, 1, 120);
        if ((int)mission.entities.size() > maxMissionEntities)
            mission.entities.resize((size_t)maxMissionEntities);
        if ((int)mission.objectives.size() > maxMissionObjectives)
            mission.objectives.resize((size_t)maxMissionObjectives);

        auto validEntityType = [](MissionEntityType type)
        {
            int v = (int)type;
            return v >= (int)MissionEntityType::Ped && v <= (int)MissionEntityType::Object;
        };
        auto validObjectiveType = [](MissionObjectiveType type)
        {
            int v = (int)type;
            return v >= (int)MissionObjectiveType::GoToPoint && v <= (int)MissionObjectiveType::ReachCheckpoint;
        };

        Vector3 storedFallback = MissionStoredPositionFallback();
        for (auto& e : mission.entities)
        {
            if (!validEntityType(e.type)) e.type = MissionEntityType::Ped;
            std::string fallbackModel = e.type == MissionEntityType::Vehicle ? "tailgater" : (e.type == MissionEntityType::Object ? "prop_barrel_02a" : "a_m_m_business_01");
            e.model = NormalizeModelName(e.model, fallbackModel);
            e.label = NormalizeFlatText(e.label.empty() ? MissionEntityTypeName(e.type) : e.label);
            e.weapon = NormalizeModelName(e.weapon, "WEAPON_PISTOL");
            if (e.health < 1) e.health = 1;
            if (e.health > 5000) e.health = 5000;
            if (e.ammo < 0) e.ammo = 0;
            if (e.ammo > 9999) e.ammo = 9999;
            Vector3 p{}; p.x = e.x; p.y = e.y; p.z = e.z;
            if (!IsUsableWorldPosition(p, -200.0f, 2000.0f)) p = storedFallback;
            e.x = p.x; e.y = p.y; e.z = p.z;
            e.heading = NormalizeHeading(e.heading, 0.0f);
        }

        for (auto& o : mission.objectives)
        {
            if (!validObjectiveType(o.type)) o.type = MissionObjectiveType::GoToPoint;
            o.label = NormalizeFlatText(o.label.empty() ? MissionObjectiveTypeName(o.type) : o.label, 80, MissionObjectiveTypeName(o.type));
            o.targetLabel = NormalizeFlatText(o.targetLabel, 80, "");
            if (o.durationSec < 0) o.durationSec = 0;
            if (o.durationSec > 3600) o.durationSec = 3600;
            if (!IsFiniteFloat(o.radius) || o.radius < 1.0f) o.radius = 1.0f;
            if (o.radius > 100.0f) o.radius = 100.0f;
            if (o.markerType < 0) o.markerType = 1;
            if (o.markerType > 100) o.markerType = 100;
            if (o.blipSprite < 1) o.blipSprite = 1;
            if (o.blipSprite > kMaxBlipSpriteId) o.blipSprite = kMaxBlipSpriteId;
            if (o.blipColor < 0) o.blipColor = 0;
            if (o.blipColor > 85) o.blipColor = 85;
            Vector3 p{}; p.x = o.x; p.y = o.y; p.z = o.z;
            if (!IsUsableWorldPosition(p, -200.0f, 2000.0f)) p = storedFallback;
            o.x = p.x; o.y = p.y; o.z = p.z;
            o.completed = false;
        }
    }

    static bool SaveMissionSlot(int slot, bool notifyResult = true)
    {
        if (slot < 1 || slot > cfg.missionSlots)
        {
            if (notifyResult) Notify("Invalid mission slot.");
            return false;
        }
        st.currentMission.name = NormalizeMissionName(st.missionName.empty() ? st.currentMission.name : st.missionName);
        NormalizeMissionData(st.currentMission);
        st.missionName = st.currentMission.name;
        ClampMissionSettings();
        std::vector<std::string> existingLines;
        ReadTextLinesSafe(MissionsPath(), existingLines);
        std::vector<std::string> lines;
        bool skipping = false;
        for (const std::string& line : existingLines)
        {
            if (line == "BEGIN_SLOT|" + std::to_string(slot)) { skipping = true; continue; }
            if (skipping)
            {
                if (line == "END_SLOT") { skipping = false; continue; }
                // Corrupt mission files may miss END_SLOT. Do not let one broken
                // slot consume every following slot during save/replace.
                if (StartsWith(line, "BEGIN_SLOT|"))
                {
                    skipping = false;
                    lines.push_back(line);
                }
                continue;
            }
            lines.push_back(line);
        }
        lines.push_back("BEGIN_SLOT|" + std::to_string(slot));
        lines.push_back("NAME|" + EscapeField(st.currentMission.name));
        lines.push_back("SETTINGS|" + std::to_string(st.missionRewardCash) + "|" + std::to_string(st.missionRewardRp) + "|" +
                        std::to_string(st.missionFailOnPlayerDeath ? 1 : 0) + "|" + std::to_string(st.missionFailOnWanted ? 1 : 0) + "|" +
                        EscapeField(st.missionStartDialog) + "|" + EscapeField(st.missionCompleteDialog) + "|" +
                        std::to_string(st.missionRouteEnabled ? 1 : 0) + "|" + std::to_string(st.missionAutoStartCombat ? 1 : 0));
        for (const auto& e : st.currentMission.entities)
        {
            std::stringstream ss;
            ss << "ENTITY|" << MissionEntityTypeName(e.type) << "|" << EscapeField(e.model) << "|" << EscapeField(e.label) << "|"
               << EscapeField(e.weapon) << "|" << RelationName(e.relation) << "|" << e.health << "|" << e.ammo << "|" << VecLine(e.x, e.y, e.z, e.heading);
            lines.push_back(ss.str());
        }
        for (const auto& o : st.currentMission.objectives)
        {
            std::stringstream ss;
            ss << "OBJECTIVE|" << EscapeField(o.label) << "|" << MissionObjectiveTypeName(o.type) << "|" << o.durationSec << "|" << EscapeField(o.targetLabel) << "|"
               << o.radius << "|" << o.markerType << "|" << o.blipSprite << "|" << o.blipColor << "|" << VecLine(o.x, o.y, o.z, 0.0f);
            lines.push_back(ss.str());
        }
        lines.push_back("END_SLOT");
        if (!AtomicWriteLines(MissionsPath(), lines))
        {
            if (notifyResult) Notify("Mission save failed.");
            return false;
        }
        if (notifyResult) Notify("Mission saved to slot " + std::to_string(slot));
        return true;
    }

    static void LoadMissionSlot(int slot)
    {
        if (slot < 1 || slot > cfg.missionSlots) { Notify("Invalid mission slot."); return; }
        std::vector<std::string> lines;
        if (!ReadTextLinesSafe(MissionsPath(), lines)) { Notify("Mission file not found."); return; }

        CustomMission m;
        int rewardCash = cfg.missionDefaultRewardCash;
        int rewardRp = cfg.missionDefaultRewardRp;
        bool failOnPlayerDeath = true;
        bool failOnWanted = false;
        bool routeEnabled = true;
        bool autoStartCombat = true;
        std::string startDialog = "Mission started.";
        std::string completeDialog = "Mission completed.";
        bool reading = false;
        bool foundSlot = false;
        bool hasReadableData = false;

        auto safeInt = [](const std::string& v, int fallback) -> int
        {
            int parsed = fallback;
            return TryParseIntStrict(v, parsed) ? parsed : fallback;
        };
        auto safeFloat = [](const std::string& v, float fallback) -> float
        {
            float parsed = fallback;
            return TryParseFloatStrict(v, parsed) ? parsed : fallback;
        };

        for (std::string line : lines)
        {
            line = Trim(line);
            if (line == "BEGIN_SLOT|" + std::to_string(slot))
            {
                reading = true;
                foundSlot = true;
                continue;
            }
            if (reading && line == "END_SLOT") break;
            if (reading && StartsWith(line, "BEGIN_SLOT|")) break;
            if (!reading || line.empty() || StartsWith(line, "#")) continue;
            auto p = Split(line, '|'); if (p.empty()) continue;
            try
            {
                if (p[0] == "NAME" && p.size() >= 2)
                {
                    m.name = NormalizeMissionName(p[1]);
                    hasReadableData = true;
                }
                else if (p[0] == "SETTINGS" && p.size() >= 7)
                {
                    rewardCash = safeInt(p[1], rewardCash);
                    rewardRp = safeInt(p[2], rewardRp);
                    failOnPlayerDeath = safeInt(p[3], failOnPlayerDeath ? 1 : 0) != 0;
                    failOnWanted = safeInt(p[4], failOnWanted ? 1 : 0) != 0;
                    startDialog = NormalizeFlatText(p[5], 120, "Mission started.");
                    completeDialog = NormalizeFlatText(p[6], 120, "Mission completed.");
                    if (p.size() >= 8) routeEnabled = safeInt(p[7], routeEnabled ? 1 : 0) != 0;
                    if (p.size() >= 9) autoStartCombat = safeInt(p[8], autoStartCombat ? 1 : 0) != 0;
                    hasReadableData = true;
                }
                else if (p[0] == "ENTITY" && p.size() >= 12)
                {
                    if ((int)m.entities.size() >= cfg.maxMissionEntities) continue;
                    MissionEntityDef e;
                    e.type = p[1] == "Vehicle" ? MissionEntityType::Vehicle : p[1] == "Object" ? MissionEntityType::Object : MissionEntityType::Ped;
                    e.model = NormalizeFlatText(p[2], 64, e.type == MissionEntityType::Vehicle ? "sultan" : (e.type == MissionEntityType::Object ? "prop_barrel_02a" : "s_m_y_cop_01"));
                    e.label = NormalizeFlatText(p[3], 80, MissionEntityTypeName(e.type));
                    e.weapon = NormalizeFlatText(p[4], 64, "NONE");
                    e.relation = ParseRelationName(p[5]);
                    e.health = std::max(1, std::min(10000, safeInt(p[6], 200)));
                    e.ammo = std::max(0, std::min(99999, safeInt(p[7], 120)));
                    e.x = safeFloat(p[8], 0.0f); e.y = safeFloat(p[9], 0.0f); e.z = safeFloat(p[10], 75.0f); e.heading = safeFloat(p[11], 0.0f);
                    m.entities.push_back(e);
                    hasReadableData = true;
                }
                else if (p[0] == "OBJECTIVE" && p.size() >= 9)
                {
                    if ((int)m.objectives.size() >= cfg.maxMissionObjectives) continue;
                    MissionObjectiveDef o;
                    o.label = NormalizeFlatText(p[1], 80, "Objective");
                    if (p.size() >= 13 && IsNewObjectiveLineType(p[2]))
                    {
                        o.type = ParseMissionObjectiveType(p[2]);
                        o.durationSec = std::max(0, std::min(3600, safeInt(p[3], cfg.missionDefaultTimerSec)));
                        o.targetLabel = NormalizeFlatText(p[4], 80, "");
                        o.radius = std::max(0.5f, std::min(100.0f, safeFloat(p[5], cfg.missionObjectiveRadius)));
                        o.markerType = std::max(0, std::min(100, safeInt(p[6], 1)));
                        o.blipSprite = ParseBlipSpriteOrDlcName(p[7], 1);
                        o.blipColor = std::max(0, std::min(85, safeInt(p[8], 5)));
                        o.x = safeFloat(p[9], 0.0f); o.y = safeFloat(p[10], 0.0f); o.z = safeFloat(p[11], 75.0f);
                    }
                    else if (p.size() >= 9)
                    {
                        o.radius = std::max(0.5f, std::min(100.0f, safeFloat(p[2], cfg.missionObjectiveRadius)));
                        o.markerType = std::max(0, std::min(100, safeInt(p[3], 1)));
                        o.blipSprite = ParseBlipSpriteOrDlcName(p[4], 1);
                        o.blipColor = std::max(0, std::min(85, safeInt(p[5], 5)));
                        o.x = safeFloat(p[6], 0.0f); o.y = safeFloat(p[7], 0.0f); o.z = safeFloat(p[8], 75.0f);
                    }
                    m.objectives.push_back(o);
                    hasReadableData = true;
                }
            }
            catch (...) {}
        }

        if (!foundSlot || !hasReadableData)
        {
            Notify("Mission slot empty.");
            return;
        }

        PushMissionUndo("load mission slot");
        CancelSafeSpawnPreview(false);
        StopMissionPlaytest(false); ClearMissionSpawnedEntities(); ClearMissionBlips();
        NormalizeMissionData(m);
        st.currentMission = m;
        st.missionName = NormalizeMissionName(m.name);
        st.currentMission.name = st.missionName;
        st.missionRewardCash = rewardCash;
        st.missionRewardRp = rewardRp;
        st.missionFailOnPlayerDeath = failOnPlayerDeath;
        st.missionFailOnWanted = failOnWanted;
        st.missionStartDialog = startDialog;
        st.missionCompleteDialog = completeDialog;
        st.missionRouteEnabled = routeEnabled;
        st.missionAutoStartCombat = autoStartCombat;
        st.selectedMissionObjectiveIndex = 0;
        st.missionActiveObjective = 0;
        st.missionObjectiveStartTick = 0;
        ClampMissionSettings();
        Notify("Mission loaded: " + st.missionName);
    }

