    static void DuplicateMissionToNextSlot()
    {
        int target = st.selectedMissionSlot + 1;
        if (target > cfg.missionSlots) target = 1;
        if (!SaveMissionSlot(target, false))
        {
            Notify("Mission duplicate failed.");
            return;
        }
        st.selectedMissionSlot = target;
        Notify("Mission duplicated to slot " + std::to_string(target));
    }

