    static bool SafeSpawnPreviewIsVehicle(SafeSpawnPreviewType type)
    {
        return type == SafeSpawnPreviewType::Vehicle || type == SafeSpawnPreviewType::MissionVehicle;
    }

    static bool SafeSpawnPreviewIsPed(SafeSpawnPreviewType type)
    {
        return type == SafeSpawnPreviewType::Ped || type == SafeSpawnPreviewType::MissionPed;
    }

    static bool SafeSpawnPreviewIsMissionEntity(SafeSpawnPreviewType type)
    {
        return type == SafeSpawnPreviewType::MissionPed || type == SafeSpawnPreviewType::MissionVehicle || type == SafeSpawnPreviewType::MissionObject;
    }

    static std::string SafeSpawnPreviewTypeName(SafeSpawnPreviewType type)
    {
        switch (type)
        {
            case SafeSpawnPreviewType::Ped: return "NPC";
            case SafeSpawnPreviewType::Vehicle: return "Vehicle";
            case SafeSpawnPreviewType::Object: return "Object";
            case SafeSpawnPreviewType::MissionPed: return "Mission NPC";
            case SafeSpawnPreviewType::MissionVehicle: return "Mission Vehicle";
            case SafeSpawnPreviewType::MissionObject: return "Mission Object";
            default: return "Preview";
        }
    }

    static Vector3 OffsetPreviewPosition(Vector3 pos, float heading, float forward, float right)
    {
        Vector3 next = pos;
        float rad = heading * 0.0174532924f;
        float forwardX = -sinf(rad);
        float forwardY =  cosf(rad);
        float rightX =  cosf(rad);
        float rightY =  sinf(rad);
        next.x += (forwardX * forward) + (rightX * right);
        next.y += (forwardY * forward) + (rightY * right);
        bool forVehicle = SafeSpawnPreviewIsVehicle(st.safeSpawnPreviewType);
        if (cfg.spawnSafetyEnabled && !st.safeSpawnPreviewManualZ)
            next.z = ResolveGroundZ(next.x, next.y, next.z) + (forVehicle ? 0.45f : 0.10f);
        if (!IsUsableWorldPosition(next, -200.0f, 2000.0f)) return pos;
        return next;
    }

    static bool SafeSpawnPreviewShiftHeld()
    {
        return (GetAsyncKeyState(VK_SHIFT) & 0x8000) != 0;
    }

    static void ResetSafeSpawnPreviewState()
    {
        st.safeSpawnPreviewActive = false;
        st.safeSpawnPreviewType = SafeSpawnPreviewType::None;
        st.safeSpawnPreviewModel.clear();
        st.safeSpawnPreviewWeapon = "NONE";
        st.safeSpawnPreviewRelation = Relation::Neutral;
        st.safeSpawnPreviewHealth = 200;
        st.safeSpawnPreviewAmmo = 0;
        st.safeSpawnPreviewWarpPlayer = false;
        st.safeSpawnPreviewManualZ = false;
        st.safeSpawnPreviewPos = Vector3{};
        st.safeSpawnPreviewHeading = 0.0f;
    }

    static void CancelSafeSpawnPreview(bool notifyResult)
    {
        if (notifyResult && st.safeSpawnPreviewActive) Notify("Spawn preview cancelled.");
        ResetSafeSpawnPreviewState();
    }

    static void ApplyManualPreviewTransform(Entity entity, Vector3 pos, float heading, bool forVehicle)
    {
        if (!entity || !core::Exists((Entity)(entity))) return;
        core::safe_native::SetCoords(entity, pos, false, &g_coreErrors, "preview");
        core::safe_native::SetHeading(entity, NormalizeHeading(heading, 0.0f), &g_coreErrors, "preview");
        if (forVehicle && core::IsVehicle((Entity)(entity)))
            SafeSetVehicleEngineOn((Vehicle)entity, true, "full_audit");
    }

    static void AddMissionEntityFromPreview()
    {
        if ((int)st.currentMission.entities.size() >= cfg.maxMissionEntities)
        {
            Notify("Mission entity limit reached.");
            return;
        }

        if (!IsUsableWorldPosition(st.safeSpawnPreviewPos, -200.0f, 2000.0f))
        {
            Notify("Mission entity placement failed: invalid preview position.");
            return;
        }

        std::string cleanModel = NormalizeModelName(st.safeSpawnPreviewModel, "");
        if (cleanModel.empty())
        {
            Notify("Mission entity placement failed: invalid preview model.");
            return;
        }
        float safeHeading = NormalizeHeading(st.safeSpawnPreviewHeading, SafePlayerHeading());

        ResetMissionRuntimeForCreatorEdit(true);
        PushMissionUndo("safe spawn preview entity");
        MissionEntityDef e;
        if (st.safeSpawnPreviewType == SafeSpawnPreviewType::MissionPed)
        {
            e.type = MissionEntityType::Ped;
            e.label = "Ped: " + cleanModel;
            e.weapon = st.safeSpawnPreviewWeapon.empty() ? "NONE" : st.safeSpawnPreviewWeapon;
            e.relation = st.safeSpawnPreviewRelation;
            e.health = ClampIntValue(st.safeSpawnPreviewHealth, 1, 10000);
            e.ammo = ClampIntValue(st.safeSpawnPreviewAmmo, 0, 9999);
        }
        else if (st.safeSpawnPreviewType == SafeSpawnPreviewType::MissionVehicle)
        {
            e.type = MissionEntityType::Vehicle;
            e.label = "Vehicle: " + cleanModel;
        }
        else
        {
            e.type = MissionEntityType::Object;
            e.label = "Object: " + cleanModel;
        }
        e.model = cleanModel;
        e.x = st.safeSpawnPreviewPos.x;
        e.y = st.safeSpawnPreviewPos.y;
        e.z = st.safeSpawnPreviewPos.z;
        e.heading = safeHeading;
        st.currentMission.entities.push_back(e);
        Notify("Mission entity placed: " + e.model);
    }

    static void ConfirmSafeSpawnPreview(bool notifyResult = true)
    {
        if (!st.safeSpawnPreviewActive || st.safeSpawnPreviewType == SafeSpawnPreviewType::None) return;

        SafeSpawnPreviewType type = st.safeSpawnPreviewType;
        std::string model = NormalizeModelName(st.safeSpawnPreviewModel, "");
        Vector3 pos = st.safeSpawnPreviewPos;
        float heading = NormalizeHeading(st.safeSpawnPreviewHeading, SafePlayerHeading());
        bool warpPlayer = st.safeSpawnPreviewWarpPlayer;
        Relation relation = st.safeSpawnPreviewRelation;
        int health = ClampIntValue(st.safeSpawnPreviewHealth, 1, 10000);
        std::string weapon = st.safeSpawnPreviewWeapon.empty() ? "NONE" : st.safeSpawnPreviewWeapon;
        int ammo = ClampIntValue(st.safeSpawnPreviewAmmo, 0, 9999);
        bool manualZ = st.safeSpawnPreviewManualZ;

        if (model.empty() || !IsUsableWorldPosition(pos, -200.0f, 2000.0f))
        {
            ResetSafeSpawnPreviewState();
            if (notifyResult) Notify("Spawn preview failed: invalid final preview state.");
            return;
        }

        if (SafeSpawnPreviewIsMissionEntity(type))
        {
            AddMissionEntityFromPreview();
            ResetSafeSpawnPreviewState();
            return;
        }

        ResetSafeSpawnPreviewState();
        if (type == SafeSpawnPreviewType::Vehicle)
        {
            Vehicle veh = SpawnVehicleByModelAt(model, pos, heading, warpPlayer, notifyResult, true);
            if (manualZ) ApplyManualPreviewTransform((Entity)veh, pos, heading, true);
        }
        else if (type == SafeSpawnPreviewType::Ped)
        {
            Ped ped = SpawnPedAtModel(model, relation, health, weapon, ammo, pos, heading, true);
            if (manualZ) ApplyManualPreviewTransform((Entity)ped, pos, heading, false);
            if (ped && notifyResult) Notify("Spawned NPC: " + model);
        }
        else if (type == SafeSpawnPreviewType::Object)
        {
            SpawnObjectByModelAt(model, pos, heading, notifyResult, true, manualZ);
        }
    }

    static void BeginSafeSpawnPreview(SafeSpawnPreviewType type, const std::string& model, bool warpPlayer, Vector3 pos, float heading, Relation relation, int health, const std::string& weapon, int ammo)
    {
        CancelSafeSpawnPreview(false);

        std::string cleanModel = NormalizeModelName(model, "");
        if (cleanModel.empty())
        {
            Notify("Invalid preview model.");
            return;
        }

        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f))
        {
            Notify("Invalid preview position.");
            return;
        }

        bool forVehicle = SafeSpawnPreviewIsVehicle(type);
        if (cfg.spawnSafetyEnabled)
            pos.z = ResolveGroundZ(pos.x, pos.y, pos.z) + (forVehicle ? 0.45f : 0.10f);
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f))
        {
            Notify("Invalid preview ground position.");
            return;
        }

        st.safeSpawnPreviewType = type;
        st.safeSpawnPreviewModel = cleanModel;
        st.safeSpawnPreviewWeapon = weapon.empty() ? "NONE" : weapon;
        st.safeSpawnPreviewRelation = relation;
        st.safeSpawnPreviewHealth = ClampIntValue(health, 1, 10000);
        st.safeSpawnPreviewAmmo = ClampIntValue(ammo, 0, 9999);
        st.safeSpawnPreviewWarpPlayer = warpPlayer;
        st.safeSpawnPreviewManualZ = false;
        st.safeSpawnPreviewHeading = NormalizeHeading(heading, SafePlayerHeading());
        st.safeSpawnPreviewPos = pos;
        st.safeSpawnPreviewActive = true;

        if (!cfg.safeSpawnPreviewEnabled)
        {
            ConfirmSafeSpawnPreview(true);
            return;
        }

        // Preview is controlled by raw keyboard input. Hide the trainer menu and cool down
        // Enter/Esc/open hotkeys only when the preview overlay is actually active.
        // Direct-spawn mode keeps the menu open and no longer swallows the menu input.
        st.menuOpen = false;
        DWORD previewInputCooldown = GetTickCount();
        lastKeyTick[VK_RETURN] = previewInputCooldown;
        lastKeyTick[VK_ESCAPE] = previewInputCooldown;
        lastKeyTick[VK_BACK] = previewInputCooldown;
        if (cfg.openKey > 0 && cfg.openKey < 256) lastKeyTick[cfg.openKey] = previewInputCooldown;

        Notify("Spawn preview: " + SafeSpawnPreviewTypeName(type) + " / " + cleanModel);
    }

    static void BeginSafeSpawnPreviewNearPlayer(SafeSpawnPreviewType type, const std::string& model, bool warpPlayer, float forward, bool forVehicle, Relation relation, int health, const std::string& weapon, int ammo)
    {
        Vector3 playerBase{};
        if (!TryGetPlayerPosition(playerBase))
        {
            Notify("Spawn preview failed: player position invalid.");
            return;
        }
        Vector3 pos = SpawnSafetyPosition(forward, forVehicle);
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f))
        {
            Notify("Spawn preview failed: safe position invalid.");
            return;
        }
        float heading = 0.0f;
        Ped playerPed = 0;
        if (GetPlayerPedSafe(playerPed)) heading = core::SafeGetEntityHeading((Entity)(playerPed), 0.0f);
        BeginSafeSpawnPreview(type, model, warpPlayer, pos, heading, relation, health, weapon, ammo);
    }

    static void DrawSafeSpawnPreview()
    {
        if (!st.safeSpawnPreviewActive) return;
        Vector3 p = st.safeSpawnPreviewPos;
        bool vehicle = SafeSpawnPreviewIsVehicle(st.safeSpawnPreviewType);
        bool ped = SafeSpawnPreviewIsPed(st.safeSpawnPreviewType);
        float radius = vehicle ? 2.6f : (ped ? 0.9f : 1.25f);
        int r = vehicle ? 80 : (ped ? 80 : 220);
        int g = vehicle ? 180 : (ped ? 230 : 170);
        int b = vehicle ? 255 : (ped ? 120 : 255);

        SafeDrawMarkerRuntime(1, MakeVector3(p.x, p.y, p.z + 0.05f), Vector3{}, MakeVector3(0.0f, 0.0f, st.safeSpawnPreviewHeading),
                              MakeVector3(radius, radius, vehicle ? 0.45f : 0.25f), r, g, b, 145, false, true, 2, false, "safe_spawn_preview");
        SafeDrawMarkerRuntime(2, MakeVector3(p.x, p.y, p.z + (vehicle ? 1.6f : 1.15f)), Vector3{}, MakeVector3(0.0f, 0.0f, st.safeSpawnPreviewHeading),
                              MakeVector3(0.55f, 0.55f, 0.55f), r, g, b, 185, false, true, 2, false, "safe_spawn_preview");

        DrawRect(0.5f, 0.875f, 0.68f, 0.116f, 12, 12, 16, 175);
        DrawText(0.17f, 0.829f, 0.31f, FitTextWidth(Tr("Preview Active") + ": " + SafeSpawnPreviewTypeName(st.safeSpawnPreviewType) + " / " + st.safeSpawnPreviewModel, 0.31f, 0.64f), 245, 245, 245, 255, false);
        DrawText(0.17f, 0.862f, 0.245f, FitTextWidth("Enter = " + Tr("Confirm Spawn") + " | Back/Esc = " + Tr("Cancel Preview") + " | Left/Right = " + Tr("Rotate Preview"), 0.245f, 0.64f), 220, 220, 220, 245, false);
        DrawText(0.17f, 0.893f, 0.245f, FitTextWidth("Up/Down = forward/back | A/D or Shift+Left/Right = side move | PgUp/PgDn = height", 0.245f, 0.64f), 220, 220, 220, 245, false);
    }

    static void TickSafeSpawnPreview()
    {
        if (!st.safeSpawnPreviewActive) return;
        DrawSafeSpawnPreview();

        if (JustPressed(VK_ESCAPE, 160) || JustPressed(VK_BACK, 160))
        {
            CancelSafeSpawnPreview(true);
            return;
        }
        bool shiftHeld = SafeSpawnPreviewShiftHeld();
        if (JustPressed(VK_LEFT, 65))
        {
            if (shiftHeld)
            {
                st.safeSpawnPreviewPos = OffsetPreviewPosition(st.safeSpawnPreviewPos, st.safeSpawnPreviewHeading, 0.0f, -cfg.safeSpawnPreviewMoveStep);
            }
            else
            {
                st.safeSpawnPreviewHeading = NormalizeHeading(st.safeSpawnPreviewHeading - cfg.safeSpawnPreviewRotateStep, st.safeSpawnPreviewHeading);
            }
        }
        if (JustPressed(VK_RIGHT, 65))
        {
            if (shiftHeld)
            {
                st.safeSpawnPreviewPos = OffsetPreviewPosition(st.safeSpawnPreviewPos, st.safeSpawnPreviewHeading, 0.0f, cfg.safeSpawnPreviewMoveStep);
            }
            else
            {
                st.safeSpawnPreviewHeading = NormalizeHeading(st.safeSpawnPreviewHeading + cfg.safeSpawnPreviewRotateStep, st.safeSpawnPreviewHeading);
            }
        }
        if (JustPressed('A', 65))
        {
            st.safeSpawnPreviewPos = OffsetPreviewPosition(st.safeSpawnPreviewPos, st.safeSpawnPreviewHeading, 0.0f, -cfg.safeSpawnPreviewMoveStep);
        }
        if (JustPressed('D', 65))
        {
            st.safeSpawnPreviewPos = OffsetPreviewPosition(st.safeSpawnPreviewPos, st.safeSpawnPreviewHeading, 0.0f, cfg.safeSpawnPreviewMoveStep);
        }
        if (JustPressed(VK_UP, 65))
        {
            st.safeSpawnPreviewPos = OffsetPreviewPosition(st.safeSpawnPreviewPos, st.safeSpawnPreviewHeading, cfg.safeSpawnPreviewMoveStep, 0.0f);
        }
        if (JustPressed(VK_DOWN, 65))
        {
            st.safeSpawnPreviewPos = OffsetPreviewPosition(st.safeSpawnPreviewPos, st.safeSpawnPreviewHeading, -cfg.safeSpawnPreviewMoveStep, 0.0f);
        }
        if (JustPressed(VK_PRIOR, 80))
        {
            st.safeSpawnPreviewPos.z += 0.25f;
            st.safeSpawnPreviewManualZ = true;
        }
        if (JustPressed(VK_NEXT, 80))
        {
            st.safeSpawnPreviewPos.z -= 0.25f;
            st.safeSpawnPreviewManualZ = true;
        }
        if (JustPressed(VK_RETURN, 160))
        {
            ConfirmSafeSpawnPreview(true);
        }
    }

    static bool LastObjectExists()
    {
        if (!st.lastObject || !core::Exists((Entity)(st.lastObject)))
        {
            st.lastObject = 0;
            st.lastObjectFrozen = true;
            CleanupDeadObjects();
            return false;
        }
        Vector3 pos{};
        if (!TryGetStrictTrackedEntityPosition((Entity)st.lastObject, pos))
        {
            Object badObject = st.lastObject;
            st.spawnedObjects.erase(std::remove(st.spawnedObjects.begin(), st.spawnedObjects.end(), badObject), st.spawnedObjects.end());
            RemoveTrackedEntity((Entity)badObject);
            st.lastObject = 0;
            st.lastObjectFrozen = true;
            CleanupDeadObjects();
            return false;
        }
        return true;
    }

    static void MoveLastObject(float forward, float right, float up)
    {
        if (!LastObjectExists()) { Notify("No last object."); return; }
        UndoEntitySnapshot before;
        const bool canUndo = cfg.undoRecordSpawns && CanRecordUndo() && SnapshotEntityForUndo((Entity)st.lastObject, before);
        Vector3 pos{};
        if (!TryGetStrictTrackedEntityPosition((Entity)st.lastObject, pos)) { Notify("Move object failed: current position invalid."); return; }
        float h = NormalizeHeading((float)core::SafeGetEntityHeading((Entity)(st.lastObject), 0.0f), 0.0f) * 0.0174532924f;
        Vector3 target = pos;
        target.x += (-sinf(h) * forward) + ( cosf(h) * right);
        target.y += ( cosf(h) * forward) + ( sinf(h) * right);
        target.z += up;
        if (!IsUsableWorldPosition(target, -200.0f, 2000.0f)) { Notify("Move object rejected: target position invalid."); return; }

        core::safe_native::Freeze((Entity)st.lastObject, false, &g_coreErrors, "object");
        core::safe_native::SetCoords((Entity)st.lastObject, target, false, &g_coreErrors, "object");
        core::safe_native::Freeze((Entity)st.lastObject, st.lastObjectFrozen, &g_coreErrors, "object");
        if (!IsEntityFinalPositionAcceptable((Entity)st.lastObject, target, 25.0f))
        {
            if (canUndo) ApplyEntitySnapshotToExisting((Entity)st.lastObject, before);
            core::safe_native::Freeze((Entity)st.lastObject, st.lastObjectFrozen, &g_coreErrors, "object");
            Notify("Move object rejected: final position invalid.");
            return;
        }
        if (canUndo)
        {
            UndoAction a;
            a.type = UndoActionType::RestoreEntityState;
            a.label = "Move Last Object";
            a.entities.push_back((Entity)st.lastObject);
            a.entitySnapshots.push_back(before);
            PushUndo(a);
        }
    }

    static void RotateLastObject(float delta)
    {
        if (!LastObjectExists()) { Notify("No last object."); return; }
        PushEntityStateUndo("Rotate Last Object", (Entity)st.lastObject);
        core::safe_native::Freeze((Entity)st.lastObject, false, &g_coreErrors, "object");
        float h = NormalizeHeading((float)core::SafeGetEntityHeading((Entity)(st.lastObject), 0.0f) + delta, 0.0f);
        core::safe_native::SetHeading((Entity)st.lastObject, h, &g_coreErrors, "object");
        core::safe_native::Freeze((Entity)st.lastObject, st.lastObjectFrozen, &g_coreErrors, "object");
        Vector3 finalPos{};
        if (!TryGetStrictTrackedEntityPosition((Entity)st.lastObject, finalPos) ||
            !IsEntityFinalPositionAcceptable((Entity)st.lastObject, finalPos, 25.0f))
        {
            Notify("Rotate object warning: final position invalid.");
            LastObjectExists();
        }
    }

    static void ToggleFreezeLastObject()
    {
        if (!LastObjectExists()) { Notify("No last object."); return; }
        PushEntityStateUndo("Freeze Last Object", (Entity)st.lastObject);
        st.lastObjectFrozen = !st.lastObjectFrozen;
        core::safe_native::Freeze((Entity)st.lastObject, st.lastObjectFrozen, &g_coreErrors, "object");
        Notify(st.lastObjectFrozen ? "Last object frozen." : "Last object unfrozen.");
    }

    static void EraseSpawnedObjectHandle(Object obj)
    {
        st.spawnedObjects.erase(std::remove_if(st.spawnedObjects.begin(), st.spawnedObjects.end(), [obj](Object tracked)
        {
            return tracked == obj || !tracked || !core::Exists((Entity)(tracked));
        }), st.spawnedObjects.end());
    }

    static void DeleteLastObject()
    {
        if (!LastObjectExists()) { Notify("No last object."); return; }
        Object obj = st.lastObject;
        UndoEntitySnapshot deletedSnapshot;
        bool hasDeletedSnapshot = SnapshotEntityForUndo((Entity)obj, deletedSnapshot);
        if (DeleteObjectSafely(obj))
        {
            if (hasDeletedSnapshot)
            {
                UndoAction restore;
                restore.type = UndoActionType::RestoreEntities;
                restore.label = "Delete Last Object";
                restore.entitySnapshots.push_back(deletedSnapshot);
                PushUndo(restore);
            }
            EraseSpawnedObjectHandle(obj);
            RemoveTrackedEntity((Entity)obj);
            st.lastObject = 0;
            st.lastObjectFrozen = true;
            CleanupDeadObjects();
            Notify("Last object deleted.");
        }
        else
        {
            TrackSpawnedObjectIfAlive(obj);
            Notify("Last object delete blocked; still tracked.");
        }
    }

    static void ClearSpawnedObjects()
    {
        std::vector<Object> rawObjects = st.spawnedObjects;
        std::vector<Object> targets;
        targets.reserve(rawObjects.size() + 1);
        for (Object obj : rawObjects)
        {
            if (obj && core::Exists((Entity)(obj)) && std::find(targets.begin(), targets.end(), obj) == targets.end())
                targets.push_back(obj);
        }
        if (st.lastObject && core::Exists((Entity)(st.lastObject)) && std::find(targets.begin(), targets.end(), st.lastObject) == targets.end())
            targets.push_back(st.lastObject);
        UndoAction restoreDeleted;
        restoreDeleted.type = UndoActionType::RestoreEntities;
        restoreDeleted.label = "Clear Spawned Objects";
        Object previousLastObject = st.lastObject;
        bool previousLastObjectFrozen = st.lastObjectFrozen;

        std::vector<Object> kept;
        st.spawnedObjects.clear();
        for (Object obj : targets)
        {
            if (!obj || !core::Exists((Entity)(obj)))
            {
                if (obj) RemoveTrackedEntity((Entity)obj);
                continue;
            }
            UndoEntitySnapshot snap;
            bool hasSnap = SnapshotEntityForUndo((Entity)obj, snap);
            if (DeleteObjectSafely(obj))
            {
                if (hasSnap) restoreDeleted.entitySnapshots.push_back(snap);
                RemoveTrackedEntity((Entity)obj);
            }
            else if (std::find(kept.begin(), kept.end(), obj) == kept.end())
            {
                kept.push_back(obj);
            }
        }
        if (!restoreDeleted.entitySnapshots.empty()) PushUndo(restoreDeleted);
        st.spawnedObjects.swap(kept);
        if (!st.lastObject || !core::Exists((Entity)(st.lastObject)) || std::find(st.spawnedObjects.begin(), st.spawnedObjects.end(), st.lastObject) == st.spawnedObjects.end())
        {
            st.lastObject = st.spawnedObjects.empty() ? 0 : st.spawnedObjects.back();
            st.lastObjectFrozen = (st.lastObject && st.lastObject == previousLastObject) ? previousLastObjectFrozen : true;
        }
        else if (st.lastObject == previousLastObject)
        {
            st.lastObjectFrozen = previousLastObjectFrozen;
        }
        Notify(st.spawnedObjects.empty() ? "Spawned objects cleared." : "Spawned objects clear partially blocked.");
    }

    template<typename T>
    static int CountExistingUniqueHandles(const std::vector<T>& list)
    {
        std::vector<Entity> unique;
        unique.reserve(list.size());
        for (T value : list)
        {
            Entity e = (Entity)value;
            if (!e || !core::Exists(e)) continue;
            Vector3 pos{};
            if (!TryGetStrictTrackedEntityPosition((Entity)e, pos)) continue;
            if (std::find(unique.begin(), unique.end(), e) == unique.end()) unique.push_back(e);
        }
        return (int)unique.size();
    }

    static int CountExistingPeds(const std::vector<Ped>& list)
    {
        std::vector<Entity> unique;
        unique.reserve(list.size());
        for (Ped ped : list)
        {
            if (!IsUsablePedHandle(ped, false, false, true)) continue;
            Entity e = (Entity)ped;
            if (std::find(unique.begin(), unique.end(), e) == unique.end()) unique.push_back(e);
        }
        return (int)unique.size();
    }

