    static void AddExistingEntityUnique(std::vector<Entity>& unique, Entity entity)
    {
        if (!entity || !core::Exists((Entity)(entity))) return;
        Vector3 pos{};
        if (!TryGetStrictTrackedEntityPosition((Entity)entity, pos)) return;
        if (std::find(unique.begin(), unique.end(), entity) == unique.end())
            unique.push_back(entity);
    }

    template<typename T>
    static void AddExistingEntitiesUnique(std::vector<Entity>& unique, const std::vector<T>& list)
    {
        for (T item : list)
            AddExistingEntityUnique(unique, (Entity)item);
    }

    static bool ExistingEntityMatchesRuntimeKind(Entity entity, core::EntityKind kind)
    {
        if (!entity || !core::Exists((Entity)(entity))) return false;
        switch (kind)
        {
            case core::EntityKind::Ped:
                return core::IsPed(entity) && !core::IsPlayerPed(entity);
            case core::EntityKind::Vehicle:
                return core::IsVehicle(entity);
            case core::EntityKind::Object:
                return core::IsObject(entity);
            case core::EntityKind::Any:
            default:
                return true;
        }
    }

    static void AddExistingEntityUniqueByKind(std::vector<Entity>& unique, Entity entity, core::EntityKind kind)
    {
        if (!ExistingEntityMatchesRuntimeKind(entity, kind)) return;
        Vector3 pos{};
        if (!TryGetStrictTrackedEntityPosition((Entity)entity, pos)) return;
        if (std::find(unique.begin(), unique.end(), entity) == unique.end())
            unique.push_back(entity);
    }

    template<typename T>
    static void AddExistingEntitiesUniqueByKind(std::vector<Entity>& unique, const std::vector<T>& list, core::EntityKind kind)
    {
        for (T item : list)
            AddExistingEntityUniqueByKind(unique, (Entity)item, kind);
    }

    static int CountUniqueExistingRuntimeEntitiesByKind(core::EntityKind kind)
    {
        std::vector<Entity> unique;
        unique.reserve(st.spawnedPeds.size() + st.bodyguards.size() + st.enemies.size() + st.scenarioPeds.size() +
                       st.spawnedVehicles.size() + st.scenarioVehicles.size() + st.spawnedObjects.size() +
                       st.worldDirectorEntities.size() + st.urbanLifeEntities.size() + st.vehicleAIEntities.size() +
                       st.policeRealismEntities.size() + st.gameMode.trackedEntities.size() +
                       st.missionSpawnedEntities.size());
        AddExistingEntitiesUniqueByKind(unique, st.spawnedPeds, kind);
        AddExistingEntitiesUniqueByKind(unique, st.bodyguards, kind);
        AddExistingEntitiesUniqueByKind(unique, st.enemies, kind);
        AddExistingEntitiesUniqueByKind(unique, st.scenarioPeds, kind);
        AddExistingEntitiesUniqueByKind(unique, st.spawnedVehicles, kind);
        AddExistingEntitiesUniqueByKind(unique, st.scenarioVehicles, kind);
        AddExistingEntitiesUniqueByKind(unique, st.spawnedObjects, kind);
        AddExistingEntitiesUniqueByKind(unique, st.worldDirectorEntities, kind);
        AddExistingEntitiesUniqueByKind(unique, st.urbanLifeEntities, kind);
        AddExistingEntitiesUniqueByKind(unique, st.vehicleAIEntities, kind);
        AddExistingEntitiesUniqueByKind(unique, st.policeRealismEntities, kind);
        AddExistingEntitiesUniqueByKind(unique, st.gameMode.trackedEntities, kind);
        AddExistingEntitiesUniqueByKind(unique, st.missionSpawnedEntities, kind);
        return (int)unique.size();
    }

