    [[maybe_unused]] static bool IsPlayerCurrentVehicle(Vehicle v)
    {
        Ped player = 0;
        return GetPlayerPedSafe(player) && core::IsPedInAnyVehicle((Ped)(player), false) && (Vehicle)core::GetVehiclePedIsIn((Ped)(player), false) == v;
    }

    static bool ShouldAlwaysProtectVehicleFromCleanup(Vehicle vehicle)
    {
        if (!IsUsableVehicleHandle(vehicle, false)) return false;
        return IsActiveGameModeEntity((Entity)vehicle) || IsPlayerInVehicleEntity(vehicle);
    }

    static bool VehicleHasTrackedSeatOccupants(Vehicle v)
    {
        if (!IsUsableVehicleHandle(v, true)) return false;
        if (!core::IsVehicleSeatFree((Vehicle)(v), -1)) return true;
        int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        for (int seat = 0; seat <= maxSeat; ++seat)
        {
            if (!core::IsVehicleSeatFree((Vehicle)(v), seat)) return true;
        }
        return false;
    }

    [[maybe_unused]] static bool IsTrackedVehicleEmpty(Vehicle v)
    {
        if (!IsUsableVehicleHandle(v, false)) return true;
        if (ShouldProtectVehicleFromCleanup(v, true)) return false;
        return !VehicleHasTrackedSeatOccupants(v);
    }

    static bool IsTrackedVehicleEmptyForSmartCleanup(Vehicle v)
    {
        if (!IsUsableVehicleHandle(v, false)) return true;
        if (ShouldAlwaysProtectVehicleFromCleanup(v)) return false;
        if (cfg.smartCleanupRetainProtectedVehicles && ShouldProtectVehicleFromCleanup(v, true)) return false;
        return !VehicleHasTrackedSeatOccupants(v);
    }

    static int CountDeadPedCleanupCandidates()
    {
        std::vector<Entity> unique;
        auto addPed = [&](Ped p)
        {
            Entity e = (Entity)p;
            if (!IsUsablePedHandle(p, false, false, true) || IsActiveGameModeEntity(e)) return;
            if (!core::IsPedDeadOrDying((Ped)(p), true, true)) return;
            if (std::find(unique.begin(), unique.end(), e) == unique.end()) unique.push_back(e);
        };
        auto addMixed = [&](const std::vector<Entity>& list)
        {
            for (Entity e : list)
            {
                if (!e || !core::Exists((Entity)(e)) || IsActiveGameModeEntity(e)) continue;
                if (!core::IsPed((Entity)(e))) continue;
                Ped p = (Ped)e;
                if (core::IsPlayerPed((Entity)(p)) || !core::IsPedDeadOrDying((Ped)(p), true, true)) continue;
                if (std::find(unique.begin(), unique.end(), e) == unique.end()) unique.push_back(e);
            }
        };

        for (Ped p : st.enemies) addPed(p);
        if (cfg.smartCleanupIncludeWorldDirector) addMixed(st.worldDirectorEntities);
        if (cfg.smartCleanupIncludeUrbanLife) addMixed(st.urbanLifeEntities);
        if (cfg.smartCleanupIncludeVehicleAI) addMixed(st.vehicleAIEntities);
        if (cfg.smartCleanupIncludePoliceRealism) addMixed(st.policeRealismEntities);
        return (int)unique.size();
    }

    static int CountEmptyVehicleCleanupCandidates()
    {
        std::vector<Entity> unique;
        auto addVehicle = [&](Vehicle v)
        {
            Entity e = (Entity)v;
            if (!v || !core::Exists((Entity)(e)) || IsActiveGameModeEntity(e)) return;
            if (!IsTrackedVehicleEmptyForSmartCleanup(v)) return;
            if (std::find(unique.begin(), unique.end(), e) == unique.end()) unique.push_back(e);
        };
        auto addMixed = [&](const std::vector<Entity>& list)
        {
            for (Entity e : list)
            {
                if (!e || !core::Exists((Entity)(e)) || IsActiveGameModeEntity(e)) continue;
                if (!core::IsVehicle((Entity)(e))) continue;
                Vehicle v = (Vehicle)e;
                if (!IsTrackedVehicleEmptyForSmartCleanup(v)) continue;
                if (std::find(unique.begin(), unique.end(), e) == unique.end()) unique.push_back(e);
            }
        };

        for (Vehicle v : st.spawnedVehicles) addVehicle(v);
        for (Vehicle v : st.scenarioVehicles) addVehicle(v);
        if (cfg.smartCleanupIncludeWorldDirector) addMixed(st.worldDirectorEntities);
        if (cfg.smartCleanupIncludeUrbanLife) addMixed(st.urbanLifeEntities);
        if (cfg.smartCleanupIncludeVehicleAI) addMixed(st.vehicleAIEntities);
        if (cfg.smartCleanupIncludePoliceRealism) addMixed(st.policeRealismEntities);
        return (int)unique.size();
    }


    template<typename T>
    static int CompactInvalidEntityVector(std::vector<T>& list);
    template<typename T>
    static int CompactInvalidPedVector(std::vector<T>& list);
    template<typename T>
    static int CompactInvalidVehicleVector(std::vector<T>& list);
    template<typename T>
    static int CompactInvalidObjectVector(std::vector<T>& list);
    static int CountExistingMixedEntities(const std::vector<Entity>& list);
    static void CleanOnlyMissionPreview();

    static bool IsValidCinematicRuntimeEntity(Entity entity)
    {
        if (!entity || !core::Exists((Entity)entity)) return false;
        if (core::IsPed((Entity)entity))
        {
            Ped ped = (Ped)entity;
            Vector3 pos{};
            return IsUsablePedHandle(ped, true, false, false) &&
                TryGetUsableEntityPosition((Entity)ped, pos) &&
                !core::IsPedDeadOrDying((Ped)ped, true, true);
        }
        if (core::IsVehicle((Entity)entity))
        {
            Vehicle vehicle = (Vehicle)entity;
            Vector3 pos{};
            return IsUsableVehicleHandle(vehicle, false) &&
                TryGetUsableEntityPosition((Entity)vehicle, pos) &&
                (int)core::SafeGetEntityHealth((Entity)vehicle, 0) > 0;
        }
        return false;
    }

    static int PurgeInvalidCinematicNpcRuntimeState()
    {
        int removed = 0;
        auto purgeMap = [&](auto& mapRef)
        {
            for (auto it = mapRef.begin(); it != mapRef.end(); )
            {
                if (IsValidCinematicRuntimeEntity(it->first))
                {
                    ++it;
                }
                else
                {
                    it = mapRef.erase(it);
                    ++removed;
                }
            }
        };

        purgeMap(st.cinematicNpcLastManeuverTick);
        purgeMap(st.cinematicNpcPursuitRoles);
        return removed;
    }

    static int ClearCinematicNpcRuntimeReferencesToEntity(Entity entity)
    {
        if (!entity) return 0;
        int removed = 0;
        removed += (int)st.cinematicNpcLastManeuverTick.erase(entity);
        removed += (int)st.cinematicNpcPursuitRoles.erase(entity);
        return removed;
    }

    static int CompactInvalidTrackedEntities()
    {
        int removed = 0;
        removed += CompactInvalidPedVector(st.spawnedPeds);
        removed += CompactInvalidPedVector(st.friendlyPeds);
        removed += CompactInvalidPedVector(st.bodyguards);
        removed += CompactInvalidPedVector(st.enemies);
        removed += CompactInvalidPedVector(st.scenarioPeds);
        removed += CompactInvalidVehicleVector(st.spawnedVehicles);
        removed += CompactInvalidVehicleVector(st.scenarioVehicles);
        removed += CompactInvalidObjectVector(st.spawnedObjects);
        removed += CompactInvalidEntityVector(st.worldDirectorEntities);
        removed += CompactInvalidEntityVector(st.urbanLifeEntities);
        removed += CompactInvalidEntityVector(st.vehicleAIEntities);
        removed += CompactInvalidEntityVector(st.policeRealismEntities);
        removed += PurgeInvalidCinematicNpcRuntimeState();
        size_t beforeGameMode = st.gameMode.trackedEntities.size();
        CompactGameModeEntities();
        if (beforeGameMode > st.gameMode.trackedEntities.size())
            removed += (int)(beforeGameMode - st.gameMode.trackedEntities.size());
        size_t beforeMission = st.missionSpawnedEntities.size();
        CompactMissionSpawnedEntityLists();
        if (beforeMission > st.missionSpawnedEntities.size())
            removed += (int)(beforeMission - st.missionSpawnedEntities.size());
        removed += PurgeStaleBodyguardRuntimeState();
        Vector3 singletonPos{};
        if (st.lastObject && (!core::IsObject((Entity)st.lastObject) || !TryGetUsableEntityPosition((Entity)st.lastObject, singletonPos)))
        {
            st.lastObject = 0;
            st.lastObjectFrozen = true;
            ++removed;
        }
        if (st.lastPlayerVehicleForBodyguards && (!core::IsVehicle((Entity)st.lastPlayerVehicleForBodyguards) || !TryGetUsableEntityPosition((Entity)st.lastPlayerVehicleForBodyguards, singletonPos)))
        {
            st.lastPlayerVehicleForBodyguards = 0;
            ++removed;
        }
        if (st.bodyguardProtectedVehicle && (!core::IsVehicle((Entity)st.bodyguardProtectedVehicle) || !TryGetUsableEntityPosition((Entity)st.bodyguardProtectedVehicle, singletonPos)))
        {
            st.bodyguardProtectedVehicle = 0;
            ++removed;
        }
        if (st.garageLastLoadedVehicle && (!core::IsVehicle((Entity)st.garageLastLoadedVehicle) || !TryGetUsableEntityPosition((Entity)st.garageLastLoadedVehicle, singletonPos)))
        {
            st.garageLastLoadedVehicle = 0;
            ++removed;
        }
        if (st.chauffeur && (!core::IsPed((Entity)st.chauffeur) || !TryGetUsableEntityPosition((Entity)st.chauffeur, singletonPos) || core::IsPedDeadOrDying(st.chauffeur, true, true)))
        {
            st.chauffeur = 0;
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
            ++removed;
        }
        if (st.chauffeurVehicle && (!core::IsVehicle((Entity)st.chauffeurVehicle) || !TryGetUsableEntityPosition((Entity)st.chauffeurVehicle, singletonPos)))
        {
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
            ++removed;
        }
        for (auto it = st.inspectorFrozenStates.begin(); it != st.inspectorFrozenStates.end(); )
        {
            if (!it->first || !core::Exists((Entity)it->first) || !TryGetUsableEntityPosition((Entity)it->first, singletonPos))
            {
                it = st.inspectorFrozenStates.erase(it);
                ++removed;
            }
            else ++it;
        }
        if (st.inspectedEntity && (!core::Exists((Entity)st.inspectedEntity) || !TryGetUsableEntityPosition((Entity)st.inspectedEntity, singletonPos)))
        {
            st.inspectedEntity = 0;
            st.lastInspectorStatus = "No entity selected";
            ++removed;
        }
        return removed;
    }

    static bool TryGetPlayerPosition(Vector3& pos)
    {
        return TryGetValidatedPlayerCoords(pos);
    }

    static float SafeSmartCleanupRadius()
    {
        if (!std::isfinite(cfg.smartCleanupFarRadius)) cfg.smartCleanupFarRadius = 135.0f;
        cfg.smartCleanupFarRadius = ClampFloatValue(cfg.smartCleanupFarRadius, 25.0f, 500.0f, 135.0f);
        return cfg.smartCleanupFarRadius;
    }

    static void KeepMixedEntityIfAlive(std::vector<Entity>& kept, Entity e)
    {
        if (!core::Exists(e)) return;
        Vector3 pos{};
        if (!TryGetUsableEntityPosition(e, pos)) return;
        if (std::find(kept.begin(), kept.end(), e) == kept.end()) kept.push_back(e);
    }

    static void RefreshRuntimeAfterCleanup()
    {
        Vector3 refreshPos{};
        for (auto it = st.inspectorFrozenStates.begin(); it != st.inspectorFrozenStates.end(); )
        {
            if (!it->first || !core::Exists((Entity)(it->first)) || !TryGetUsableEntityPosition((Entity)it->first, refreshPos))
                it = st.inspectorFrozenStates.erase(it);
            else ++it;
        }
        if (st.inspectedEntity && (!core::Exists((Entity)(st.inspectedEntity)) || !TryGetUsableEntityPosition((Entity)st.inspectedEntity, refreshPos)))
        {
            st.inspectedEntity = 0;
            st.lastInspectorStatus = "No entity selected";
        }
        if (st.lastObject && (!core::Exists((Entity)(st.lastObject)) || !TryGetUsableEntityPosition((Entity)st.lastObject, refreshPos)))
        {
            st.lastObject = 0;
            st.lastObjectFrozen = true;
        }
        SanitizeCompanionRuntimeState();
        CompactUndoRedoStacks();
        ClampStateIndexes();
    }

    static void CompactInvalidEntitiesNow()
    {
        int removed = CompactInvalidTrackedEntities();
        RefreshRuntimeAfterCleanup();
        st.lastSmartCleanupReport = "Invalid references compacted: " + std::to_string(removed);
        Notify(st.lastSmartCleanupReport);
    }

    static void RebuildRuntimeTrackingNow()
    {
        int repaired = 0;
        int invalid = CompactInvalidTrackedEntities();
        auto trackVehicle = [&](Vehicle vehicle)
        {
            if (!IsUsableVehicleHandle(vehicle, true)) return;
            const size_t before = st.spawnedVehicles.size();
            TrackSpawnedVehicleIfAlive(vehicle);
            if (st.spawnedVehicles.size() > before)
            {
                ++repaired;
                core::safe_native::SetMissionEntity((Entity)((Entity)vehicle), true, true, &g_coreErrors, "full_audit");
            }
        };

        Ped player = 0;
        if (GetPlayerPedSafe(player) && core::IsPedInAnyVehicle((Ped)(player), false))
            trackVehicle(core::GetVehiclePedIsIn((Ped)(player), false));
        trackVehicle(st.chauffeurVehicle);
        trackVehicle(st.bodyguardProtectedVehicle);
        trackVehicle(st.lastPlayerVehicleForBodyguards);
        trackVehicle(st.garageLastLoadedVehicle);

        SanitizeCompanionRuntimeState();
        RefreshRuntimeAfterCleanup();
        st.lastSmartCleanupReport = "Runtime tracking rebuilt: protected vehicles " + std::to_string(repaired) + ", invalid " + std::to_string(invalid);
        Notify(st.lastSmartCleanupReport);
    }

    static void EmergencyStabilizeRecoveryCleanup()
    {
        CancelSafeSpawnPreview(false);
        ClearRandomMissionPreviewState();
        cfg.worldDirectorAutoEvents = false;
        cfg.urbanLifeAutoEvents = false;
        cfg.vehicleAIAutoEvents = false;
        st.policeRealismActive = false;
        st.worldDirectorActive = false;
        st.urbanLifeActive = false;
        st.vehicleAIActive = false;
        ClearWorldDirector(false);
        ClearUrbanLife(false);
        ClearVehicleAI(false);
        ClearPoliceRealism(false);
        RebuildRuntimeTrackingNow();
        RunSmartCleanup2();
        RunAutoRecoveryScan(false, true);
        RunHealthCheck(false, false);
        st.lastSmartCleanupReport = "Emergency Stabilize 2.0 complete.";
        Notify(st.lastSmartCleanupReport);
    }

    static void CleanTrackedEverything()
    {
        int cleaned = 0;

        // Stop transient systems before deleting their entities so no active tick can re-issue
        // tasks to handles that are about to be removed.
        CancelSafeSpawnPreview(false);
        StopMissionPlaytest(false);
        ClearRandomMissionPreviewState();
        st.battleActive = false;
        st.scenarioActive = false;
        st.scenarioMode = ScenarioMode::None;
        st.worldDirectorActive = false;
        st.urbanLifeActive = false;
        st.vehicleAIActive = false;
        st.policeRealismActive = false;

        int directorBefore = CountExistingMixedEntities(st.worldDirectorEntities);
        int urbanBefore = CountExistingMixedEntities(st.urbanLifeEntities);
        int vehicleAIBefore = CountExistingMixedEntities(st.vehicleAIEntities);
        int policeBefore = CountExistingMixedEntities(st.policeRealismEntities);
        ClearWorldDirector(false);
        ClearUrbanLife(false);
        ClearVehicleAI(false);
        ClearPoliceRealism(false);
        st.worldDirectorActive = false;
        st.urbanLifeActive = false;
        st.vehicleAIActive = false;
        st.policeRealismActive = false;
        st.lastWorldDirectorTick = GetTickCount();
        st.lastUrbanLifeTick = GetTickCount();
        st.lastVehicleAITick = GetTickCount();

        // Delete peds before vehicles and then disable chauffeur protection for the vehicle pass.
        // The old order could protect the chauffeur car, delete the chauffeur afterwards,
        // and leave an orphaned tracked vehicle behind after "Clean Tracked Everything".
        Vehicle chauffeurVehicleToClean = st.chauffeurVehicle;
        cleaned += DismissPeds(st.spawnedPeds);
        cleaned += DismissBodyguards();
        // Bodyguard cleanup should not keep protecting the old escort car.
        // If the player is still inside, IsPlayerInVehicleEntity() will protect it independently.
        st.lastPlayerVehicleForBodyguards = 0;
        cleaned += DismissPeds(st.enemies);
        cleaned += DismissPeds(st.scenarioPeds);
        bool chauffeurDeletedOrInvalid = true;
        if (st.chauffeur && core::Exists((Entity)(st.chauffeur)) && !core::IsPlayerPed((Entity)(st.chauffeur)))
        {
            chauffeurDeletedOrInvalid = DeleteEntityAndUntrackIfGone((Entity)st.chauffeur, true);
            if (chauffeurDeletedOrInvalid) ++cleaned;
        }
        if (chauffeurDeletedOrInvalid)
        {
            st.chauffeur = 0;
            ClearChauffeurRuntimeState();
        }

        cleaned += DismissVehicles(st.spawnedVehicles, false);
        cleaned += DismissVehicles(st.scenarioVehicles, false);
        if (chauffeurVehicleToClean && !IsPlayerInVehicleEntity(chauffeurVehicleToClean))
        {
            if (core::Exists((Entity)(chauffeurVehicleToClean)))
            {
                if (DeleteEntityAndUntrackIfGone((Entity)chauffeurVehicleToClean, true))
                {
                    ++cleaned;
                    if (st.chauffeurVehicle == chauffeurVehicleToClean) st.chauffeurVehicle = 0;
                }
            }
            else if (st.chauffeurVehicle == chauffeurVehicleToClean) st.chauffeurVehicle = 0;
        }
        if (!IsUsableVehicleHandle(st.chauffeurVehicle, true)) st.chauffeurVehicle = 0;
        if (!st.chauffeur && !st.chauffeurVehicle) ResetChauffeurDriveState(false);

        int objBefore = CountExistingObjects(st.spawnedObjects);
        ClearSpawnedObjects();
        int previewBefore = CountMissionPreviewEntities();
        ClearMissionSpawnedEntities();
        ClearMissionBlips();
        int invalid = CompactInvalidTrackedEntities();
        st.lastSmartCleanupReport = "Everything cleaned: " + std::to_string(cleaned + objBefore + previewBefore + directorBefore + urbanBefore + vehicleAIBefore + policeBefore) + ", invalid: " + std::to_string(invalid);
        RefreshRuntimeAfterCleanup();
        Notify(st.lastSmartCleanupReport);
    }

    static void CleanOnlySpawnedVehicles()
    {
        int cleaned = 0;
        cleaned += DismissVehicles(st.spawnedVehicles);
        cleaned += DismissVehicles(st.scenarioVehicles);
        st.scenarioActive = false;
        st.scenarioMode = ScenarioMode::None;
        if (st.chauffeurVehicle && !IsUsableVehicleHandle(st.chauffeurVehicle, true))
        {
            st.chauffeurVehicle = 0;
            ResetChauffeurDriveState(false);
        }
        if (st.chauffeurVehicle && !IsActiveChauffeurVehicle(st.chauffeurVehicle) && !IsPlayerInVehicleEntity(st.chauffeurVehicle))
        {
            st.chauffeurVehicle = 0;
            ResetChauffeurDriveState(false);
        }
        int protectedVehicles = CountExistingVehicles(st.spawnedVehicles) + CountExistingVehicles(st.scenarioVehicles);
        st.lastSmartCleanupReport = "Spawned vehicles cleaned: " + std::to_string(cleaned) + (protectedVehicles > 0 ? " protected: " + std::to_string(protectedVehicles) : "");
        RefreshRuntimeAfterCleanup();
        Notify(st.lastSmartCleanupReport);
    }

    static void CleanOnlySpawnedNPCs()
    {
        int cleaned = 0;
        Vehicle chauffeurVehicleToKeepTracked = st.chauffeurVehicle;
        cleaned += DismissPeds(st.spawnedPeds);
        cleaned += DismissBodyguards();
        cleaned += DismissPeds(st.enemies);
        cleaned += DismissPeds(st.scenarioPeds);
        bool chauffeurDeletedOrInvalid = true;
        if (st.chauffeur && core::Exists((Entity)(st.chauffeur)) && !core::IsPlayerPed((Entity)(st.chauffeur)))
        {
            chauffeurDeletedOrInvalid = DeleteEntityAndUntrackIfGone((Entity)st.chauffeur, true);
            if (chauffeurDeletedOrInvalid) ++cleaned;
        }
        TrackSpawnedVehicleIfAlive(chauffeurVehicleToKeepTracked);
        if (chauffeurDeletedOrInvalid)
        {
            st.chauffeur = 0;
            st.chauffeurVehicle = 0;
            ResetChauffeurDriveState(false);
        }
        st.battleActive = false;
        st.scenarioActive = false;
        st.scenarioMode = ScenarioMode::None;
        st.lastSmartCleanupReport = "Spawned NPCs cleaned: " + std::to_string(cleaned);
        RefreshRuntimeAfterCleanup();
        Notify(st.lastSmartCleanupReport);
    }

