    static int CleanFarPeds(std::vector<Ped>& list, float radiusSq)
    {
        Vector3 playerPos{};
        if (!TryGetPlayerPosition(playerPos)) return 0;
        std::vector<Ped> targets = list;
        std::vector<Ped> kept;
        list.clear();
        int cleaned = 0;

        for (Ped p : targets)
        {
            if (!core::IsPed((Entity)p)) { DropInvalidTrackedEntity((Entity)p); continue; }
            if (core::IsPlayerPed((Entity)(p)) || IsActiveGameModeEntity((Entity)p))
            {
                if (std::find(kept.begin(), kept.end(), p) == kept.end()) kept.push_back(p);
                continue;
            }
            Vector3 pos{};
            if (!TryGetUsableEntityPosition((Entity)p, pos))
            {
                RemoveTrackedEntity((Entity)p);
                ++cleaned;
                continue;
            }
            if (DistanceSq(playerPos, pos) > radiusSq)
            {
                if (DeletePedSafely(p))
                {
                    RemoveTrackedEntity((Entity)p);
                    ++cleaned;
                }
                else if (core::Exists((Entity)(p)) && std::find(kept.begin(), kept.end(), p) == kept.end())
                {
                    kept.push_back(p);
                }
            }
            else if (std::find(kept.begin(), kept.end(), p) == kept.end())
            {
                kept.push_back(p);
            }
        }

        list = kept;
        return cleaned;
    }

