    static int CountExistingMixedEntities(const std::vector<Entity>& list)
    {
        return CountExistingUniqueHandles(list);
    }

    [[maybe_unused]] static int CountExistingMixedEntitiesByKind(const std::vector<Entity>& list, core::EntityKind kind)
    {
        std::vector<Entity> unique;
        unique.reserve(list.size());
        for (Entity entity : list)
        {
            if (!entity || !core::Exists(entity)) continue;
            bool kindMatches = false;
            switch (kind)
            {
                case core::EntityKind::Ped:
                    kindMatches = core::IsPed(entity) && !core::IsPlayerPed(entity);
                    break;
                case core::EntityKind::Vehicle:
                    kindMatches = core::IsVehicle(entity);
                    break;
                case core::EntityKind::Object:
                    kindMatches = core::IsObject(entity);
                    break;
                case core::EntityKind::Any:
                default:
                    kindMatches = true;
                    break;
            }
            if (!kindMatches) continue;
            Vector3 pos{};
            if (!TryGetUsableEntityPosition(entity, pos)) continue;
            if (std::find(unique.begin(), unique.end(), entity) == unique.end())
                unique.push_back(entity);
        }
        return static_cast<int>(unique.size());
    }

    static bool DeleteMixedTrackedEntity(Entity e, bool keepPlayerVehicle = true, bool protectSoftVehicles = true)
    {
        if (!e || !core::Exists((Entity)(e))) return false;
        if (IsActiveGameModeEntity(e)) return false;
        if (core::IsVehicle((Entity)(e)))
        {
            Vehicle v = (Vehicle)e;
            if (keepPlayerVehicle && ShouldAlwaysProtectVehicleFromCleanup(v)) return false;
            if (protectSoftVehicles && ShouldProtectVehicleFromCleanup(v, true)) return false;
            if (!DeleteVehicleSafely(v, false)) return false;
            RemoveTrackedEntity(e);
            return true;
        }
        if (core::IsPed((Entity)(e)))
        {
            Ped p = (Ped)e;
            if (core::IsPlayerPed((Entity)(p))) return false;
            if (!DeletePedSafely(p)) return false;
            RemoveTrackedEntity(e);
            return true;
        }
        if (!DeleteObjectSafely((Object)e)) return false;
        RemoveTrackedEntity(e);
        return true;
    }


    static bool DeleteSubsystemEntityForRollback(Entity ent, bool preserveProtectedVehicle = true)
    {
        if (!ent || !core::Exists((Entity)(ent))) return true;
        if (core::IsVehicle((Entity)(ent)))
        {
            Vehicle v = (Vehicle)ent;
            if (preserveProtectedVehicle && PreserveProtectedVehicleForPlayer(v))
                return true; // Detach from subsystem only; keep protected vehicle globally tracked.
        }
        return DeleteMixedTrackedEntity(ent, true, true);
    }

    static bool DeletePoliceRealismSpawnedEntity(Entity ent)
    {
        if (!ent || !core::Exists((Entity)(ent))) return true;
        if (core::IsVehicle((Entity)(ent)) && PreserveProtectedVehicleForPlayer((Vehicle)ent))
            return true; // Detach from police list only; keep protected vehicle alive.
        return DeleteMixedTrackedEntity(ent, true, true);
    }

    static void RefreshPoliceRealismActiveState()
    {
        st.policeRealismActive = CountExistingMixedEntities(st.policeRealismEntities) > 0 || !st.witnessReports.empty();
    }

    static int CleanFarMixedEntities(std::vector<Entity>& list, float radiusSq)
    {
        Vector3 playerPos{};
        if (!TryGetPlayerPosition(playerPos)) return 0;
        std::vector<Entity> targets = list;
        std::vector<Entity> kept;
        list.clear();
        int cleaned = 0;
        for (Entity e : targets)
        {
            if (!e || !core::Exists((Entity)(e))) { DropInvalidTrackedEntity(e); continue; }
            if (IsActiveGameModeEntity(e) ||
                (core::IsVehicle((Entity)(e)) && ShouldProtectVehicleFromSmartCleanup((Vehicle)e)))
            {
                if (std::find(kept.begin(), kept.end(), e) == kept.end()) kept.push_back(e);
                continue;
            }
            Vector3 pos{};
            if (!TryGetStrictTrackedEntityPosition((Entity)e, pos))
            {
                if (DeleteMixedTrackedEntity(e, true, cfg.smartCleanupRetainProtectedVehicles)) ++cleaned;
                else DropInvalidTrackedEntity(e);
                continue;
            }
            if (DistanceSq(playerPos, pos) > radiusSq)
            {
                if (DeleteMixedTrackedEntity(e, true, cfg.smartCleanupRetainProtectedVehicles)) ++cleaned;
                else KeepMixedEntityIfAlive(kept, e);
            }
            else
            {
                KeepMixedEntityIfAlive(kept, e);
            }
        }
        list = kept;
        return cleaned;
    }

