    static void ClearAreaAroundPlayer()
    {
        Ped playerPed = 0;
        if (!GetPlayerPedSafe(playerPed))
        {
            Notify("Player unavailable.");
            return;
        }
        Vector3 p{};
        if (!TryGetPlayerPosition(p))
        {
            Notify("Clear area skipped: player position invalid.");
            return;
        }
        PushWorldUndo("Clear Area Around Player");
        ProtectCurrentVehicleBeforeWorldClear();
        SafeClearAreaRuntime(p, 90.0f, true, true, false, false, "world_clear");
        CompactInvalidEntitiesNow();
        RebuildRuntimeTrackingNow();
        Notify("Area cleared around player. Protected vehicles retained.");
    }

    static int WorldDirectorEventCount()
    {
        return (int)WorldDirectorEvent::EmergencyResponse + 1;
    }

    static std::string WorldDirectorEventName(WorldDirectorEvent event)
    {
        switch (event)
        {
            case WorldDirectorEvent::TrafficAccident: return "Traffic Accident";
            case WorldDirectorEvent::PolicePursuit: return "Police Pursuit";
            case WorldDirectorEvent::StreetFight: return "Street Fight";
            case WorldDirectorEvent::StoreRobbery: return "Store Robbery";
            case WorldDirectorEvent::FireEmergency: return "Fire Emergency";
            case WorldDirectorEvent::GangAmbush: return "Gang Ambush";
            case WorldDirectorEvent::VipConvoy: return "VIP Convoy";
            case WorldDirectorEvent::DrunkDriver: return "Drunk Driver";
            case WorldDirectorEvent::PoliceRoadblock: return "Police Roadblock";
            case WorldDirectorEvent::GangVsPolice: return "Gang vs Police";
            case WorldDirectorEvent::EmergencyResponse: return "Emergency Response";
            default: return "Unknown";
        }
    }

    static bool IsWorldDirectorDangerousEvent(WorldDirectorEvent event)
    {
        switch (event)
        {
            case WorldDirectorEvent::PolicePursuit:
            case WorldDirectorEvent::StreetFight:
            case WorldDirectorEvent::StoreRobbery:
            case WorldDirectorEvent::GangAmbush:
            case WorldDirectorEvent::DrunkDriver:
            case WorldDirectorEvent::PoliceRoadblock:
            case WorldDirectorEvent::GangVsPolice:
                return true;
            default:
                return false;
        }
    }

    static std::string WorldDirectorProfileName(WorldDirectorProfile profile)
    {
        switch (profile)
        {
            case WorldDirectorProfile::Civil: return "Civil";
            case WorldDirectorProfile::Action: return "Action";
            case WorldDirectorProfile::Emergency: return "Emergency";
            case WorldDirectorProfile::Gang: return "Gang";
            case WorldDirectorProfile::Traffic: return "Traffic";
            case WorldDirectorProfile::Balanced:
            default: return "Balanced";
        }
    }

    static WorldDirectorProfile CurrentWorldDirectorProfile()
    {
        return (WorldDirectorProfile)ClampIntValue(cfg.worldDirectorProfile, 0, 5);
    }

    static int WorldDirectorProfileWeight(WorldDirectorEvent event)
    {
        WorldDirectorProfile profile = CurrentWorldDirectorProfile();
        int chaos = ClampIntValue(cfg.worldDirectorChaosLevel, 1, 5);
        switch (profile)
        {
            case WorldDirectorProfile::Civil:
                switch (event)
                {
                    case WorldDirectorEvent::TrafficAccident: return 5;
                    case WorldDirectorEvent::VipConvoy: return 3;
                    case WorldDirectorEvent::FireEmergency: return 2;
                    case WorldDirectorEvent::EmergencyResponse: return 2;
                    default: return chaos >= 4 ? 1 : 0;
                }
            case WorldDirectorProfile::Action:
                switch (event)
                {
                    case WorldDirectorEvent::PolicePursuit: return 5;
                    case WorldDirectorEvent::GangAmbush: return 4;
                    case WorldDirectorEvent::StoreRobbery: return 3;
                    case WorldDirectorEvent::GangVsPolice: return 3;
                    case WorldDirectorEvent::DrunkDriver: return 2;
                    default: return 1;
                }
            case WorldDirectorProfile::Emergency:
                switch (event)
                {
                    case WorldDirectorEvent::FireEmergency: return 5;
                    case WorldDirectorEvent::EmergencyResponse: return 5;
                    case WorldDirectorEvent::TrafficAccident: return 3;
                    case WorldDirectorEvent::PoliceRoadblock: return 2;
                    default: return 1;
                }
            case WorldDirectorProfile::Gang:
                switch (event)
                {
                    case WorldDirectorEvent::GangAmbush: return 5;
                    case WorldDirectorEvent::GangVsPolice: return 5;
                    case WorldDirectorEvent::StreetFight: return 4;
                    case WorldDirectorEvent::StoreRobbery: return 3;
                    default: return 1;
                }
            case WorldDirectorProfile::Traffic:
                switch (event)
                {
                    case WorldDirectorEvent::TrafficAccident: return 5;
                    case WorldDirectorEvent::PolicePursuit: return 3;
                    case WorldDirectorEvent::DrunkDriver: return 4;
                    case WorldDirectorEvent::PoliceRoadblock: return 3;
                    case WorldDirectorEvent::VipConvoy: return 2;
                    default: return 1;
                }
            case WorldDirectorProfile::Balanced:
            default:
                return 2 + (IsWorldDirectorDangerousEvent(event) ? std::max(0, chaos - 2) : 0);
        }
    }

    static int EffectiveWorldDirectorCooldownMs(WorldDirectorEvent event)
    {
        int base = std::max(0, cfg.worldDirectorEventCooldownMs);
        if (!cfg.worldDirectorAdaptiveCooldown || base <= 0) return base;
        int live = CountExistingMixedEntities(st.worldDirectorEntities);
        int cap = std::max(1, cfg.worldDirectorMaxTrackedEntities);
        int pressure = ClampIntValue((live * 100) / cap, 0, 100);
        int multiplier = 100 + pressure;
        if (IsWorldDirectorDangerousEvent(event)) multiplier += 20;
        return (base * multiplier) / 100;
    }

    static void PushWorldDirectorHistory(const std::string& text)
    {
        if (text.empty()) return;
        st.worldDirectorHistory.insert(st.worldDirectorHistory.begin(), text);
        while (st.worldDirectorHistory.size() > 8) st.worldDirectorHistory.pop_back();
    }

    static void WorldDirectorNotify(const std::string& text)
    {
        st.lastWorldDirectorEvent = text;
        PushWorldDirectorHistory(text);
        if (cfg.worldDirectorNotify) Notify(text);
    }

    static void ThrottleWorldDirectorAutoAttempt(bool manual)
    {
        if (!manual) st.lastWorldDirectorTick = GetTickCount();
    }

    static void CompactWorldDirectorEntities()
    {
        std::vector<Entity> compacted;
        compacted.reserve(st.worldDirectorEntities.size());
        for (Entity ent : st.worldDirectorEntities)
        {
            if (!ent || !core::Exists((Entity)(ent))) continue;
            Vector3 pos{};
            if (!TryGetStrictTrackedEntityPosition((Entity)ent, pos)) continue;
            if (std::find(compacted.begin(), compacted.end(), ent) != compacted.end()) continue;
            compacted.push_back(ent);
        }
        st.worldDirectorEntities.swap(compacted);
    }

    static bool IsBrokenWorldDirectorEntity(Entity ent)
    {
        if (!ent || !core::Exists((Entity)(ent))) return true;
        if (core::IsPed((Entity)(ent)) && core::IsPedDeadOrDying((Ped)ent, true, true)) return true;
        if (core::IsVehicle((Entity)(ent)) && (int)core::SafeGetEntityHealth((Entity)(ent), 0) <= 0) return true;
        return false;
    }

    static bool TrackWorldDirectorEntity(Entity entity)
    {
        if (!entity || !core::Exists((Entity)(entity))) return false;
        CompactWorldDirectorEntities();
        if ((int)st.worldDirectorEntities.size() >= cfg.worldDirectorMaxTrackedEntities) return false;
        if (std::find(st.worldDirectorEntities.begin(), st.worldDirectorEntities.end(), entity) == st.worldDirectorEntities.end())
            st.worldDirectorEntities.push_back(entity);
        return true;
    }

    static bool WorldDirectorEventAllowedBySettings(WorldDirectorEvent event)
    {
        if (cfg.worldDirectorDangerousEvents) return true;
        return !IsWorldDirectorDangerousEvent(event);
    }

    static bool WorldDirectorEventCoolingDown(WorldDirectorEvent event)
    {
        if (cfg.worldDirectorEventCooldownMs <= 0) return false;
        auto it = st.worldDirectorEventLastTick.find((int)event);
        if (it == st.worldDirectorEventLastTick.end()) return false;
        return !core::TickElapsed(GetTickCount(), it->second, SafeIntervalFromIntMs(EffectiveWorldDirectorCooldownMs(event), cfg.worldDirectorEventCooldownMs, 0, 600000, "world_director", "event cooldown"));
    }

    static bool WorldDirectorCanSelectEvent(WorldDirectorEvent event)
    {
        if (!WorldDirectorEventAllowedBySettings(event)) return false;
        if (WorldDirectorEventCoolingDown(event)) return false;
        if (cfg.worldDirectorPreventRepeat && st.worldDirectorEventCount > 0 && event == st.lastWorldDirectorEventType) return false;
        return true;
    }

    static WorldDirectorEvent PickRandomWorldDirectorEvent()
    {
        std::vector<std::pair<WorldDirectorEvent, int>> weighted;
        int totalWeight = 0;
        for (int i = 0; i < WorldDirectorEventCount(); ++i)
        {
            WorldDirectorEvent event = (WorldDirectorEvent)i;
            if (!WorldDirectorCanSelectEvent(event)) continue;
            int w = std::max(0, WorldDirectorProfileWeight(event));
            if (w <= 0) continue;
            weighted.push_back({event, w});
            totalWeight += w;
        }
        if (weighted.empty())
        {
            for (int i = 0; i < WorldDirectorEventCount(); ++i)
            {
                WorldDirectorEvent event = (WorldDirectorEvent)i;
                if (!WorldDirectorEventAllowedBySettings(event)) continue;
                int w = std::max(1, WorldDirectorProfileWeight(event));
                weighted.push_back({event, w});
                totalWeight += w;
            }
        }
        if (weighted.empty()) return WorldDirectorEvent::TrafficAccident;
        int roll = SafeRandomIntRuntime(1, std::max(1, totalWeight) + 1, 1, "world_director");
        for (const auto& it : weighted)
        {
            roll -= it.second;
            if (roll <= 0) return it.first;
        }
        return weighted.back().first;
    }


    static bool TryGetClosestVehicleNodeForWorldDirector(const Vector3& desired, Vector3& outNode)
    {
        for (int i = 1; i <= 10; ++i)
        {
            Vector3 node{};
            if (SafeGetClosestVehicleNodeRuntime(desired, i, node, "event_pathfind") &&
                IsUsableWorldPosition(node, -200.0f, 2000.0f))
            {
                outNode = node;
                return true;
            }
        }
        return false;
    }

    static Vector3 WorldDirectorSpawnPos(int index, int total, float radiusBias = 0.0f, bool preferRoad = false)
    {
        Vector3 base{};
        if (!TryGetPlayerPosition(base)) return InvalidWorldVector();

        float minR = (float)std::max(cfg.worldDirectorSafeSpawnDistance, cfg.worldDirectorMinRadius);
        float maxR = (float)std::max(cfg.worldDirectorMaxRadius, (int)minR + 15);
        float radius = SafeRandomFloatRuntime(minR, maxR, minR, "spawn");
        if (radiusBias > 0.0f) radius += radiusBias;

        float slice = 360.0f / (float)std::max(1, total);
        float angle = (slice * (float)index + (float)SafeRandomFloatRuntime(-18.0f, 18.0f, 0.0f, "world_director")) * 0.0174532924f;
        Vector3 pos{};
        pos.x = base.x + cosf(angle) * radius;
        pos.y = base.y + sinf(angle) * radius;
        pos.z = base.z + 3.0f;

        if (preferRoad)
        {
            Vector3 road{};
            if (TryGetClosestVehicleNodeForWorldDirector(pos, road))
            {
                pos.x = road.x;
                pos.y = road.y;
                pos.z = road.z + 0.45f;
            }
        }

        pos.z = ResolveGroundZ(pos.x, pos.y, pos.z) + 0.35f;
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f)) return InvalidWorldVector();
        return ApplySpawnSafety(pos, preferRoad);
    }

    static Vehicle SpawnWorldDirectorVehicle(const std::string& modelName, Vector3 pos, float heading, bool damaged = false)
    {
        Vehicle veh = SpawnVehicleByModelAt(modelName, pos, heading, false, false, false, false);
        if (!IsUsableVehicleHandle(veh, true)) return 0;
        core::safe_native::SetMissionEntity((Entity)(veh), true, true, &g_coreErrors, "full_audit");
        SafeSetVehicleOnGround(veh, "full_audit");
        SafeSetVehicleEngineOn(veh, true, "full_audit");
        if (damaged)
        {
            SafeSetVehicleEngineHealth(veh, SafeRandomFloatRuntime(250.0f, 650.0f, 450.0f, "world_director"), "world_director");
            SafeSetVehicleDamage(veh, 0.0f, 1.2f, 0.4f, 160.0f, 80.0f, true, "world_director");
            if (cfg.worldDirectorChaosLevel >= 3) SafeVehicleRuntimeNative(veh, "world_director", "smash vehicle window", [&](){ VEHICLE::SMASH_VEHICLE_WINDOW(veh, ClampIntValue(SafeRandomIntRuntime(0, 4, 0, "entity_damage"), 0, 7)); });
        }
        if (!TrackWorldDirectorEntity((Entity)veh))
        {
            DeleteRejectedSpawnOrKeepTracked((Entity)veh, true);
            return 0;
        }
        PushEntityUndo("World Director Vehicle: " + modelName, (Entity)veh);
        return veh;
    }

    static Ped SpawnWorldDirectorPed(const std::string& modelName, Relation relation, Vector3 pos, float heading, const std::string& weapon = "None", int health = 180)
    {
        Ped ped = SpawnPedAtModel(modelName, relation, health, weapon, cfg.npcAmmo, pos, NormalizeHeading(heading, 0.0f), false, false);
        if (!IsUsablePedHandle(ped, false, false, true)) return 0;
        if (!TrackWorldDirectorEntity((Entity)ped))
        {
            DeleteRejectedSpawnOrKeepTracked((Entity)ped, true);
            return 0;
        }
        PushEntityUndo("World Director Ped: " + modelName, (Entity)ped);
        return ped;
    }

    static Object SpawnWorldDirectorObject(const std::string& modelName, Vector3 pos, float heading)
    {
        Object obj = SpawnObjectByModelAt(modelName, pos, NormalizeHeading(heading, 0.0f), false, false);
        if (!obj || !core::Exists((Entity)(obj)) || !core::IsObject((Entity)obj)) return 0;
        if (!TrackWorldDirectorEntity((Entity)obj))
        {
            DeleteRejectedSpawnOrKeepTracked((Entity)obj, true);
            return 0;
        }
        PushEntityUndo("World Director Object: " + modelName, (Entity)obj);
        return obj;
    }

    static Ped SpawnWorldDirectorDriver(Vehicle vehicle, const std::string& modelName, int seat, Relation relation = Relation::Neutral)
    {
        if (!IsUsableVehicleHandle(vehicle, true)) return 0;
        if (seat < -1) seat = -1;
        if (seat > 15) seat = 15;
        if (!core::IsVehicleSeatFree((Vehicle)(vehicle), seat)) return 0;

        Vector3 pos{};
        if (!TryGetUsableEntityPosition((Entity)vehicle, pos)) return 0;

        const UndoRedoRollbackPoint undoPoint = CaptureUndoRedoRollbackPoint();
        Ped ped = SpawnWorldDirectorPed(modelName, relation, pos, NormalizeHeading((float)core::SafeGetEntityHeading((Entity)(vehicle), 0.0f), 0.0f), "None", 180);
        if (!IsUsablePedHandle(ped, false, false, true)) return 0;
        core::SetPedIntoVehicleSafe((Ped)(ped), (Vehicle)(vehicle), seat);
        if (!core::IsPedInVehicle((Ped)(ped), (Vehicle)(vehicle), false))
        {
            if (DeletePedSafely(ped)) RemoveTrackedEntity((Entity)ped);
            RollbackUndoRedoStacksTo(undoPoint);
            return 0;
        }
        return ped;
    }

    static void ClearWorldDirector(bool notify)
    {
        std::vector<Entity> entities = st.worldDirectorEntities;
        std::vector<Entity> kept;
        for (Entity ent : entities)
        {
            if (!ent || !core::Exists((Entity)(ent))) continue;
            ClearCinematicNpcRuntimeReferencesToEntity(ent);
            if (core::IsVehicle((Entity)(ent)) && PreserveProtectedVehicleForPlayer((Vehicle)ent))
            {
                // PreserveProtectedVehicleForPlayer() re-registers protected vehicles in
                // spawnedVehicles. Do not call the global removal helper here: it clears
                // tracking and protected runtime references. This cleanup
                // should only detach the vehicle from the subsystem list.
                continue;
            }
            if (!DeleteMixedTrackedEntity(ent, true) && core::Exists((Entity)(ent)))
                kept.push_back(ent);
        }
        st.worldDirectorEntities.swap(kept);
        st.worldDirectorActive = !st.worldDirectorEntities.empty();
        st.lastWorldDirectorTick = GetTickCount();
        st.lastWorldDirectorEvent = st.worldDirectorActive ? "Delete retry pending" : "None";
        if (notify) Notify(st.worldDirectorActive ? "World Director clear partially blocked." : "World Director entities cleared.");
    }

    static void WorldDirectorCleanupFarEntities()
    {
        if (!cfg.worldDirectorAutoCleanup) return;
        DWORD now = GetTickCount();
        if (!core::TickElapsed(now, st.lastWorldDirectorCleanupTick, 3000u)) return;
        st.lastWorldDirectorCleanupTick = now;

        Vector3 playerPos{};
        if (!TryGetPlayerPosition(playerPos)) return;
        float limit = (float)std::max(80, cfg.worldDirectorCleanupRadius);
        float limitSq = limit * limit;

        std::vector<Entity> snapshot = st.worldDirectorEntities;
        std::vector<Entity> keep;
        for (Entity ent : snapshot)
        {
            if (!ent || !core::Exists((Entity)(ent))) continue;
            Vector3 pos{};
            const bool badPosition = !TryGetStrictTrackedEntityPosition((Entity)ent, pos);
            const bool broken = IsBrokenWorldDirectorEntity(ent);
            const bool farAway = badPosition || DistanceSq(playerPos, pos) > limitSq;
            if (broken || farAway)
            {
                if (core::IsVehicle((Entity)(ent)) && PreserveProtectedVehicleForPlayer((Vehicle)ent))
                {
                    // Detach from this subsystem only; PreserveProtectedVehicleForPlayer()
                    // keeps the vehicle alive and globally tracked.
                    continue;
                }
                if (!DeleteMixedTrackedEntity(ent, true) && core::Exists((Entity)(ent)) && std::find(keep.begin(), keep.end(), ent) == keep.end())
                    keep.push_back(ent);
            }
            else if (std::find(keep.begin(), keep.end(), ent) == keep.end()) keep.push_back(ent);
        }
        st.worldDirectorEntities.swap(keep);
    }

    static void CycleWorldDirectorEvent()
    {
        int idx = (int)st.selectedWorldDirectorEvent;
        for (int tries = 0; tries < WorldDirectorEventCount(); ++tries)
        {
            idx++;
            if (idx >= WorldDirectorEventCount()) idx = 0;
            WorldDirectorEvent candidate = (WorldDirectorEvent)idx;
            if (WorldDirectorEventAllowedBySettings(candidate))
            {
                st.selectedWorldDirectorEvent = candidate;
                Notify("World Director event: " + WorldDirectorEventName(st.selectedWorldDirectorEvent));
                return;
            }
        }
        st.selectedWorldDirectorEvent = WorldDirectorEvent::TrafficAccident;
        Notify("World Director event: " + WorldDirectorEventName(st.selectedWorldDirectorEvent));
    }

    static int WorldDirectorEventEntityReserve(WorldDirectorEvent event)
    {
        switch (event)
        {
            case WorldDirectorEvent::TrafficAccident: return 4;
            case WorldDirectorEvent::PolicePursuit: return 4;
            case WorldDirectorEvent::StreetFight: return 2;
            case WorldDirectorEvent::StoreRobbery: return cfg.worldDirectorChaosLevel >= 3 ? 3 : 2;
            case WorldDirectorEvent::FireEmergency: return 3;
            case WorldDirectorEvent::GangAmbush: return cfg.worldDirectorChaosLevel >= 4 ? 5 : 3;
            case WorldDirectorEvent::VipConvoy: return 6;
            case WorldDirectorEvent::DrunkDriver: return 2;
            case WorldDirectorEvent::PoliceRoadblock: return 6;
            case WorldDirectorEvent::GangVsPolice: return cfg.worldDirectorChaosLevel >= 4 ? 8 : 6;
            case WorldDirectorEvent::EmergencyResponse: return cfg.worldDirectorChaosLevel >= 3 ? 5 : 3;
            default: return cfg.worldDirectorChaosLevel >= 4 ? 8 : 5;
        }
    }

    static int WorldDirectorEventMinEntities(WorldDirectorEvent event)
    {
        switch (event)
        {
            case WorldDirectorEvent::TrafficAccident: return 2;
            case WorldDirectorEvent::PolicePursuit: return 4;
            case WorldDirectorEvent::StreetFight: return 2;
            case WorldDirectorEvent::StoreRobbery: return 2;
            case WorldDirectorEvent::FireEmergency: return 2;
            case WorldDirectorEvent::GangAmbush: return 2;
            case WorldDirectorEvent::VipConvoy: return 4;
            case WorldDirectorEvent::DrunkDriver: return 2;
            case WorldDirectorEvent::PoliceRoadblock: return 4;
            case WorldDirectorEvent::GangVsPolice: return 4;
            case WorldDirectorEvent::EmergencyResponse: return cfg.worldDirectorChaosLevel >= 3 ? 4 : 3;
            default: return 1;
        }
    }

    static void RollbackWorldDirectorEntitiesFrom(size_t startIndex)
    {
        if (startIndex >= st.worldDirectorEntities.size()) return;
        std::vector<Entity> kept(st.worldDirectorEntities.begin(), st.worldDirectorEntities.begin() + startIndex);
        std::vector<Entity> spawned(st.worldDirectorEntities.begin() + startIndex, st.worldDirectorEntities.end());
        for (Entity ent : spawned)
        {
            if (!ent || !core::Exists((Entity)(ent))) continue;
            if (!DeleteSubsystemEntityForRollback(ent, true) && core::Exists((Entity)(ent)) &&
                std::find(kept.begin(), kept.end(), ent) == kept.end())
                kept.push_back(ent);
        }
        st.worldDirectorEntities.swap(kept);
        CompactWorldDirectorEntities();
    }

