    static void WorldDirectorGangVsPolice()
    {
        Vector3 base = WorldDirectorSpawnPos(0, 6, 0.0f, true);
        Vector3 policePos = base; policePos.x += 8.0f;
        Vector3 gangPos = base; gangPos.x -= 8.0f;
        Vehicle policeCar = SpawnWorldDirectorVehicle("police3", policePos, 0.0f, false);
        if (policeCar) SafeSetVehicleSiren(policeCar, true, "full_audit");
        Ped copA = policeCar ? SpawnWorldDirectorDriver(policeCar, "s_m_y_cop_01", -1, Relation::Friendly) : SpawnWorldDirectorPed("s_m_y_cop_01", Relation::Friendly, policePos, 0.0f, "WEAPON_PISTOL", 220);
        Ped copB = SpawnWorldDirectorPed("s_m_y_cop_01", Relation::Friendly, policePos, 0.0f, "WEAPON_PISTOL", 220);
        int gangCount = cfg.worldDirectorChaosLevel >= 4 ? 5 : 3;
        Ped firstGang = 0;
        for (int i = 0; i < gangCount; ++i)
        {
            Vector3 pos = gangPos; pos.y += (float)(i - gangCount / 2) * 2.3f; pos.z = ResolveGroundZ(pos.x, pos.y, pos.z) + 0.15f;
            Ped gang = SpawnWorldDirectorPed(i % 2 == 0 ? "g_m_y_ballaeast_01" : "g_m_y_lost_01", Relation::Enemy, pos, 180.0f, cfg.worldDirectorChaosLevel >= 3 ? "WEAPON_SMG" : "WEAPON_PISTOL", 230);
            if (!firstGang && gang) firstGang = gang;
            if (gang && copA) SafeTaskCombatPed(gang, copA, "full_audit");
        }
        if (copA && firstGang) SafeTaskCombatPed(copA, firstGang, "full_audit");
        if (copB && firstGang) SafeTaskCombatPed(copB, firstGang, "full_audit");
    }

