    static void RunUrbanLifeEvent(UrbanLifeEvent event, bool manual)
    {
        if (!cfg.urbanLifeEnabled)
        {
            if (manual) Notify("Urban Life is disabled.");
            ThrottleUrbanLifeAutoAttempt(manual);
            return;
        }

        Vector3 urbanLifePlayerBase{};
        if (!TryGetPlayerPosition(urbanLifePlayerBase))
        {
            if (manual) Notify("Urban Life: invalid player position.");
            ThrottleUrbanLifeAutoAttempt(manual);
            return;
        }

        CompactUrbanLifeEntities();
        const size_t rollbackStart = st.urbanLifeEntities.size();
        const int before = (int)rollbackStart;
        const int reserve = UrbanLifeEventEntityReserve(event);
        if ((int)st.urbanLifeEntities.size() + reserve > cfg.urbanLifeMaxTrackedEntities)
        {
            if (cfg.urbanLifeAutoCleanup) UrbanLifeCleanupFarEntities();
            CompactUrbanLifeEntities();
            if ((int)st.urbanLifeEntities.size() + reserve > cfg.urbanLifeMaxTrackedEntities)
            {
                if (manual) Notify("Urban Life entity limit reached. Clear entities first.");
                ThrottleUrbanLifeAutoAttempt(manual);
                return;
            }
        }

        const UndoRedoRollbackPoint undoPoint = CaptureUndoRedoRollbackPoint();
        PushWorldUndo("Urban Life: " + UrbanLifeEventName(event));
        switch (event)
        {
            case UrbanLifeEvent::CivilianArgument: UrbanLifeCivilianArgument(); break;
            case UrbanLifeEvent::VehicleBreakdown: UrbanLifeVehicleBreakdown(); break;
            case UrbanLifeEvent::MedicalCall: UrbanLifeMedicalCall(); break;
            case UrbanLifeEvent::RoadRage: UrbanLifeRoadRage(); break;
            case UrbanLifeEvent::WitnessFilming: UrbanLifeWitnessFilming(); break;
            case UrbanLifeEvent::TaxiPickup: UrbanLifeTaxiPickup(); break;
            default: break;
        }

        CompactUrbanLifeEntities();
        const int spawnedCount = (int)st.urbanLifeEntities.size() - before;
        if (spawnedCount < UrbanLifeEventMinEntities(event))
        {
            RollbackUrbanLifeEntitiesFrom(rollbackStart);
            RollbackUndoRedoStacksTo(undoPoint);
            if (manual) Notify(spawnedCount <= 0 ? "Urban Life: no valid entities spawned." : "Urban Life: partial spawn rolled back.");
            ThrottleUrbanLifeAutoAttempt(manual);
            return;
        }

        st.urbanLifeActive = true;
        st.urbanLifeManualPaused = false;
        st.lastUrbanLifeTick = GetTickCount();
        ++st.urbanLifeEventCount;
        UrbanLifeNotify("Urban Life: " + UrbanLifeEventName(event));
    }

    static void TriggerSelectedUrbanLifeEvent()
    {
        RunUrbanLifeEvent(st.selectedUrbanLifeEvent, true);
    }

    static void TriggerRandomUrbanLifeEvent(bool manual)
    {
        RunUrbanLifeEvent(PickRandomUrbanLifeEvent(), manual);
    }

    static void ToggleUrbanLifeAutoEvents()
    {
        cfg.urbanLifeAutoEvents = !cfg.urbanLifeAutoEvents;
        if (cfg.urbanLifeAutoEvents)
        {
            cfg.urbanLifeEnabled = true;
            st.urbanLifeActive = true;
            st.urbanLifeManualPaused = false;
            st.lastUrbanLifeTick = GetTickCount();
            Notify("Urban Life auto events ON.");
        }
        else
        {
            st.urbanLifeActive = false;
            st.urbanLifeManualPaused = false;
            st.lastUrbanLifeTick = GetTickCount();
            Notify("Urban Life auto events OFF.");
        }
    }

    static void ToggleUrbanLifeActive()
    {
        if (!cfg.urbanLifeEnabled)
        {
            st.urbanLifeActive = false;
            st.urbanLifeManualPaused = false;
            Notify("Urban Life is disabled.");
            return;
        }

        const bool activating = !st.urbanLifeActive;
        st.urbanLifeActive = activating;
        st.urbanLifeManualPaused = !activating;
        if (activating)
        {
            cfg.urbanLifeAutoEvents = true;
            st.lastUrbanLifeTick = GetTickCount();
        }
        Notify(st.urbanLifeActive ? "Urban Life active." : "Urban Life paused.");
    }

    static void TickUrbanLife()
    {
        if (!cfg.urbanLifeEnabled)
        {
            st.urbanLifeActive = false;
            st.urbanLifeManualPaused = false;
            return;
        }

        CompactUrbanLifeEntities();
        UrbanLifeCleanupFarEntities();

        DWORD now = GetTickCount();
        if (cfg.urbanLifeAutoEvents && !st.urbanLifeActive && !st.urbanLifeManualPaused)
        {
            st.urbanLifeActive = true;
            st.lastUrbanLifeTick = now;
        }

        if (!st.urbanLifeActive || !cfg.urbanLifeAutoEvents) return;
        if (!core::TickElapsed(now, st.lastUrbanLifeTick, SafeIntervalFromIntMs(cfg.urbanLifeIntervalMs, 60000, 10000, 300000, "urban_life", "interval"))) return;
        TriggerRandomUrbanLifeEvent(false);
    }

