    static void ClearVehicleAI(bool notify)
    {
        std::vector<Entity> entities = st.vehicleAIEntities;
        std::vector<Entity> kept;
        for (Entity ent : entities)
        {
            if (!ent || !core::Exists((Entity)(ent))) continue;
            ClearCinematicNpcRuntimeReferencesToEntity(ent);
            if (core::IsVehicle((Entity)(ent)) && PreserveProtectedVehicleForPlayer((Vehicle)ent))
            {
                // PreserveProtectedVehicleForPlayer() re-registers protected vehicles in
                // spawnedVehicles. Do not call the global removal helper here: it clears
                // tracking and protected runtime references. This cleanup
                // should only detach the vehicle from the subsystem list.
                continue;
            }
            if (!DeleteMixedTrackedEntity(ent, true) && core::Exists((Entity)(ent)))
                kept.push_back(ent);
        }
        st.vehicleAIEntities.swap(kept);
        st.vehicleAIActive = !st.vehicleAIEntities.empty();
        st.lastVehicleAITick = GetTickCount();
        st.lastVehicleAIEvent = st.vehicleAIActive ? "Delete retry pending" : "None";
        if (notify) Notify(st.vehicleAIActive ? "Vehicle AI clear partially blocked." : "Vehicle AI entities cleared.");
    }

    static void VehicleAICleanupFarEntities()
    {
        if (!cfg.vehicleAIAutoCleanup) return;
        DWORD now = GetTickCount();
        if (!core::TickElapsed(now, st.lastVehicleAICleanupTick, 3000u)) return;
        st.lastVehicleAICleanupTick = now;

        Vector3 playerPos{};
        if (!TryGetPlayerPosition(playerPos)) return;
        float limit = (float)std::max(80, cfg.vehicleAICleanupRadius);
        float limitSq = limit * limit;

        std::vector<Entity> snapshot = st.vehicleAIEntities;
        std::vector<Entity> keep;
        for (Entity ent : snapshot)
        {
            if (!ent || !core::Exists((Entity)(ent))) continue;
            Vector3 pos{};
            bool remove = !TryGetStrictTrackedEntityPosition((Entity)ent, pos) || DistanceSq(playerPos, pos) > limitSq;
            if (core::IsPed((Entity)(ent)) && core::IsPedDeadOrDying((Ped)ent, true, true)) remove = true;
            if (core::IsVehicle((Entity)(ent)) && (int)core::SafeGetEntityHealth((Entity)(ent), 0) <= 0) remove = true;
            if (remove)
            {
                ClearCinematicNpcRuntimeReferencesToEntity(ent);
                if (core::IsVehicle((Entity)(ent)) && PreserveProtectedVehicleForPlayer((Vehicle)ent))
                {
                    // Detach from this subsystem only; PreserveProtectedVehicleForPlayer()
                    // keeps the vehicle alive and globally tracked.
                    continue;
                }
                if (!DeleteMixedTrackedEntity(ent, true) && core::Exists((Entity)(ent)) && std::find(keep.begin(), keep.end(), ent) == keep.end())
                    keep.push_back(ent);
            }
            else if (std::find(keep.begin(), keep.end(), ent) == keep.end()) keep.push_back(ent);
        }
        st.vehicleAIEntities.swap(keep);
    }

    static void RunVehicleAIEvent(VehicleAIEvent event, bool manual)
    {
        if (!cfg.vehicleAIEnabled)
        {
            if (manual) Notify("Vehicle AI is disabled.");
            st.lastVehicleAITick = GetTickCount();
            return;
        }
        if (!VehicleAIEventAllowedBySettings(event))
        {
            if (manual) Notify("Vehicle AI event blocked by Safe Mode.");
            st.lastVehicleAITick = GetTickCount();
            return;
        }

        CompactVehicleAIEntities();
        const size_t rollbackStart = st.vehicleAIEntities.size();
        const int before = (int)rollbackStart;
        int reserve = VehicleAIEventEntityReserve(event);
        if ((int)st.vehicleAIEntities.size() + reserve > cfg.vehicleAIMaxTrackedEntities)
        {
            if (cfg.vehicleAIAutoCleanup) VehicleAICleanupFarEntities();
            CompactVehicleAIEntities();
            if ((int)st.vehicleAIEntities.size() + reserve > cfg.vehicleAIMaxTrackedEntities)
            {
                if (manual) Notify("Vehicle AI entity limit reached. Clear entities first.");
                st.lastVehicleAITick = GetTickCount();
                return;
            }
        }

        Vector3 vehicleAIPlayerBase{};
        if (!TryGetPlayerPosition(vehicleAIPlayerBase))
        {
            if (manual) Notify("Vehicle AI: invalid player position.");
            st.lastVehicleAITick = GetTickCount();
            return;
        }

        const UndoRedoRollbackPoint undoPoint = CaptureUndoRedoRollbackPoint();
        PushWorldUndo("Vehicle AI: " + VehicleAIEventName(event));
        switch (event)
        {
            case VehicleAIEvent::TrafficPatrol: VehicleAITrafficPatrol(); break;
            case VehicleAIEvent::RoadViolation: VehicleAIRoadViolation(); break;
            case VehicleAIEvent::DrunkDriver: VehicleAIDrunkDriver(); break;
            case VehicleAIEvent::StreetRacers: VehicleAIStreetRacers(); break;
            case VehicleAIEvent::PolicePursuit: VehicleAIPolicePursuit(); break;
            case VehicleAIEvent::EmergencyRun: VehicleAIEmergencyRun(); break;
            case VehicleAIEvent::VipMotorcade: VehicleAIVipMotorcade(); break;
            case VehicleAIEvent::RoadRagePair: VehicleAIRoadRagePair(); break;
            default: break;
        }

        CompactVehicleAIEntities();
        const int spawnedCount = (int)st.vehicleAIEntities.size() - before;
        if (spawnedCount < VehicleAIEventMinEntities(event))
        {
            RollbackVehicleAIEntitiesFrom(rollbackStart);
            RollbackUndoRedoStacksTo(undoPoint);
            if (manual) Notify(spawnedCount <= 0 ? "Vehicle AI: no valid entities spawned." : "Vehicle AI: partial spawn rolled back.");
            st.lastVehicleAITick = GetTickCount();
            return;
        }

        st.vehicleAIActive = true;
        st.vehicleAIManualPaused = false;
        st.lastVehicleAITick = GetTickCount();
        ++st.vehicleAIEventCount;
        VehicleAINotify("Vehicle AI: " + VehicleAIEventName(event));
    }

    static void CycleVehicleAIProfile()
    {
        cfg.vehicleAIProfile = (cfg.vehicleAIProfile + 1) % 6;
        Notify("Vehicle AI profile: " + VehicleAIProfileName(CurrentVehicleAIProfile()));
    }

    static void CycleVehicleAIEvent()
    {
        int idx = (int)st.selectedVehicleAIEvent;
        for (int tries = 0; tries < VehicleAIEventCount(); ++tries)
        {
            idx = (idx + 1) % std::max(1, VehicleAIEventCount());
            VehicleAIEvent event = (VehicleAIEvent)idx;
            if (VehicleAIEventAllowedBySettings(event))
            {
                st.selectedVehicleAIEvent = event;
                Notify("Vehicle AI event: " + VehicleAIEventName(event));
                return;
            }
        }
        st.selectedVehicleAIEvent = VehicleAIEvent::TrafficPatrol;
    }

    static void TriggerSelectedVehicleAIEvent()
    {
        RunVehicleAIEvent(st.selectedVehicleAIEvent, true);
    }

    static void TriggerRandomVehicleAIEvent(bool manual = true)
    {
        RunVehicleAIEvent(PickRandomVehicleAIEvent(), manual);
    }

    static void ToggleVehicleAIEnabled()
    {
        cfg.vehicleAIEnabled = !cfg.vehicleAIEnabled;
        if (!cfg.vehicleAIEnabled)
        {
            st.vehicleAIActive = false;
            st.vehicleAIManualPaused = true;
            st.lastVehicleAIEvent = "Vehicle AI disabled";
        }
        else
        {
            st.vehicleAIManualPaused = false;
            st.lastVehicleAITick = GetTickCount();
            st.lastVehicleAIEvent = "Vehicle AI enabled";
        }
        Notify(std::string("Vehicle AI ") + (cfg.vehicleAIEnabled ? "enabled" : "disabled"));
    }

    static void ToggleVehicleAIAutoEvents()
    {
        cfg.vehicleAIAutoEvents = !cfg.vehicleAIAutoEvents;
        if (cfg.vehicleAIAutoEvents)
        {
            cfg.vehicleAIEnabled = true;
            st.vehicleAIActive = true;
            st.vehicleAIManualPaused = false;
            st.lastVehicleAITick = GetTickCount();
            Notify("Vehicle AI auto events ON.");
        }
        else
        {
            st.vehicleAIActive = false;
            st.vehicleAIManualPaused = false;
            st.lastVehicleAITick = GetTickCount();
            Notify("Vehicle AI auto events OFF.");
        }
    }

    static void ToggleVehicleAIActive()
    {
        if (!cfg.vehicleAIEnabled)
        {
            st.vehicleAIActive = false;
            st.vehicleAIManualPaused = false;
            Notify("Vehicle AI is disabled.");
            return;
        }
        const bool activating = !st.vehicleAIActive;
        st.vehicleAIActive = activating;
        st.vehicleAIManualPaused = !activating;
        if (activating)
        {
            cfg.vehicleAIAutoEvents = true;
            st.lastVehicleAITick = GetTickCount();
        }
        Notify(st.vehicleAIActive ? "Vehicle AI active." : "Vehicle AI paused.");
    }

    static void ToggleVehicleAISafeMode()
    {
        cfg.vehicleAISafeMode = !cfg.vehicleAISafeMode;
        NormalizeSelectedVehicleAIEvent();
        Notify(std::string("Vehicle AI Safe Mode: ") + OnOff(cfg.vehicleAISafeMode));
    }

    static void TickVehicleAI()
    {
        if (!cfg.vehicleAIEnabled)
        {
            st.vehicleAIActive = false;
            st.vehicleAIManualPaused = false;
            return;
        }
        NormalizeSelectedVehicleAIEvent();
        if (cfg.vehicleAIAffectAmbientDensity && !st.noTraffic)
        {
            float density = 0.75f + 0.25f * (float)ClampIntValue(cfg.vehicleAIIntensity, 1, 5);
            SafeSetVehicleDensityFrameRuntime(density, false, "vehicle_ai");
        }

        CompactVehicleAIEntities();
        VehicleAICleanupFarEntities();

        DWORD now = GetTickCount();
        if (cfg.vehicleAIAutoEvents && !st.vehicleAIActive && !st.vehicleAIManualPaused)
        {
            st.vehicleAIActive = true;
            st.lastVehicleAITick = now;
        }

        if (!st.vehicleAIActive || !cfg.vehicleAIAutoEvents) return;
        if (!core::TickElapsed(now, st.lastVehicleAITick, SafeIntervalFromIntMs(cfg.vehicleAIIntervalMs, 50000, 10000, 300000, "vehicle_ai", "interval"))) return;
        TriggerRandomVehicleAIEvent(false);
    }

    static std::string ControlCenterSystemSummary()
    {
        DWORD now = GetTickCount();
        if (core::TickElapsed(now, st.lastControlCenterRefreshTick, SafeIntervalAddOneMs(cfg.controlCenterRefreshMs, 1000, 250, 10000, "control_center", "refresh")))
        {
            st.lastControlCenterRefreshTick = now;
            st.controlCenterEntityTotal = CountUniqueExistingRuntimeEntities();
            st.controlCenterStatus = "Ent " + std::to_string(st.controlCenterEntityTotal) +
                " | WD " + OnOff(st.worldDirectorActive) +
                " | UL " + OnOff(st.urbanLifeActive) +
                " | VAI " + OnOff(st.vehicleAIActive);
        }
        return st.controlCenterStatus;
    }

