    static std::string SmartPreset2Name(int kind)
    {
        switch ((SmartPreset2Kind)ClampIntValue(kind, 0, kSmartPreset2Count - 1))
        {
            case SmartPreset2Kind::PeacefulRoleplay: return "Peaceful Roleplay";
            case SmartPreset2Kind::ZombieNight: return "Zombie Night";
            case SmartPreset2Kind::GangWarDowntown: return "Gang War Downtown";
            case SmartPreset2Kind::VipConvoy: return "VIP Convoy";
            case SmartPreset2Kind::PoliceLockdown: return "Police Lockdown";
            case SmartPreset2Kind::MovieChase: return "Movie Chase";
            case SmartPreset2Kind::MilitaryCity: return "Military City";
            case SmartPreset2Kind::ChaosMode: return "Chaos Mode";
            case SmartPreset2Kind::SafeTesting: return "Safe Testing";
            default: return "Peaceful Roleplay";
        }
    }

    static void CycleSmartPreset2()
    {
        st.selectedSmartPreset2++;
        if (st.selectedSmartPreset2 >= kSmartPreset2Count) st.selectedSmartPreset2 = 0;
    }

    static void ApplySmartPreset2CoreDefaults()
    {
        st.noTraffic = false;
        st.noPeds = false;
        st.denseTraffic = false;
        st.densePeds = false;
        st.blackout = false;
        st.lowGravity = false;
        cfg.randomMission3Enabled = true;
        cfg.randomMission4Enabled = true;
        cfg.randomMissionPreviewEnabled = true;
        ClearRandomMissionPreviewState();
        if (cfg.smartPresetApplyCleanup)
        {
            ClearWorldDirector(false);
            ClearUrbanLife(false);
            ClearVehicleAI(false);
            if (cfg.smartCleanupCompactInvalid) CompactInvalidTrackedEntities();
        }
    }

    static void ApplySmartPreset2ByIndex(int kind)
    {
        if (!cfg.smartPresets2Enabled)
        {
            Notify("Smart Presets 2.0 disabled in config.");
            return;
        }

        struct SmartPresetWorldSnapshot
        {
            bool noTraffic, noPeds, denseTraffic, densePeds, blackout, lowGravity;
            bool worldDirectorEnabled, worldDirectorAutoEvents, worldDirectorDangerousEvents, worldDirectorActive, worldDirectorManualPaused;
            int worldDirectorChaosLevel;
            DWORD lastWorldDirectorTick;
            bool urbanLifeEnabled, urbanLifeAutoEvents, urbanLifeSafeMode, urbanLifeActive, urbanLifeManualPaused;
            int urbanLifeIntensity;
            DWORD lastUrbanLifeTick;
            ScenarioMode scenarioMode;
            bool scenarioActive;
            MovieSceneKind selectedMovieScene;
            bool movieSceneCinematicCameraEnabled;
            MovieSceneCameraMode movieSceneCameraMode;
        };
        struct SmartPresetSafetySnapshot
        {
            bool noWanted, policeIgnore, everyoneIgnore, policeIgnoreManual, everyoneIgnoreManual;
        };
        struct SmartPresetMissionSnapshot
        {
            bool randomMissionGeneratorEnabled, randomMissionExtraTypes, randomMission2Enabled, randomMission3Enabled, randomMission4Enabled;
            bool randomMissionPreviewEnabled, randomMissionLargeScaleEnabled, randomMissionUseCategoryFilter;
            bool randomMissionAllowFriendlyMissions, randomMissionSetWantedForEscape;
            bool randomMissionBonusObjectives, randomMissionAdaptiveDifficulty, randomMissionPreferRoadTargets;
            int randomMissionLargeScaleChance, randomMissionEnemyCount, randomMissionTwistChance, randomMissionEscalationChance;
            int randomMissionBonusChance, randomMissionTimePressureChance;
            int gameModeDefaultDifficulty, gameModeDefaultDurationSec;
            float randomMissionRewardMultiplier;
            int randomMissionPreferredCategory, randomMissionSelectedKindIndex;
            bool randomMissionForceSelectedKind, randomMissionPreviewReady;
            RandomMissionKind randomMissionPreviewKind;
            std::string randomMissionPreviewLocation, randomMissionPreviewConstraint, randomMissionPreviewComplication;
        };

        const SmartPresetWorldSnapshot worldBefore{
            st.noTraffic, st.noPeds, st.denseTraffic, st.densePeds, st.blackout, st.lowGravity,
            cfg.worldDirectorEnabled, cfg.worldDirectorAutoEvents, cfg.worldDirectorDangerousEvents, st.worldDirectorActive, st.worldDirectorManualPaused,
            cfg.worldDirectorChaosLevel, st.lastWorldDirectorTick,
            cfg.urbanLifeEnabled, cfg.urbanLifeAutoEvents, cfg.urbanLifeSafeMode, st.urbanLifeActive, st.urbanLifeManualPaused,
            cfg.urbanLifeIntensity, st.lastUrbanLifeTick,
            st.scenarioMode, st.scenarioActive, st.selectedMovieScene, cfg.movieSceneCinematicCameraEnabled, cfg.movieSceneCameraMode
        };
        const SmartPresetSafetySnapshot safetyBefore{ st.noWanted, st.policeIgnore, st.everyoneIgnore, st.policeIgnoreManual, st.everyoneIgnoreManual };
        const SmartPresetMissionSnapshot missionBefore{
            cfg.randomMissionGeneratorEnabled, cfg.randomMissionExtraTypes, cfg.randomMission2Enabled, cfg.randomMission3Enabled, cfg.randomMission4Enabled,
            cfg.randomMissionPreviewEnabled, cfg.randomMissionLargeScaleEnabled, cfg.randomMissionUseCategoryFilter,
            cfg.randomMissionAllowFriendlyMissions, cfg.randomMissionSetWantedForEscape,
            cfg.randomMissionBonusObjectives, cfg.randomMissionAdaptiveDifficulty, cfg.randomMissionPreferRoadTargets,
            cfg.randomMissionLargeScaleChance, cfg.randomMissionEnemyCount, cfg.randomMissionTwistChance, cfg.randomMissionEscalationChance,
            cfg.randomMissionBonusChance, cfg.randomMissionTimePressureChance,
            cfg.gameModeDefaultDifficulty, cfg.gameModeDefaultDurationSec,
            cfg.randomMissionRewardMultiplier,
            st.randomMissionPreferredCategory, st.randomMissionSelectedKindIndex,
            st.randomMissionForceSelectedKind, st.randomMissionPreviewReady, st.randomMissionPreviewKind,
            st.randomMissionPreviewLocation, st.randomMissionPreviewConstraint, st.randomMissionPreviewComplication
        };

        kind = ClampIntValue(kind, 0, kSmartPreset2Count - 1);
        st.selectedSmartPreset2 = kind;
        ApplySmartPreset2CoreDefaults();

        if (cfg.smartPresetApplyWorld)
        {
            cfg.worldDirectorEnabled = true;
            cfg.urbanLifeEnabled = true;
        }

        if (cfg.smartPresetApplyMissionGenerator)
        {
            cfg.randomMissionGeneratorEnabled = true;
            cfg.randomMissionExtraTypes = true;
            cfg.randomMission2Enabled = true;
            cfg.randomMission4Enabled = true;
            cfg.randomMissionBonusObjectives = true;
            cfg.randomMissionAdaptiveDifficulty = true;
            cfg.randomMissionPreferRoadTargets = true;
            cfg.randomMissionLargeScaleEnabled = true;
            cfg.randomMissionUseCategoryFilter = true;
            cfg.randomMissionRewardMultiplier = 1.0f;
            cfg.randomMissionTwistChance = 55;
            cfg.randomMissionEscalationChance = 35;
            st.randomMissionForceSelectedKind = false;
        }

        switch ((SmartPreset2Kind)kind)
        {
            case SmartPreset2Kind::PeacefulRoleplay:
                if (cfg.smartPresetApplyPlayerSafety) { st.noWanted = true; st.policeIgnore = true; st.everyoneIgnore = false; }
                cfg.worldDirectorAutoEvents = false;
                cfg.worldDirectorDangerousEvents = false;
                st.worldDirectorActive = false;
                cfg.urbanLifeAutoEvents = true;
                cfg.urbanLifeSafeMode = true;
                cfg.urbanLifeIntensity = 1;
                st.urbanLifeActive = true;
                st.randomMissionPreferredCategory = 2;
                cfg.gameModeDefaultDifficulty = 1;
                cfg.gameModeDefaultDurationSec = 600;
                cfg.randomMissionAllowFriendlyMissions = true;
                cfg.randomMissionLargeScaleChance = 5;
                cfg.randomMissionEnemyCount = 2;
                st.denseTraffic = true;
                st.densePeds = true;
                break;
            case SmartPreset2Kind::ZombieNight:
                if (cfg.smartPresetApplyPlayerSafety) { st.noWanted = true; st.policeIgnore = true; st.everyoneIgnore = false; }
                cfg.worldDirectorAutoEvents = true;
                cfg.worldDirectorDangerousEvents = true;
                cfg.worldDirectorChaosLevel = 4;
                st.worldDirectorActive = true;
                cfg.urbanLifeAutoEvents = false;
                st.urbanLifeActive = false;
                st.scenarioMode = ScenarioMode::ZombieMode;
                st.selectedMovieScene = MovieSceneKind::ZombieStreet;
                st.randomMissionPreferredCategory = 0;
                cfg.gameModeDefaultDifficulty = 3;
                cfg.randomMissionEnemyCount = 7;
                cfg.randomMissionLargeScaleChance = 45;
                cfg.randomMissionTwistChance = 75;
                st.blackout = true;
                break;
            case SmartPreset2Kind::GangWarDowntown:
                if (cfg.smartPresetApplyPlayerSafety) { st.noWanted = false; st.policeIgnore = false; st.everyoneIgnore = false; }
                cfg.worldDirectorAutoEvents = true;
                cfg.worldDirectorDangerousEvents = true;
                cfg.worldDirectorChaosLevel = 4;
                st.worldDirectorActive = true;
                cfg.urbanLifeAutoEvents = true;
                cfg.urbanLifeSafeMode = false;
                cfg.urbanLifeIntensity = 4;
                st.urbanLifeActive = true;
                st.scenarioMode = ScenarioMode::GangWar;
                st.selectedMovieScene = MovieSceneKind::GangShootout;
                st.randomMissionPreferredCategory = 1;
                cfg.gameModeDefaultDifficulty = 4;
                cfg.randomMissionEnemyCount = 8;
                cfg.randomMissionLargeScaleChance = 50;
                break;
            case SmartPreset2Kind::VipConvoy:
                if (cfg.smartPresetApplyPlayerSafety) { st.noWanted = false; st.policeIgnore = false; st.everyoneIgnore = false; }
                cfg.worldDirectorAutoEvents = true;
                cfg.worldDirectorDangerousEvents = false;
                cfg.worldDirectorChaosLevel = 2;
                st.worldDirectorActive = true;
                cfg.urbanLifeAutoEvents = true;
                cfg.urbanLifeSafeMode = true;
                cfg.urbanLifeIntensity = 2;
                st.urbanLifeActive = true;
                st.scenarioMode = ScenarioMode::VIPConvoy;
                st.selectedMovieScene = MovieSceneKind::VipArrival;
                st.randomMissionPreferredCategory = 2;
                st.randomMissionSelectedKindIndex = 5; // Escort VIP
                st.randomMissionForceSelectedKind = true;
                cfg.gameModeDefaultDifficulty = 2;
                cfg.randomMissionAllowFriendlyMissions = true;
                cfg.randomMissionLargeScaleChance = 20;
                break;
            case SmartPreset2Kind::PoliceLockdown:
                if (cfg.smartPresetApplyPlayerSafety) { st.noWanted = false; st.policeIgnore = false; st.everyoneIgnore = false; }
                cfg.worldDirectorAutoEvents = true;
                cfg.worldDirectorDangerousEvents = true;
                cfg.worldDirectorChaosLevel = 5;
                st.worldDirectorActive = true;
                cfg.urbanLifeAutoEvents = true;
                cfg.urbanLifeSafeMode = false;
                cfg.urbanLifeIntensity = 3;
                st.urbanLifeActive = true;
                st.scenarioMode = ScenarioMode::PoliceWar;
                st.selectedMovieScene = MovieSceneKind::PoliceAmbush;
                st.randomMissionPreferredCategory = 1;
                st.randomMissionSelectedKindIndex = 4; // Escape Wanted
                st.randomMissionForceSelectedKind = true;
                cfg.gameModeDefaultDifficulty = 4;
                cfg.randomMissionSetWantedForEscape = true;
                break;
            case SmartPreset2Kind::MovieChase:
                if (cfg.smartPresetApplyPlayerSafety) { st.noWanted = false; st.policeIgnore = false; st.everyoneIgnore = false; }
                cfg.worldDirectorAutoEvents = true;
                cfg.worldDirectorDangerousEvents = true;
                cfg.worldDirectorChaosLevel = 3;
                st.worldDirectorActive = true;
                cfg.urbanLifeAutoEvents = false;
                st.urbanLifeActive = false;
                st.scenarioMode = ScenarioMode::RoadRage;
                st.selectedMovieScene = MovieSceneKind::HighwayChase;
                cfg.movieSceneCinematicCameraEnabled = true;
                cfg.movieSceneCameraMode = MovieSceneCameraMode::ActionCut;
                st.randomMissionPreferredCategory = 1;
                cfg.gameModeDefaultDifficulty = 3;
                cfg.randomMissionLargeScaleChance = 35;
                break;
            case SmartPreset2Kind::MilitaryCity:
                if (cfg.smartPresetApplyPlayerSafety) { st.noWanted = false; st.policeIgnore = false; st.everyoneIgnore = false; }
                cfg.worldDirectorAutoEvents = true;
                cfg.worldDirectorDangerousEvents = true;
                cfg.worldDirectorChaosLevel = 5;
                st.worldDirectorActive = true;
                cfg.urbanLifeAutoEvents = false;
                st.urbanLifeActive = false;
                st.scenarioMode = ScenarioMode::MilitaryCheckpoint;
                st.selectedMovieScene = MovieSceneKind::MilitaryRaid;
                st.randomMissionPreferredCategory = 3;
                cfg.gameModeDefaultDifficulty = 5;
                cfg.randomMissionEnemyCount = 10;
                cfg.randomMissionLargeScaleChance = 80;
                cfg.randomMissionEscalationChance = 70;
                break;
            case SmartPreset2Kind::ChaosMode:
                if (cfg.smartPresetApplyPlayerSafety) { st.noWanted = false; st.policeIgnore = false; st.everyoneIgnore = false; }
                cfg.worldDirectorAutoEvents = true;
                cfg.worldDirectorDangerousEvents = true;
                cfg.worldDirectorChaosLevel = 5;
                st.worldDirectorActive = true;
                cfg.urbanLifeAutoEvents = true;
                cfg.urbanLifeSafeMode = false;
                cfg.urbanLifeIntensity = 5;
                st.urbanLifeActive = true;
                st.scenarioMode = ScenarioMode::WorldRiot;
                st.selectedMovieScene = MovieSceneKind::ChaosDowntown;
                st.randomMissionPreferredCategory = 0;
                cfg.randomMissionUseCategoryFilter = false;
                cfg.gameModeDefaultDifficulty = 5;
                cfg.randomMissionEnemyCount = 12;
                cfg.randomMissionLargeScaleChance = 65;
                cfg.randomMissionTwistChance = 90;
                cfg.randomMissionEscalationChance = 80;
                st.denseTraffic = true;
                st.densePeds = true;
                break;
            case SmartPreset2Kind::SafeTesting:
            default:
                if (cfg.smartPresetApplyPlayerSafety) { st.noWanted = true; st.policeIgnore = true; st.everyoneIgnore = true; }
                cfg.worldDirectorAutoEvents = false;
                cfg.worldDirectorDangerousEvents = false;
                st.worldDirectorActive = false;
                cfg.urbanLifeAutoEvents = false;
                cfg.urbanLifeSafeMode = true;
                st.urbanLifeActive = false;
                cfg.gameModeDefaultDifficulty = 1;
                cfg.randomMissionEnemyCount = 1;
                cfg.randomMissionLargeScaleChance = 0;
                cfg.randomMissionTwistChance = 0;
                cfg.randomMissionEscalationChance = 0;
                st.randomMissionPreferredCategory = 2;
                break;
        }

        if (cfg.smartPresetApplyPlayerSafety)
        {
            // Smart presets own these safety suppressors. They should not become
            // sticky manual Ignore toggles after a profile/preset apply.
            st.policeIgnoreManual = false;
            st.everyoneIgnoreManual = false;
        }

        if (cfg.smartPresetApplyWorld)
        {
            st.worldDirectorManualPaused = false;
            st.urbanLifeManualPaused = false;
            st.lastWorldDirectorTick = GetTickCount();
            st.lastUrbanLifeTick = GetTickCount();
        }

        if (!cfg.smartPresetApplyWorld)
        {
            st.noTraffic = worldBefore.noTraffic; st.noPeds = worldBefore.noPeds;
            st.denseTraffic = worldBefore.denseTraffic; st.densePeds = worldBefore.densePeds;
            st.blackout = worldBefore.blackout; st.lowGravity = worldBefore.lowGravity;
            cfg.worldDirectorEnabled = worldBefore.worldDirectorEnabled;
            cfg.worldDirectorAutoEvents = worldBefore.worldDirectorAutoEvents;
            cfg.worldDirectorDangerousEvents = worldBefore.worldDirectorDangerousEvents;
            cfg.worldDirectorChaosLevel = worldBefore.worldDirectorChaosLevel;
            st.worldDirectorActive = worldBefore.worldDirectorActive;
            st.worldDirectorManualPaused = worldBefore.worldDirectorManualPaused;
            st.lastWorldDirectorTick = worldBefore.lastWorldDirectorTick;
            cfg.urbanLifeEnabled = worldBefore.urbanLifeEnabled;
            cfg.urbanLifeAutoEvents = worldBefore.urbanLifeAutoEvents;
            cfg.urbanLifeSafeMode = worldBefore.urbanLifeSafeMode;
            cfg.urbanLifeIntensity = worldBefore.urbanLifeIntensity;
            st.urbanLifeActive = worldBefore.urbanLifeActive;
            st.urbanLifeManualPaused = worldBefore.urbanLifeManualPaused;
            st.lastUrbanLifeTick = worldBefore.lastUrbanLifeTick;
            st.scenarioMode = worldBefore.scenarioMode;
            st.scenarioActive = worldBefore.scenarioActive;
            st.selectedMovieScene = worldBefore.selectedMovieScene;
            cfg.movieSceneCinematicCameraEnabled = worldBefore.movieSceneCinematicCameraEnabled;
            cfg.movieSceneCameraMode = worldBefore.movieSceneCameraMode;
        }
        if (!cfg.smartPresetApplyPlayerSafety)
        {
            st.noWanted = safetyBefore.noWanted;
            st.policeIgnore = safetyBefore.policeIgnore;
            st.everyoneIgnore = safetyBefore.everyoneIgnore;
            st.policeIgnoreManual = safetyBefore.policeIgnoreManual;
            st.everyoneIgnoreManual = safetyBefore.everyoneIgnoreManual;
        }
        if (!cfg.smartPresetApplyMissionGenerator)
        {
            cfg.randomMissionGeneratorEnabled = missionBefore.randomMissionGeneratorEnabled;
            cfg.randomMissionExtraTypes = missionBefore.randomMissionExtraTypes;
            cfg.randomMission2Enabled = missionBefore.randomMission2Enabled;
            cfg.randomMission3Enabled = missionBefore.randomMission3Enabled;
            cfg.randomMission4Enabled = missionBefore.randomMission4Enabled;
            cfg.randomMissionPreviewEnabled = missionBefore.randomMissionPreviewEnabled;
            cfg.randomMissionLargeScaleEnabled = missionBefore.randomMissionLargeScaleEnabled;
            cfg.randomMissionUseCategoryFilter = missionBefore.randomMissionUseCategoryFilter;
            cfg.randomMissionAllowFriendlyMissions = missionBefore.randomMissionAllowFriendlyMissions;
            cfg.randomMissionSetWantedForEscape = missionBefore.randomMissionSetWantedForEscape;
            cfg.randomMissionBonusObjectives = missionBefore.randomMissionBonusObjectives;
            cfg.randomMissionAdaptiveDifficulty = missionBefore.randomMissionAdaptiveDifficulty;
            cfg.randomMissionPreferRoadTargets = missionBefore.randomMissionPreferRoadTargets;
            cfg.randomMissionLargeScaleChance = missionBefore.randomMissionLargeScaleChance;
            cfg.randomMissionEnemyCount = missionBefore.randomMissionEnemyCount;
            cfg.randomMissionTwistChance = missionBefore.randomMissionTwistChance;
            cfg.randomMissionEscalationChance = missionBefore.randomMissionEscalationChance;
            cfg.randomMissionBonusChance = missionBefore.randomMissionBonusChance;
            cfg.randomMissionTimePressureChance = missionBefore.randomMissionTimePressureChance;
            cfg.gameModeDefaultDifficulty = missionBefore.gameModeDefaultDifficulty;
            cfg.gameModeDefaultDurationSec = missionBefore.gameModeDefaultDurationSec;
            cfg.randomMissionRewardMultiplier = missionBefore.randomMissionRewardMultiplier;
            st.randomMissionPreferredCategory = missionBefore.randomMissionPreferredCategory;
            st.randomMissionSelectedKindIndex = missionBefore.randomMissionSelectedKindIndex;
            st.randomMissionForceSelectedKind = missionBefore.randomMissionForceSelectedKind;
            st.randomMissionPreviewReady = missionBefore.randomMissionPreviewReady;
            st.randomMissionPreviewKind = missionBefore.randomMissionPreviewKind;
            st.randomMissionPreviewLocation = missionBefore.randomMissionPreviewLocation;
            st.randomMissionPreviewConstraint = missionBefore.randomMissionPreviewConstraint;
            st.randomMissionPreviewComplication = missionBefore.randomMissionPreviewComplication;
        }

        ClampConfigValues();
        ClampStateIndexes();
        ApplyRuntimeStateNow();
        if (cfg.smartPresetAutoHealthCheck) RunHealthCheck(false, false);
        Notify("Smart Presets 2.0 applied: " + SmartPreset2Name(kind));
    }

