    static void NormalizeTeleportRuntimeState()
    {
        cfg.teleportSlots = ClampIntValue(cfg.teleportSlots, 1, 100);
        cfg.teleportFavoriteLimit = ClampIntValue(cfg.teleportFavoriteLimit, 1, 50);
        cfg.teleportHistoryLimit = ClampIntValue(cfg.teleportHistoryLimit, 1, 30);
        cfg.teleportCompanionSpread = ClampFloatValue(cfg.teleportCompanionSpread, 2.0f, 12.0f, 4.0f);
        const int maxLocationPage = std::max(0, (cfg.teleportSlots - 1) / 5);
        st.locationSlotPage = ClampIntValue(st.locationSlotPage, 0, maxLocationPage);
        TrimTeleportPointList(st.teleportFavorites, cfg.teleportFavoriteLimit);
        TrimTeleportPointList(st.teleportHistory, cfg.teleportHistoryLimit);
        if (st.teleportFavorites.empty()) st.selectedTeleportFavorite = 0;
        else st.selectedTeleportFavorite = ClampIntValue(st.selectedTeleportFavorite, 0, (int)st.teleportFavorites.size() - 1);
        if (st.teleportHistory.empty()) st.selectedTeleportHistory = 0;
        else st.selectedTeleportHistory = ClampIntValue(st.selectedTeleportHistory, 0, (int)st.teleportHistory.size() - 1);
        if (st.hasLastTeleportDestination)
        {
            if (!IsUsableRuntimeWorldPosition(st.lastTeleportDestination))
            {
                st.hasLastTeleportDestination = false;
                st.lastTeleportLabel = "None";
                st.lastTeleportDestination = Vector3{};
                st.lastTeleportHeading = 0.0f;
            }
            else
            {
                // BUGFIX 190: this normalization path also runs during boot/catalog/profile
                // loading. Do not call SafePlayerCoords/SafePlayerHeading here; those touch
                // PLAYER_PED_ID/entity natives and can crash or stall Story Mode loading.
                const Vector3 lastTeleportFallback = st.lastTeleportDestination;
                st.lastTeleportDestination = SanitizeRuntimeVector(st.lastTeleportDestination, lastTeleportFallback);
                st.lastTeleportHeading = NormalizeHeading(st.lastTeleportHeading, st.lastTeleportHeading);
            }
        }
    }

    static void NormalizeWorldControlRuntimeState()
    {
        if (st.noTraffic && st.denseTraffic) st.denseTraffic = false;
        if (st.noPeds && st.densePeds) st.densePeds = false;
        cfg.denseTrafficMultiplier = ClampFloatValue(cfg.denseTrafficMultiplier, 0.0f, 6.0f, 2.0f);
        cfg.densePedMultiplier = ClampFloatValue(cfg.densePedMultiplier, 0.0f, 6.0f, 2.0f);
        st.selectedHour = (st.selectedHour % 24 + 24) % 24;
        st.selectedMinute = (st.selectedMinute % 60 + 60) % 60;
        if (!weatherTypes.empty() && (st.weatherIndex < 0 || st.weatherIndex >= (int)weatherTypes.size())) st.weatherIndex = 0;
    }

