    static void TickWorldControl()
    {
        NormalizeWorldControlRuntimeState();
        SafePauseClockRuntime(st.freezeTime);
        if (st.freezeWeather && !weatherTypes.empty())
            SafeSetOverrideWeatherRuntime(CurrentWeatherName());
        static bool lowGravityWasApplied = false;
        if (st.lowGravity)
        {
            SafeSetGravityLevelRuntime(3);
            lowGravityWasApplied = true;
        }
        else if (lowGravityWasApplied)
        {
            SafeSetGravityLevelRuntime(0);
            lowGravityWasApplied = false;
        }

        if (st.noTraffic)
        {
            SafeSetVehicleDensityFrameRuntime(0.0f, true, "world_control");
        }
        else if (st.denseTraffic)
        {
            SafeSetVehicleDensityFrameRuntime(cfg.denseTrafficMultiplier, true, "world_control");
        }

        if (st.noPeds)
        {
            SafeSetPedDensityFrameRuntime(0.0f, "world_control");
        }
        else if (st.densePeds)
        {
            SafeSetPedDensityFrameRuntime(cfg.densePedMultiplier, "world_control");
        }
    }

