    static bool MoveCurrentVehicleToPosition(Vector3 desired, float heading, const std::string& label, bool applyRoadSafety)
    {
        Vehicle v = 0;
        if (!GetCurrentVehicle(v, true)) return false;
        if (!IsUsableWorldPosition(desired, -200.0f, 2000.0f))
        {
            st.lastVehicleToolStatus = label + " failed: invalid target.";
            Notify(st.lastVehicleToolStatus);
            return false;
        }
        Vector3 before{};
        if (!TryGetUsableEntityPosition((Entity)v, before))
        {
            st.lastVehicleToolStatus = label + " failed: current position invalid.";
            Notify(st.lastVehicleToolStatus);
            return false;
        }
        float beforeHeading = NormalizeHeading(core::SafeGetEntityHeading((Entity)(v), 0.0f), SafePlayerHeading());
        Vector3 target = desired;
        if (applyRoadSafety) target = ApplySpawnSafety(target, true);
        if (!IsUsableWorldPosition(target, -200.0f, 2000.0f))
        {
            st.lastVehicleToolStatus = label + " failed: unsafe target.";
            Notify(st.lastVehicleToolStatus);
            return false;
        }
        if (!IsUsableVehicleHandle(v, false))
        {
            st.lastVehicleToolStatus = label + " failed: vehicle disappeared.";
            Notify(st.lastVehicleToolStatus);
            return false;
        }
        core::safe_native::SetVelocity((Entity)v, Vector3{}, &g_coreErrors, "vehicle_tools");
        core::safe_native::SetCoords((Entity)v, target, false, &g_coreErrors, "vehicle_tools");
        core::safe_native::SetHeading((Entity)v, NormalizeHeading(heading, beforeHeading), &g_coreErrors, "vehicle_tools");
        SafeSetVehicleOnGround(v, "full_audit");
        SafeSetVehicleEngineOn(v, true, "full_audit");
        Vector3 after{};
        const bool afterOk = core::TryGetEntityCoords((Entity)v, after, false) && IsUsableWorldPosition(after, -200.0f, 2000.0f);
        float movedDx = afterOk ? (after.x - target.x) : 0.0f;
        float movedDy = afterOk ? (after.y - target.y) : 0.0f;
        if (!afterOk || (movedDx * movedDx + movedDy * movedDy) > 2025.0f)
        {
            if (IsUsableWorldPosition(before, -200.0f, 2000.0f))
            {
                core::safe_native::SetCoords((Entity)v, before, false, &g_coreErrors, "vehicle_tools");
                core::safe_native::SetHeading((Entity)v, beforeHeading, &g_coreErrors, "vehicle_tools");
                core::safe_native::SetVelocity((Entity)v, Vector3{}, &g_coreErrors, "vehicle_tools");
                SafeSetVehicleOnGround(v, "full_audit");
                SafeSetVehicleEngineOn(v, true, "full_audit");
            }
            st.lastVehicleToolStatus = label + " failed: final position rejected.";
            Notify(st.lastVehicleToolStatus);
            return false;
        }
        st.lastVehicleToolStatus = label + " completed.";
        Notify(st.lastVehicleToolStatus);
        return true;
    }

    static void RestoreCurrentVehicleRecoveryPoint()
    {
        if (!st.hasVehicleRecoveryPoint || !IsUsableWorldPosition(st.vehicleRecoveryPos, -200.0f, 2000.0f))
        {
            st.lastVehicleToolStatus = "No valid vehicle recovery point.";
            Notify(st.lastVehicleToolStatus);
            return;
        }
        MoveCurrentVehicleToPosition(st.vehicleRecoveryPos, st.vehicleRecoveryHeading, "Vehicle recovery restore", true);
    }

    static void MoveCurrentVehicleToSafeSpawn()
    {
        Vector3 target = SpawnSafetyPosition(7.0f, true);
        if (!IsUsableWorldPosition(target, -200.0f, 2000.0f))
        {
            st.lastVehicleToolStatus = "Safe unstuck failed: no valid safe spawn.";
            Notify(st.lastVehicleToolStatus);
            return;
        }
        MoveCurrentVehicleToPosition(target, SafePlayerHeading(), "Vehicle safe unstuck", true);
    }

    static void ApplyVehicleConditionPreset(int preset)
    {
        Vehicle v = 0;
        if (!GetCurrentVehicle(v, true)) return;
        if (!IsUsableVehicleHandle(v, true)) { Notify("Condition preset rejected: invalid vehicle."); return; }
        switch (preset)
        {
            case 1: // Used
                SafeSetVehicleDirtLevel(v, 4.5f, "vehicle_condition");
                SafeSetVehicleEngineHealth(v, 760.0f, "vehicle_condition");
                SafeSetVehicleBodyHealth(v, 760.0f, "vehicle_condition");
                SafeSetVehicleOnGround(v, "full_audit");
                SafeSetVehicleEngineOn(v, true, "full_audit");
                st.lastVehicleToolStatus = "Condition preset applied: Used.";
                break;
            case 2: // Damaged
                SafeSetVehicleDirtLevel(v, 11.0f, "vehicle_condition");
                SafeSetVehicleEngineHealth(v, 420.0f, "vehicle_condition");
                SafeSetVehicleBodyHealth(v, 460.0f, "vehicle_condition");
                SafeSetVehicleOnGround(v, "full_audit");
                SafeSetVehicleEngineOn(v, true, "full_audit");
                st.lastVehicleToolStatus = "Condition preset applied: Damaged.";
                break;
            case 3: // Wrecked but not hard-deleted
                SafeSetVehicleDirtLevel(v, 15.0f, "vehicle_condition");
                SafeSetVehicleEngineHealth(v, 120.0f, "vehicle_condition");
                SafeSetVehicleBodyHealth(v, 160.0f, "vehicle_condition");
                SafeSetVehicleOnGround(v, "full_audit");
                SafeVehicleRuntimeNative(v, "full_audit", "disable vehicle engine", [&](){ VEHICLE::SET_VEHICLE_ENGINE_ON(v, false, true, false); });
                st.lastVehicleToolStatus = "Condition preset applied: Wrecked.";
                break;
            case 4: // Chase ready
                SafeSetVehicleFixedRuntime(v, "vehicle");
                SafeSetVehicleDirtLevel(v, 0.0f, "vehicle");
                SafeSetVehicleEngineHealth(v, 1000.0f, "vehicle");
                SafeSetVehicleBodyHealth(v, 900.0f, "vehicle");
                SafeSetVehicleTyresCanBurst(v, false, "vehicle");
                SafeSetVehicleOnGround(v, "full_audit");
                SafeSetVehicleEngineOn(v, true, "full_audit");
                ApplyMaxPerformanceVehicle(false);
                st.lastVehicleToolStatus = "Condition preset applied: Chase Ready.";
                break;
            default: // Factory New
                SafeSetVehicleFixedRuntime(v, "vehicle");
                SafeSetVehicleDirtLevel(v, 0.0f, "vehicle");
                SafeSetVehicleEngineHealth(v, 1000.0f, "vehicle");
                SafeSetVehicleBodyHealth(v, 1000.0f, "vehicle");
                SafeSetVehicleTyresCanBurst(v, true, "vehicle");
                SafeSetVehicleOnGround(v, "full_audit");
                SafeSetVehicleEngineOn(v, true, "full_audit");
                st.lastVehicleToolStatus = "Condition preset applied: Factory New.";
                break;
        }

        Vector3 finalPos{};
        if (!TryGetUsableEntityPosition((Entity)v, finalPos))
        {
            st.lastVehicleToolStatus = "Condition preset failed: final position invalid.";
            Notify(st.lastVehicleToolStatus);
            return;
        }

        Notify(st.lastVehicleToolStatus);
    }

