    static void TickPoliceRealismCleanup()
    {
        if (!cfg.policeRealismEnabled && st.policeRealismEntities.empty()) return;
        DWORD now = GetTickCount();
        if (st.lastPoliceRealismCleanupTick && !core::TickElapsed(now, st.lastPoliceRealismCleanupTick, 8000u)) return;
        st.lastPoliceRealismCleanupTick = now;
        CompactPoliceRealismEntities();
        float radius = (float)std::max(cfg.policeCleanupRadius, cfg.witnessCleanupRadius);
        CleanFarMixedEntities(st.policeRealismEntities, radius * radius);
        CompactPoliceRealismEntities();
        if (st.policeRealismEntities.empty() && st.witnessReports.empty()) st.policeRealismActive = false;
    }

    static void TickPoliceRealismEscalation()
    {
        if (!cfg.policeRealismEnabled) return;
        DWORD now = GetTickCount();
        int wanted = SafeGetWantedLevelRuntime();
        if (wanted < 2) return;
        if (st.lastPoliceRealismBackupTick && !core::TickElapsed(now, st.lastPoliceRealismBackupTick, SafeIntervalFromIntMs(cfg.policeBackupDelayMs, 15000, 3000, 180000, "police_realism", "backup delay"))) return;
        WitnessReport synthetic;
        synthetic.kind = wanted >= 4 ? WitnessReportKind::ShotsFired : WitnessReportKind::HitAndRun;
        synthetic.wantedLevel = wanted;
        synthetic.description = "active wanted response";
        SpawnPoliceBackupForReport(synthetic);
    }

    static void TickWitnessPoliceRealism()
    {
        if (cfg.witnessSystemEnabled)
        {
            ProcessDueWitnessReports();
            TickWitnessAutoReports();
        }
        else if (!st.witnessReports.empty())
        {
            ClearWitnessReportsOnly(false);
            st.lastWitnessReport = "Witness System disabled: pending reports cleared";
        }

        if (cfg.policeRealismEnabled)
            TickPoliceRealismEscalation();
        TickPoliceRealismCleanup();
    }

    static bool IsWantedPolice2StartupGuardActive(DWORD now, DWORD graceMs = 12000u)
    {
        // BUGFIX 229: Wanted/Police 2.0 diagnostics and repair must not spam
        // player/wanted natives while Story Mode has just crossed the heavy-runtime
        // gate. Treat an unset first-ready tick as guarded too; this protects manual
        // menu calls made during late loading or transition screens.
        if (!g_heavyRuntimeWorldReadyOnce || g_firstHeavyRuntimeReadyTick == 0) return true;
        return !core::TickElapsed(now, g_firstHeavyRuntimeReadyTick, graceMs);
    }

    static void ClearAdvancedDispatchNativeQueue(const std::string& reason)
    {
        g_pendingDispatchServiceRestore = false;
        g_pendingDispatchServiceRestoreEnabled = true;
        g_lastDispatchServiceRestoreAttemptTick = 0;
        g_dispatchServiceRestoreHardCooldownUntil = 0;
        g_dispatchServiceRestoreNextService = 1;
        if (!reason.empty()) Log("Advanced dispatch native queue cleared: " + reason);
    }

    static void ToggleWantedPoliceRepairDispatchServices()
    {
        cfg.wantedPoliceRepairDispatchServices = !cfg.wantedPoliceRepairDispatchServices;
        if (!cfg.wantedPoliceRepairDispatchServices)
        {
            cfg.wantedPoliceRepairDispatchServiceNative = false;
            ClearAdvancedDispatchNativeQueue("Repair Dispatch Services disabled from menu");
            st.lastPoliceWanted2Report = "Dispatch service repair disabled; unsafe native queue cleared.";
        }
        else
        {
            // Keep the dangerous native switch opt-in even after enabling the parent
            // repair option. Normal police repair still uses safer player/wanted natives.
            cfg.wantedPoliceRepairDispatchServiceNative = false;
            ClearAdvancedDispatchNativeQueue("Repair Dispatch Services enabled with native still OFF");
            st.lastPoliceWanted2Report = "Dispatch service repair enabled; advanced native remains OFF.";
        }
        Notify(st.lastPoliceWanted2Report);
    }

    static void ToggleWantedPoliceRepairDispatchNative()
    {
        if (!cfg.wantedPoliceRepairDispatchServices)
        {
            cfg.wantedPoliceRepairDispatchServiceNative = false;
            ClearAdvancedDispatchNativeQueue("Unsafe native toggle blocked because parent repair is OFF");
            st.lastPoliceWanted2Report = "Enable Repair Dispatch Services before Advanced Dispatch Native.";
            Notify(st.lastPoliceWanted2Report);
            return;
        }

        cfg.wantedPoliceRepairDispatchServiceNative = !cfg.wantedPoliceRepairDispatchServiceNative;
        if (!cfg.wantedPoliceRepairDispatchServiceNative)
        {
            ClearAdvancedDispatchNativeQueue("Advanced Dispatch Native disabled from menu");
            st.lastPoliceWanted2Report = "Advanced dispatch native disabled; queued native restore cleared.";
        }
        else
        {
            ClearAdvancedDispatchNativeQueue("Advanced Dispatch Native enabled; waiting for explicit repair/preset request");
            st.lastPoliceWanted2Report = "Advanced dispatch native enabled. It will run slowly after the crash-safe gate.";
        }
        Notify(st.lastPoliceWanted2Report);
    }

