    static std::string PoliceWantedPreset2Name(PoliceWantedPreset2 preset)
    {
        switch (preset)
        {
            case PoliceWantedPreset2::NoWanted: return "No Wanted";
            case PoliceWantedPreset2::RealisticPolice: return "Realistic Police";
            case PoliceWantedPreset2::CinematicChase: return "Cinematic Chase";
            case PoliceWantedPreset2::ChaosPolice: return "Chaos Police";
            default: return "Vanilla Wanted";
        }
    }

    static void CyclePoliceWantedPreset2()
    {
        int idx = static_cast<int>(st.selectedPoliceWantedPreset2) + 1;
        if (idx > static_cast<int>(PoliceWantedPreset2::ChaosPolice)) idx = 0;
        st.selectedPoliceWantedPreset2 = static_cast<PoliceWantedPreset2>(idx);
        st.lastPoliceWanted2Report = "Selected preset: " + PoliceWantedPreset2Name(st.selectedPoliceWantedPreset2);
        Notify(st.lastPoliceWanted2Report);
    }

    static void UpdatePoliceWanted2Diagnostics(const std::string& reason = "manual")
    {
        const DWORD now = GetTickCount();
        st.lastPoliceWanted2DiagnosticTick = now;
        if (IsWantedPolice2StartupGuardActive(now, 12000u))
        {
            st.lastPoliceWanted2Diagnostics = "Startup crash guard active; diagnostics delayed until stable gameplay.";
            return;
        }
        int currentWanted = SafeGetWantedLevelRuntime("wanted_police_2_diag");
        std::ostringstream ss;
        ss << "Wanted " << currentWanted << "/" << ClampWantedLevelValue(st.maxWantedLevel)
           << " | noWanted=" << (st.noWanted ? "yes" : "no")
           << " | freeze=" << (st.freezeWanted ? "yes" : "no")
           << " | policeIgnore=" << (st.policeIgnore ? (st.policeIgnoreManual ? "manual" : "runtime") : "off")
           << " | everyoneIgnore=" << (st.everyoneIgnore ? (st.everyoneIgnoreManual ? "manual" : "runtime") : "off")
           << " | dispatch=" << (g_pendingDispatchServiceRestore ? "queued" : "ready")
           << " | realism=" << (cfg.policeRealismEnabled ? "on" : "off")
           << " | reason=" << reason;
        st.lastPoliceWanted2Diagnostics = ss.str();
    }

    static bool RepairPoliceWantedSystem2Core(bool notifyResult, const std::string& reason, bool forceNow = false)
    {
        const DWORD now = GetTickCount();
        const DWORD cooldown = SafeIntervalFromIntMs(cfg.wantedPoliceRepairCooldownMs, 9000, 1000, 60000, "wanted_police_2", "repair cooldown");
        if (IsWantedPolice2StartupGuardActive(now, forceNow ? 3500u : 12000u))
        {
            st.lastPoliceWanted2Report = "Repair 2.0 delayed by startup crash guard.";
            if (notifyResult) Notify(st.lastPoliceWanted2Report);
            return false;
        }
        if (!forceNow && !notifyResult && st.lastPoliceWanted2RepairTick != 0 && !core::TickElapsed(now, st.lastPoliceWanted2RepairTick, cooldown))
            return false;

        st.lastPoliceWanted2RepairTick = now;
        ++st.policeWanted2RepairCount;

        if (st.noWanted)
        {
            st.freezeWanted = false;
            st.maxWantedLevel = 0;
            st.selectedWantedLevel = 0;
            st.frozenWantedLevel = 0;
            SafeClearPlayerWantedLevelRuntime("wanted_police_2_repair");
            SafeSetMaxWantedLevelRuntime(0, "wanted_police_2_repair");
            SafeSetWantedLevelMultiplierRuntime(0.0f, "wanted_police_2_repair");
            SafeSetDispatchCopsForPlayerRuntime(false, "wanted_police_2_repair");
            if (cfg.wantedPoliceRepairDispatchServices) SafeSetDispatchServicesRuntime(false, "wanted_police_2_repair");
            st.lastPoliceWanted2Report = "Repair 2.0: No Wanted suppression enforced safely.";
        }
        else
        {
            EffectiveNaturalMaxWantedLevelRuntime();
            if (cfg.wantedPoliceRepairIgnoreFlags)
            {
                if (st.policeIgnore && !st.policeIgnoreManual) st.policeIgnore = false;
                if (st.everyoneIgnore && !st.everyoneIgnoreManual) st.everyoneIgnore = false;
            }
            SafeSetMaxWantedLevelRuntime(EffectiveNaturalMaxWantedLevelRuntime(), "wanted_police_2_repair");
            SafeSetWantedLevelMultiplierRuntime(st.wantedMultiplierBoost ? 2.5f : 1.0f, "wanted_police_2_repair");
            SafeSetDispatchCopsForPlayerRuntime(true, "wanted_police_2_repair");
            if (cfg.wantedPoliceRepairDispatchServices) SafeSetDispatchServicesRuntime(true, "wanted_police_2_repair");
            SafeSetPoliceIgnorePlayerRuntime(st.policeIgnore, "wanted_police_2_repair");
            SafeSetEveryoneIgnorePlayerRuntime(st.everyoneIgnore, "wanted_police_2_repair");
            if (st.freezeWanted)
            {
                st.frozenWantedLevel = ClampWantedLevelToMax(st.frozenWantedLevel);
                SafeSetPlayerWantedLevelRuntime(st.frozenWantedLevel, true, "wanted_police_2_repair");
            }
            st.lastPoliceWanted2Report = "Repair 2.0: natural police/wanted response restored.";
        }

        UpdatePoliceWanted2Diagnostics(reason);
        if (notifyResult) Notify(st.lastPoliceWanted2Report);
        return true;
    }

    static void RepairPoliceWantedSystem2()
    {
        RepairPoliceWantedSystem2Core(true, "manual repair");
    }

    static void ApplyPoliceWantedPreset2()
    {
        PushWantedUndo("Wanted & Police 2.0 Preset");
        switch (st.selectedPoliceWantedPreset2)
        {
            case PoliceWantedPreset2::NoWanted:
                st.noWanted = true;
                st.freezeWanted = false;
                st.maxWantedLevel = 0;
                st.selectedWantedLevel = 0;
                st.frozenWantedLevel = 0;
                st.wantedMultiplierBoost = false;
                cfg.policeRealismEnabled = false;
                cfg.witnessSystemEnabled = false;
                cfg.cinematicPursuitsEnabled = false;
                ClearPoliceRealism(false, true);
                break;
            case PoliceWantedPreset2::RealisticPolice:
                st.noWanted = false;
                st.freezeWanted = false;
                st.maxWantedLevel = 5;
                st.selectedWantedLevel = 0;
                st.frozenWantedLevel = 0;
                st.wantedMultiplierBoost = false;
                cfg.witnessSystemEnabled = true;
                cfg.witnessAutoReports = true;
                cfg.policeRealismEnabled = true;
                cfg.policeTrafficStops = true;
                cfg.policeFines = true;
                cfg.policeRoadblocks = true;
                cfg.policeSearchByDescription = true;
                cfg.policeNpcArrests = true;
                cfg.policeChaseTactics = true;
                cfg.policeBackupDelayMs = 15000;
                cfg.policeRoadblockWantedLevel = 3;
                cfg.cinematicPursuitsEnabled = false;
                break;
            case PoliceWantedPreset2::CinematicChase:
                st.noWanted = false;
                st.freezeWanted = false;
                st.maxWantedLevel = 5;
                st.selectedWantedLevel = ClampWantedLevelToMax(std::max(3, st.selectedWantedLevel));
                st.wantedMultiplierBoost = true;
                cfg.witnessSystemEnabled = true;
                cfg.policeRealismEnabled = true;
                cfg.policeRoadblocks = true;
                cfg.policeChaseTactics = true;
                cfg.cinematicPursuitsEnabled = true;
                cfg.cinematicPursuitIntensity = 4;
                cfg.cinematicPursuitRefreshMs = 450;
                cfg.policeBackupDelayMs = 9000;
                cfg.policeRoadblockWantedLevel = 3;
                break;
            case PoliceWantedPreset2::ChaosPolice:
                st.noWanted = false;
                st.freezeWanted = false;
                st.maxWantedLevel = 5;
                st.selectedWantedLevel = ClampWantedLevelToMax(5);
                st.wantedMultiplierBoost = true;
                cfg.witnessSystemEnabled = true;
                cfg.witnessAutoReports = true;
                cfg.policeRealismEnabled = true;
                cfg.policeRoadblocks = true;
                cfg.policeChaseTactics = true;
                cfg.cinematicPursuitsEnabled = true;
                cfg.cinematicPursuitIntensity = 5;
                cfg.cinematicPursuitRefreshMs = 300;
                cfg.policeBackupDelayMs = 5000;
                cfg.policeRoadblockWantedLevel = 2;
                break;
            default:
                st.noWanted = false;
                st.freezeWanted = false;
                st.maxWantedLevel = 5;
                st.selectedWantedLevel = 0;
                st.frozenWantedLevel = 0;
                st.wantedMultiplierBoost = false;
                cfg.witnessSystemEnabled = true;
                cfg.policeRealismEnabled = false;
                cfg.cinematicPursuitsEnabled = false;
                break;
        }

        // Preset application is a direct user action; never let the auto-repair
        // cooldown delay native state application, especially for No Wanted.
        RepairPoliceWantedSystem2Core(false, "preset apply", true);
        if (!st.noWanted && st.selectedWantedLevel > 0)
            SafeSetPlayerWantedLevelRuntime(st.selectedWantedLevel, true, "wanted_police_2_preset");
        st.lastPoliceWanted2Report = "Preset applied: " + PoliceWantedPreset2Name(st.selectedPoliceWantedPreset2);
        Notify(st.lastPoliceWanted2Report);
    }

