    static std::string PresetKeyToken(const std::string& key)
    {
        std::string out;
        out.reserve(key.size());
        for (unsigned char c : key)
        {
            if (std::isalnum(c)) out.push_back((char)std::tolower(c));
        }
        return out;
    }

