    static void LoadTrainerPresetSlot(int slot, bool notifyResult)
    {
        slot = ClampIntValue(slot, 1, std::max(1, cfg.trainerPresetSlots));
        std::vector<std::string> lines;
        if (!ReadTextLinesSafe(TrainerPresetsPath(), lines)) { if (notifyResult) Notify("Preset file not found."); return; }
        bool backupBeforeApply = cfg.smartProfilesEnabled && cfg.smartProfilesAutoBackupBeforeLoad && PresetSlotContainsLoadableData(slot);
        bool reading = false, loaded = false, clearedForStateLoad = false;
        bool sawPoliceIgnore = false, sawEveryoneIgnore = false;
        bool sawPoliceIgnoreManual = false, sawEveryoneIgnoreManual = false;
        bool loadedPoliceIgnoreValue = false, loadedEveryoneIgnoreValue = false;
        int loadedStateFormat = 0;
        std::string loadedName = PresetBaseName(slot);
        for (std::string line : lines)
        {
            line = Trim(line);
            if (line == "BEGIN_PRESET|" + std::to_string(slot))
            {
                reading = true;
                if (backupBeforeApply)
                {
                    CreateSmartProfileBackupSlot(NextSmartProfileAutoBackupSlot(), false, "before profile load", false);
                    backupBeforeApply = false;
                }
                continue;
            }
            if (reading && line == "END_PRESET") break;
            if (!reading || line.empty()) continue;
            auto eq = line.find('='); if (eq == std::string::npos) continue;
            std::string k = NormalizeTrainerPresetKey(Trim(line.substr(0, eq)));
            std::string v = Trim(line.substr(eq + 1));
            if (k == "name") { loadedName = v; continue; }
            if (k == "stateFormat") { loadedStateFormat = ParseIntOr(v, loadedStateFormat); continue; }

            // BUGFIX 183: metadata-only or unknown/corrupt profile lines must not
            // count as real state. Previously stateFormat alone could trigger
            // ClearRuntimeEffectFlags() and wipe the current session.
            if (!IsTrainerPresetStateKey(k))
            {
                Log("Preset load skipped unknown key: " + k);
                continue;
            }

            if (k == "policeIgnore") { sawPoliceIgnore = true; loadedPoliceIgnoreValue = ParseBool(v); }
            else if (k == "everyoneIgnore") { sawEveryoneIgnore = true; loadedEveryoneIgnoreValue = ParseBool(v); }
            else if (k == "policeIgnoreManual") sawPoliceIgnoreManual = true;
            else if (k == "everyoneIgnoreManual") sawEveryoneIgnoreManual = true;
            if (!clearedForStateLoad)
            {
                // BUGFIX 165/183: only a recognized state key may reset the live
                // runtime before applying a profile. Metadata-only slots and
                // unknown/corrupt keys leave the current session untouched.
                ClearRuntimeEffectFlags(true);
                DisableCinematicTools();
                CancelSafeSpawnPreview(false);
                clearedForStateLoad = true;
            }
            try { ApplyPresetKeyValue(k, v); loaded = true; } catch (...) { Log("Preset key failed to apply: " + k); }
        }
        if (loaded)
        {
            // BUGFIX 182/183: migrate legacy presets/autosaves created before manual-owner
            // flags were persisted. A stored true Ignore value represented a user-visible
            // enabled menu state, so keep it player-owned unless the preset explicitly
            // says the runtime owns/cleans it.
            const bool legacyPresetWithoutManualOwners = loadedStateFormat <= 0 || loadedStateFormat < 182;
            if (legacyPresetWithoutManualOwners && sawPoliceIgnore && loadedPoliceIgnoreValue && !sawPoliceIgnoreManual)
                st.policeIgnoreManual = true;
            if (legacyPresetWithoutManualOwners && sawEveryoneIgnore && loadedEveryoneIgnoreValue && !sawEveryoneIgnoreManual)
                st.everyoneIgnoreManual = true;
            if (!st.policeIgnore) st.policeIgnoreManual = false;
            if (!st.everyoneIgnore) st.everyoneIgnoreManual = false;

            st.currentPresetName = loadedName;
            SyncRuntimeStateAfterConfigProfileLoad(true);
        }
        if (notifyResult) Notify(loaded ? "Preset loaded: " + loadedName : "Preset slot empty.");
    }


    static bool HasMissionCreatorProgress()
    {
        if (!st.currentMission.entities.empty() || !st.currentMission.objectives.empty()) return true;
        if (!st.missionName.empty() && NormalizeMissionName(st.missionName) != "Custom Mission") return true;
        if (NormalizeFlatText(st.missionStartDialog, 120, "") != "Mission started.") return true;
        if (NormalizeFlatText(st.missionCompleteDialog, 120, "") != "Mission completed.") return true;
        if (st.missionRewardCash != cfg.missionDefaultRewardCash || st.missionRewardRp != cfg.missionDefaultRewardRp) return true;
        if (st.missionFailOnPlayerDeath != true || st.missionFailOnWanted != false) return true;
        if (st.missionRouteEnabled != true || st.missionAutoStartCombat != true) return true;
        return false;
    }

    static int RunAutoSave(bool notifyResult)
    {
        ClampStateIndexes();

        int saved = 0;
        int skipped = 0;
        bool anyCategory = cfg.autoSaveTrainerState || cfg.autoSaveMissionCreatorProgress || cfg.autoSaveLastVehicle || cfg.autoSaveLastOutfit;
        if (!anyCategory)
        {
            if (notifyResult) Notify("Auto Save: no categories enabled.");
            return 0;
        }

        if (cfg.autoSaveTrainerState)
        {
            int oldSlot = st.selectedTrainerPresetSlot;
            std::string oldName = st.currentPresetName;
            st.selectedTrainerPresetSlot = cfg.autoSaveSlot;
            st.currentPresetName = "Auto Save";
            bool ok = SaveTrainerPresetSlot(cfg.autoSaveSlot, false);
            st.selectedTrainerPresetSlot = oldSlot;
            st.currentPresetName = oldName;
            if (ok) ++saved;
            else ++skipped;
        }

        if (cfg.autoSaveMissionCreatorProgress)
        {
            if (HasMissionCreatorProgress() && SaveMissionSlot(cfg.autoSaveMissionSlot, false)) ++saved;
            else ++skipped;
        }

        if (cfg.autoSaveLastVehicle)
        {
            Ped p = 0;
            if (GetPlayerPedSafe(p) && core::IsPedInAnyVehicle((Ped)(p), false) && SaveCurrentVehicleToSlot(cfg.autoSaveGarageSlot, false)) ++saved;
            else ++skipped;
        }

        if (cfg.autoSaveLastOutfit)
        {
            if (SaveOutfitToSlot(cfg.autoSaveOutfitSlot, false)) ++saved;
            else ++skipped;
        }

        if (notifyResult)
        {
            Notify("Auto Save done: " + std::to_string(saved) + " saved, " + std::to_string(skipped) + " skipped.");
        }
        else
        {
            Log("Auto Save done: " + std::to_string(saved) + " saved, " + std::to_string(skipped) + " skipped.");
        }
        return saved;
    }

    static void TickAutoSave()
    {
        if (!cfg.autoSaveEnabled) return;
        DWORD now = GetTickCount();
        if (st.lastAutoSaveTick == 0) st.lastAutoSaveTick = now;
        if (!core::TickElapsed(now, st.lastAutoSaveTick, SafeIntervalFromIntMs(cfg.autoSaveIntervalMs, 120000, 10000, 1800000, "autosave", "interval"))) return;
        RunAutoSave(false);
        st.lastAutoSaveTick = now;
    }

    static void ForceAutoSaveNow()
    {
        RunAutoSave(true);
        st.lastAutoSaveTick = GetTickCount();
        st.lastSmartProfileAutoBackupTick = GetTickCount();
        st.lastPerformanceSafetyTick = GetTickCount();
        g_lastCoreMaintenanceTick = core::kUnsetTick;
        RunCoreMaintenance(true);
    }

    static bool IsMissionCreatorPage()
    {
        return st.page == Page::MissionCreator || st.page == Page::MissionTemplates || st.page == Page::MissionEntities || st.page == Page::MissionObjectives || st.page == Page::MissionPlaytest;
    }

    static void ClearAmbientWorldForMissionCreator(bool notify)
    {
        Vector3 pos{};
        if (!TryGetPlayerPosition(pos))
        {
            if (notify) Notify("Creator area clear skipped: player position invalid.");
            return;
        }
        SafeClearAreaRuntime(pos, cfg.missionCreatorCleanRadius, true, false, false, false, "mission_creator");
        if (notify) Notify("Creator area cleared.");
    }

    static void TickMissionCreatorTools()
    {
        if (!IsMissionCreatorPage()) return;
        if (JustPressed(cfg.missionCreatorFreeCamKey, 250))
        {
            ToggleFreeCamera();
            Notify(st.freeCamActive ? "Mission creator free camera ON." : "Mission creator free camera OFF.");
        }
        if (cfg.missionCreatorAutoClearWorld && st.menuOpen && !st.missionPlaytestActive && st.missionSpawnedEntities.empty())
        {
            DWORD now = GetTickCount();
            if (core::TickElapsed(now, st.lastMissionCreatorCleanTick, 1501u))
            {
                ClearAmbientWorldForMissionCreator(false);
                st.lastMissionCreatorCleanTick = now;
            }
        }
    }


    static bool IsBadRecoveryPosition(const Vector3& pos, float belowMapZ)
    {
        if (!IsFiniteFloat(pos.x) || !IsFiniteFloat(pos.y) || !IsFiniteFloat(pos.z)) return true;
        if (std::fabs(pos.x) > 12000.0f || std::fabs(pos.y) > 12000.0f) return true;
        if (pos.z < belowMapZ || pos.z > 1600.0f) return true;
        return false;
    }

    static Vector3 SafeRecoveryFallbackPosition()
    {
        if (st.hasLastSafePlayerPos && IsRecoveryFallbackCandidate(st.lastSafePlayerPos))
            return st.lastSafePlayerPos;
        return EmergencyRecoveryLandmark();
    }

    static bool RecoveryCooldownReady(DWORD lastTick)
    {
        if (lastTick == 0) return true;
        DWORD now = GetTickCount();
        return core::TickElapsed(now, lastTick, SafeIntervalFromIntMs(cfg.recoveryCooldownMs, 4500, 1000, 60000, "recovery", "cooldown"));
    }

    static void AppendRecoveryIncident(const std::string& action)
    {
        if (!cfg.autoRecoveryWriteIncidentLog || g_rootDir.empty()) return;
        const std::string path = CaoTrainerTextFilePath("CaoUrbanTrainerASI_RECOVERY_INCIDENTS.txt");
        std::ofstream out(path, std::ios::app);
        if (!out) return;
        out << "tick=" << GetTickCount() << " | " << action << "\n";
        st.lastRecoveryIncidentPath = "CaoUrbanTrainerASI_RECOVERY_INCIDENTS.txt";
    }


    static void RecordAutoRecoveryAction(const std::string& action, int* categoryCounter = nullptr, bool notifyResult = true)
    {
        st.lastAutoRecoveryAction = action;
        ++st.autoRecoveryFixes;
        if (categoryCounter) ++(*categoryCounter);
        Log("Auto Recovery: " + action);
        AppendRecoveryIncident(action);
        if (notifyResult && cfg.autoRecoveryNotify) Notify("Auto Recovery: " + action);
    }

    template <typename T, typename Predicate>
    static int CompactInvalidEntityVectorBy(std::vector<T>& list, Predicate&& predicate)
    {
        int removed = 0;
        std::vector<T> kept;
        kept.reserve(list.size());
        for (T value : list)
        {
            Entity e = (Entity)value;
            if (!predicate(e))
            {
                ++removed;
                continue;
            }
            Vector3 pos{};
            if (!TryGetStrictTrackedEntityPosition((Entity)e, pos))
            {
                ++removed;
                continue;
            }
            if (std::find(kept.begin(), kept.end(), value) == kept.end()) kept.push_back(value);
            else ++removed;
        }
        list = kept;
        return removed;
    }

    template <typename T>
    static int CompactInvalidEntityVector(std::vector<T>& list)
    {
        return CompactInvalidEntityVectorBy(list, [](Entity e) { return e && core::Exists((Entity)(e)); });
    }

    template <typename T>
    static int CompactInvalidPedVector(std::vector<T>& list)
    {
        return CompactInvalidEntityVectorBy(list, [](Entity e) { return e && core::Exists((Entity)(e)) && core::IsPed((Entity)(e)); });
    }

    template <typename T>
    static int CompactInvalidVehicleVector(std::vector<T>& list)
    {
        return CompactInvalidEntityVectorBy(list, [](Entity e) { return e && core::Exists((Entity)(e)) && core::IsVehicle((Entity)(e)); });
    }

    template <typename T>
    static int CompactInvalidObjectVector(std::vector<T>& list)
    {
        return CompactInvalidEntityVectorBy(list, [](Entity e) { return e && core::Exists((Entity)(e)) && !core::IsPed((Entity)(e)) && !core::IsVehicle((Entity)(e)); });
    }

    static int CompactInvalidTrackedEntities(bool notifyResult)
    {
        int removed = 0;
        removed += CompactInvalidPedVector(st.spawnedPeds);
        removed += CompactInvalidPedVector(st.friendlyPeds);
        removed += CompactInvalidPedVector(st.bodyguards);
        removed += CompactInvalidPedVector(st.enemies);
        removed += CompactInvalidPedVector(st.scenarioPeds);
        removed += CompactInvalidVehicleVector(st.spawnedVehicles);
        removed += CompactInvalidVehicleVector(st.scenarioVehicles);
        removed += CompactInvalidObjectVector(st.spawnedObjects);
        removed += CompactInvalidEntityVector(st.worldDirectorEntities);
        removed += CompactInvalidEntityVector(st.urbanLifeEntities);
        removed += CompactInvalidEntityVector(st.vehicleAIEntities);
        removed += CompactInvalidEntityVector(st.policeRealismEntities);
        removed += PurgeInvalidCinematicNpcRuntimeState();

        size_t beforeMission = st.missionSpawnedEntities.size();
        CompactMissionSpawnedEntityLists();
        if (beforeMission > st.missionSpawnedEntities.size())
            removed += (int)(beforeMission - st.missionSpawnedEntities.size());

        removed += PurgeStaleBodyguardRuntimeState();

        size_t beforeGameMode = st.gameMode.trackedEntities.size();
        CompactGameModeEntities();
        if (beforeGameMode > st.gameMode.trackedEntities.size())
            removed += (int)(beforeGameMode - st.gameMode.trackedEntities.size());

        Vector3 singletonPos{};
        if (st.lastObject && (!core::IsObject((Entity)st.lastObject) || !TryGetUsableEntityPosition((Entity)st.lastObject, singletonPos)))
        {
            st.lastObject = 0;
            st.lastObjectFrozen = true;
            ++removed;
        }
        if (st.lastPlayerVehicleForBodyguards && (!core::IsVehicle((Entity)st.lastPlayerVehicleForBodyguards) || !TryGetUsableEntityPosition((Entity)st.lastPlayerVehicleForBodyguards, singletonPos)))
        {
            st.lastPlayerVehicleForBodyguards = 0;
            ++removed;
        }
        if (st.bodyguardProtectedVehicle && (!core::IsVehicle((Entity)st.bodyguardProtectedVehicle) || !TryGetUsableEntityPosition((Entity)st.bodyguardProtectedVehicle, singletonPos)))
        {
            st.bodyguardProtectedVehicle = 0;
            ++removed;
        }
        if (st.garageLastLoadedVehicle && (!core::IsVehicle((Entity)st.garageLastLoadedVehicle) || !TryGetUsableEntityPosition((Entity)st.garageLastLoadedVehicle, singletonPos)))
        {
            st.garageLastLoadedVehicle = 0;
            ++removed;
        }
        if (st.chauffeur && (!core::IsPed((Entity)st.chauffeur) || !TryGetUsableEntityPosition((Entity)st.chauffeur, singletonPos) || core::IsPedDeadOrDying(st.chauffeur, true, true)))
        {
            st.chauffeur = 0;
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
            ++removed;
        }
        if (st.chauffeurVehicle && (!core::IsVehicle((Entity)st.chauffeurVehicle) || !TryGetUsableEntityPosition((Entity)st.chauffeurVehicle, singletonPos)))
        {
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
            ++removed;
        }
        for (auto it = st.inspectorFrozenStates.begin(); it != st.inspectorFrozenStates.end(); )
        {
            if (!it->first || !core::Exists((Entity)it->first) || !TryGetUsableEntityPosition((Entity)it->first, singletonPos))
            {
                it = st.inspectorFrozenStates.erase(it);
                ++removed;
            }
            else ++it;
        }
        if (st.inspectedEntity && (!core::Exists((Entity)st.inspectedEntity) || !TryGetUsableEntityPosition((Entity)st.inspectedEntity, singletonPos)))
        {
            st.inspectedEntity = 0;
            st.lastInspectorStatus = "No entity selected";
            ++removed;
        }

        if (removed > 0)
        {
            st.autoRecoveryInvalidCleanups += removed;
            RecordAutoRecoveryAction("removed " + std::to_string(removed) + " invalid tracked entities", nullptr, notifyResult);
        }
        return removed;
    }

    static bool IsVehicleDestroyedOrInvalid(Vehicle v)
    {
        if (!v || !core::Exists((Entity)(v)) || !core::IsVehicle((Entity)v)) return true;
        Vector3 pos{};
        if (!TryGetUsableEntityPosition((Entity)v, pos)) return true;
        return (int)core::SafeGetEntityHealth((Entity)(v), 0) <= 0;
    }


    static int RecoverPlayerEmergencyState(bool notifyResult)
    {
        Ped playerPed = 0;
        if (!GetPlayerPedSafe(playerPed)) return 0;

        Entity recoveryEntity = PlayerRecoveryEntity();
        if (!recoveryEntity || !core::Exists((Entity)(recoveryEntity))) return 0;

        Vector3 pos{};
        const bool hasUsablePosition = TryGetUsableEntityPosition((Entity)recoveryEntity, pos);
        const bool isVehicle = core::IsVehicle((Entity)(recoveryEntity));
        const float belowZ = isVehicle ? cfg.vehicleBelowMapZ : cfg.playerBelowMapZ;

        if (hasUsablePosition && !IsBadRecoveryPosition(pos, belowZ))
        {
            Vector3 safeCandidate{};
            if (TryGetPlayerPosition(safeCandidate) && IsRecoveryFallbackCandidate(safeCandidate))
            {
                st.lastSafePlayerPos = safeCandidate;
                st.hasLastSafePlayerPos = true;
            }
            return 0;
        }

        if (!RecoveryCooldownReady(st.lastPlayerEmergencyRecoveryTick)) return 0;

        Vector3 safe = SanitizeVector(SafeRecoveryFallbackPosition(), EmergencyRecoveryLandmark());
        SafeRequestCollisionRuntime(safe, "collision_request");
        safe.z = ResolveGroundZ(safe.x, safe.y, safe.z + 5.0f) + (isVehicle ? 0.55f : 1.0f);

        core::safe_native::Freeze(recoveryEntity, false, &g_coreErrors, "auto_recovery");
        core::safe_native::SetCollision(recoveryEntity, true, true, &g_coreErrors, "auto_recovery");
        core::safe_native::SetVelocity(recoveryEntity, Vector3{}, &g_coreErrors, "auto_recovery");
        if (!core::safe_native::SetCoords(recoveryEntity, safe, false, &g_coreErrors, "auto_recovery"))
        {
            ReportCore2(core::ErrorSeverity::Warning, "auto_recovery", "player emergency recovery", "Recovery teleport failed; state was not marked as fixed");
            return 0;
        }

        if (isVehicle)
        {
            Vehicle v = (Vehicle)recoveryEntity;
            SafeSetVehicleOnGround(v, "full_audit");
            SafeSetVehicleEngineOn(v, true, "full_audit");
        }
        else
        {
            core::safe_native::ClearPedTasks(playerPed, true, &g_coreErrors, "auto_recovery");
        }

        st.lastSafePlayerPos = safe;
        st.hasLastSafePlayerPos = true;
        st.lastPlayerEmergencyRecoveryTick = GetTickCount();
        RecordAutoRecoveryAction(std::string("player emergency position recovered") + (isVehicle ? " with vehicle" : ""), &st.autoRecoveryPlayerFixes, notifyResult);
        return 1;
    }

    static int RecoverCurrentVehicleEmergencyState(bool notifyResult)
    {
        Ped playerPed = 0;
        if (!GetPlayerPedSafe(playerPed) || !core::IsPedInAnyVehicle((Ped)(playerPed), false)) return 0;

        Vehicle vehicle = core::GetVehiclePedIsIn((Ped)(playerPed), false);
        if (!IsUsableVehicleHandle(vehicle, false)) return 0;

        int fixes = 0;
        Vector3 pos{};
        const bool hasUsableVehiclePos = TryGetUsableEntityPosition((Entity)vehicle, pos);
        if ((!hasUsableVehiclePos || IsBadRecoveryPosition(pos, cfg.vehicleBelowMapZ)) && RecoveryCooldownReady(st.lastVehiclePositionRecoveryTick))
        {
            Vector3 safe = SanitizeVector(SafeRecoveryFallbackPosition(), EmergencyRecoveryLandmark());
            SafeRequestCollisionRuntime(safe, "collision_request");
            safe.z = ResolveGroundZ(safe.x, safe.y, safe.z + 5.0f) + 0.55f;
            core::safe_native::Freeze((Entity)vehicle, false, &g_coreErrors, "auto_recovery");
            core::safe_native::SetCollision((Entity)vehicle, true, true, &g_coreErrors, "auto_recovery");
            core::safe_native::SetVelocity((Entity)vehicle, Vector3{}, &g_coreErrors, "auto_recovery");
            if (core::safe_native::SetCoords((Entity)vehicle, safe, false, &g_coreErrors, "auto_recovery"))
            {
                SafeSetVehicleOnGround(vehicle, "full_audit");
                SafeSetVehicleEngineOn(vehicle, true, "full_audit");
                st.lastVehiclePositionRecoveryTick = GetTickCount();
                st.lastSafePlayerPos = safe;
                st.hasLastSafePlayerPos = true;
                ++fixes;
            }
            else
            {
                ReportCore2(core::ErrorSeverity::Warning, "auto_recovery", "vehicle emergency recovery", "Vehicle recovery teleport failed; repair/status was not marked as fixed");
            }
        }

        int currentVehicleHealth = (int)core::SafeGetEntityHealth((Entity)(vehicle), 0);
        if (cfg.autoRecoverVehicleEmergencyRepair && currentVehicleHealth > 0 && currentVehicleHealth <= cfg.vehicleEmergencyHealth && RecoveryCooldownReady(st.lastVehicleRepairRecoveryTick))
        {
            SafeSetVehicleFixedRuntime(vehicle, "vehicle_recovery");
            SafeSetVehicleEngineHealth(vehicle, 1000.0f, "entity_inspector");
            SafeSetVehicleBodyHealth(vehicle, 1000.0f, "entity_inspector");
            SafeSetVehicleEngineOn(vehicle, true, "full_audit");
            st.lastVehicleRepairRecoveryTick = GetTickCount();
            ++fixes;
        }

        if (fixes > 0)
            RecordAutoRecoveryAction("current vehicle emergency recovery fixed " + std::to_string(fixes) + " issue(s)", &st.autoRecoveryVehicleFixes, notifyResult);
        return fixes;
    }

    static int RecoverBlipState(bool notifyResult)
    {
        int removed = 0;
        std::vector<Blip> kept;
        kept.reserve(st.missionBlips.size());
        for (Blip b : st.missionBlips)
        {
            if (b && SafeDoesBlipExistRuntime(b)) kept.push_back(b);
            else ++removed;
        }
        st.missionBlips = kept;

        if (st.gameMode.randomMissionBlip && !SafeDoesBlipExistRuntime(st.gameMode.randomMissionBlip))
        {
            st.gameMode.randomMissionBlip = 0;
            ++removed;
        }

        for (auto it = st.friendlyBlips.begin(); it != st.friendlyBlips.end(); )
        {
            if (!cfg.friendlyNpcMapBlips || !it->first || !IsFriendlyNpcTracked(it->first) ||
                !IsUsablePedHandle(it->first, false, true, true) || !it->second ||
                !SafeDoesBlipExistRuntime(it->second, "friendly_blip"))
            {
                // Do not only drop the stale map entry: when the ped handle is stale,
                // no longer tracked as friendly, or blips are disabled, the marker can
                // remain on the map unless the runtime blip itself is removed.
                Blip staleBlip = it->second;
                SafeRemoveBlipRuntime(staleBlip, "friendly_blip");
                it = st.friendlyBlips.erase(it);
                ++removed;
            }
            else ++it;
        }

        if (removed > 0)
            RecordAutoRecoveryAction("removed " + std::to_string(removed) + " stale blip reference(s)", &st.autoRecoveryBlipFixes, notifyResult);
        return removed;
    }

    static int RecoverChauffeurState(bool notifyResult)
    {
        int fixes = 0;
        const bool chauffeurInvalid = st.chauffeur && (!IsUsablePedHandle(st.chauffeur, false, false, true) || core::IsPedDeadOrDying((Ped)(st.chauffeur), true, true));
        if (chauffeurInvalid)
        {
            Ped deadChauffeur = st.chauffeur;
            Vehicle oldVehicle = st.chauffeurVehicle;

            if (deadChauffeur && core::Exists((Entity)(deadChauffeur)) && core::IsPed((Entity)deadChauffeur) && !core::IsPlayerPed((Entity)(deadChauffeur)))
                DeleteEntityAndUntrackIfGone((Entity)deadChauffeur, true);
            else
                RemoveTrackedEntity((Entity)deadChauffeur);

            if (oldVehicle && IsVehicleDestroyedOrInvalid(oldVehicle))
            {
                if (core::Exists((Entity)(oldVehicle)) && core::IsVehicle((Entity)oldVehicle) && !IsPlayerInVehicleEntity(oldVehicle))
                    DeleteEntityAndUntrackIfGone((Entity)oldVehicle, false);
                else if (!core::Exists((Entity)(oldVehicle)) || !core::IsVehicle((Entity)oldVehicle))
                    RemoveTrackedEntity((Entity)oldVehicle);
            }

            st.chauffeur = 0;
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
            ++fixes;
            RecordAutoRecoveryAction("chauffeur invalid/dead; active chauffeur cleared, respawn available from NPC menu", &st.autoRecoveryChauffeurFixes, notifyResult);
        }

        if (st.chauffeurVehicle && IsVehicleDestroyedOrInvalid(st.chauffeurVehicle))
        {
            Vehicle brokenVehicle = st.chauffeurVehicle;
            if (IsUsablePedHandle(st.chauffeur, false, false, false) && !core::IsPlayerPed((Entity)(st.chauffeur)))
                DeleteEntityAndUntrackIfGone((Entity)st.chauffeur, true);
            st.chauffeur = 0;
            if (core::Exists((Entity)(brokenVehicle)) && core::IsVehicle((Entity)brokenVehicle) && !IsPlayerInVehicleEntity(brokenVehicle))
                DeleteEntityAndUntrackIfGone((Entity)brokenVehicle, false);
            else if (!core::Exists((Entity)(brokenVehicle)) || !core::IsVehicle((Entity)brokenVehicle))
                RemoveTrackedEntity((Entity)brokenVehicle);
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
            ++fixes;
            RecordAutoRecoveryAction("chauffeur vehicle invalid/destroyed; chauffeur state cleared", &st.autoRecoveryChauffeurFixes, notifyResult);
        }

        if (!st.chauffeur && !st.chauffeurVehicle)
            ClearChauffeurRuntimeState();

        return fixes;
    }

    static int RecoverStuckBodyguards(bool notifyResult)
    {
        int fixed = 0;
        if (st.bodyguards.empty()) return 0;

        DWORD now = GetTickCount();
        Ped player = 0;
        if (!GetPlayerPedSafe(player)) return 0;
        Vector3 pp{};
        if (!TryGetPlayerPosition(pp)) return 0;
        float farSq = cfg.bodyguardStuckRadius * cfg.bodyguardStuckRadius;
        int idx = 0;

        for (Ped g : st.bodyguards)
        {
            if (!IsUsablePedHandle(g, false, true, true)) { DropInvalidTrackedEntity((Entity)g); ClearBodyguardRuntimeState(g); ++idx; continue; }
            if (IsCompanionVehicleTaskProtected(g))
            {
                // BUGFIX 116: stuck-recovery teleport must not cancel a protected
                // leave/enter/transfer handoff. Keep the recovery baseline fresh
                // while the NPC is running to the player's new vehicle.
                Vector3 protectedPos{};
                if (TryGetUsableEntityPosition((Entity)g, protectedPos))
                {
                    st.bodyguardLastRecoveryPos[g] = protectedPos;
                    st.bodyguardLastMoveTick[g] = now;
                }
                ++idx;
                continue;
            }
            if (core::IsPedInAnyVehicle((Ped)(g), false))
            {
                Vector3 inVehiclePos{};
                if (TryGetUsableEntityPosition((Entity)g, inVehiclePos))
                {
                    st.bodyguardLastRecoveryPos[g] = inVehiclePos;
                    st.bodyguardLastMoveTick[g] = now;
                }
                ++idx;
                continue;
            }

            Vector3 gp{};
            if (!TryGetUsableEntityPosition((Entity)g, gp))
            {
                ClearBodyguardRuntimeState(g);
                ++idx;
                continue;
            }
            auto posIt = st.bodyguardLastRecoveryPos.find(g);
            if (posIt == st.bodyguardLastRecoveryPos.end())
            {
                st.bodyguardLastRecoveryPos[g] = gp;
                st.bodyguardLastMoveTick[g] = now;
                ++idx;
                continue;
            }

            float movedSq = DistanceSq(posIt->second, gp);
            if (movedSq > 0.75f * 0.75f)
            {
                posIt->second = gp;
                st.bodyguardLastMoveTick[g] = now;
                ++idx;
                continue;
            }

            DWORD lastMove = st.bodyguardLastMoveTick[g];
            if (lastMove == 0) st.bodyguardLastMoveTick[g] = now;

            if (DistanceSq(pp, gp) > farSq && core::TickElapsed(now, st.bodyguardLastMoveTick[g], SafeIntervalFromIntMs(cfg.bodyguardStuckMs, 7000, 1000, 120000, "bodyguards", "stuck interval")))
            {
                Vector3 off = BodyguardFollowOffset(idx);
                core::safe_native::ClearPedTasks(g, false, &g_coreErrors, "bodyguards");
                Vector3 target = core::MakeVector(pp.x + off.x, pp.y + off.y, pp.z);
                if (core::safe_native::SetCoords((Entity)g, target, true, &g_coreErrors, "bodyguards"))
                {
                    if (!TrySeatFriendlyNpcInPlayerVehicleOrSuppressFootFollow(g, "bodyguards", true))
                        SafeTaskFollowToOffset(g, (Entity)player, off.x, off.y, off.z, 2.4f, -1, std::max(1.5f, cfg.bodyguardFollowDistance), true, "bodyguards");
                    Vector3 recoveredPos{};
                    if (TryGetStrictTrackedEntityPosition((Entity)g, recoveredPos))
                    {
                        st.bodyguardLastRecoveryPos[g] = recoveredPos;
                        st.bodyguardLastMoveTick[g] = now;
                        ++fixed;
                    }
                    else
                    {
                        ClearBodyguardRuntimeState(g);
                        DropInvalidTrackedEntity((Entity)g);
                    }
                }
                else
                {
                    ClearBodyguardRuntimeState(g);
                    DropInvalidTrackedEntity((Entity)g);
                }
            }
            ++idx;
        }

        if (fixed > 0)
            RecordAutoRecoveryAction("teleported " + std::to_string(fixed) + " stuck bodyguard(s)", &st.autoRecoveryBodyguardFixes, notifyResult);
        return fixed;
    }

    static bool MissionObjectiveNeedsTrackedEntity(MissionObjectiveType type)
    {
        switch (type)
        {
            case MissionObjectiveType::KillEnemies:
            case MissionObjectiveType::ProtectAllies:
            case MissionObjectiveType::EscortVehicle:
            case MissionObjectiveType::StealVehicle:
            case MissionObjectiveType::CollectItem:
            case MissionObjectiveType::DestroyObject:
            case MissionObjectiveType::FollowNpc:
                return true;
            default:
                return false;
        }
    }

    static int RecoverMissionCreatorState(bool notifyResult)
    {
        if (!st.missionPlaytestActive) return 0;
        CompactMissionSpawnedEntityLists();

        if (st.currentMission.objectives.empty() || st.missionActiveObjective < 0 || st.missionActiveObjective >= (int)st.currentMission.objectives.size())
        {
            StopMissionPlaytest(false);
            RecordAutoRecoveryAction("mission playtest stopped safely: invalid objective index", &st.autoRecoveryMissionFixes, notifyResult);
            return 1;
        }

        const MissionObjectiveDef& obj = st.currentMission.objectives[st.missionActiveObjective];
        if (MissionObjectiveNeedsTrackedEntity(obj.type) && !st.currentMission.entities.empty() && st.missionSpawnedEntities.empty())
        {
            StopMissionPlaytest(false);
            RecordAutoRecoveryAction("mission playtest stopped safely: target entities were lost", &st.autoRecoveryMissionFixes, notifyResult);
            return 1;
        }
        return 0;
    }

    static bool ShouldRunAutoRecoveryModule(bool moduleEnabled, bool forceWhenDisabled)
    {
        return moduleEnabled || forceWhenDisabled;
    }

    static int RecoverUiStateNow(bool notifyResult)
    {
        int fixes = 0;
        int pageValue = static_cast<int>(st.page);
        if (pageValue < static_cast<int>(Page::Main) || pageValue > static_cast<int>(Page::Settings))
        {
            st.page = Page::Main;
            st.selected = 0;
            st.pageStack.clear();
            ++fixes;
            RecordAutoRecoveryAction("UI page reset from invalid state", &st.autoRecoveryUiFixes, notifyResult);
        }

        if (st.pageStack.size() > 48)
        {
            st.pageStack.clear();
            ++fixes;
            RecordAutoRecoveryAction("UI navigation stack trimmed", &st.autoRecoveryUiFixes, notifyResult);
        }

        if (st.selected < 0)
        {
            st.selected = 0;
            ++fixes;
            RecordAutoRecoveryAction("UI selected index fixed", &st.autoRecoveryUiFixes, notifyResult);
        }

        const size_t undoBefore = st.undoStack.size();
        const size_t redoBefore = st.redoStack.size();
        CompactUndoRedoStacks();
        if (st.undoStack.size() != undoBefore || st.redoStack.size() != redoBefore)
        {
            ++fixes;
            RecordAutoRecoveryAction("Undo / Redo history compacted", &st.autoRecoveryUiFixes, notifyResult);
        }

        return fixes;
    }

    static int RecoverCompanionRuntimeState(bool notifyResult)
    {
        int fixes = 0;
        auto rememberVehicle = [&](Vehicle vehicle)
        {
            if (!IsUsableVehicleHandle(vehicle, true)) return;
            size_t before = st.spawnedVehicles.size();
            TrackSpawnedVehicleIfAlive(vehicle);
            if (st.spawnedVehicles.size() > before) ++fixes;
        };

        if (st.chauffeurVehicle && !IsUsableVehicleHandle(st.chauffeurVehicle, true))
        {
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
            ++fixes;
        }
        if (st.bodyguardProtectedVehicle && !IsUsableVehicleHandle(st.bodyguardProtectedVehicle, true))
        {
            st.bodyguardProtectedVehicle = 0;
            ++fixes;
        }
        if (st.garageLastLoadedVehicle && !IsUsableVehicleHandle(st.garageLastLoadedVehicle, true))
        {
            st.garageLastLoadedVehicle = 0;
            st.garageLastLoadedSlot = 0;
            ++fixes;
        }

        rememberVehicle(st.chauffeurVehicle);
        rememberVehicle(st.bodyguardProtectedVehicle);
        rememberVehicle(st.lastPlayerVehicleForBodyguards);
        rememberVehicle(st.garageLastLoadedVehicle);
        SanitizeCompanionRuntimeState();

        if (fixes > 0)
            RecordAutoRecoveryAction("companion/garage runtime references repaired", &st.autoRecoveryBodyguardFixes, notifyResult);
        return fixes;
    }

    static int RecoverWorldCleanupState(bool notifyResult)
    {
        int fixes = 0;
        if (cfg.smartCleanupIncludeWorldDirector && CountExistingMixedEntities(st.worldDirectorEntities) > cfg.worldDirectorMaxTrackedEntities)
            fixes += CleanFarMixedEntities(st.worldDirectorEntities, (float)cfg.worldDirectorCleanupRadius * (float)cfg.worldDirectorCleanupRadius);
        if (cfg.smartCleanupIncludeUrbanLife && CountExistingMixedEntities(st.urbanLifeEntities) > cfg.urbanLifeMaxTrackedEntities)
            fixes += CleanFarMixedEntities(st.urbanLifeEntities, (float)cfg.urbanLifeCleanupRadius * (float)cfg.urbanLifeCleanupRadius);

        if (fixes > 0)
            RecordAutoRecoveryAction("world/urban cleanup overflow fixed " + std::to_string(fixes) + " entity(s)", &st.autoRecoveryInvalidCleanups, notifyResult);
        return fixes;
    }

    static int RunAutoRecoveryScan(bool notifyResult, bool forceWhenDisabled)
    {
        if (!cfg.autoRecoveryEnabled && !forceWhenDisabled)
        {
            if (notifyResult) Notify("Auto Recovery: disabled.");
            return 0;
        }

        int fixes = 0;
        if (ShouldRunAutoRecoveryModule(cfg.autoRecoverPlayer, forceWhenDisabled)) fixes += RecoverPlayerEmergencyState(notifyResult);
        if (ShouldRunAutoRecoveryModule(cfg.autoRecoverCurrentVehicle, forceWhenDisabled)) fixes += RecoverCurrentVehicleEmergencyState(notifyResult);
        if (ShouldRunAutoRecoveryModule(cfg.autoRecoverInvalidEntities, forceWhenDisabled)) fixes += CompactInvalidTrackedEntities(notifyResult);
        if (ShouldRunAutoRecoveryModule(cfg.autoRecoverBlips, forceWhenDisabled)) fixes += RecoverBlipState(notifyResult);
        if (ShouldRunAutoRecoveryModule(cfg.autoRecoverChauffeur, forceWhenDisabled)) fixes += RecoverChauffeurState(notifyResult);
        if (ShouldRunAutoRecoveryModule(cfg.autoRecoverBodyguards, forceWhenDisabled)) fixes += RecoverStuckBodyguards(notifyResult);
        if (ShouldRunAutoRecoveryModule(cfg.autoRecoverCompanionRuntime, forceWhenDisabled)) fixes += RecoverCompanionRuntimeState(notifyResult);
        if (ShouldRunAutoRecoveryModule(cfg.autoRecoverWorldCleanupState, forceWhenDisabled)) fixes += RecoverWorldCleanupState(notifyResult);
        if (ShouldRunAutoRecoveryModule(cfg.autoRecoverMissionCreator, forceWhenDisabled)) fixes += RecoverMissionCreatorState(notifyResult);
        if (ShouldRunAutoRecoveryModule(cfg.autoRecoverUi, forceWhenDisabled)) fixes += RecoverUiStateNow(notifyResult);
        if (notifyResult && fixes == 0) Notify("Auto Recovery: no stuck states found.");
        return fixes;
    }

    static void TickAutoRecovery()
    {
        if (!cfg.autoRecoveryEnabled) return;
        DWORD now = GetTickCount();
        if (st.lastAutoRecoveryTick != 0 && !core::TickElapsed(now, st.lastAutoRecoveryTick, SafeIntervalFromIntMs(cfg.autoRecoveryIntervalMs, 1200, 250, 60000, "auto_recovery", "interval"))) return;
        st.lastAutoRecoveryTick = now;
        RunAutoRecoveryScan(false);
    }



    static std::string GameModeName(GameModeType type)
    {
        switch (type)
        {
            case GameModeType::CoreTest: return "Core Test Mode";
            case GameModeType::ChaosSurvival: return "Chaos Survival";
            case GameModeType::ChauffeurVip: return "Chauffeur VIP";
            case GameModeType::BodyguardDefense: return "Bodyguard Defense";
            case GameModeType::ContractMode: return "Contract Mode";
            case GameModeType::RandomMission: return "Random Mission Generator";
            case GameModeType::MovieScene: return "Movie Scene Mode";
            case GameModeType::None:
            default: return "None";
        }
    }

