    {
        switch (phase)
        {
            case GameModePhase::Setup: return "Setup";
            case GameModePhase::Running: return "Running";
            case GameModePhase::Paused: return "Paused";
            case GameModePhase::Completed: return "Completed";
            case GameModePhase::Failed: return "Failed";
            case GameModePhase::Idle:
            default: return "Idle";
        }
    }

    static std::string FormatGameModeTime(int ms)
    {
        if (ms < 0) ms = 0;
        int total = ms / 1000;
        int min = total / 60;
        int sec = total % 60;
        std::ostringstream ss;
        ss << min << ":" << std::setw(2) << std::setfill('0') << sec;
        return ss.str();
    }


