    static int RandomIntInclusive(int low, int high)
    {
        if (high < low) std::swap(low, high);
        if (high == low) return low;
        if (high == std::numeric_limits<int>::max())
            return SafeRandomIntRuntime(low, high, low, "movie_scene");
        return SafeRandomIntRuntime(low, high + 1, low, "movie_scene");
    }

    static std::string PickRandomText(const std::vector<std::string>& values, const std::string& fallback)
    {
        if (values.empty()) return fallback;
        int idx = RandomIntInclusive(0, (int)values.size() - 1);
        if (idx < 0 || idx >= (int)values.size()) idx = 0;
        return values[idx];
    }

    static Vector3 RandomMissionPointAroundPlayer(float minDistance, float maxDistance)
    {
        minDistance = std::max(30.0f, minDistance);
        maxDistance = std::max(minDistance + 10.0f, maxDistance);
        Ped playerPed = 0;
        Vector3 center{};
        if (!GetPlayerPedSafe(playerPed)) return InvalidWorldVector();
        Vector3 raw{};
        if (!TryGetStrictTrackedEntityPosition((Entity)playerPed, raw)) return InvalidWorldVector();
        center = raw;
        float angle = (float)RandomIntInclusive(0, 359) * 0.0174532924f;
        float dist = (float)RandomIntInclusive((int)minDistance, (int)maxDistance);
        center.x += cosf(angle) * dist;
        center.y += sinf(angle) * dist;
        center.z = ResolveGroundZ(center.x, center.y, center.z) + 0.25f;
        if (!IsUsableWorldPosition(center, -200.0f, 2000.0f))
            return InvalidWorldVector();
        if (cfg.randomMission4Enabled && cfg.randomMissionPreferRoadTargets)
        {
            Vector3 node{};
            for (int i = 1; i <= 6; ++i)
            {
                if (SafeGetClosestVehicleNodeRuntime(center, i, node, "mission_pathfind"))
                {
                    node.z = ResolveGroundZ(node.x, node.y, node.z) + 0.25f;
                    if (IsUsableWorldPosition(node, -200.0f, 2000.0f))
                        return node;
                }
            }
        }
        return center;
    }

    static void ClearRandomMissionBlip()
    {
        Blip b = st.gameMode.randomMissionBlip;
        if (b && SafeDoesBlipExistRuntime(b)) SafeRemoveBlipRuntime(b);
        st.gameMode.randomMissionBlip = 0;
    }

    static void SetRandomMissionBlip(Vector3 pos)
    {
        ClearRandomMissionBlip();
        Blip b = SafeAddBlipForCoordRuntime(pos);
        if (b)
        {
            SafeSetBlipSpriteRuntime(b, 1);
            SafeSetBlipColourRuntime(b, 5);
            SafeSetBlipScaleRuntime(b, 0.90f);
            SafeSetBlipShortRangeRuntime(b, false);
            SafeSetBlipRouteRuntime(b, true);
            st.gameMode.randomMissionBlip = b;
        }
    }

    static std::string BuildRandomMissionObjectiveText()
    {
        std::string text = st.gameMode.randomMissionTitle.empty() ? RandomMissionKindName(st.gameMode.randomMissionKind) : st.gameMode.randomMissionTitle;
        if (cfg.randomMissionDetailedBriefing && !st.gameMode.randomMissionLocation.empty()) text += " / " + st.gameMode.randomMissionLocation;
        if (cfg.randomMissionDetailedBriefing && cfg.randomMissionChainLength > 1)
        {
            int stage = ClampIntValue(st.randomMissionChainProgress <= 0 ? 1 : st.randomMissionChainProgress, 1, cfg.randomMissionChainLength);
            text += " / Chain " + std::to_string(stage) + "/" + std::to_string(cfg.randomMissionChainLength);
        }
        if (cfg.randomMissionDetailedBriefing && !st.gameMode.randomMissionConstraint.empty()) text += " / Rule: " + st.gameMode.randomMissionConstraint;
        if (cfg.randomMissionDetailedBriefing && !st.gameMode.randomMissionComplication.empty()) text += " / Twist: " + st.gameMode.randomMissionComplication;
        return text;
    }

    static void SetRandomMissionObjectiveStatus(const std::string& status)
    {
        std::string prefix = BuildRandomMissionObjectiveText();
        std::string full = prefix.empty() ? status : (prefix + " -> " + status);
        if (cfg.randomMission4Enabled)
        {
            if (st.gameMode.randomMissionBonusActive && !st.gameMode.randomMissionBonusCompleted && !st.gameMode.randomMissionBonusText.empty())
                full += " / Bonus: " + st.gameMode.randomMissionBonusText;
            else if (st.gameMode.randomMissionBonusCompleted)
                full += " / Bonus complete";
        }
        st.gameMode.objectiveText = full;
    }

    static void ClearRandomMissionWantedSideEffects()
    {
        if (st.gameMode.type == GameModeType::RandomMission && st.gameMode.randomMissionWantedApplied)
        {
            SafeSetPlayerWantedLevelRuntime(0, true, "random_mission_cleanup");
            RestoreNaturalWantedSuppressionRuntime("random_mission_cleanup");
            st.gameMode.randomMissionWantedApplied = false;
        }
        st.gameMode.randomMissionLargeScale = false;
    }

    static int RandomMissionAliveTrackedEnemies()
    {
        int alive = 0;
        for (Entity e : st.gameMode.trackedEntities)
        {
            if (!e || !core::Exists((Entity)(e)) || !core::IsPed((Entity)(e))) continue;
            Ped p = (Ped)e;
            // Friendly VIPs, hostages and staged allies are tracked for cleanup too.
            // Only hostile mission peds should keep combat/survival objectives alive.
            if (!IsGameModeEnemyPed(p)) continue;
            if (!core::IsPedDeadOrDying((Ped)(p), true, true)) ++alive;
        }
        return alive;
    }

    static bool RandomMissionPedAlive(Ped ped)
    {
        if (!ped || !core::Exists((Entity)(ped)) || core::IsPedDeadOrDying((Ped)(ped), true, true)) return false;
        Vector3 pos{};
        return TryGetStrictTrackedEntityPosition((Entity)ped, pos);
    }

    static bool RandomMissionVehicleUsable(Vehicle vehicle)
    {
        if (!vehicle || !core::Exists((Entity)(vehicle)) || (int)core::SafeGetEntityHealth((Entity)(vehicle), 0) <= 0) return false;
        Vector3 pos{};
        return TryGetStrictTrackedEntityPosition((Entity)vehicle, pos);
    }

    static float RandomMissionEscapeDistance(float baseDistance, float buffer, float minimum)
    {
        float configured = (float)std::max(cfg.randomMissionMaxDistance, cfg.randomMissionMinDistance);
        return std::max(minimum, std::max(baseDistance, configured + buffer));
    }

    static bool RandomMissionPedInPlayerVehicle(Ped ped)
    {
        Ped player = 0;
        if (!GetPlayerPedSafe(player)) return false;
        if (!RandomMissionPedAlive(ped) || !core::IsPedInAnyVehicle((Ped)(player), false) || !core::IsPedInAnyVehicle((Ped)(ped), false)) return false;
        return (Vehicle)core::GetVehiclePedIsIn((Ped)(player), false) == (Vehicle)core::GetVehiclePedIsIn((Ped)(ped), false);
    }

    static void RandomMissionMakePedEnterPlayerVehicle(Ped ped, int preferredSeat)
    {
        Ped player = 0;
        if (!GetPlayerPedSafe(player)) return;
        if (!RandomMissionPedAlive(ped) || !core::IsPedInAnyVehicle((Ped)(player), false)) return;

        Vehicle playerVehicle = core::GetVehiclePedIsIn((Ped)(player), false);
        if (!playerVehicle || !core::Exists((Entity)(playerVehicle))) return;

        if (core::IsPedInAnyVehicle((Ped)(ped), false) && (Vehicle)core::GetVehiclePedIsIn((Ped)(ped), false) == playerVehicle) return;

        int maxSeat = std::max(0, std::min(15, cfg.bodyguardsVehicleSeatSearchMax));
        int seat = -2;
        if (preferredSeat >= 0 && preferredSeat <= maxSeat && core::IsVehicleSeatFree((Vehicle)(playerVehicle), preferredSeat))
        {
            seat = preferredSeat;
        }
        else
        {
            seat = FindNextFreePassengerSeat(playerVehicle, 0, maxSeat);
        }

        if (seat >= 0)
            SeatPedInVehicleOrTaskEnter(ped, playerVehicle, seat, true, 8000, "random_mission");
        else
            SuppressFriendlyFootFollowWhilePlayerIsDriving(ped, "random_mission");
    }

    static int RandomMissionActiveEntityCount();

    static int SpawnRandomMissionGuards(Vector3 center, int count, const std::string& model, const std::string& weapon, int health)
    {
        if (!IsUsableWorldPosition(center, -200.0f, 2000.0f)) return 0;
        const int scaleLimit = st.gameMode.randomMissionLargeScale ? 60 : 24;
        const int remainingSlots = std::max(0, cfg.randomMissionMaxActiveEntities - RandomMissionActiveEntityCount());
        count = ClampIntValue(count, 0, std::min(scaleLimit, remainingSlots));
        if (count <= 0) return 0;
        int spawned = 0;
        for (int i = 0; i < count; ++i)
        {
            float angle = ((float)i / std::max(1, count)) * 6.283185307f;
            Vector3 pos = center;
            pos.x += cosf(angle) * (8.0f + (float)(i % 3) * 2.5f);
            pos.y += sinf(angle) * (8.0f + (float)(i % 3) * 2.5f);
            pos.z = ResolveGroundZ(pos.x, pos.y, pos.z) + 0.15f;
            if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f)) continue;
            Ped guard = SpawnPedAtModel(model, Relation::Enemy, health, weapon, 500, pos, 0.0f, false);
            if (guard)
            {
                st.enemies.push_back(guard);
                TrackGameModeEntity((Entity)guard);
                ++spawned;
            }
        }
        return spawned;
    }


    static bool IsLargeRandomMissionKind(RandomMissionKind kind)
    {
        return kind == RandomMissionKind::StrongholdRaid ||
               kind == RandomMissionKind::MegaConvoyAttack ||
               kind == RandomMissionKind::HostageRescue ||
               kind == RandomMissionKind::ArmoredCargoRun ||
               kind == RandomMissionKind::CitywideCheckpointRun ||
               kind == RandomMissionKind::GangTerritorySweep ||
               kind == RandomMissionKind::EmergencyEvacuation ||
               kind == RandomMissionKind::SmugglerRun;
    }

    static Vector3 GameModeOffsetFromOrigin(Vector3 origin, float heading, float forward, float right, bool forVehicle)
    {
        if (!IsUsableWorldPosition(origin, -200.0f, 2000.0f))
            origin = EmergencyRecoveryLandmark();
        heading = NormalizeHeading(heading, 0.0f);
        float rad = heading * 0.0174532924f;
        Vector3 p = origin;
        p.x += (-sinf(rad) * forward) + (-sinf(rad + 1.5707963f) * right);
        p.y += ( cosf(rad) * forward) + ( cosf(rad + 1.5707963f) * right);
        p.z = ResolveGroundZ(p.x, p.y, p.z) + (forVehicle ? 0.45f : 0.10f);
        if (!IsUsableWorldPosition(p, -200.0f, 2000.0f))
            p = origin;
        return p;
    }

    static Vehicle SpawnRandomMissionVehicleWithDriver(const std::string& vehicleModel, const std::string& driverModel, Vector3 pos, float heading, const std::string& weapon, int health, bool chasePlayer, Ped* outDriver = nullptr)
    {
        if (outDriver) *outDriver = 0;
        if (!IsUsableWorldPosition(pos, -200.0f, 2000.0f)) return 0;
        // A vehicle-with-driver consumes two tracked entity slots. Respect the RMG entity cap
        // before spawning either one, otherwise failed large jobs can flood the save/session.
        if (RandomMissionActiveEntityCount() + 2 > cfg.randomMissionMaxActiveEntities) return 0;
        Vehicle v = SpawnVehicleByModelAt(vehicleModel, pos, heading, false, false, false, false);
        if (!v) return 0;
        TrackGameModeEntity((Entity)v);
        Ped driver = SpawnPedAtModel(driverModel, Relation::Enemy, health, weapon, 600, pos, heading, false, false);
        if (!driver)
        {
            DeleteGameModeEntityAndUntrackIfGone((Entity)v, false);
            return 0;
        }
        st.enemies.push_back(driver);
        TrackGameModeEntity((Entity)driver);
        if (outDriver) *outDriver = driver;
        core::SetPedIntoVehicleSafe((Ped)(driver), (Vehicle)(v), -1);
        if (chasePlayer)
        {
            Ped playerPed = 0;
            if (GetPlayerPedSafe(playerPed)) SafeTaskVehicleChase(driver, playerPed, "scenario");
            else SafeTaskVehicleDriveWander(driver, v, 24.0f, 786603, "full_audit");
        }
        else SafeTaskVehicleDriveWander(driver, v, 24.0f, 786603, "full_audit");
        return v;
    }


