                st.gameMode.objectiveText = "Reach the stranded driver and bring them to safety.";
                Vehicle broken = SpawnVehicleByModelAt("emperor", st.gameMode.randomMissionTarget, 0.0f, false, false, false, false);
                if (broken)
                {
                    SafeSetVehicleEngineHealth(broken, 120.0f, "random_mission");
                    SafeVehicleRuntimeNative(broken, "full_audit", "disable broken vehicle engine", [&](){ VEHICLE::SET_VEHICLE_ENGINE_ON(broken, false, true, true); });
                    TrackGameModeEntity((Entity)broken);
                }
                Vector3 driverPos = st.gameMode.randomMissionTarget; driverPos.x += 2.0f; driverPos.z = ResolveGroundZ(driverPos.x, driverPos.y, driverPos.z) + 0.15f;
