                int spawnedB = SpawnRandomMissionGuards(GameModeOffsetFromOrigin(st.gameMode.randomMissionTarget, 0.0f, 8.0f, 0.0f, false), std::max(2, enemyCount / 2 + 1), "g_m_y_lost_02", "WEAPON_SMG", enemyHealth);
