    struct MenuItem
    {
        std::string label;
        std::string value;
        std::function<void()> action;
        bool isToggle = false;
        bool* toggle = nullptr;
        std::string description;

        MenuItem() = default;
        MenuItem(std::string itemLabel, std::string itemValue, std::function<void()> itemAction, std::string itemDescription = "")
            : label(std::move(itemLabel)), value(std::move(itemValue)), action(std::move(itemAction)), description(std::move(itemDescription)) {}
        MenuItem(std::string itemLabel, std::string itemValue, std::function<void()> itemAction, bool toggleItem, bool* togglePtr, std::string itemDescription = "")
            : label(std::move(itemLabel)), value(std::move(itemValue)), action(std::move(itemAction)), isToggle(toggleItem), toggle(togglePtr), description(std::move(itemDescription)) {}
    };

    struct QuickFavoriteEntry
    {
        Page sourcePage = Page::Main;
        std::string sourceSearchQuery;
        MenuItem item;
    };

    static std::vector<QuickFavoriteEntry> quickFavorites;
    static const int maxQuickFavorites = 20;
    static std::vector<MenuItem> BuildMenu();
