    static bool ExecuteQuickFavoriteEntry(const QuickFavoriteEntry& fav);

    static std::string OnOff(bool v) { return v ? "ON" : "OFF"; }

    static bool IsMenuSeparatorLabel(const std::string& label)
    {
        const std::string clean = Trim(label);
        return clean.size() >= 4 && clean.rfind("==", 0) == 0 && clean.substr(clean.size() - 2) == "==";
    }

    static std::string CleanMenuSeparatorText(const std::string& label)
    {
        std::string clean = Trim(label);
        if (clean.rfind("==", 0) == 0) clean = Trim(clean.substr(2));
        if (clean.size() >= 2 && clean.substr(clean.size() - 2) == "==") clean = Trim(clean.substr(0, clean.size() - 2));
        return clean;
    }

    static bool IsMenuSeparatorItem(const MenuItem& item)
    {
        return IsMenuSeparatorLabel(item.label) && !item.action && !(item.isToggle && item.toggle);
    }

    static bool IsMenuExecutableItem(const MenuItem& item)
    {
        return item.action || (item.isToggle && item.toggle);
    }

    static bool IsMenuSelectableItem(const MenuItem& item)
    {
        // BUGFIX 170: Premium UX introduced more compact informational rows.
        // They must be visible, but they should not receive focus or appear
        // executable; otherwise arrows can highlight rows such as Status,
        // Last Report or Current Vehicle and Enter appears broken.
        return !IsMenuSeparatorItem(item) && IsMenuExecutableItem(item);
    }

    static int FindFirstSelectableMenuIndex(const std::vector<MenuItem>& items)
    {
        for (int i = 0; i < (int)items.size(); ++i)
        {
            if (IsMenuSelectableItem(items[i])) return i;
        }
        return 0;
    }

    static int FindNextSelectableMenuIndex(const std::vector<MenuItem>& items, int start, int direction)
    {
        if (items.empty()) return 0;
        const int count = (int)items.size();
        if (direction == 0) direction = 1;
        int index = start;
        for (int step = 0; step < count; ++step)
        {
            index = (index + direction + count) % count;
            if (IsMenuSelectableItem(items[index])) return index;
        }
        return std::max(0, std::min(start, count - 1));
    }

    static bool ClampMenuSelectionForItems(const std::vector<MenuItem>& items)
    {
        if (items.empty())
        {
            if (st.selected != 0)
            {
                st.selected = 0;
                return true;
            }
            return false;
        }
        const int maxIndex = static_cast<int>(items.size()) - 1;
        int wanted = st.selected;
        if (wanted < 0) wanted = 0;
        if (wanted > maxIndex) wanted = maxIndex;
        if (!IsMenuSelectableItem(items[wanted]))
        {
            int down = wanted;
            for (int step = 0; step < (int)items.size(); ++step)
            {
                if (IsMenuSelectableItem(items[down])) { wanted = down; break; }
                down = (down + 1) % (int)items.size();
            }
            if (!IsMenuSelectableItem(items[wanted])) wanted = FindFirstSelectableMenuIndex(items);
        }
        if (st.selected != wanted)
        {
            st.selected = wanted;
            return true;
        }
        return false;
    }

    static int SanitizeMenuPageStack()
    {
        int removed = 0;
        std::vector<Page> clean;
        clean.reserve(std::min<std::size_t>(st.pageStack.size(), 48));

        for (Page rawPage : st.pageStack)
        {
            Page page = ValidPageOrMain(rawPage);
            if (page == Page::Main && rawPage != Page::Main)
            {
                ++removed;
                continue;
            }
            if (page == st.page)
            {
                ++removed;
                continue;
            }
            if (!clean.empty() && clean.back() == page)
            {
                ++removed;
                continue;
            }
            clean.push_back(page);
        }

        if (clean.size() > 48)
        {
            removed += static_cast<int>(clean.size() - 48);
            clean.erase(clean.begin(), clean.end() - 48);
        }

        if (removed > 0 || clean.size() != st.pageStack.size())
            st.pageStack.swap(clean);
        return removed;
    }

    static bool HasNumericSuffixAfterPrefix(const std::string& label, const std::string& prefix)
    {
        if (label.rfind(prefix, 0) != 0) return false;
        std::string suffix = Trim(label.substr(prefix.size()));
        if (suffix.empty()) return false;
        size_t i = 0;
        while (i < suffix.size() && std::isdigit(static_cast<unsigned char>(suffix[i]))) ++i;
        return i > 0 && (i == suffix.size() || std::isspace(static_cast<unsigned char>(suffix[i])) || suffix[i] == '/' || suffix[i] == ':' || suffix[i] == '-');
    }

    static bool IsTransientQuickFavoriteControlLabel(const std::string& clean)
    {
        static const char* kExactTransientLabels[] =
        {
            "Previous Page",
            "Next Page",
            "Page -",
            "Page +",
            "Garage Page -",
            "Garage Page +",
            "Vehicle Page -",
            "Vehicle Page +",
            "Object Page -",
            "Object Page +",
            "Objective Page -",
            "Objective Page +",
            "Components Previous Page",
            "Components Next Page",
            "Category",
            "Selected Favorite",
            "Selected History",
            "Selected Slot",
            "Selected Garage Slot",
            "Selected Outfit Slot",
            "Selected Preset Slot",
            "Selected Profile Slot",
            "Current Slot Info",
            "Slot",
            "Component Slot",
            "Prop Slot",
            "Backup Slot",
            "Search Query",
            "Selected Model",
            "Selected Weapon",
            "Selected Ped",
            "Selected Vehicle",
            "Selected Object",
            "Selected Weather",
            "Selected Animation",
            "Selected Wanted Level",
            "Selected Mode",
            "Selected Scene",
            "Selected Builder Preset",
            "Selected Template",
            "Selected Objective",
            "Selected Movie Scene",
            "Selected Smart Preset",
            "Target Character",
            "Skill Value Preset",
            "Money Preset",
            "Custom Skill Value",
            "Custom Money Value",
            "Current Vehicle Status",
            "Current Vehicle Recovery",
            "Current Preset Name",
            "Current Movie Scene",
            "Current Wave",
            "Current Slot Info",
            "Last Vehicle Tool",
            "Last Teleport",
            "Last Map Tool Report",
            "Last Witness Report",
            "Last Police Action",
            "Last Builder Report",
            "Last Cleanup Report",
            "Last Backup",
            "Last Result",
            "Last Report",
            "Status",
            "Core Runtime",
            "Core Last Error",
            "Health Status",
            "Ped Browser Page",
            "No Favorites Yet",
            "No Ped Models In Catalog",
            "No Vehicles In Catalog",
            "No Add-On Vehicles",
            "No Objects In Catalog",
            "No Teleport Favorites",
            "No Teleport History",
            "No Search Results",
            "Search Page"
        };

        for (const char* exact : kExactTransientLabels)
        {
            if (clean == exact) return true;
        }

        // Browser/category page controls mutate local pagination state. Copying
        // their lambdas into Quick Favorites can later change a different list
        // than the user expected after catalogs are reloaded or pages rebuilt.
        if (clean.size() >= 5 && clean.compare(clean.size() - 5, 5, " Page") == 0) return true;
        if (clean.rfind("Selected ", 0) == 0) return true;
        if (clean.rfind("Current ", 0) == 0) return true;
        if (clean.rfind("Last ", 0) == 0) return true;
        // Do not blanket-block stable actions such as "No Wanted", "No Reload",
        // "No Traffic" or menu entries such as "Teleport History". Placeholders are
        // handled by exact labels above, while dynamic history rows are handled by
        // numeric prefixes below.
        if (clean.find(" Page ") != std::string::npos) return true;
        if (clean.find(" Slot") != std::string::npos && (clean.rfind("Save ", 0) != 0 && clean.rfind("Load ", 0) != 0)) return true;

        return false;
    }

    static Page CanonicalMergedMenuPage(Page page)
    {
        switch (page)
        {
            case Page::EntityInspector:
                return Page::ObjectSpawner;
            case Page::SmartProfiles:
                return Page::TrainerPresets;
            default:
                return page;
        }
    }

