    static void InitializeCore2Modules()
    {
        if (g_coreModulesRegistered) return;
        const DWORD now = GetTickCount();
        for (const Core2ModuleDef& module : kCore2ModuleDefs)
            g_coreModules.Register(module.id, module.label, core::ModuleStatus::Active, now);
        g_coreModulesRegistered = true;
        st.lastCore2Report = "Core 2.0 initialized / " + g_coreModules.Summary();
        st.lastCore2Error = g_coreErrors.LastProblemMessage();
    }

    static void SyncCore2RegistryFromErrors()
    {
        InitializeCore2Modules();
        g_coreModules.ReconcileFromEvents(g_coreErrors.Events(), GetTickCount());
    }

    static void RefreshCore2CountersOnly()
    {
        SyncCore2RegistryFromErrors();
        st.lastCore2Error = g_coreErrors.LastProblemMessage();
        st.core2WarningCount = g_coreErrors.WarningCount();
        st.core2ErrorCount = g_coreErrors.ErrorCount();
        st.core2FaultedModules = g_coreModules.CountByStatus(core::ModuleStatus::Faulted);
    }

    static void ReportCore2(core::ErrorSeverity severity, const std::string& module, const std::string& action, const std::string& message)
    {
        InitializeCore2Modules();
        std::string safeModule = core::SanitizeCoreText(module.empty() ? "core" : module, 96);
        std::string safeAction = core::SanitizeCoreText(action.empty() ? "runtime" : action, 96);
        std::string safeMessage = core::SanitizeCoreText(message.empty() ? "No details" : message, 512);
        if (safeModule.empty()) safeModule = "core";
        if (safeAction.empty()) safeAction = "runtime";
        if (safeMessage.empty()) safeMessage = "No details";
        const bool newDiagnosticEvent = g_coreErrors.Report(severity, safeModule, safeAction, safeMessage);
        if (newDiagnosticEvent)
            g_coreModules.Report(safeModule, severity, safeMessage);
        else
            g_coreModules.TouchDiagnostic(safeModule, severity, safeMessage);
        RefreshCore2CountersOnly();
        if (newDiagnosticEvent)
            Log(std::string("[Core2][") + core::SeverityName(severity) + "][" + safeModule + "][" + safeAction + "] " + safeMessage);
    }

    static int ClearResolvedCore2Problems(const std::string& module, const std::string& actionPrefix, core::ModuleStatus recoveredStatus, const std::string& message)
    {
        InitializeCore2Modules();
        const std::string safeModule = core::SanitizeCoreText(module, 96);
        const int cleared = g_coreErrors.ClearWhere(safeModule, actionPrefix);
        // ErrorReporter is a bounded ring buffer. By the time a subsystem reports
        // a clean scan, its old transient warning may already have been evicted;
        // the module counters still need to be cleared or the Core2 UI/recovery
        // baseline can stay faulted with zero visible events.
        if (!safeModule.empty())
            g_coreModules.ClearTransientProblems(safeModule, recoveredStatus, message);
        RefreshCore2CountersOnly();
        return cleared;
    }


    static bool RootFileExists(const std::string& name)
    {
        return !g_rootDir.empty() && FileExists(g_rootDir + name);
    }

    static bool AnyRootFileExists(const std::vector<std::string>& names)
    {
        for (const std::string& name : names) if (RootFileExists(name)) return true;
        return false;
    }

    static std::string FirstExistingRootFile(const std::vector<std::string>& names)
    {
        for (const std::string& name : names) if (RootFileExists(name)) return name;
        return "not found";
    }

    static bool WriteCompatibilityReportFile()
    {
        if (g_rootDir.empty())
        {
            Log("Compatibility report skipped: root directory is unresolved.");
            return false;
        }

        std::vector<std::string> lines;
        lines.push_back("Cao Urban Trainer ASI " + std::string(kTrainerVersion) + " - Mod Compatibility Report");
        lines.push_back("Generated: " + FileStamp());
        lines.push_back("RootDir=" + g_rootDir);
        lines.push_back("Summary=" + st.lastCompatibilityReport);
        lines.push_back("FallbackActive=" + OnOff(st.compatibilityFallbackActive));
        lines.push_back("FallbackSnapshotActive=" + OnOff(st.compatibilityFallbackSnapshotActive));
        lines.push_back("ScriptHookV=" + std::string(st.compatibilityScriptHookFound ? "found" : "missing"));
        lines.push_back("ASILoader=" + std::string(st.compatibilityAsiLoaderFound ? "found" : "missing"));
        lines.push_back("GTAExecutable=" + std::string(st.compatibilityGtaExeFound ? "found" : "missing"));
        lines.push_back("GTAEnhancedDetected=" + std::string(st.compatibilityEnhancedDetected ? "yes" : "no"));
        lines.push_back("OptionalUILibraries=" + std::string(st.compatibilityOptionalUiFound ? "found" : "missing"));
        lines.push_back("");
        for (const auto& check : g_coreCompatibility.Checks())
        {
            lines.push_back(std::string("[") + core::CompatibilityLevelName(check.level) + "] " + check.label + " - " + check.detail);
        }
        return AtomicWriteLines(CaoTrainerTextFilePath("CaoUrbanTrainerASI_COMPAT_REPORT.txt"), lines, true);
    }

    static void SaveCompatibilityFallbackSnapshot()
    {
        if (st.compatibilityFallbackSnapshotActive) return;
        st.compatibilityFallbackWorldDirectorActive = st.worldDirectorActive;
        st.compatibilityFallbackUrbanLifeActive = st.urbanLifeActive;
        st.compatibilityFallbackVehicleAIActive = st.vehicleAIActive;
        st.compatibilityFallbackPoliceRealismActive = st.policeRealismActive;
        st.compatibilityFallbackWorldDirectorAutoEvents = cfg.worldDirectorAutoEvents;
        st.compatibilityFallbackUrbanLifeAutoEvents = cfg.urbanLifeAutoEvents;
        st.compatibilityFallbackVehicleAIAutoEvents = cfg.vehicleAIAutoEvents;
        st.compatibilityFallbackSnapshotActive = true;
    }

    static void RestoreCompatibilityFallbackSnapshot(bool notifyResult, const std::string& reason)
    {
        const bool hadSnapshot = st.compatibilityFallbackSnapshotActive;
        if (hadSnapshot)
        {
            st.worldDirectorActive = st.compatibilityFallbackWorldDirectorActive;
            st.urbanLifeActive = st.compatibilityFallbackUrbanLifeActive;
            st.vehicleAIActive = st.compatibilityFallbackVehicleAIActive;
            st.policeRealismActive = st.compatibilityFallbackPoliceRealismActive;
            cfg.worldDirectorAutoEvents = st.compatibilityFallbackWorldDirectorAutoEvents;
            cfg.urbanLifeAutoEvents = st.compatibilityFallbackUrbanLifeAutoEvents;
            cfg.vehicleAIAutoEvents = st.compatibilityFallbackVehicleAIAutoEvents;
        }

        st.compatibilityFallbackSnapshotActive = false;
        st.compatibilityFallbackActive = false;
        g_coreCompatibility.SetFallbackActive(false);

        if (hadSnapshot)
        {
            st.lastCompatibilityReport += " / fallback restored";
            ReportCore2(core::ErrorSeverity::Info, "compatibility", "fallback", "Compatibility fallback restored suspended settings: " + reason);
            if (notifyResult && cfg.compatibilityNotify) Notify("Compatibility fallback restored.");
        }
    }

    static void ResetCompatibilityDetectionFlags()
    {
        st.compatibilityScriptHookFound = false;
        st.compatibilityAsiLoaderFound = false;
        st.compatibilityGtaExeFound = false;
        st.compatibilityEnhancedDetected = false;
        st.compatibilityOptionalUiFound = false;
    }

    static void ApplyCompatibilityFallbacks(bool notifyResult)
    {
        const bool shouldFallback = cfg.compatibilityLayerEnabled && cfg.compatibilityGracefulFallback &&
            (st.compatibilityErrorCount > 0 || (cfg.compatibilityStrictMode && st.compatibilityWarningCount > 0));

        if (!shouldFallback)
        {
            RestoreCompatibilityFallbackSnapshot(notifyResult, "compatibility scan passed or fallback disabled");
            return;
        }

        SaveCompatibilityFallbackSnapshot();

        bool changed = !st.compatibilityFallbackActive;
        st.compatibilityFallbackActive = true;
        g_coreCompatibility.SetFallbackActive(true);

        if (st.worldDirectorActive || cfg.worldDirectorAutoEvents) changed = true;
        if (st.urbanLifeActive || cfg.urbanLifeAutoEvents) changed = true;
        if (st.vehicleAIActive || cfg.vehicleAIAutoEvents) changed = true;
        if (st.policeRealismActive) changed = true;

        st.worldDirectorActive = false;
        st.urbanLifeActive = false;
        st.vehicleAIActive = false;
        st.policeRealismActive = false;
        cfg.worldDirectorAutoEvents = false;
        cfg.urbanLifeAutoEvents = false;
        cfg.vehicleAIAutoEvents = false;

        st.lastCompatibilityReport += " / fallback: heavy auto-events suspended";
        if (changed)
        {
            ReportCore2(core::ErrorSeverity::Warning, "compatibility", "fallback", "Heavy auto-events suspended by compatibility layer.");
            if (notifyResult && cfg.compatibilityNotify) Notify("Compatibility fallback: heavy auto-events suspended.");
        }
    }

    static void RunCompatibilityScan(bool notifyResult, bool writeReport)
    {
        InitializeCore2Modules();
        const int previousWarnings = st.compatibilityWarningCount;
        const int previousErrors = st.compatibilityErrorCount;
        const std::string previousProblem = st.lastCompatibilityProblem;
        g_coreCompatibility.BeginScan();

        if (!cfg.compatibilityLayerEnabled)
        {
            st.compatibilityWarningCount = 0;
            st.compatibilityErrorCount = 0;
            st.lastCompatibilityReport = "Compatibility Layer disabled";
            st.lastCompatibilityProblem = "Disabled";
            st.lastCompatibilityScanTick = GetTickCount();
            ResetCompatibilityDetectionFlags();
            RestoreCompatibilityFallbackSnapshot(notifyResult, "compatibility layer disabled");
            g_coreModules.SetStatus("compatibility", core::ModuleStatus::Disabled, st.lastCompatibilityReport, GetTickCount());
            if (writeReport) WriteCompatibilityReportFile();
            return;
        }

        st.compatibilityScriptHookFound = RootFileExists("ScriptHookV.dll");
        st.compatibilityAsiLoaderFound = AnyRootFileExists({"dinput8.dll", "version.dll", "dsound.dll"});
        const bool standardGtaExeFound = RootFileExists("GTA5.exe") || RootFileExists("PlayGTAV.exe");
        const bool enhancedGtaExeFound = cfg.compatibilityEnhancedSupport && AnyRootFileExists({"GTA5_Enhanced.exe", "GTA5Enhanced.exe", "PlayGTAV_Enhanced.exe", "PlayGTAVEnhanced.exe"});
        st.compatibilityEnhancedDetected = enhancedGtaExeFound;
        st.compatibilityGtaExeFound = standardGtaExeFound || enhancedGtaExeFound;
        st.compatibilityOptionalUiFound = AnyRootFileExists({"LemonUI.dll", "LemonUI.SHVDN3.dll", "NativeUI.dll"});

        if (g_rootDir.empty())
            g_coreCompatibility.Add("root", "ASI Root Directory", core::CompatibilityLevel::Error, "Root path could not be resolved.");
        else
            g_coreCompatibility.Add("root", "ASI Root Directory", core::CompatibilityLevel::Ok, g_rootDir);

        if (st.compatibilityScriptHookFound)
            g_coreCompatibility.Add("scripthookv", "ScriptHookV Runtime", core::CompatibilityLevel::Ok, "ScriptHookV.dll found near ASI.");
        else
            g_coreCompatibility.Add("scripthookv", "ScriptHookV Runtime", cfg.compatibilityRequireScriptHookV ? core::CompatibilityLevel::Error : core::CompatibilityLevel::Warning, "ScriptHookV.dll not found near ASI.");

        if (st.compatibilityAsiLoaderFound)
            g_coreCompatibility.Add("asi_loader", "ASI Loader", core::CompatibilityLevel::Ok, FirstExistingRootFile({"dinput8.dll", "version.dll", "dsound.dll"}));
        else
            g_coreCompatibility.Add("asi_loader", "ASI Loader", cfg.compatibilityRequireAsiLoader ? core::CompatibilityLevel::Error : core::CompatibilityLevel::Warning, "No dinput8/version/dsound ASI loader found near ASI.");

        if (st.compatibilityGtaExeFound)
            g_coreCompatibility.Add("gta_exe", "GTA V Executable", core::CompatibilityLevel::Ok, FirstExistingRootFile({"GTA5.exe", "PlayGTAV.exe", "GTA5_Enhanced.exe", "GTA5Enhanced.exe", "PlayGTAV_Enhanced.exe", "PlayGTAVEnhanced.exe"}));
        else
            g_coreCompatibility.Add("gta_exe", "GTA V Executable", cfg.compatibilityWarnMissingGtaExe ? core::CompatibilityLevel::Warning : core::CompatibilityLevel::Info, "GTA5/Enhanced executable not found in ASI root; this can be normal with a mod-manager staging folder.");

        g_coreCompatibility.Add("gta_enhanced", "GTA V Enhanced Support", cfg.compatibilityEnhancedSupport ? core::CompatibilityLevel::Ok : core::CompatibilityLevel::Info,
            cfg.compatibilityEnhancedSupport ? (st.compatibilityEnhancedDetected ? "Enhanced executable detected; Enhanced-safe teleport/freecam/native guards enabled." : "Enhanced-safe guards enabled; standard executable layout detected or staged.") : "Enhanced-safe guards disabled by config.");

        if (st.compatibilityOptionalUiFound)
            g_coreCompatibility.Add("ui_lib", "Optional UI Libraries", core::CompatibilityLevel::Ok, FirstExistingRootFile({"LemonUI.dll", "LemonUI.SHVDN3.dll", "NativeUI.dll"}));
        else
            g_coreCompatibility.Add("ui_lib", "Optional UI Libraries", cfg.compatibilityWarnOptionalUiLibraries ? core::CompatibilityLevel::Warning : core::CompatibilityLevel::Info, "Optional LemonUI/NativeUI files not found; current trainer UI is internal, so this is not fatal.");

        const bool menyooFound = AnyRootFileExists({"Menyoo.asi", "MenyooStuff.xml", "menyooConfig.ini"});
        const bool shvdnFound = AnyRootFileExists({"ScriptHookVDotNet.asi", "ScriptHookVDotNet2.dll", "ScriptHookVDotNet3.dll"});
        if (menyooFound || shvdnFound)
        {
            std::string detail = std::string("Menyoo=") + (menyooFound ? "found" : "not found") + ", SHVDN=" + (shvdnFound ? "found" : "not found") + "; language parser, preset language restore and native compatibility fallbacks are guarded.";
            g_coreCompatibility.Add("menyoo_shvdn", "Menyoo / ScriptHookVDotNet Coexistence", core::CompatibilityLevel::Ok, detail);
        }
        else
        {
            g_coreCompatibility.Add("menyoo_shvdn", "Menyoo / ScriptHookVDotNet Coexistence", core::CompatibilityLevel::Info, "Menyoo/SHVDN not detected; guarded language and native fallback paths still enabled.");
        }
        g_coreCompatibility.Add("legacy_patterns", "Legacy Memory Pattern Compatibility", core::CompatibilityLevel::Ok, "Pattern-sensitive calls use backwards-compatible native wrappers and safe fallbacks instead of hard-crashing on older runtime layouts.");

        g_coreCompatibility.Add("story_mode", "Mode Guard", core::CompatibilityLevel::Info, "Designed for GTA V Story Mode / Offline only. Online use is not supported.");
        g_coreCompatibility.Add("safe_native", "SafeNative Guard", core::CompatibilityLevel::Ok, "Core 2.0 SafeNative wrappers enabled for risky entity operations.");
        g_coreCompatibility.Add("runtime_registry", "Runtime Registry", core::CompatibilityLevel::Ok, "Typed runtime cleanup and stale-handle purging enabled.");

        st.compatibilityWarningCount = g_coreCompatibility.WarningCount();
        st.compatibilityErrorCount = g_coreCompatibility.ErrorCount();
        st.lastCompatibilityProblem = g_coreCompatibility.LastProblem();
        st.lastCompatibilityReport = g_coreCompatibility.Summary();
        st.lastCompatibilityScanTick = GetTickCount();

        ApplyCompatibilityFallbacks(notifyResult);

        if (cfg.compatibilityWriteReport || writeReport) WriteCompatibilityReportFile();

        const bool compatibilityChanged = previousWarnings != st.compatibilityWarningCount ||
            previousErrors != st.compatibilityErrorCount || previousProblem != st.lastCompatibilityProblem;

        if (st.compatibilityErrorCount > 0)
        {
            g_coreModules.SetStatus("compatibility", core::ModuleStatus::Faulted, st.lastCompatibilityReport, GetTickCount());
            if (notifyResult || compatibilityChanged)
                ReportCore2(core::ErrorSeverity::Error, "compatibility", "scan", st.lastCompatibilityProblem);
        }
        else if (st.compatibilityWarningCount > 0)
        {
            g_coreModules.SetStatus("compatibility", core::ModuleStatus::Active, st.lastCompatibilityReport, GetTickCount(), true);
            if (notifyResult || compatibilityChanged)
                ReportCore2(core::ErrorSeverity::Warning, "compatibility", "scan", st.lastCompatibilityProblem);
        }
        else
        {
            g_coreModules.SetStatus("compatibility", core::ModuleStatus::Active, st.lastCompatibilityReport, GetTickCount(), true);
            ClearResolvedCore2Problems("compatibility", "scan", core::ModuleStatus::Active, st.lastCompatibilityReport);
        }

        if (notifyResult && cfg.compatibilityNotify)
        {
            if (st.compatibilityErrorCount > 0) Notify("Compatibility: ERROR / " + st.lastCompatibilityProblem);
            else if (st.compatibilityWarningCount > 0) Notify("Compatibility: WARN / " + st.lastCompatibilityProblem);
            else Notify("Compatibility: OK");
        }
    }

    static void TickCompatibilityLayer()
    {
        if (!cfg.compatibilityLayerEnabled || !cfg.compatibilityAutoScan) return;
        cfg.compatibilityScanIntervalMs = ClampIntValue(cfg.compatibilityScanIntervalMs, 3000, 120000);
        st.pedElongationScale = ClampFloatValue(st.pedElongationScale, 0.70f, 1.80f, 1.15f);
        st.selectedMakeupTint = ClampIntValue(st.selectedMakeupTint, 0, 63);
        const DWORD now = GetTickCount();
        if (st.lastCompatibilityScanTick == 0 || core::TickElapsed(now, st.lastCompatibilityScanTick, SafeIntervalFromIntMs(cfg.compatibilityScanIntervalMs, 15000, 3000, 120000, "compatibility", "scan interval")))
            RunCompatibilityScan(false, false);
    }

