    static void UpdateCore2Snapshot()
    {
        InitializeCore2Modules();
        SyncCore2RegistryFromErrors();
        st.core2RuntimeEntities = g_coreRuntime.TotalAfter();
        st.core2RuntimeRemoved = g_coreRuntime.TotalRemoved();
        st.core2WarningCount = g_coreErrors.WarningCount();
        st.core2ErrorCount = g_coreErrors.ErrorCount();
        st.core2FaultedModules = g_coreModules.CountByStatus(core::ModuleStatus::Faulted);
        st.lastCore2Error = g_coreErrors.LastProblemMessage();
        st.lastCore2Report = g_coreRuntime.Summary() + " / " + g_coreModules.Summary() + " / " + g_coreErrors.Summary();
    }

    template <typename T>
    static int CorePurgeAndRecord(const std::string& name, core::EntityKind kind, std::vector<T>& values)
    {
        const int before = static_cast<int>(values.size());
        int removed = 0;
        if (kind == core::EntityKind::Ped) removed = CorePurgePedVector(values);
        else if (kind == core::EntityKind::Vehicle) removed = CorePurgeVehicleVector(values);
        else if (kind == core::EntityKind::Object) removed = CorePurgeObjectVector(values);
        else removed = CorePurgeMixedEntityVector(values);
        const int after = static_cast<int>(values.size());
        g_coreRuntime.Record(name, kind, before, after, removed);
        if (removed > 0)
            ReportCore2(core::ErrorSeverity::Warning, "runtime", name, "Purged stale " + std::string(core::EntityKindName(kind)) + " handles: " + std::to_string(removed));
        return removed;
    }

    static int CorePurgeMissionAndRecord()
    {
        const int before = static_cast<int>(st.missionSpawnedEntities.size());
        const int removed = CorePurgeMissionRuntimeEntities();
        const int after = static_cast<int>(st.missionSpawnedEntities.size());
        g_coreRuntime.Record("mission.playtest.entities", core::EntityKind::Any, before, after, removed);
        if (removed > 0)
            ReportCore2(core::ErrorSeverity::Warning, "mission", "runtime purge", "Fixed mission runtime entities/def-indexes: " + std::to_string(removed));
        return removed;
    }

    static void RunCoreMaintenance(bool force)
    {
        InitializeCore2Modules();
        const DWORD now = GetTickCount();
        if (force)
            g_lastCoreMaintenanceTick = now;
        else if (!core::Due(now, g_lastCoreMaintenanceTick, 1500)) return;

        g_coreRuntime.BeginScan();

        int removed = 0;
        removed += CorePurgeAndRecord("npc.spawned", core::EntityKind::Ped, st.spawnedPeds);
        removed += CorePurgeAndRecord("npc.bodyguards", core::EntityKind::Ped, st.bodyguards);
        removed += CorePurgeAndRecord("npc.enemies", core::EntityKind::Ped, st.enemies);
        removed += CorePurgeAndRecord("scenario.peds", core::EntityKind::Ped, st.scenarioPeds);
        removed += CorePurgeAndRecord("vehicle.spawned", core::EntityKind::Vehicle, st.spawnedVehicles);
        removed += CorePurgeAndRecord("scenario.vehicles", core::EntityKind::Vehicle, st.scenarioVehicles);
        removed += CorePurgeAndRecord("objects.spawned", core::EntityKind::Object, st.spawnedObjects);
        removed += CorePurgeAndRecord("police.entities", core::EntityKind::Any, st.policeRealismEntities);
        removed += CorePurgeAndRecord("world.director.entities", core::EntityKind::Any, st.worldDirectorEntities);
        removed += CorePurgeAndRecord("urban.life.entities", core::EntityKind::Any, st.urbanLifeEntities);
        removed += CorePurgeAndRecord("vehicle.ai.entities", core::EntityKind::Any, st.vehicleAIEntities);
        removed += CorePurgeAndRecord("game.mode.entities", core::EntityKind::Any, st.gameMode.trackedEntities);
        removed += CorePurgeMissionAndRecord();
        removed += CorePurgeBodyguardRoleMap();
        removed += CorePurgeBodyguardPedRuntimeMap(st.bodyguardLastCombatRefreshTick);
        removed += CorePurgeBodyguardPedRuntimeMap(st.bodyguardLastMoveTick);
        removed += CorePurgePedRuntimeMap(st.companionVehicleEntryUntilTick);
        removed += CorePurgePedVehicleMap(st.companionVehicleEntryTarget);
        removed += CorePurgePedRuntimeMap(st.companionVehicleEntryIssuedTick);
        removed += CorePurgePedRuntimeMap(st.companionVehicleEntrySeat);
        removed += CorePurgePedRuntimeMap(st.companionVehicleEntryAvoidSeat);
        removed += CorePurgePedVehicleMap(st.companionVehicleEntryAvoidVehicle);
        removed += CorePurgePedRuntimeMap(st.companionVehicleLeaveUntilTick);
        removed += CorePurgePedVehicleMap(st.companionVehicleLeaveTarget);
        removed += CorePurgePedRuntimeMap(st.companionVehicleTransferUntilTick);
        removed += CorePurgePedVehicleMap(st.companionVehicleTransferTarget);
        // BUGFIX 176: keep all companion combat maps under the same global
        // maintenance pass.  Earlier builds cleaned some vehicle-fire throttles
        // only in anti-panic/bodyguard ticks, so stale targets could survive when
        // the related AI page was not active or when a companion died off-screen.
        removed += PurgeInvalidCompanionCombatTargetRuntime();
        removed += CorePurgePedRuntimeMap(st.companionVehicleFireLastReissueTick);
        removed += CorePurgePedRuntimeMap(st.companionVehicleWeaponPrepLastTick);
        removed += CorePurgePedRuntimeMap(st.companionVehicleFireTaskLastIssueTick);
        removed += CorePurgePedTargetMap(st.companionVehicleFireTaskTarget);
        removed += CorePurgePedRuntimeMap(st.companionPanicLastCleanupAttemptTick);
        removed += CorePurgePedRuntimeMap(st.companionPanicLastPoliceScanTick);
        removed += CorePurgePedRuntimeMap(st.companionWantedPoliceEmergencyLastScanTick);
        removed += CorePurgePedRuntimeMap(st.companionDefensiveAssistLastTick);
        CompactCompanionVehicleEntryState();
        removed += CorePurgePedVectorMap(st.bodyguardLastRecoveryPos);

        Vector3 singletonPos{};
        if (st.chauffeur && (!core::IsPed((Entity)st.chauffeur) || !TryGetUsableEntityPosition((Entity)st.chauffeur, singletonPos)))
        {
            st.chauffeur = 0;
            ClearChauffeurRuntimeState();
            ++removed;
        }
        if (st.chauffeurVehicle && (!core::IsVehicle((Entity)st.chauffeurVehicle) || !TryGetUsableEntityPosition((Entity)st.chauffeurVehicle, singletonPos)))
        {
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
            ++removed;
        }
        if (st.bodyguardProtectedVehicle && (!core::IsVehicle((Entity)st.bodyguardProtectedVehicle) || !TryGetUsableEntityPosition((Entity)st.bodyguardProtectedVehicle, singletonPos)))
        {
            st.bodyguardProtectedVehicle = 0;
            ++removed;
        }
        if (st.garageLastLoadedVehicle && (!core::IsVehicle((Entity)st.garageLastLoadedVehicle) || !TryGetUsableEntityPosition((Entity)st.garageLastLoadedVehicle, singletonPos)))
        {
            st.garageLastLoadedVehicle = 0;
            ++removed;
        }
        if (st.lastObject && (!core::IsObject((Entity)st.lastObject) || !TryGetUsableEntityPosition((Entity)st.lastObject, singletonPos)))
        {
            st.lastObject = 0;
            st.lastObjectFrozen = true;
            ++removed;
        }
        if (st.lastPlayerVehicleForBodyguards && (!core::IsVehicle((Entity)st.lastPlayerVehicleForBodyguards) || !TryGetUsableEntityPosition((Entity)st.lastPlayerVehicleForBodyguards, singletonPos)))
        {
            st.lastPlayerVehicleForBodyguards = 0;
            ++removed;
        }
        if (st.inspectedEntity && (!core::Exists(st.inspectedEntity) || !TryGetUsableEntityPosition(st.inspectedEntity, singletonPos)))
        {
            st.inspectedEntity = 0;
            st.lastInspectorStatus = "No entity selected";
            ++removed;
        }
        for (auto it = st.inspectorFrozenStates.begin(); it != st.inspectorFrozenStates.end(); )
        {
            if (!core::Exists(it->first) || !TryGetUsableEntityPosition(it->first, singletonPos))
            {
                it = st.inspectorFrozenStates.erase(it);
                ++removed;
            }
            else ++it;
        }
        if (st.freeCamActive && (st.freeCam == 0 || !SafeDoesCamExistRuntime(st.freeCam, "free_camera")))
        {
            CleanupFreeCameraRuntime(false);
            ++removed;
        }

        st.page = ValidPageOrMain(st.page);
        st.previousPage = ValidPageOrMain(st.previousPage);
        st.browserReturnPage = ValidPageOrMain(st.browserReturnPage);
        for (Page& page : st.pageStack) page = ValidPageOrMain(page);
        st.pageStack.erase(std::remove(st.pageStack.begin(), st.pageStack.end(), st.page), st.pageStack.end());
        if (st.pageStack.size() > 48) st.pageStack.erase(st.pageStack.begin(), st.pageStack.end() - 48);

        ClampStateIndexes();
        const int untrackedCleanupRemoved = removed - g_coreRuntime.TotalRemoved();
        if (untrackedCleanupRemoved > 0)
            g_coreRuntime.RecordCleanup("runtime.maps.singletons", core::EntityKind::Any, untrackedCleanupRemoved);

        if (removed > 0)
        {
            st.lastPerformanceSafetyReport = "Core maintenance removed stale runtime handles: " + std::to_string(removed);
            Log(st.lastPerformanceSafetyReport);
        }
        else
        {
            ClearResolvedCore2Problems("runtime", std::string(), core::ModuleStatus::Active, "Runtime cleanup clean");
            ClearResolvedCore2Problems("mission", "runtime purge", st.missionPlaytestActive ? core::ModuleStatus::Active : core::ModuleStatus::Suspended, "Mission runtime clean");
        }

        UpdateCore2ModuleStatuses();
        UpdateCore2Snapshot();
    }

