    static void RunMenuIntegrityAudit(bool notifyResult)
    {
        const State savedState = st;
        const Config savedConfig = cfg;

        st.menuAuditPages = 0;
        st.menuAuditWarnings = 0;
        st.menuAuditErrors = 0;
        std::vector<std::string> duplicateRows;
        std::vector<std::string> emptyPages;

        for (Page page : AllMenuPagesForAudit())
        {
            st.page = page;
            st.previousPage = Page::Main;
            st.pageStack.clear();
            st.selected = 0;
            if (page == Page::Search)
            {
                st.searchQuery.clear();
                st.searchPage = 0;
            }
            if (page == Page::PedBrowser && !IsValidPageValue(st.browserReturnPage))
                st.browserReturnPage = Page::Npc;

            std::vector<MenuItem> pageItems = BuildMenu();
            ++st.menuAuditPages;
            if (pageItems.empty())
            {
                ++st.menuAuditErrors;
                emptyPages.push_back(MenuPageDebugName(page));
                continue;
            }

            std::vector<std::string> rowKeys;
            rowKeys.reserve(pageItems.size());
            for (const MenuItem& item : pageItems)
            {
                const std::string labelKey = IniNameKey(NormalizeFlatText(item.label, 96, ""));
                const std::string valueKey = IniNameKey(NormalizeFlatText(item.value, 96, ""));
                if (labelKey.empty())
                {
                    ++st.menuAuditWarnings;
                    duplicateRows.push_back(std::string(MenuPageDebugName(page)) + ": empty label");
                    continue;
                }
                const std::string key = labelKey + "|" + valueKey;
                if (std::find(rowKeys.begin(), rowKeys.end(), key) != rowKeys.end())
                {
                    ++st.menuAuditWarnings;
                    duplicateRows.push_back(std::string(MenuPageDebugName(page)) + ": duplicate row " + item.label);
                }
                else rowKeys.push_back(key);
            }

        }

        const int auditPages = st.menuAuditPages;
        const int auditWarnings = st.menuAuditWarnings;
        const int auditErrors = st.menuAuditErrors;
        const std::string auditReport = std::to_string(auditPages) + " pages, " +
            std::to_string(auditErrors) + " errors, " + std::to_string(auditWarnings) + " warnings";

        st = savedState;
        cfg = savedConfig;
        st.menuAuditPages = auditPages;
        st.menuAuditWarnings = auditWarnings;
        st.menuAuditErrors = auditErrors;
        st.lastMenuAuditReport = auditReport;
        InvalidateAdaptiveMenuWidth();

        Log("Menu Integrity Audit: " + st.lastMenuAuditReport);
        for (const std::string& row : duplicateRows) Log("Menu Audit warning: " + row);
        for (const std::string& pageName : emptyPages) Log("Menu Audit error: empty page " + pageName);

        if (notifyResult)
        {
            if (st.menuAuditErrors > 0) Notify("Menu Audit: ERROR (" + std::to_string(st.menuAuditErrors) + " errors)");
            else if (st.menuAuditWarnings > 0) Notify("Menu Audit: WARN (" + std::to_string(st.menuAuditWarnings) + " warnings)");
            else Notify("Menu Audit: OK");
        }
    }

    static void ExecuteMenuItemSafely(const MenuItem& item)
    {
        if (IsMenuSeparatorItem(item) || !IsMenuExecutableItem(item))
        {
            return;
        }

        const bool hadToggle = item.isToggle && item.toggle;
        const bool previousToggleValue = hadToggle ? *item.toggle : false;

        auto result = core::RunAction(item.label.c_str(), [&]()
        {
            if (hadToggle) *item.toggle = !*item.toggle;
            if (item.action) item.action();
        });

        if (!result.ok)
        {
            if (hadToggle) *item.toggle = previousToggleValue;
            Log(result.error);
            ReportCore2(core::ErrorSeverity::Error, "ui", item.label, result.error);
            try { Notify("Action failed safely: " + item.label); }
            catch (...) { Log("Notify failed after action failure: " + item.label); }
        }

        ClampConfigValues();
        ClampStateIndexes();
        PurgeInvalidQuickFavorites();
        RunCoreMaintenance(true);
    }

