    static void ApplyBodyguardRolesNow()
    {
        int idx = 0;
        for (Ped g : st.bodyguards)
        {
            if (!IsUsablePedHandle(g, false, true, true)) continue;
            st.bodyguardRoles[g] = cfg.bodyguardUseRoles ? BodyguardRoleForSpawnIndex(idx) : cfg.bodyguardDefaultRole;
            st.bodyguardLastCombatRefreshTick[g] = 0;
            ConfigureBodyguard(g);
            ++idx;
        }
        Notify("Bodyguard roles applied.");
    }

    static void BodyguardsEnterChauffeurVehicle()
    {
        if (!IsUsableVehicleHandle(st.chauffeurVehicle, true)) { Notify("No chauffeur vehicle."); return; }
        CommandBodyguardsEnterVehicle(st.chauffeurVehicle, true, false);
    }

    static void SetBodyguardCommandMode(BodyguardCommandMode mode, bool notifyResult = true)
    {
        st.bodyguardCommandMode = mode;
        st.lastBodyguardCommandTick = 0;
        if (mode != BodyguardCommandMode::HoldPosition)
            st.bodyguardHoldPositionActive = false;
        if (mode != BodyguardCommandMode::CoverVehicle)
            st.bodyguardProtectedVehicle = 0;
        if (mode == BodyguardCommandMode::Follow)
            BodyguardsFollow(false);
        if (notifyResult) Notify("Bodyguard Command: " + BodyguardCommandModeName(mode));
    }

    static void BodyguardsHoldPosition()
    {
        Ped player = 0;
        if (!GetPlayerPedSafe(player)) { Notify("Player unavailable."); return; }
        Vector3 holdPos{};
        if (!TryGetPlayerPosition(holdPos)) { Notify("Hold position failed: player position invalid."); return; }
        st.bodyguardHoldPosition = holdPos;
        st.bodyguardHoldPositionActive = true;
        st.bodyguardProtectedVehicle = 0;
        SetBodyguardCommandMode(BodyguardCommandMode::HoldPosition, false);
        StopBodyguards(false);
        Notify("Bodyguards holding current position.");
    }

    static void BodyguardsCoverPlayer()
    {
        st.bodyguardProtectedVehicle = 0;
        st.bodyguardHoldPositionActive = false;
        SetBodyguardCommandMode(BodyguardCommandMode::CoverPlayer, false);
        BodyguardsFollow(false);
        Notify("Bodyguards covering player.");
    }

    static bool SelectVehicleForBodyguardCover(bool preferChauffeur)
    {
        Vehicle v = 0;
        if (preferChauffeur && IsUsableVehicleHandle(st.chauffeurVehicle, true)) v = st.chauffeurVehicle;
        else
        {
            Ped player = 0;
            if (GetPlayerPedSafe(player) && core::IsPedInAnyVehicle((Ped)(player), false)) v = core::GetVehiclePedIsIn((Ped)(player), false);
            if (!v && IsUsableVehicleHandle(st.chauffeurVehicle, true)) v = st.chauffeurVehicle;
        }
        if (!IsUsableVehicleHandle(v, true)) return false;
        Vector3 vehiclePos{};
        if (!TryGetUsableEntityPosition((Entity)v, vehiclePos)) return false;
        st.bodyguardProtectedVehicle = v;
        st.bodyguardHoldPositionActive = false;
        SetBodyguardCommandMode(BodyguardCommandMode::CoverVehicle, false);
        return true;
    }

    static void BodyguardsCoverCurrentVehicle()
    {
        if (!SelectVehicleForBodyguardCover(false)) { Notify("No vehicle to cover."); return; }
        Notify("Bodyguards covering vehicle.");
    }

    static void BodyguardsCoverChauffeurVehicle()
    {
        if (!SelectVehicleForBodyguardCover(true)) { Notify("No chauffeur vehicle."); return; }
        Notify("Bodyguards covering chauffeur vehicle.");
    }

    static void BodyguardsAttackNearbyThreats()
    {
        if (cfg.bodyguardCombatMode == BodyguardCombatMode::HoldFire)
        {
            Notify("Bodyguards are in Hold Fire mode.");
            return;
        }
        SetBodyguardCommandMode(BodyguardCommandMode::AttackThreats, false);
        int ordered = 0;
        for (Ped g : st.bodyguards)
        {
            if (!IsUsablePedHandle(g, false, true, true)) continue;
            Ped target = FindClosestThreatForBodyguard(g);
            if (IsUsablePedHandle(target, false, true, true))
            {
                if (CommandFriendlyNpcAttackThreat(g, target, "bodyguards"))
                    ++ordered;
            }
        }
        Notify(ordered > 0 ? "Bodyguards attacking nearby threats." : "No nearby threats found.");
    }

    static void BodyguardMedicPulse()
    {
        Ped player = 0;
        if (GetPlayerPedSafe(player))
        {
            core::safe_native::SetHealth((Entity)(player), 200, &g_coreErrors, "full_audit");
            core::safe_native::SetPedArmour(player, 100, &g_coreErrors, "runtime");
        }
        int healed = 0;
        for (Ped g : st.bodyguards)
        {
            if (!IsUsablePedHandle(g, false, true, true)) continue;
            core::safe_native::SetHealth((Entity)(g), cfg.bodyguardHealth, &g_coreErrors, "full_audit");
            core::safe_native::SetPedArmour(g, 100, &g_coreErrors, "runtime");
            ++healed;
        }
        SetBodyguardCommandMode(BodyguardCommandMode::MedicSupport, false);
        st.lastBodyguardMedicHealTick = GetTickCount();
        Notify("Medic pulse complete. Guards healed: " + std::to_string(healed));
    }

    static void CycleBodyguardCommandMode()
    {
        int next = ((int)st.bodyguardCommandMode + 1) % 6;
        BodyguardCommandMode mode = (BodyguardCommandMode)next;
        switch (mode)
        {
            case BodyguardCommandMode::Follow:
                SetBodyguardCommandMode(BodyguardCommandMode::Follow);
                break;
            case BodyguardCommandMode::HoldPosition:
                BodyguardsHoldPosition();
                break;
            case BodyguardCommandMode::CoverPlayer:
                BodyguardsCoverPlayer();
                break;
            case BodyguardCommandMode::CoverVehicle:
                BodyguardsCoverCurrentVehicle();
                break;
            case BodyguardCommandMode::AttackThreats:
                BodyguardsAttackNearbyThreats();
                break;
            case BodyguardCommandMode::MedicSupport:
                BodyguardMedicPulse();
                break;
        }
    }

    static bool BodyguardCommandSuppressesOpportunisticThreatScan()
    {
        if (!cfg.bodyguardCommandWheelEnabled || !cfg.bodyguardAutoKeepCommandMode) return false;
        return st.bodyguardCommandMode == BodyguardCommandMode::HoldPosition ||
               st.bodyguardCommandMode == BodyguardCommandMode::CoverVehicle ||
               st.bodyguardCommandMode == BodyguardCommandMode::MedicSupport;
    }

    static void SanitizeCompanionRuntimeState()
    {
        Vector3 companionSingletonPos{};
        if (st.bodyguardProtectedVehicle && (!core::IsVehicle((Entity)st.bodyguardProtectedVehicle) || !TryGetUsableEntityPosition((Entity)st.bodyguardProtectedVehicle, companionSingletonPos)))
            st.bodyguardProtectedVehicle = 0;
        if (st.lastPlayerVehicleForBodyguards && (!core::IsVehicle((Entity)st.lastPlayerVehicleForBodyguards) || !TryGetUsableEntityPosition((Entity)st.lastPlayerVehicleForBodyguards, companionSingletonPos)))
            st.lastPlayerVehicleForBodyguards = 0;
        if (st.garageLastLoadedVehicle && (!core::IsVehicle((Entity)st.garageLastLoadedVehicle) || !TryGetUsableEntityPosition((Entity)st.garageLastLoadedVehicle, companionSingletonPos)))
        {
            st.garageLastLoadedVehicle = 0;
            st.garageLastLoadedSlot = 0;
        }
        if (st.chauffeur && (!core::IsPed((Entity)st.chauffeur) || !TryGetUsableEntityPosition((Entity)st.chauffeur, companionSingletonPos) || core::IsPedDeadOrDying(st.chauffeur, true, true)))
        {
            st.chauffeur = 0;
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
        }
        if (st.chauffeurVehicle && (!core::IsVehicle((Entity)st.chauffeurVehicle) || !TryGetUsableEntityPosition((Entity)st.chauffeurVehicle, companionSingletonPos)))
        {
            st.chauffeurVehicle = 0;
            ClearChauffeurRuntimeState();
        }

        // BUGFIX 166: old packages could leave bodyguards duplicated in st.friendlyPeds
        // because bodyguard spawn first registered them as generic friendly NPCs.
        // Keep blips in friendlyBlips, but remove the duplicate friendly-list entry so
        // bodyguard AI has a single owner and Hold Fire is respected consistently.
        st.friendlyPeds.erase(std::remove_if(st.friendlyPeds.begin(), st.friendlyPeds.end(), [](Ped ped)
        {
            return PedHandleInList(st.bodyguards, ped);
        }), st.friendlyPeds.end());

        PurgeStaleBodyguardRuntimeState();

        if (!cfg.bodyguardCommandWheelEnabled)
        {
            if (st.bodyguardCommandMode != BodyguardCommandMode::Follow)
                SetBodyguardCommandMode(BodyguardCommandMode::Follow, false);
            return;
        }

        if (st.bodyguardCommandMode == BodyguardCommandMode::HoldPosition && !st.bodyguardHoldPositionActive)
            SetBodyguardCommandMode(BodyguardCommandMode::Follow, false);
        if (st.bodyguardCommandMode == BodyguardCommandMode::CoverVehicle &&
            (!st.bodyguardProtectedVehicle || !core::IsVehicle((Entity)st.bodyguardProtectedVehicle) || !TryGetUsableEntityPosition((Entity)st.bodyguardProtectedVehicle, companionSingletonPos)))
            SetBodyguardCommandMode(BodyguardCommandMode::Follow, false);
    }

    static void SetBodyguardCombatMode(BodyguardCombatMode mode)
    {
        cfg.bodyguardCombatMode = mode;
        if (mode == BodyguardCombatMode::HoldFire)
        {
            if (st.bodyguardCommandMode == BodyguardCommandMode::AttackThreats)
                SetBodyguardCommandMode(BodyguardCommandMode::Follow, false);
            StopBodyguards(false);
        }
        else BodyguardsFollow(false);
        Notify("Bodyguard Mode: " + BodyguardCombatModeName(mode));
    }

