    static bool TryParseStateManagerMoneyInput(std::string text, int& out)
    {
        text = StripInlineCommentBasic(text);
        text.erase(std::remove_if(text.begin(), text.end(), [](unsigned char c)
        {
            return std::isspace(c) || c == '$' || c == ',' || c == '\'';
        }), text.end());
        return TryParseIntStrict(text, out);
    }

