    static void PromptTeleportToCustomCoordinates()
    {
        NormalizeTeleportRuntimeState();
        std::string text;
        if (!TryShowTextInputDialogUtf8(st.customCoordinateText, "Teleport To Custom Coordinates", "Enter coordinates X,Y,Z", 80, text) || text.empty()) return;
        std::replace(text.begin(), text.end(), ';', ',');
        auto parts = Split(text, ',');
        if (parts.size() < 3) { Notify("Use format: X,Y,Z"); return; }
        float x = 0.0f, y = 0.0f, z = 0.0f;
        if (!TryParseFloatStrict(parts[0], x) || !TryParseFloatStrict(parts[1], y) || !TryParseFloatStrict(parts[2], z))
        {
            Notify("Invalid coordinates.");
            return;
        }

        Entity target = PlayerTeleportEntity();
        if (!target || !core::Exists((Entity)(target)))
        {
            Notify("Teleport target unavailable.");
            return;
        }

        Vector3 fallback = core::SafeGetEntityCoords((Entity)(target), SafeWorldFallbackPosition(), true);
        Vector3 safe{}; safe.x = x; safe.y = y; safe.z = z;
        if (!IsUsableRuntimeWorldPosition(safe)) { Notify("Custom coordinates rejected: unsafe position."); return; }
        safe = SanitizeRuntimeVector(safe, fallback);
        st.customCoordinateText = VecLine(safe.x, safe.y, safe.z);
        if (TeleportEntityTo(safe.x, safe.y, safe.z, core::SafeGetEntityHeading((Entity)(target), 0.0f), false, "Custom Coordinates"))
            Notify("Teleported to custom coordinates.");
    }

