        if (st.selectedOutfitSlot < 1) st.selectedOutfitSlot = 1;
        if (st.selectedOutfitSlot > cfg.outfitSlots) st.selectedOutfitSlot = cfg.outfitSlots;
        ClampVehicleBuilderState();
        if (cfg.autoRecoveryIntervalMs < 250) cfg.autoRecoveryIntervalMs = 250;
