    static Page ValidPageOrMain(Page page)
    {
        int v = static_cast<int>(page);
        return (v >= static_cast<int>(Page::Main) && v <= static_cast<int>(Page::Settings)) ? page : Page::Main;
    }

    static void SetPageNoStack(Page page)
    {
        st.previousPage = ValidPageOrMain(st.page);
        st.page = ValidPageOrMain(page);
        st.selected = 0;
        InvalidateAdaptiveMenuWidth();
    }

    static void Go(Page page)
    {
        st.page = ValidPageOrMain(st.page);
        page = ValidPageOrMain(page);

        if (page == st.page)
        {
            st.selected = 0;
            InvalidateAdaptiveMenuWidth();
            return;
        }

        SanitizeMenuPageStack();
        if (st.pageStack.empty() || st.pageStack.back() != st.page)
        {
            st.pageStack.push_back(st.page);
            if (st.pageStack.size() > 48)
                st.pageStack.erase(st.pageStack.begin());
        }

        SetPageNoStack(page);
    }

    [[maybe_unused]] static void GoDirect(Page page)
    {
        st.page = ValidPageOrMain(st.page);
        page = ValidPageOrMain(page);

        st.pageStack.clear();
        if (page == st.page)
        {
            st.selected = 0;
            InvalidateAdaptiveMenuWidth();
            return;
        }
        SetPageNoStack(page);
    }

    static Page ParentPage(Page page)
    {
        // Search opens many pages directly. In that flow Back should return to Search first,
        // then Search returns to Main. This avoids confusing jumps after using global search.
        if (st.previousPage == Page::Search && page != Page::Search && page != Page::Main)
        {
            return Page::Search;
        }

        switch (page)
        {
            case Page::PedBrowser:
                return st.browserReturnPage;

            // Player branch
            case Page::StateManager:
                return Page::AdvancedPlayer;
            case Page::BetterGodMode:
            case Page::PlayerRecovery:
                return st.previousPage == Page::AdvancedPlayer ? Page::AdvancedPlayer : Page::Player;
            case Page::AdvancedPlayer:
            case Page::SkinModel:
                return Page::Player;
            case Page::PoliceWanted:
                return st.previousPage == Page::ControlCenter ? Page::ControlCenter : Page::Player;
            case Page::OutfitEditor:
                return st.previousPage == Page::SkinModel ? Page::SkinModel : Page::Player;

            // Weapons branch
            case Page::WeaponLoadouts:
            case Page::AdvancedWeapons:
                return Page::Weapons;
            case Page::AdvancedWeaponComponents:
            case Page::AdvancedWeaponEffects:
                return Page::AdvancedWeapons;

            // Vehicle branch
            case Page::VehicleSpawner:
            case Page::VehicleTuning:
            case Page::Garage:
                return Page::Vehicle;
            case Page::VehicleAI:
                return st.previousPage == Page::ControlCenter ? Page::ControlCenter : Page::Vehicle;
            case Page::VehicleBuilder:
                return st.previousPage == Page::Garage ? Page::Garage : Page::Vehicle;
            case Page::AddonVehicles:
                return Page::VehicleSpawner;

            // NPC branch
            case Page::Bodyguards:
            case Page::EnemySpawner:
            case Page::ChauffeurVehicles:
                return Page::Npc;
            case Page::BattleArena:
                return Page::EnemySpawner;

            // Scenario / Mission Creator branch
            case Page::ScenarioPresets:
            case Page::ScenarioDirector:
            case Page::ScenarioBuilder:
            case Page::GameModes:
            case Page::OneClickSetups:
            case Page::MissionCreator:
                return Page::ScenarioMenu;
            case Page::MissionTemplates:
            case Page::MissionEntities:
            case Page::MissionObjectives:
            case Page::MissionPlaytest:
                return Page::MissionCreator;

            // Tools that can be opened from another tool
            case Page::ScreenshotTools:
                return st.previousPage == Page::CinematicCamera ? Page::CinematicCamera : Page::Main;
            case Page::CinematicCamera:
                return st.previousPage == Page::ScreenshotTools ? Page::ScreenshotTools : Page::ScenarioMenu;
            case Page::WorldDirector:
                return st.previousPage == Page::WorldControl ? Page::WorldControl :
                       (st.previousPage == Page::ControlCenter ? Page::ControlCenter : Page::Main);
            case Page::UrbanLife:
                return st.previousPage == Page::WorldControl ? Page::WorldControl :
                       (st.previousPage == Page::ControlCenter ? Page::ControlCenter : Page::Main);
            case Page::SmartCleanup:
                if (st.previousPage == Page::PerformanceSafety) return Page::PerformanceSafety;
                return Page::UndoSystem;
            case Page::StabilityCore2:
                if (st.previousPage == Page::Settings) return Page::Settings;
                if (st.previousPage == Page::HealthCheck) return Page::HealthCheck;
                if (st.previousPage == Page::ControlCenter) return Page::ControlCenter;
                return Page::PerformanceSafety;
            case Page::PerformanceSafety:
                if (st.previousPage == Page::Settings) return Page::Settings;
                if (st.previousPage == Page::ControlCenter) return Page::ControlCenter;
                if (st.previousPage == Page::SmartCleanup) return Page::SmartCleanup;
                if (st.previousPage == Page::UndoSystem) return Page::UndoSystem;
                return Page::Main;
            case Page::HealthCheck:
                if (st.previousPage == Page::PerformanceSafety) return Page::PerformanceSafety;
                if (st.previousPage == Page::Settings) return Page::Settings;
                if (st.previousPage == Page::ControlCenter) return Page::ControlCenter;
                return Page::UndoSystem;
            case Page::TrainerInfo:
                return Page::Settings;
            case Page::SmartProfiles:
                return Page::TrainerPresets;
            case Page::EntityInspector:
                return Page::ObjectSpawner;

            // Teleport branch
            case Page::TeleportFavorites:
            case Page::TeleportHistory:
            case Page::MapMods:
                return Page::TeleportMenu;

            // Main level pages
            case Page::ControlCenter:
            case Page::Favorites:
            case Page::Search:
            case Page::UndoSystem:
            case Page::Player:
            case Page::Weapons:
            case Page::Vehicle:
            case Page::Npc:
            case Page::ScenarioMenu:
            case Page::ObjectSpawner:
            case Page::AnimationMenu:
            case Page::WorldControl:
            case Page::TeleportMenu:
            case Page::TrainerPresets:
            case Page::Settings:
                return Page::Main;

            case Page::Main:
            default:
                return Page::Main;
        }
    }

    static void GoBack()
    {
        st.page = ValidPageOrMain(st.page);

        if (st.page == Page::Main)
        {
            st.menuOpen = false;
            st.pageStack.clear();
            return;
        }

        SanitizeMenuPageStack();
        if (!st.pageStack.empty())
        {
            Page parent = Page::Main;
            bool haveParent = false;

            // Collapse any corrupted duplicate/self-loop entries. A few older
            // navigation flows could push the same page repeatedly; popping only
            // one duplicate could keep Back stuck on the current page.
            while (!st.pageStack.empty())
            {
                parent = ValidPageOrMain(st.pageStack.back());
                st.pageStack.pop_back();
                if (parent != st.page)
                {
                    haveParent = true;
                    break;
                }
            }

            if (!haveParent) parent = ParentPage(st.page);
            parent = ValidPageOrMain(parent);
            if (parent == st.page) parent = Page::Main;

            SetPageNoStack(parent);
            return;
        }

        Page parent = ValidPageOrMain(ParentPage(st.page));
        if (parent == st.page) parent = Page::Main;
        SetPageNoStack(parent);
    }


    static bool IsValidPageValue(Page page)
    {
        return ValidPageOrMain(page) == page;
    }

    static void TickAutoRecoveryUI(std::vector<MenuItem>& items)
    {
        // UI recovery is intentionally independent from the global Auto Recovery tick.
        // If the menu gets stuck while AutoRecovery/Enabled=false, the UI can still
        // reset itself as long as UIRecovery=true.
        if (!cfg.autoRecoverUi) return;
        if (!IsValidPageValue(st.page))
        {
            st.page = Page::Main;
            st.selected = 0;
            st.pageStack.clear();
            items.clear();
            RecordAutoRecoveryAction("UI page reset from invalid state", &st.autoRecoveryUiFixes, true);
            return;
        }

        if (!st.menuOpen)
        {
            st.uiEmptySinceTick = 0;
            return;
        }

        DWORD now = GetTickCount();
        if (st.pageStack.size() > 48)
        {
            st.pageStack.clear();
            st.selected = 0;
            RecordAutoRecoveryAction("UI navigation stack trimmed", &st.autoRecoveryUiFixes, true);
        }

        if (items.empty())
        {
            if (st.uiEmptySinceTick == 0) st.uiEmptySinceTick = now;
            if (core::TickElapsed(now, st.uiEmptySinceTick, SafeIntervalFromIntMs(cfg.uiRecoveryResetMs, 3500, 500, 60000, "ui", "empty recovery")))
            {
                st.page = Page::Main;
                st.selected = 0;
                st.searchQuery.clear();
                st.pageStack.clear();
                st.uiEmptySinceTick = 0;
                items.clear();
                RecordAutoRecoveryAction("UI soft reset after empty menu", &st.autoRecoveryUiFixes, true);
            }
            return;
        }

        st.uiEmptySinceTick = 0;
        if (st.selected < 0 || st.selected >= (int)items.size())
        {
            st.selected = 0;
            RecordAutoRecoveryAction("UI selection clamped", &st.autoRecoveryUiFixes, false);
        }
    }


