    static int NextValueInCycle(const std::vector<int>& values, int current, int fallback)
    {
        if (values.empty()) return fallback;
        auto it = std::find(values.begin(), values.end(), current);
        if (it == values.end()) return values.front();
        ++it;
        if (it == values.end()) it = values.begin();
        return *it;
    }

