    static std::string VehicleCategoryNameSafe(int index)
    {
        if (vehicleCategories.empty()) return vehicleCatalog.empty() ? "None" : "All";
        index = ClampIntValue(index, 0, (int)vehicleCategories.size() - 1);
        return vehicleCategories[index];
    }

    static std::vector<CatalogEntry> VehicleCatalogEntriesForCategorySafe(int index)
    {
        std::vector<CatalogEntry> visible;
        if (vehicleCatalog.empty()) return visible;
        if (vehicleCategories.empty())
        {
            visible = vehicleCatalog;
            return visible;
        }
        index = ClampIntValue(index, 0, (int)vehicleCategories.size() - 1);
        const std::string& cat = vehicleCategories[index];
        for (const auto& e : vehicleCatalog)
        {
            if (SameCatalogCategory(e.category, cat)) visible.push_back(e);
        }
        if (visible.empty()) visible = vehicleCatalog;
        return visible;
    }

