    static bool HandleMenuInput(std::vector<MenuItem>& items)
    {
        if (st.safeSpawnPreviewActive) return false;
        bool uiChanged = false;
        if (JustPressed(cfg.openKey, 250))
        {
            st.menuOpen = !st.menuOpen;
            PlayMenuSound(st.menuOpen ? MenuSoundKind::Open : MenuSoundKind::Close);
            st.selected = 0;
            InvalidateAdaptiveMenuWidth();
            return true;
        }
        if (!st.menuOpen) return false;
        if (items.empty())
        {
            if (ClampMenuSelectionForItems(items)) uiChanged = true;
            if (JustPressed(VK_BACK) || JustPressed(VK_ESCAPE))
            {
                PlayMenuSound(MenuSoundKind::Back);
                GoBack();
                return true;
            }
            return uiChanged;
        }
        if (ClampMenuSelectionForItems(items)) uiChanged = true;

        if (JustPressed(VK_UP))
        {
            const int next = FindNextSelectableMenuIndex(items, st.selected, -1);
            if (next != st.selected)
            {
                st.selected = next;
                PlayMenuSound(MenuSoundKind::Navigate);
                uiChanged = true;
            }
        }
        if (JustPressed(VK_DOWN))
        {
            const int next = FindNextSelectableMenuIndex(items, st.selected, 1);
            if (next != st.selected)
            {
                st.selected = next;
                PlayMenuSound(MenuSoundKind::Navigate);
                uiChanged = true;
            }
        }
        if (JustPressed(cfg.quickFavoriteAddKey, 250))
        {
            ClampMenuSelectionForItems(items);
            if (!items.empty() && IsQuickFavoriteEligibleForPage(st.page, items[st.selected]))
                PlayMenuSound(MenuSoundKind::Favorite);
            AddSelectedQuickFavorite(items);
            InvalidateAdaptiveMenuWidth();
            return true;
        }
        if (JustPressed(VK_RETURN))
        {
            const DWORD now = GetTickCount();
            if (!core::TickElapsed(now, g_lastMenuExecuteTick, 180u))
                return uiChanged;
            g_lastMenuExecuteTick = now;
            if (!items.empty())
            {
                ClampMenuSelectionForItems(items);
                auto item = items[st.selected];
                if (IsMenuSeparatorItem(item) || !IsMenuExecutableItem(item))
                {
                    return uiChanged;
                }
                PlayMenuSound((item.isToggle && item.toggle) ? MenuSoundKind::Favorite : MenuSoundKind::Select);
                ExecuteMenuItemSafely(item);
                InvalidateAdaptiveMenuWidth();
                return true;
            }
        }
        if (JustPressed(VK_BACK) || JustPressed(VK_ESCAPE))
        {
            PlayMenuSound(MenuSoundKind::Back);
            GoBack();
            return true;
        }
        if (uiChanged) InvalidateAdaptiveMenuWidth();
        return uiChanged;
    }

